def _resolve_palette_color(color: str, palette: dict[str, str]) -> str:
    return palette.get(color, color)


def _hex_to_srgb(color: str) -> tuple[float, float, float]:
    value = color.strip().lstrip("#")
    if len(value) != 6:
        raise ValueError(f"Expected #RRGGBB color, got {color!r}")
    try:
        return tuple(int(value[index:index + 2], 16) / 255 for index in (0, 2, 4))
    except ValueError as exc:
        raise ValueError(f"Expected #RRGGBB color, got {color!r}") from exc


def _linearize_srgb_channel(channel: float) -> float:
    if channel <= 0.03928:
        return channel / 12.92
    return ((channel + 0.055) / 1.055) ** 2.4


def relative_luminance(color: str) -> float:
    red, green, blue = (_linearize_srgb_channel(channel) for channel in _hex_to_srgb(color))
    return (0.2126 * red) + (0.7152 * green) + (0.0722 * blue)


def contrast_ratio(foreground: str, background: str) -> float:
    fg_luminance = relative_luminance(foreground)
    bg_luminance = relative_luminance(background)
    lighter = max(fg_luminance, bg_luminance)
    darker = min(fg_luminance, bg_luminance)
    return (lighter + 0.05) / (darker + 0.05)


def build_accessibility_audit_report(palette: dict[str, str] | None = None) -> dict:
    palette = palette or PALETTE
    contrast_pairs = []
    for label, fg_key, bg_key, minimum in ACCESSIBILITY_CONTRAST_PAIRS:
        foreground = _resolve_palette_color(fg_key, palette)
        background = _resolve_palette_color(bg_key, palette)
        ratio = contrast_ratio(foreground, background)
        contrast_pairs.append({
            "label": label,
            "foreground": foreground,
            "background": background,
            "ratio": round(ratio, 2),
            "minimum": minimum,
            "passes": ratio >= minimum,
        })

    return {
        "contrast_pairs": contrast_pairs,
        "summary": {
            "total_pairs": len(contrast_pairs),
            "passing_pairs": sum(1 for pair in contrast_pairs if pair["passes"]),
        },
        "font_checks": [
            "Primary UI font uses Segoe UI at 10pt or larger.",
            "Code/editor surfaces use Consolas at 10pt or larger.",
            "Windows DPI awareness is enabled before the Tk root is built.",
        ],
        "assistive_tech_checks": [
            "Primary commands use visible text labels, not icon-only buttons.",
            "Tooltips are supplemental; core actions also have button/menu labels.",
            "Manual Narrator/NVDA checks should cover menu traversal, editor focus, dialogs, and status updates.",
        ],
    }


def format_accessibility_audit_report(report: dict) -> str:
    summary = report.get("summary", {})
    lines = [
        "Accessibility audit",
        f"Contrast pairs: {summary.get('passing_pairs', 0)}/{summary.get('total_pairs', 0)} passing",
        "",
        "Contrast:",
    ]
    for pair in report.get("contrast_pairs", []):
        status = "PASS" if pair.get("passes") else "FAIL"
        lines.append(
            f"  {status} {pair.get('label')}: {pair.get('ratio')}:1 "
            f"(min {pair.get('minimum')}:1, fg {pair.get('foreground')}, bg {pair.get('background')})"
        )
    lines.append("")
    lines.append("Font checks:")
    for item in report.get("font_checks", []):
        lines.append(f"  - {item}")
    lines.append("")
    lines.append("Assistive-technology checks:")
    for item in report.get("assistive_tech_checks", []):
        lines.append(f"  - {item}")
    return "\n".join(lines)

# ----------------------------- Tooltip Helper --------------------------------
class ToolTip:
    """Creates a tooltip for a given widget.

    Tooltips show after a short hover delay (450ms) to avoid flashing
    on every transient mouse-over, and hide on click or when the widget
    is destroyed.
    """
    _SHOW_DELAY_MS = 450

    def __init__(self, widget, text):
        self.widget = widget
        self.text = text
        self.tooltip_window = None
        self._show_job = None
        self.widget.bind("<Enter>", self._schedule_show, add="+")
        self.widget.bind("<Leave>", self.hide_tooltip, add="+")
        self.widget.bind("<Destroy>", self.hide_tooltip, add="+")
        # Clicking or keyboard-activating the widget should dismiss any
        # lingering tooltip immediately so it doesn't hover over a just-
        # pressed button.
        self.widget.bind("<ButtonPress>", self.hide_tooltip, add="+")
        self.widget.bind("<KeyPress>", self.hide_tooltip, add="+")

    def _schedule_show(self, event=None):
        self._cancel_pending_show()
        try:
            self._show_job = self.widget.after(self._SHOW_DELAY_MS, self.show_tooltip)
        except tk.TclError:
            self._show_job = None

    def _cancel_pending_show(self):
        if self._show_job is not None:
            try:
                self.widget.after_cancel(self._show_job)
            except (tk.TclError, ValueError):
                pass
            self._show_job = None

    def show_tooltip(self, event=None):
        self._show_job = None
        if self.tooltip_window:
            return
        # Any of these widget calls can raise if the widget was destroyed
        # between scheduling and firing (e.g. during a config reload).
        try:
            if not self.widget.winfo_exists():
                return
            try:
                x, y, _, _ = self.widget.bbox("insert")
            except Exception:
                x, y = (0, 0)
            x += self.widget.winfo_rootx() + 25
            y += self.widget.winfo_rooty() + 25

            self.tooltip_window = tk.Toplevel(self.widget)
            self.tooltip_window.wm_overrideredirect(True)
            self.tooltip_window.wm_geometry(f"+{x}+{y}")
            label = tk.Label(
                self.tooltip_window,
                text=self.text,
                justify="left",
                background=PALETTE["mantle"],
                foreground=PALETTE["text"],
                relief="solid",
                borderwidth=1,
                font=("Segoe UI", 9),
            )
            label.pack(ipadx=6, ipady=3)
        except tk.TclError:
            self.tooltip_window = None

    def hide_tooltip(self, event=None):
        self._cancel_pending_show()
        if self.tooltip_window:
            try:
                self.tooltip_window.destroy()
            except tk.TclError:
                pass
        self.tooltip_window = None

# ------------------------------ Preview Window --------------------------------
class PreviewWindow(tk.Toplevel):
    def __init__(
        self,
        parent,
        original_lines,
        new_lines,
        title="Preview Changes",
        on_apply_callback=None,
        stats=None,
        apply_label="Apply Changes",
        cancel_label="Keep Current",
    ):
        super().__init__(parent.root)
        self.parent_editor = parent
        self.new_lines = new_lines
        self.on_apply_callback = on_apply_callback
        self.stats = stats or {}
        self._is_applying = False
        self._added_lines = 0
        self._removed_lines = 0

        self.title(title)
        # Clamp to available screen so the preview never opens larger than
        # the user's display (common on 1366x768 laptops where 900x650 +
        # window chrome overflows).
        try:
            screen_w = parent.root.winfo_screenwidth()
            screen_h = parent.root.winfo_screenheight()
        except Exception:
            screen_w, screen_h = 900, 650
        width = min(900, max(640, screen_w - 80))
        height = min(650, max(420, screen_h - 120))
        if hasattr(parent, "_configure_modal_window"):
            parent._configure_modal_window(
                self,
                title=title,
                size=f"{width}x{height}",
                min_size=(640, 420),
            )
        else:
            self.title(title)
            self.geometry(f"{width}x{height}")
            self.configure(bg=PALETTE["base"])
            self.transient(parent.root)
        self.grab_set()

        header_frame = ttk.Frame(self, padding=(16, 16, 16, 0))
        header_frame.pack(fill='x', side=tk.TOP)
        ttk.Label(header_frame, text="Preview changes", style="Eyebrow.TLabel").pack(anchor='w')
        ttk.Label(header_frame, text=title, font=("Segoe UI Semibold", 14)).pack(anchor='w', pady=(4, 0))
        ttk.Label(
            header_frame,
            text="Review the exact before-and-after output before applying it to the editor or disk.",
            foreground=PALETTE["subtext"]
        ).pack(anchor='w', pady=(4, 0))

        # Top stats/warning frame
        if self.stats:
            stats_frame = ttk.Frame(self, padding=(14, 12, 14, 0))
            stats_frame.pack(fill='x', side=tk.TOP)
            self._add_stat_banner(stats_frame)
        
        top_padding = 4 if self.stats else 12
        text_frame = ttk.Frame(self, padding=(16, top_padding, 16, 0))
        text_frame.pack(expand=True, fill='both')
        self.preview_text = scrolledtext.ScrolledText(
            text_frame, wrap=tk.NONE, font=("Consolas", 11),
        )
        if hasattr(parent, "_style_code_surface"):
            parent._style_code_surface(self.preview_text, font_spec=("Consolas", 11))
        self.preview_text.pack(expand=True, fill='both')

        ttk.Separator(self, orient="horizontal").pack(fill="x", pady=(12, 0))

        button_frame = ttk.Frame(self, padding=(16, 12, 16, 14))
        button_frame.pack(fill=tk.X, side=tk.BOTTOM)

        legend_frame = ttk.Frame(button_frame)
        legend_frame.pack(side=tk.LEFT)
        self.preview_summary_label = ttk.Label(legend_frame, text="", foreground=PALETTE["subtext"])
        self.preview_summary_label.pack(anchor='w')
        self.preview_legend_label = ttk.Label(legend_frame, text="", foreground=PALETTE["overlay1"])
        self.preview_legend_label.pack(anchor='w', pady=(2, 0))

        self.apply_button = ttk.Button(button_frame, text=apply_label, command=self.apply_changes, style="Action.TButton")
        self.apply_button.pack(side=tk.RIGHT, padx=6)
        ttk.Button(button_frame, text=cancel_label, command=self.destroy, style="Secondary.TButton").pack(side=tk.RIGHT, padx=6)

        self.preview_text.tag_config('added', foreground="#89D68D")
        self.preview_text.tag_config('removed', foreground=PALETTE["red"])
        self.preview_text.tag_config('header', foreground=PALETTE["blue"])
        self.display_diff(original_lines, new_lines)
        self.protocol("WM_DELETE_WINDOW", self.destroy)
        self.bind("<Escape>", lambda _event: self.destroy(), add="+")
        # Return/Enter confirms the preview without forcing the user to
        # mouse over to the button. Bound on the window so it works from
        # wherever focus sits (scrolling, header, etc.).
        self.bind("<Return>", lambda _event: self.apply_changes(), add="+")
        self.bind("<KP_Enter>", lambda _event: self.apply_changes(), add="+")
        # Focus the apply button so keyboard activation is predictable and
        # screen readers pick up the primary action.
        self.apply_button.focus_set()

    def _add_stat_banner(self, parent):
        total_discarded = self.stats.get('total_discarded', 0)
        transformed_count = self.stats.get('transformed', 0)

        if total_discarded > 0 and transformed_count > 0:
            warning_text = f"Cleaned Save will remove {total_discarded} entries and normalize {transformed_count} line(s)."
            warning_color = PALETTE["red"]
        elif total_discarded > 0:
            warning_text = f"Cleaned Save will remove {total_discarded} entries."
            warning_color = PALETTE["red"]
        elif transformed_count > 0:
            warning_text = f"Cleaned Save will normalize {transformed_count} line(s) without discarding any entries."
            warning_color = PALETTE["yellow"]
        else:
            warning_text = "Cleaned Save will preserve every current entry."
            warning_color = PALETTE["green"]

        warn_label = ttk.Label(parent, text=warning_text, foreground=warning_color, font=("Segoe UI", 11, "bold"))
        warn_label.pack(fill='x', pady=(0, 5))
        ttk.Label(
            parent,
            text="Review the categories below if you want to confirm why lines will change or be removed.",
            foreground=PALETTE["subtext"]
        ).pack(fill='x', pady=(0, 6))

        detail_frame = ttk.Frame(parent)
        detail_frame.pack(fill='x')

        detail_items = [
            ("Whitelist", self.stats.get('removed_whitelist', 0), PALETTE["blue"]),
            ("Invalid", self.stats.get('removed_invalid', 0), PALETTE["red"]),
            ("Duplicates", self.stats.get('removed_duplicates', 0), PALETTE["red"]),
            ("Comments", self.stats.get('removed_comments', 0), PALETTE["overlay1"]),
            ("Blanks", self.stats.get('removed_blanks', 0), PALETTE["overlay1"]),
        ]
        for column, (label, value, color) in enumerate(detail_items):
            chip = tk.Label(
                detail_frame,
                text=f"{label}: {value}",
                bg=PALETTE["surface0"],
                fg=color,
                font=("Segoe UI", 9, "bold"),
                padx=8,
                pady=4,
                bd=0
            )
            chip.grid(row=0, column=column, padx=(0, 6), pady=(0, 2), sticky="w")

        for column in range(len(detail_items)):
            detail_frame.grid_columnconfigure(column, weight=1)


    def display_diff(self, original, new):
        self.preview_text.config(state=tk.NORMAL)
        self.preview_text.delete('1.0', tk.END)
        self._added_lines = 0
        self._removed_lines = 0

        # difflib.ndiff is O(n*m). For very large editors (hundreds of
        # thousands of lines) it can hang the preview dialog for tens of
        # seconds. Fall back to unified_diff above the threshold - it still
        # classifies every line as added/removed/context, just without the
        # character-level hint lines.
        use_ndiff = max(len(original), len(new)) <= NDIFF_LINE_LIMIT

        if use_ndiff:
            for line in difflib.ndiff(original, new):
                line_content = line[2:] + '\n'
                if line.startswith('+ '):
                    self._added_lines += 1
                    self.preview_text.insert(tk.END, line_content, 'added')
                elif line.startswith('- '):
                    self._removed_lines += 1
                    self.preview_text.insert(tk.END, line_content, 'removed')
                elif not line.startswith('? '):
                    self.preview_text.insert(tk.END, line_content)
        else:
            for line in difflib.unified_diff(original, new, n=3, lineterm=""):
                if line.startswith("+++") or line.startswith("---"):
                    continue
                if line.startswith('@@'):
                    self.preview_text.insert(tk.END, line + '\n', 'header')
                    continue
                if line.startswith('+'):
                    self._added_lines += 1
                    self.preview_text.insert(tk.END, line[1:] + '\n', 'added')
                elif line.startswith('-'):
                    self._removed_lines += 1
                    self.preview_text.insert(tk.END, line[1:] + '\n', 'removed')
                else:
                    self.preview_text.insert(tk.END, line[1:] + '\n' if line.startswith(' ') else line + '\n')

        self.preview_text.config(state=tk.DISABLED)
        self.preview_summary_label.config(
            text=f"{self._added_lines:,} line(s) added, {self._removed_lines:,} removed"
        )
        legend = "Green lines are new. Red lines will be removed."
        if not use_ndiff:
            legend += " (Compact diff used for large files.)"
        self.preview_legend_label.config(text=legend)

    def apply_changes(self):
        if self._is_applying:
            return

        self._is_applying = True
        self.apply_button.configure(state="disabled")
        try:
            if self.on_apply_callback:
                self.on_apply_callback(self.new_lines)
            else:
                self.parent_editor.set_text(self.new_lines)
                self.parent_editor.update_status(f"Changes from '{self.title()}' applied.")
        except Exception as e:
            self._is_applying = False
            self.apply_button.configure(state="normal")
            self.parent_editor._show_notice_dialog(
                "Could not apply preview changes",
                "The approved preview could not be applied to the editor.",
                tone="error",
                details=str(e),
            )
            return

        self.destroy()

# -------------------------- Add Custom Source Dialog --------------------------
class AddSourceDialog(simpledialog.Dialog):
    def __init__(self, editor, initial_name="", initial_url=""):
        self.editor = editor
        self.initial_name = initial_name
        self.initial_url = initial_url
        self.feedback_var = tk.StringVar(value="")
        super().__init__(editor.root)

    def body(self, master):
        self.title("Add Custom Blocklist Source")
        self.configure(bg=PALETTE["base"])
        master.columnconfigure(1, weight=1)
        try:
            master.configure(padx=18, pady=16)
        except tk.TclError:
            pass
        ttk.Label(
            master,
            text="Save a reusable feed so it appears in Saved Sources for one-click imports later.",
            foreground=PALETTE["subtext"],
            wraplength=360,
            justify="left"
        ).grid(row=0, column=0, columnspan=2, sticky='w', pady=(0, 10))
        ttk.Label(master, text="Display Name").grid(row=1, sticky='w', pady=5)
        ttk.Label(master, text="Source URL").grid(row=2, sticky='w', pady=5)
        self.name_entry = ttk.Entry(master, width=40)
        self.url_entry = ttk.Entry(master, width=40)
        self.name_entry.grid(row=1, column=1, padx=5, sticky="ew")
        self.url_entry.grid(row=2, column=1, padx=5, sticky="ew")
        ttk.Label(
            master,
            text="Use a short, recognizable label such as the publisher or use case.",
            foreground=PALETTE["overlay1"],
            wraplength=360,
            justify="left",
        ).grid(row=3, column=1, sticky="w", padx=5, pady=(0, 6))
        ttk.Label(
            master,
            text="Only direct `http://` or `https://` feed URLs are accepted.",
            foreground=PALETTE["overlay1"],
            wraplength=360,
            justify="left",
        ).grid(row=4, column=1, sticky="w", padx=5, pady=(0, 0))
        self.feedback_shell = tk.Frame(
            master,
            bg=PALETTE["panel_alt"],
            highlightthickness=1,
            highlightbackground=PALETTE["border"],
            highlightcolor=PALETTE["focus"],
            bd=0,
        )
        self.feedback_shell.grid(row=5, column=0, columnspan=2, sticky="ew", pady=(12, 0))
        self.feedback_label = tk.Label(
            self.feedback_shell,
            textvariable=self.feedback_var,
            bg=PALETTE["panel_alt"],
            fg=PALETTE["yellow"],
            justify="left",
            wraplength=360,
            anchor="w",
            padx=12,
            pady=10,
        )
        self.feedback_label.pack(fill="x")
        self.feedback_shell.grid_remove()
        if self.initial_name:
            self.name_entry.insert(0, self.initial_name)
        if self.initial_url:
            self.url_entry.insert(0, self.initial_url)
        self.name_entry.bind("<KeyRelease>", lambda _event: self._clear_feedback(), add="+")
        self.url_entry.bind("<KeyRelease>", lambda _event: self._clear_feedback(), add="+")
        return self.name_entry

    # Upper bound on any custom source URL. 2083 is the practical browser
    # limit (IE/Edge legacy); anything longer is almost certainly pasted
    # junk or a prompt-injection attempt against the sidebar text.
    _URL_MAX_LEN = 2083
    _NAME_MAX_LEN = 120

    def _set_feedback(self, message: str, *, tone: str = "warning"):
        accent = {
            "warning": PALETTE["yellow"],
            "error": PALETTE["red"],
        }.get(tone, PALETTE["yellow"])
        self.feedback_var.set(message)
        self.feedback_label.configure(fg=accent)
        self.feedback_shell.configure(highlightbackground=accent, highlightcolor=accent)
        self.feedback_shell.grid()
        self.bell()

    def _clear_feedback(self):
        if hasattr(self, "feedback_shell"):
            self.feedback_var.set("")
            self.feedback_shell.grid_remove()

    def validate(self):
        self._clear_feedback()
        name, url = self.name_entry.get().strip(), self.url_entry.get().strip()
        if not name or not url:
            self._set_feedback(
                "Enter both a display name and a direct feed URL before saving this source.",
                tone="warning",
            )
            if not name:
                self.name_entry.focus_set()
            else:
                self.url_entry.focus_set()
            return False

        if len(name) > self._NAME_MAX_LEN:
            self._set_feedback(
                f"Display names are capped at {self._NAME_MAX_LEN} characters so the saved-sources list stays readable.",
                tone="error",
            )
            self.name_entry.focus_set()
            return False

        if any(ord(ch) < 32 for ch in name + url):
            # Embedded tabs / newlines / control bytes would corrupt the
            # sidebar display and the sanitized marker comments. Reject
            # rather than silently stripping.
            self._set_feedback(
                "Display names and URLs cannot contain tabs, newlines, or other control characters.",
                tone="error",
            )
            (self.url_entry if any(ord(ch) < 32 for ch in url) else self.name_entry).focus_set()
            return False

        if not url.lower().startswith(('http://', 'https://')):
            self._set_feedback(
                "Use a direct http:// or https:// URL for the feed you want to save.",
                tone="error",
            )
            self.url_entry.focus_set()
            self.url_entry.selection_range(0, tk.END)
            return False

        if len(url) > self._URL_MAX_LEN:
            self._set_feedback(
                f"Feed URLs are capped at {self._URL_MAX_LEN} characters.",
                tone="error",
            )
            self.url_entry.focus_set()
            return False

        parsed = _parse_valid_http_source_url(url)
        if parsed is None:
            self._set_feedback("That URL could not be parsed. Double-check the address and try again.", tone="error")
            self.url_entry.focus_set()
            return False

        self.result = (name, url)
        return True

    def apply(self):
        name, url = self.name_entry.get().strip(), self.url_entry.get().strip()
        self.result = (name, url)

    def buttonbox(self):
        box = ttk.Frame(self)
        box.configure(padding=(18, 8, 18, 18))
        ttk.Button(box, text="Cancel", width=14, command=self.cancel, style="Secondary.TButton").pack(side="right", padx=(0, 8))
        ttk.Button(box, text="Save Source", width=14, command=self.ok, style="Action.TButton").pack(side="right")
        self.bind("<Return>", self.ok)
        self.bind("<Escape>", self.cancel)
        box.pack(fill="x")

# -------------------------- Bulk Selection Dialog (New in v2.8.5) ----------------
class BulkSelectionDialog(tk.Toplevel):
    def __init__(self, editor, blocklist_sources, custom_sources):
        self.editor = editor
        super().__init__(editor.root)
        editor._configure_modal_window(
            self,
            title="Select Lists to Import",
            size="700x760",
            min_size=(620, 560),
        )
        self.grab_set()

        self.result = None
        self.filter_var = tk.StringVar()
        self.filter_var.trace_add("write", lambda *_args: self._rebuild_source_rows())
        self._all_sources: list[tuple[str, str, str, str]] = []
        self._selection_state: dict[tuple[str, str], bool] = {}
        for category, sources in blocklist_sources.items():
            for name, url, tooltip in sources:
                self._all_sources.append((category, name, url, tooltip))
                self._selection_state[(name, url)] = True
        for src in custom_sources:
            name = src["name"]
            url = src["url"]
            self._all_sources.append(("Custom Sources", name, url, "Custom source"))
            self._selection_state[(name, url)] = True
        self._visible_source_keys: list[tuple[str, str]] = []

        header_frame = ttk.Frame(self, padding=(18, 18, 18, 0))
        header_frame.pack(fill="x")
        ttk.Label(header_frame, text="Batch import", style="Eyebrow.TLabel").pack(anchor="w")
        ttk.Label(header_frame, text="Choose the sources you want to import together.", font=("Segoe UI Semibold", 13)).pack(anchor="w", pady=(4, 0))
        ttk.Label(
            header_frame,
            text="Selections are downloaded in a bounded parallel batch while output order stays tied to this review list.",
            foreground=PALETTE["subtext"],
            wraplength=640,
            justify="left",
        ).pack(anchor="w", pady=(4, 0))
        self.selection_summary_label = ttk.Label(header_frame, foreground=PALETTE["overlay1"])
        self.selection_summary_label.pack(anchor="w", pady=(8, 0))
        self.feedback_label = ttk.Label(
            header_frame,
            text="",
            foreground=PALETTE["yellow"],
            wraplength=640,
            justify="left",
        )
        self.feedback_label.pack(anchor="w", pady=(6, 0))

        filter_row = ttk.Frame(self, padding=(18, 14, 18, 0))
        filter_row.pack(fill="x")
        ttk.Label(filter_row, text="Filter", style="SectionTitle.TLabel").pack(side="left")
        self.filter_entry = ttk.Entry(filter_row, textvariable=self.filter_var)
        self.filter_entry.pack(side="left", fill="x", expand=True, padx=(10, 0))
        self.filter_entry.bind("<Escape>", lambda _event: (self.filter_var.set(""), "break")[-1])

        container = ttk.Frame(self, padding=(18, 14, 18, 0))
        container.pack(fill="both", expand=True)

        canvas = tk.Canvas(container, bg=PALETTE["base"], highlightthickness=0, bd=0)
        scrollbar = ttk.Scrollbar(container, orient="vertical", command=canvas.yview)
        self.scrollable_frame = ttk.Frame(canvas, padding=(0, 0, 2, 0))

        self.scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )

        def _on_mousewheel(event):
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        canvas.bind("<Enter>", lambda _event: canvas.bind_all("<MouseWheel>", _on_mousewheel))
        canvas.bind("<Leave>", lambda _event: canvas.unbind_all("<MouseWheel>"))
        self.bind("<Destroy>", lambda _event: canvas.unbind_all("<MouseWheel>"), add="+")

        canvas.bind("<Configure>", lambda e: canvas.itemconfigure("bulk-frame", width=e.width))
        canvas.create_window((0, 0), window=self.scrollable_frame, anchor="nw", width=652, tags=("bulk-frame",))
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")
        self.empty_state_label = None

        btn_frame = ttk.Frame(self, padding=(18, 14, 18, 18))
        btn_frame.pack(fill="x", side="bottom")

        left_btns = ttk.Frame(btn_frame)
        left_btns.pack(side="left")
        ttk.Button(left_btns, text="Select All Shown", command=self.select_all).pack(side="left", padx=(0, 6))
        ttk.Button(left_btns, text="Clear Shown", command=self.select_none).pack(side="left")

        right_btns = ttk.Frame(btn_frame)
        right_btns.pack(side="right")
        ttk.Button(right_btns, text="Import Selected Sources", command=self.confirm, style="Action.TButton").pack(side="left", padx=5)
        ttk.Button(right_btns, text="Cancel", command=self.destroy, style="Secondary.TButton").pack(side="left")

        self.filter_entry.focus_set()
        self._rebuild_source_rows()

    def _rebuild_source_rows(self):
        for child in self.scrollable_frame.winfo_children():
            child.destroy()
        self.empty_state_label = None
        self._clear_feedback()

        query = self.filter_var.get().strip().lower()
        self._visible_source_keys.clear()
        grouped: dict[str, list[tuple[str, str, str, str]]] = {}
        for category, name, url, tooltip in self._all_sources:
            haystack = f"{category} {name} {url} {tooltip}".lower()
            if query and query not in haystack:
                continue
            grouped.setdefault(category, []).append((category, name, url, tooltip))

        if not grouped:
            self.empty_state_label = ttk.Label(
                self.scrollable_frame,
                text="No sources match the current filter.",
                style="SectionBody.TLabel",
                wraplength=600,
                justify="left",
            )
            self.empty_state_label.pack(anchor="w", pady=(6, 0))
            self._update_selection_summary()
            return

        for category, sources in grouped.items():
            self._add_category_header(category, len(sources))
            for source_category, name, url, tooltip in sources:
                self._add_checkbox(source_category, name, url, tooltip)
        self._update_selection_summary()

    def _add_category_header(self, text, count):
        shell = tk.Frame(
            self.scrollable_frame,
            bg=PALETTE["panel"],
            highlightthickness=1,
            highlightbackground=PALETTE["border"],
            highlightcolor=PALETTE["focus"],
            bd=0,
        )
        shell.pack(fill="x", pady=(0, 6))
        inner = ttk.Frame(shell, style="Section.TFrame", padding=(14, 10, 14, 10))
        inner.pack(fill="both", expand=True)
        ttk.Label(inner, text=text, style="SectionTitle.TLabel").pack(side="left")
        ttk.Label(inner, text=f"{count} shown", style="SectionBody.TLabel").pack(side="right")

    def _add_checkbox(self, category, name, url, tooltip):
        key = (name, url)
        var = tk.BooleanVar(value=self._selection_state.get(key, True))
        shell = tk.Frame(
            self.scrollable_frame,
            bg=PALETTE["panel_alt"],
            highlightthickness=1,
            highlightbackground=PALETTE["border"],
            highlightcolor=PALETTE["focus"],
            bd=0,
        )
        shell.pack(fill="x", pady=(0, 6))
        frame = ttk.Frame(shell, style="Inset.TFrame", padding=(12, 10, 12, 10))
        frame.pack(fill="both", expand=True)

        row = ttk.Frame(frame, style="Inset.TFrame")
        row.pack(fill="x")
        cb = ttk.Checkbutton(
            row,
            text=name,
            variable=var,
            command=lambda k=key, v=var: self._toggle_selection(k, v),
        )
        cb.pack(side="left", fill="x", expand=True)
        source_host = urllib.parse.urlparse(url).netloc or url
        ttk.Label(row, text=source_host, foreground=PALETTE["subtext"]).pack(side="right", padx=(8, 0))
        if category == "Custom Sources":
            source_kind = "saved"
        elif str(category).startswith("Plugin:"):
            source_kind = "external"
        else:
            source_kind = "curated"
        last_stamp = self.editor.source_last_fetched.get(url, "") if hasattr(self.editor, "source_last_fetched") else ""
        cache_metadata = self.editor.source_cache_metadata.get(url, {}) if hasattr(self.editor, "source_cache_metadata") else {}
        trust_badges = build_source_trust_badges(
            name,
            url,
            tooltip,
            category=category,
            source_kind=source_kind,
            last_fetched=last_stamp,
            cache_metadata=cache_metadata,
        )
        ttk.Label(
            frame,
            text=format_source_trust_badges(trust_badges),
            style="SectionBody.TLabel",
            wraplength=600,
            justify="left",
        ).pack(anchor="w", pady=(5, 0))
        ttk.Label(
            frame,
            text=tooltip,
            style="SectionBody.TLabel",
            wraplength=600,
            justify="left",
        ).pack(anchor="w", pady=(6, 0))

        url_short = (url[:72] + "..") if len(url) > 72 else url
        trust_details = format_source_trust_details(trust_badges)
        ToolTip(cb, f"{tooltip}\nURL: {url_short}\n\nTrust badges:\n{trust_details}")

        self._visible_source_keys.append(key)

    def _toggle_selection(self, key, var):
        self._selection_state[key] = bool(var.get())
        self._clear_feedback()
        self._update_selection_summary()

    def _set_feedback(self, message: str):
        self.feedback_label.config(text=message)
        self.bell()

    def _clear_feedback(self):
        self.feedback_label.config(text="")

    def _update_selection_summary(self):
        total = len(self._all_sources)
        shown = len(self._visible_source_keys)
        selected_count = sum(1 for selected in self._selection_state.values() if selected)
        visible_selected = sum(1 for key in self._visible_source_keys if self._selection_state.get(key))
        if shown == total:
            self.selection_summary_label.config(text=f"{selected_count} of {total} source(s) selected.")
        else:
            self.selection_summary_label.config(
                text=f"{selected_count} of {total} selected overall. {visible_selected} of {shown} currently shown."
            )

    def select_all(self):
        targets = self._visible_source_keys if self._visible_source_keys else (
            [] if self.filter_var.get().strip() else list(self._selection_state.keys())
        )
        for key in targets:
            self._selection_state[key] = True
        self._clear_feedback()
        self._rebuild_source_rows()

    def select_none(self):
        targets = self._visible_source_keys if self._visible_source_keys else (
            [] if self.filter_var.get().strip() else list(self._selection_state.keys())
        )
        for key in targets:
            self._selection_state[key] = False
        self._clear_feedback()
        self._rebuild_source_rows()

    def confirm(self):
        selected = [
            (name, url)
            for (_category, name, url, _tooltip) in self._all_sources
            if self._selection_state.get((name, url))
        ]

        if not selected:
            self._set_feedback("Select at least one source before starting a batch import.")
            return

        self._clear_feedback()
        self.result = selected
        self.destroy()

# The match-removal dialog pages checkbox rows so large search results stay
# reviewable without asking Tk to create thousands of widgets at once.
VIRTUAL_LIST_DEFAULT_PAGE_SIZE = 200
VIRTUAL_LIST_MAX_PAGE_SIZE = 500

# Hard cap on the number of in-editor search matches we will highlight.
# A common one-letter query against a multi-megabyte hosts file could
# otherwise produce hundreds of thousands of matches and hang Tk while it
# tried to add that many tag ranges.
SEARCH_MATCH_LIMIT = 50_000


def build_virtual_list_page(rows, page_index: int = 0, page_size: int = VIRTUAL_LIST_DEFAULT_PAGE_SIZE) -> dict:
    """Return one bounded page of rows for Tk list dialogs."""
    rows = list(rows or [])
    total = len(rows)
    try:
        size = int(page_size)
    except (TypeError, ValueError):
        size = VIRTUAL_LIST_DEFAULT_PAGE_SIZE
    size = max(1, min(size, VIRTUAL_LIST_MAX_PAGE_SIZE))
    page_count = max(1, (total + size - 1) // size)
    try:
        index = int(page_index)
    except (TypeError, ValueError):
        index = 0
    index = max(0, min(index, page_count - 1))
    start = index * size
    end = min(total, start + size)
    return {
        "total": total,
        "page_index": index,
        "page_count": page_count,
        "page_size": size,
        "start": start,
        "end": end,
        "rows": rows[start:end],
    }


class MatchRemovalDialog(tk.Toplevel):
    def __init__(self, editor, query: str, matching_lines: list[tuple[int, str]]):
        self.editor = editor
        super().__init__(editor.root)
        editor._configure_modal_window(
            self,
            title=f"Remove Matches for '{query}'",
            size="820x680",
            min_size=(700, 520),
        )
        self.grab_set()

        self.result = None
        self.matching_lines = list(matching_lines)
        self.page_index = 0
        self.page_size = VIRTUAL_LIST_DEFAULT_PAGE_SIZE
        self.selected_indices = {line_index for line_index, _line in self.matching_lines}
        self.checkbox_vars = []

        header_frame = ttk.Frame(self, padding=(18, 18, 18, 0))
        header_frame.pack(fill="x")
        ttk.Label(header_frame, text="Selective removal", style="Eyebrow.TLabel").pack(anchor="w")
        ttk.Label(
            header_frame,
            text=f"Review which matches to remove for '{query}'.",
            font=("Segoe UI Semibold", 13)
        ).pack(anchor="w", pady=(4, 0))
        self.selection_summary_label = ttk.Label(
            header_frame,
            text="",
            foreground=PALETTE["subtext"]
        )
        self.selection_summary_label.pack(anchor="w", pady=(6, 0))
        self.feedback_label = ttk.Label(
            header_frame,
            text="",
            foreground=PALETTE["yellow"],
            wraplength=760,
            justify="left",
        )
        self.feedback_label.pack(anchor="w", pady=(6, 0))
        ttk.Label(
            header_frame,
            text="Unchecked lines stay in the editor. Large match sets are paged so only the visible rows are rendered.",
            foreground=PALETTE["overlay1"],
            wraplength=760,
            justify="left",
        ).pack(anchor="w", pady=(4, 0))

        container = ttk.Frame(self, padding=(18, 14, 18, 0))
        container.pack(fill="both", expand=True)

        canvas = tk.Canvas(container, bg=PALETTE["base"], highlightthickness=0, bd=0)
        scrollbar = ttk.Scrollbar(container, orient="vertical", command=canvas.yview)
        self.scrollable_frame = ttk.Frame(canvas)

        self.scrollable_frame.bind(
            "<Configure>",
            lambda e: canvas.configure(scrollregion=canvas.bbox("all"))
        )

        def _on_mousewheel(event):
            canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")

        canvas.bind("<Enter>", lambda _event: canvas.bind_all("<MouseWheel>", _on_mousewheel))
        canvas.bind("<Leave>", lambda _event: canvas.unbind_all("<MouseWheel>"))
        self.bind("<Destroy>", lambda _event: canvas.unbind_all("<MouseWheel>"), add="+")
        canvas.bind("<Configure>", lambda e: canvas.itemconfigure("match-frame", width=e.width))

        canvas.create_window((0, 0), window=self.scrollable_frame, anchor="nw", tags=("match-frame",))
        canvas.configure(yscrollcommand=scrollbar.set)

        canvas.pack(side="left", fill="both", expand=True)
        scrollbar.pack(side="right", fill="y")

        btn_frame = ttk.Frame(self, padding=(18, 14, 18, 18))
        btn_frame.pack(fill="x", side="bottom")

        left_btns = ttk.Frame(btn_frame)
        left_btns.pack(side="left")
        ttk.Button(left_btns, text="Select All", command=self.select_all).pack(side="left", padx=(0, 6))
        ttk.Button(left_btns, text="Select None", command=self.select_none).pack(side="left", padx=(0, 10))
        ttk.Button(left_btns, text="Prev", command=self.previous_page).pack(side="left", padx=(0, 6))
        ttk.Button(left_btns, text="Next", command=self.next_page).pack(side="left", padx=(0, 10))
        self.page_summary_label = ttk.Label(left_btns, text="", style="SectionBody.TLabel")
        self.page_summary_label.pack(side="left")

        right_btns = ttk.Frame(btn_frame)
        right_btns.pack(side="right")
        ttk.Button(right_btns, text="Remove Selected", command=self.confirm, style="Danger.TButton").pack(side="left", padx=5)
        ttk.Button(right_btns, text="Cancel", command=self.destroy, style="Secondary.TButton").pack(side="left")
        self._render_page()
        self._update_selection_summary()

    def _update_selection_summary(self):
        total = len(self.matching_lines)
        selected_count = len(self.selected_indices)
        self.selection_summary_label.config(text=f"{selected_count} of {total} removable line(s) currently selected")

    def _render_page(self):
        for child in self.scrollable_frame.winfo_children():
            child.destroy()
        page = build_virtual_list_page(self.matching_lines, self.page_index, self.page_size)
        self.page_index = page["page_index"]
        self.checkbox_vars = []
        if page["total"] == 0:
            ttk.Label(
                self.scrollable_frame,
                text="No matching rows are available.",
                style="SectionBody.TLabel",
            ).pack(anchor="w", padx=12, pady=12)
        for line_index, line in page["rows"]:
            var = tk.BooleanVar(value=line_index in self.selected_indices)
            shell = tk.Frame(
                self.scrollable_frame,
                bg=PALETTE["panel_alt"],
                highlightthickness=1,
                highlightbackground=PALETTE["border"],
                highlightcolor=PALETTE["focus"],
                bd=0,
            )
            shell.pack(fill="x", pady=(0, 6))
            frame = ttk.Frame(shell, style="Inset.TFrame", padding=(12, 10, 12, 10))
            frame.pack(fill="both", expand=True)

            row = ttk.Frame(frame, style="Inset.TFrame")
            row.pack(fill="x")
            cb = ttk.Checkbutton(
                row,
                text=f"Line {line_index + 1:,}",
                variable=var,
                command=lambda idx=line_index, v=var: self._on_row_selection_changed(idx, v),
            )
            cb.pack(side="left")
            ttk.Label(row, text=f"{len(line):,} chars", style="SectionBody.TLabel").pack(side="right")
            ttk.Label(
                frame,
                text=line,
                style="SectionBody.TLabel",
                wraplength=740,
                justify="left",
            ).pack(anchor="w", pady=(8, 0))
            self.checkbox_vars.append((line_index, var))
        self.page_summary_label.config(
            text=(
                f"Page {page['page_index'] + 1:,}/{page['page_count']:,}; "
                f"rows {page['start'] + 1:,}-{page['end']:,} of {page['total']:,}"
            )
            if page["total"]
            else "Page 0/0"
        )
        self._update_selection_summary()

    def _set_feedback(self, message: str):
        self.feedback_label.config(text=message)
        self.bell()

    def _clear_feedback(self):
        self.feedback_label.config(text="")

    def _on_row_selection_changed(self, line_index: int, var: tk.BooleanVar):
        if var.get():
            self.selected_indices.add(line_index)
        else:
            self.selected_indices.discard(line_index)
        self._clear_feedback()
        self._update_selection_summary()

    def select_all(self):
        self.selected_indices = {line_index for line_index, _line in self.matching_lines}
        self._render_page()
        self._clear_feedback()
        self._update_selection_summary()

    def select_none(self):
        self.selected_indices.clear()
        self._render_page()
        self._clear_feedback()
        self._update_selection_summary()

    def previous_page(self):
        if self.page_index <= 0:
            return
        self.page_index -= 1
        self._render_page()

    def next_page(self):
        page = build_virtual_list_page(self.matching_lines, self.page_index, self.page_size)
        if self.page_index >= page["page_count"] - 1:
            return
        self.page_index += 1
        self._render_page()

    def confirm(self):
        selected_indices = set(self.selected_indices)
        if not selected_indices:
            self._set_feedback("Select at least one matching line before continuing.")
            return

        self._clear_feedback()
        self.result = selected_indices
        self.destroy()

# -------------------------------- Domain & Hosts Helpers -----------------------------------

DOMAIN_REGEX = re.compile(r'^[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)+$')
IPV4_REGEX = re.compile(r'^(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)$')
IPV6_REGEX = re.compile(r'^[\da-fA-F:.]+$')
WILDCARD_STRIPPER = re.compile(r'^\*\.?(.*)')
TOKEN_SPLITTER = re.compile(r'[\s,;]+')
DNSMASQ_RULE_REGEX = re.compile(r'^(?:address|local)=/([^/]+)/?', re.IGNORECASE)
COMMENT_PREFIXES = ('#', '!', '[')
LOCAL_DOMAINS = {'localhost', 'localhost.localdomain', '::1'}
HOST_LABEL_REGEX = re.compile(r'^[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?$')
STANDARD_BLOCKING_IPS = {"0.0.0.0", "127.0.0.1", "::1"}
ADBLOCK_COSMETIC_MARKERS = (
    ("#@%#", "scriptlet exception"),
    ("#%#", "scriptlet"),
    ("#@?#", "extended cosmetic exception"),
    ("#?#", "extended cosmetic"),
    ("#@#", "cosmetic exception"),
    ("#$#", "CSS injection"),
    ("##", "cosmetic"),
)
ADBLOCK_QUARANTINE_COMMENT_PREFIX = "# HostsFileGet quarantined browser-only rule:"
RULE_TIER_FINDING_CATEGORIES = {
    "subdomain-scoped",
    "wildcard",
    "regex",
    "path-network",
    "browser-only",
    "exception",
    "invalid",
}
IDN_WARNING_CATEGORIES = {"homograph-risk", "invalid-punycode"}
IDN_LABEL_TOKEN_SPLITTER = re.compile(r'[\s,;]+')
CONFUSABLE_ASCII_MAP = {
    "\u0430": "a", "\u0410": "A",
    "\u0435": "e", "\u0415": "E",
    "\u043e": "o", "\u041e": "O",
    "\u0440": "p", "\u0420": "P",
    "\u0441": "c", "\u0421": "C",
    "\u0445": "x", "\u0425": "X",
    "\u0443": "y", "\u0423": "Y",
    "\u0456": "i", "\u0406": "I",
    "\u0458": "j", "\u0408": "J",
    "\u0455": "s", "\u0405": "S",
    "\u03b1": "a", "\u0391": "A",
    "\u03bf": "o", "\u039f": "O",
    "\u03c1": "p", "\u03a1": "P",
    "\u03b5": "e", "\u0395": "E",
    "\u03c7": "x", "\u03a7": "X",
    "\u03bd": "v", "\u039d": "N",
    "\u03b9": "i", "\u0399": "I",
}

def looks_like_domain(token: str, allow_single_label: bool = False) -> bool:
    if len(token) > 253: return False
    if token.startswith(('-', '.')) or token.endswith(('-', '.')): return False
    if IPV4_REGEX.match(token) or (IPV6_REGEX.match(token) and ':' in token): return False
    if allow_single_label and '.' not in token:
        return bool(HOST_LABEL_REGEX.match(token)) and any(character.isalpha() for character in token)
    return bool(DOMAIN_REGEX.match(token))

def _looks_like_ip_token(token: str) -> bool:
    return bool(IPV4_REGEX.match(token) or (IPV6_REGEX.match(token) and ':' in token))

def _is_comment_line(stripped: str) -> bool:
    return stripped.startswith(COMMENT_PREFIXES)

def _normalize_mapping_ip(token: str) -> tuple[str, bool, bool]:
    candidate = token.strip()
    normalized = candidate.lower() if ':' in candidate else candidate
    if normalized in STANDARD_BLOCKING_IPS:
        return "0.0.0.0", normalized != "0.0.0.0", True
    return normalized, normalized != candidate, False

def _extract_domain_from_token(token: str, allow_single_label: bool = False) -> tuple[str | None, bool]:
    candidate = token.strip().strip('\'"()[]{}<>')
    transformed = candidate != token.strip()
    if not candidate:
        return None, transformed

    if candidate.startswith('@@'):
        return None, True

    dnsmasq_match = DNSMASQ_RULE_REGEX.match(candidate)
    if dnsmasq_match:
        candidate = dnsmasq_match.group(1)
        transformed = True

    if candidate.startswith('||'):
        candidate = candidate[2:]
        transformed = True
    elif candidate.startswith('|'):
        candidate = candidate[1:]
        transformed = True

    for delimiter in ('^', '$'):
        if delimiter in candidate:
            candidate = candidate.split(delimiter, 1)[0]
            transformed = True

    if candidate.lower().startswith(('http://', 'https://', 'ftp://')):
        hostname = urllib.parse.urlsplit(candidate).hostname
        transformed = True
        if not hostname:
            return None, transformed
        candidate = hostname
    elif any(separator in candidate for separator in ('/', '?', ':')):
        try:
            hostname = urllib.parse.urlsplit(f"http://{candidate}").hostname
        except ValueError:
            hostname = None
        if hostname:
            candidate = hostname
            transformed = True

    wildcard_match = WILDCARD_STRIPPER.match(candidate)
    if wildcard_match:
        candidate = wildcard_match.group(1)
        transformed = True

    if candidate.endswith('.'):
        candidate = candidate[:-1]
        transformed = True

    domain = candidate.lower()
    if domain in LOCAL_DOMAINS or not looks_like_domain(domain, allow_single_label=allow_single_label):
        return None, transformed

    return domain, transformed


def _domain_shape_matches(domain: str, allow_single_label: bool = False) -> bool:
    if allow_single_label and "." not in domain:
        return bool(HOST_LABEL_REGEX.match(domain)) and any(character.isalpha() for character in domain)
    return looks_like_domain(domain, allow_single_label=False)


def _contains_non_ascii(value: str) -> bool:
    return any(ord(character) > 127 for character in value)


def _decode_idna_domain(domain: str) -> tuple[str | None, str | None]:
    try:
        return domain.encode("ascii").decode("idna"), None
    except (UnicodeError, UnicodeEncodeError) as exc:
        return None, str(exc)


def _encode_idna_domain(domain: str) -> tuple[str | None, str | None]:
    try:
        return domain.encode("idna").decode("ascii").lower(), None
    except UnicodeError as exc:
        return None, str(exc)


def _script_bucket(character: str) -> str | None:
    if character in ".-" or character.isdigit() or unicodedata.category(character).startswith("M"):
        return None
    if "A" <= character <= "Z" or "a" <= character <= "z":
        return "Latin"
    name = unicodedata.name(character, "")
    if not name:
        return "Other"
    for prefix, bucket in (
        ("LATIN", "Latin"),
        ("CYRILLIC", "Cyrillic"),
        ("GREEK", "Greek"),
        ("HEBREW", "Hebrew"),
        ("ARABIC", "Arabic"),
        ("DEVANAGARI", "Devanagari"),
        ("CJK", "CJK"),
        ("HIRAGANA", "Hiragana"),
        ("KATAKANA", "Katakana"),
        ("HANGUL", "Hangul"),
    ):
        if name.startswith(prefix):
            return bucket
    return "Other"


def _label_scripts(label: str) -> list[str]:
    scripts = {
        script
        for character in label
        for script in [_script_bucket(character)]
        if script
    }
    return sorted(scripts)


def _confusable_ascii_skeleton(domain: str) -> str:
    return "".join(CONFUSABLE_ASCII_MAP.get(character, character) for character in domain).lower()


def _extract_idn_candidate_from_token(token: str, allow_single_label: bool = False) -> str | None:
    candidate = token.strip().strip('\'"()[]{}<>')
    if not candidate:
        return None
    if candidate.startswith("@@"):
        candidate = candidate[2:]

    dnsmasq_match = DNSMASQ_RULE_REGEX.match(candidate)
    if dnsmasq_match:
        candidate = dnsmasq_match.group(1)

    pattern = candidate.split("$", 1)[0].strip()
    if pattern.startswith("||"):
        pattern = pattern[2:]
    elif pattern.startswith("|"):
        pattern = pattern[1:]
    pattern = pattern.rstrip("|")
    pattern = pattern.split("^", 1)[0].strip()

    if pattern.lower().startswith(("http://", "https://", "ftp://")):
        try:
            hostname = urllib.parse.urlsplit(pattern).hostname
        except ValueError:
            hostname = None
        if not hostname:
            return None
        pattern = hostname
    elif any(separator in pattern for separator in ("/", "?", ":")):
        try:
            hostname = urllib.parse.urlsplit(f"http://{pattern}").hostname
        except ValueError:
            hostname = None
        if hostname:
            pattern = hostname

    wildcard_match = WILDCARD_STRIPPER.match(pattern)
    if wildcard_match:
        pattern = wildcard_match.group(1)

    candidate = pattern.strip().strip(".").lower()
    if not candidate or candidate in LOCAL_DOMAINS or _looks_like_ip_token(candidate):
        return None

    has_idn_signal = _contains_non_ascii(candidate) or any(
        label.startswith("xn--") for label in candidate.split(".")
    )
    if not has_idn_signal:
        return None

    ascii_domain, _ = _encode_idna_domain(candidate)
    if ascii_domain and _domain_shape_matches(ascii_domain, allow_single_label=allow_single_label):
        return candidate
    if any(label.startswith("xn--") for label in candidate.split(".")):
        return candidate
    return None


def extract_idn_domain_candidates(lines: list[str]) -> list[dict]:
    candidates: list[dict] = []
    seen: set[tuple[int, str]] = set()
    for line_number, line in enumerate(lines, start=1):
        stripped = (line or "").strip()
        if not stripped or _is_comment_line(stripped):
            continue
        body = stripped
        if "#" in body and not _find_adblock_cosmetic_marker(body):
            body = body.split("#", 1)[0]
        tokens = [token for token in IDN_LABEL_TOKEN_SPLITTER.split(body) if token]
        allow_single_label = bool(tokens and _looks_like_ip_token(tokens[0]))
        for token in tokens:
            candidate = _extract_idn_candidate_from_token(token, allow_single_label=allow_single_label)
            if not candidate:
                continue
            key = (line_number, candidate)
            if key in seen:
                continue
            seen.add(key)
            candidates.append({"line_number": line_number, "domain": candidate, "line": line})
    return candidates


def classify_idn_domain(domain: str) -> dict:
    normalized = (domain or "").strip().strip(".").lower()
    result = {
        "domain": normalized,
        "category": "ascii",
        "severity": "info",
        "ascii": normalized if not _contains_non_ascii(normalized) else None,
        "unicode": normalized,
        "scripts": [],
        "mixed_script_labels": [],
        "confusable_skeleton": None,
        "warnings": [],
    }
    if not normalized:
        result["category"] = "invalid"
        result["severity"] = "warning"
        result["warnings"].append("Empty domain candidate.")
        return result

    has_punycode = any(label.startswith("xn--") for label in normalized.split("."))
    has_non_ascii = _contains_non_ascii(normalized)
    unicode_domain = normalized
    ascii_domain = normalized

    if has_punycode:
        decoded, decode_error = _decode_idna_domain(normalized)
        if decode_error or not decoded:
            result.update({
                "category": "invalid-punycode",
                "severity": "warning",
                "ascii": normalized,
                "unicode": None,
            })
            result["warnings"].append(f"Punycode label could not be decoded as valid IDNA: {decode_error}")
            return result
        unicode_domain = decoded.lower()

    encoded, encode_error = _encode_idna_domain(unicode_domain)
    if encode_error or not encoded:
        result.update({
            "category": "invalid-idn",
            "severity": "warning",
            "unicode": unicode_domain,
        })
        result["warnings"].append(f"Unicode domain could not be encoded as IDNA: {encode_error}")
        return result
    ascii_domain = encoded

    label_script_rows = []
    mixed_labels = []
    for label in unicode_domain.split("."):
        scripts = _label_scripts(label)
        label_script_rows.append({"label": label, "scripts": scripts})
        if len(scripts) > 1:
            mixed_labels.append({"label": label, "scripts": scripts})

    skeleton = _confusable_ascii_skeleton(unicode_domain)
    skeleton_is_ascii = skeleton != unicode_domain.lower() and all(ord(character) < 128 for character in skeleton)
    if mixed_labels or skeleton_is_ascii:
        result["category"] = "homograph-risk"
        result["severity"] = "warning"
        if mixed_labels:
            result["warnings"].append(
                "At least one label mixes writing systems; review before trusting or broadening this rule."
            )
        if skeleton_is_ascii:
            result["confusable_skeleton"] = skeleton
            result["warnings"].append(
                f"Known Cyrillic/Greek confusables resemble ASCII domain '{skeleton}'."
            )
    elif has_punycode:
        result["category"] = "punycode"
        result["warnings"].append("Punycode A-label decodes to a Unicode IDN; review the displayed Unicode form.")
    elif has_non_ascii:
        result["category"] = "idn"
        result["warnings"].append("Unicode IDN label is validly encodable; keep the ASCII A-label nearby for audits.")

    result.update({
        "ascii": ascii_domain,
        "unicode": unicode_domain,
        "scripts": label_script_rows,
        "mixed_script_labels": mixed_labels,
    })
    return result


def build_idn_homograph_report(lines: list[str], max_findings: int = 50) -> dict:
    counts: dict[str, int] = {}
    findings: list[dict] = []
    warning_count = 0
    punycode_count = 0
    idn_count = 0
    candidates = extract_idn_domain_candidates(lines)
    for candidate in candidates:
        classification = classify_idn_domain(candidate["domain"])
        category = classification["category"]
        counts[category] = counts.get(category, 0) + 1
        if category in {"idn", "punycode", "homograph-risk"}:
            idn_count += 1
        if any(label.startswith("xn--") for label in str(classification.get("ascii") or "").split(".")):
            punycode_count += 1
        if classification["severity"] == "warning":
            warning_count += 1
        if category != "ascii" and len(findings) < max_findings:
            findings.append({
                "line_number": candidate["line_number"],
                "domain": candidate["domain"],
                "category": category,
                "severity": classification["severity"],
                "ascii": classification.get("ascii"),
                "unicode": classification.get("unicode"),
                "confusable_skeleton": classification.get("confusable_skeleton"),
                "warnings": classification.get("warnings") or [],
                "line": candidate["line"],
            })
    return {
        "schema": "hostsfileget.idn-homograph-report.v1",
        "total_lines": len(lines),
        "candidate_domains": len(candidates),
        "idn_domains": idn_count,
        "punycode_domains": punycode_count,
        "warning_count": warning_count,
        "counts": counts,
        "findings": findings,
        "finding_limit": max_findings,
        "truncated_findings": max(0, len(candidates) - len(findings)),
        "warnings": [
            "This report is advisory; HostsFileGet does not automatically block or rewrite IDNs.",
            "Punycode A-labels and Unicode U-labels can be equivalent under IDNA, but visual spoofing is a separate security problem.",
            "Mixed-script and small confusable checks are deterministic heuristics, not a complete Unicode security engine.",
        ],
    }


def format_idn_homograph_report(report: dict) -> str:
    counts = report.get("counts") or {}
    lines = [
        "IDN and homograph report",
        f"Lines: {int(report.get('total_lines') or 0):,}",
        f"IDN/Punycode candidates: {int(report.get('candidate_domains') or 0):,}",
        f"Valid IDN domains: {int(report.get('idn_domains') or 0):,}",
        f"Punycode A-labels: {int(report.get('punycode_domains') or 0):,}",
        f"Warning candidates: {int(report.get('warning_count') or 0):,}",
        "",
        "Counts:",
    ]
    if counts:
        for category in sorted(counts):
            lines.append(f"- {category}: {int(counts[category]):,}")
    else:
        lines.append("- none: 0")
    lines.extend(["", "Warnings:"])
    for warning in report.get("warnings") or []:
        lines.append(f"- {warning}")
    findings = report.get("findings") or []
    if findings:
        lines.extend(["", "Findings:"])
        for finding in findings:
            details = []
            if finding.get("ascii"):
                details.append(f"ASCII={finding.get('ascii')}")
            if finding.get("unicode"):
                details.append(f"Unicode={finding.get('unicode')}")
            if finding.get("confusable_skeleton"):
                details.append(f"Skeleton={finding.get('confusable_skeleton')}")
            detail_text = "; ".join(details)
            warning_text = " ".join(finding.get("warnings") or [])
            line_preview = str(finding.get("line") or "").strip()
            if len(line_preview) > 120:
                line_preview = line_preview[:117] + "..."
            lines.append(
                f"- Line {finding.get('line_number')}: {finding.get('category')} "
                f"{detail_text} - {warning_text} [{line_preview}]"
            )
        truncated = int(report.get("truncated_findings") or 0)
        if truncated:
            lines.append(f"- ... {truncated:,} additional candidate(s) omitted.")
    else:
        lines.extend(["", "Findings: none"])
    return "\n".join(lines)


def _find_adblock_cosmetic_marker(stripped: str) -> tuple[str, str] | None:
    matches = []
    for marker, label in ADBLOCK_COSMETIC_MARKERS:
        index = stripped.find(marker)
        if index >= 0:
            matches.append((index, -len(marker), marker, label))
    if not matches:
        return None
    _, _, marker, label = sorted(matches)[0]
    return marker, label


def _adblock_pattern_has_url_path(pattern: str) -> bool:
    candidate = pattern.strip().strip("|")
    if not candidate:
        return False
    if candidate.lower().startswith(("http://", "https://", "ftp://")):
        try:
            parsed = urllib.parse.urlsplit(candidate)
        except ValueError:
            return False
        return bool(parsed.hostname and parsed.path and parsed.path != "/")
    host_mask = candidate.split("^", 1)[0]
    return "/" in host_mask


def classify_adblock_rule_line(line: str) -> dict:
    """Classify a line by how safely it can be represented in a hosts file."""
    stripped = (line or "").strip()
    result = {
        "line": line,
        "category": "blank",
        "severity": "info",
        "dns_compatible": False,
        "quarantine": False,
        "domain": None,
        "normalized": None,
        "reason": "Blank line.",
    }
    if not stripped:
        return result

    if stripped.startswith(ADBLOCK_QUARANTINE_COMMENT_PREFIX):
        result.update({
            "category": "quarantine-comment",
            "reason": "Already marked as a HostsFileGet quarantine comment.",
        })
        return result

    cosmetic_marker = _find_adblock_cosmetic_marker(stripped)
    if cosmetic_marker:
        marker, label = cosmetic_marker
        result.update({
            "category": "browser-only",
            "severity": "warning",
            "quarantine": True,
            "reason": f"Browser-only {label} rule uses {marker}; hosts files cannot hide page elements or run scriptlets.",
        })
        return result

    if _is_comment_line(stripped):
        result.update({"category": "comment", "reason": "Comment or metadata line."})
        return result

    if stripped.startswith("@@"):
        result.update({
            "category": "exception",
            "severity": "warning",
            "quarantine": True,
            "reason": "Adblock exception/allow rules cannot be represented as blocking hosts entries.",
        })
        return result

    pattern = stripped.split("$", 1)[0].strip()
    if pattern.startswith("||") and _adblock_pattern_has_url_path(pattern[2:]):
        result.update({
            "category": "path-network",
            "severity": "warning",
            "quarantine": True,
            "reason": "Path-level network filter would over-block if reduced to a hosts domain.",
        })
        return result
    if pattern.startswith("|") and _adblock_pattern_has_url_path(pattern):
        result.update({
            "category": "path-network",
            "severity": "warning",
            "quarantine": True,
            "reason": "URL-anchored network filter has path semantics that hosts files cannot express.",
        })
        return result

    if pattern.startswith("/") and pattern.endswith("/") and len(pattern) > 2:
        result.update({
            "category": "regex",
            "severity": "warning",
            "quarantine": True,
            "reason": "Regex filter can be DNS-provider syntax, but hosts files cannot represent regex matching.",
        })
        return result

    domain, transformed = _extract_domain_from_token(stripped, allow_single_label=False)
    if domain:
        category = "adblock-dns" if transformed or stripped.startswith(("||", "|")) or "$" in stripped else "domain"
        result.update({
            "category": category,
            "dns_compatible": True,
            "domain": domain,
            "normalized": f"0.0.0.0 {domain}",
            "reason": "Exact or hostname-scoped rule can be represented as a hosts entry.",
        })
        return result

    tokens = [token for token in TOKEN_SPLITTER.split(stripped.split("#", 1)[0].strip()) if token]
    if tokens and _looks_like_ip_token(tokens[0]):
        domains = []
        for token in tokens[1:]:
            token_domain, _ = _extract_domain_from_token(token, allow_single_label=True)
            if token_domain:
                domains.append(token_domain)
        if domains:
            result.update({
                "category": "hosts",
                "dns_compatible": True,
                "domain": domains[0],
                "normalized": f"{_normalize_mapping_ip(tokens[0])[0]} {domains[0]}",
                "reason": "Hosts-style mapping can be represented directly.",
            })
            return result

    result.update({
        "category": "invalid",
        "severity": "warning",
        "quarantine": True,
        "reason": "Line is not a valid hosts entry or exact DNS-compatible filter rule.",
    })
    return result

def parse_hosts_line_entries(line: str) -> tuple[list[tuple[str, str, bool]], bool]:
    stripped = line.strip()
    if not stripped or _is_comment_line(stripped):
        return [], False

    lint = classify_adblock_rule_line(line)
    if lint.get("quarantine"):
        return [], True

    processed = stripped.split('#', 1)[0].strip()
    if not processed:
        return [], False

    tokens = [token for token in TOKEN_SPLITTER.split(processed) if token]
    if not tokens:
        return [], False

    if _looks_like_ip_token(tokens[0]):
        mapping_ip, ip_transformed, is_block_entry = _normalize_mapping_ip(tokens[0])
        candidate_tokens = tokens[1:]
        transformed = ip_transformed or len(candidate_tokens) != 1
        allow_single_label = True
    else:
        mapping_ip = "0.0.0.0"
        is_block_entry = True
        candidate_tokens = tokens
        transformed = True
        allow_single_label = False

    parsed_entries = []
    seen_in_line = set()

    for token in candidate_tokens:
        domain, token_transformed = _extract_domain_from_token(token, allow_single_label=allow_single_label)
        transformed = transformed or token_transformed
        if not domain:
            continue

        normalized = f"{mapping_ip} {domain}"
        if normalized in seen_in_line:
            transformed = True
            continue

        seen_in_line.add(normalized)
        parsed_entries.append((normalized, domain, is_block_entry))

    return parsed_entries, transformed

def normalize_line_to_hosts_entries(line: str) -> tuple[list[str], list[str], bool]:
    parsed_entries, transformed = parse_hosts_line_entries(line)
    return [entry[0] for entry in parsed_entries], [entry[1] for entry in parsed_entries], transformed

def normalize_line_to_hosts_entry(line: str) -> tuple[str | None, str | None, bool]:
    normalized_entries, domains, transformed = normalize_line_to_hosts_entries(line)
    if normalized_entries:
        return normalized_entries[0], domains[0], transformed
    return None, None, False


def build_adblock_syntax_report(lines: list[str], max_findings: int = 50) -> dict:
    counts: dict[str, int] = {}
    findings: list[dict] = []
    dns_compatible = 0
    quarantined = 0
    for index, line in enumerate(lines, start=1):
        classification = classify_adblock_rule_line(line)
        category = classification["category"]
        counts[category] = counts.get(category, 0) + 1
        if classification.get("dns_compatible"):
            dns_compatible += 1
        if classification.get("quarantine"):
            quarantined += 1
            if len(findings) < max_findings:
                findings.append({
                    "line_number": index,
                    "category": category,
                    "reason": classification["reason"],
                    "line": line,
                    "domain": classification.get("domain"),
                })
    return {
        "schema": "hostsfileget.adblock-syntax-report.v1",
        "total_lines": len(lines),
        "dns_compatible": dns_compatible,
        "quarantined": quarantined,
        "counts": counts,
        "findings": findings,
        "finding_limit": max_findings,
        "truncated_findings": max(0, quarantined - len(findings)),
        "warnings": [
            "Browser cosmetic, scriptlet, exception, regex, and path-level adblock rules are not hosts-file entries.",
            "Path-level rules are quarantined because reducing them to a domain can over-block unrelated content.",
            "DNS-compatible adblock domain rules can be normalized to exact hosts entries, but provider-only modifiers are stripped.",
        ],
    }


def format_adblock_syntax_report(report: dict) -> str:
    counts = report.get("counts") or {}
    lines = [
        "Adblock syntax lint",
        f"Lines: {int(report.get('total_lines') or 0):,}",
        f"DNS-compatible / hosts-compatible: {int(report.get('dns_compatible') or 0):,}",
        f"Quarantined candidates: {int(report.get('quarantined') or 0):,}",
        "",
        "Counts:",
    ]
    for category in sorted(counts):
        lines.append(f"- {category}: {int(counts[category]):,}")
    lines.extend(["", "Warnings:"])
    for warning in report.get("warnings") or []:
        lines.append(f"- {warning}")
    findings = report.get("findings") or []
    if findings:
        lines.extend(["", "Findings:"])
        for finding in findings:
            line_preview = str(finding.get("line") or "").strip()
            if len(line_preview) > 140:
                line_preview = line_preview[:137] + "..."
            lines.append(
                f"- Line {finding.get('line_number')}: {finding.get('category')} - "
                f"{finding.get('reason')} [{line_preview}]"
            )
        truncated = int(report.get("truncated_findings") or 0)
        if truncated:
            lines.append(f"- ... {truncated:,} additional finding(s) omitted.")
    else:
        lines.extend(["", "Findings: none"])
    return "\n".join(lines)


def quarantine_adblock_rule_lines(lines: list[str]) -> tuple[list[str], dict]:
    quarantined_lines: list[str] = []
    changed = 0
    report = build_adblock_syntax_report(lines)
    for line in lines:
        classification = classify_adblock_rule_line(line)
        if classification.get("quarantine"):
            stripped = line.strip()
            if stripped.startswith(ADBLOCK_QUARANTINE_COMMENT_PREFIX):
                quarantined_lines.append(line)
                continue
            quarantined_lines.append(f"{ADBLOCK_QUARANTINE_COMMENT_PREFIX} {stripped}")
            changed += 1
        else:
            quarantined_lines.append(line)
    report["changed_lines"] = changed
    return quarantined_lines, report


def _split_filter_pattern_and_modifiers(stripped: str) -> tuple[str, str, bool]:
    exception = stripped.startswith("@@")
    body = stripped[2:] if exception else stripped
    if body.startswith("/") and body.endswith("/") and len(body) > 2:
        return body.strip(), "", exception
    pattern, _, modifiers = body.partition("$")
    return pattern.strip(), modifiers.strip(), exception


def _pattern_domain_label(pattern: str) -> str | None:
    candidate = pattern.strip()
    if candidate.startswith("||"):
        candidate = candidate[2:]
    candidate = candidate.strip("|")
    if candidate.lower().startswith(("http://", "https://", "ftp://")):
        try:
            parsed = urllib.parse.urlsplit(candidate)
        except ValueError:
            return None
        candidate = parsed.hostname or ""
    candidate = candidate.split("^", 1)[0].strip(".")
    if not candidate:
        return None
    validation_candidate = candidate.replace("*", "wildcard")
    validation_candidate = validation_candidate.replace("..", ".")
    if looks_like_domain(validation_candidate, allow_single_label=False):
        return candidate.lower()
    return None


def classify_rule_tier_line(line: str) -> dict:
    """Classify a rule by the matching tier that a hosts file can preserve."""
    stripped = (line or "").strip()
    result = {
        "line": line,
        "category": "blank",
        "tier": "blank",
        "severity": "info",
        "hosts_native": False,
        "hosts_effect": "ignored",
        "provider_effect": "ignored",
        "domain": None,
        "normalized": None,
        "warning": None,
    }
    if not stripped:
        return result

    if stripped.startswith(ADBLOCK_QUARANTINE_COMMENT_PREFIX):
        result.update({
            "category": "quarantine-comment",
            "tier": "comment",
            "hosts_effect": "ignored comment",
            "provider_effect": "ignored comment",
        })
        return result

    cosmetic_marker = _find_adblock_cosmetic_marker(stripped)
    if cosmetic_marker:
        marker, label = cosmetic_marker
        result.update({
            "category": "browser-only",
            "tier": "browser-only",
            "severity": "warning",
            "hosts_effect": "unsupported",
            "provider_effect": label,
            "warning": f"{marker} is browser filter syntax; hosts files cannot hide elements or run scriptlets.",
        })
        return result

    if _is_comment_line(stripped):
        result.update({
            "category": "comment",
            "tier": "comment",
            "hosts_effect": "ignored comment",
            "provider_effect": "ignored comment",
        })
        return result

    pattern, modifiers, exception = _split_filter_pattern_and_modifiers(stripped)
    is_regex = pattern.startswith("/") and pattern.endswith("/") and len(pattern) > 2
    has_wildcard = "*" in pattern
    domain_label = _pattern_domain_label(pattern)

    if is_regex:
        result.update({
            "category": "regex",
            "tier": "regex",
            "severity": "warning",
            "hosts_effect": "unsupported",
            "provider_effect": "regular expression rule",
            "domain": domain_label,
            "warning": "Hosts files cannot evaluate regex rules; keep this in a DNS provider or filter engine that documents regex support.",
        })
        return result

    if _adblock_pattern_has_url_path(pattern):
        result.update({
            "category": "path-network",
            "tier": "path",
            "severity": "warning",
            "hosts_effect": "unsupported",
            "provider_effect": "URL path/request filter",
            "domain": _pattern_domain_label(pattern),
            "warning": "Hosts files only see hostnames; URL path rules must stay in a browser or DNS provider that supports them.",
        })
        return result

    if has_wildcard:
        result.update({
            "category": "wildcard",
            "tier": "wildcard",
            "severity": "warning",
            "hosts_effect": "exact hosts entries only",
            "provider_effect": "wildcard rule",
            "domain": domain_label,
            "warning": "Hosts files do not support wildcards; cleaned output can only preserve exact domains.",
        })
        return result

    if exception:
        result.update({
            "category": "exception",
            "tier": "exception",
            "severity": "warning",
            "hosts_effect": "unsupported allow rule",
            "provider_effect": "exception or bypass rule",
            "domain": domain_label,
            "warning": "Hosts files have no rule-level allow/exception semantics; use the whitelist or downstream DNS provider.",
        })
        return result

    tokens = [token for token in TOKEN_SPLITTER.split(stripped.split("#", 1)[0].strip()) if token]
    if tokens and _looks_like_ip_token(tokens[0]):
        domains = []
        for token in tokens[1:]:
            token_domain, _ = _extract_domain_from_token(token, allow_single_label=True)
            if token_domain:
                domains.append(token_domain)
        if domains:
            mapping_ip, _, is_block_entry = _normalize_mapping_ip(tokens[0])
            result.update({
                "category": "hosts-exact" if is_block_entry else "hosts-custom-mapping",
                "tier": "exact",
                "hosts_native": True,
                "hosts_effect": "exact domain block" if is_block_entry else "exact custom mapping",
                "provider_effect": "exact domain rule",
                "domain": domains[0],
                "normalized": f"{mapping_ip} {domains[0]}",
            })
            return result

    lint = classify_adblock_rule_line(stripped)
    if lint.get("category") == "path-network":
        result.update({
            "category": "path-network",
            "tier": "path",
            "severity": "warning",
            "hosts_effect": "unsupported",
            "provider_effect": "URL path/request filter",
            "domain": lint.get("domain") or domain_label,
            "warning": lint.get("reason"),
        })
        return result
    if lint.get("dns_compatible") and pattern.startswith("||"):
        result.update({
            "category": "subdomain-scoped",
            "tier": "subdomain-scoped",
            "severity": "warning",
            "hosts_effect": "exact domain only after normalization",
            "provider_effect": "domain and subdomain rule",
            "domain": lint.get("domain") or domain_label,
            "normalized": lint.get("normalized"),
            "warning": "Rules beginning with || usually include subdomains in DNS filters; a hosts file needs one exact line per hostname.",
        })
        return result
    if lint.get("dns_compatible"):
        result.update({
            "category": "exact",
            "tier": "exact",
            "hosts_native": True,
            "hosts_effect": "exact domain block",
            "provider_effect": "exact domain rule",
            "domain": lint.get("domain") or domain_label,
            "normalized": lint.get("normalized"),
        })
        return result

    result.update({
        "category": "invalid",
        "tier": "invalid",
        "severity": "warning",
        "hosts_effect": "unsupported",
        "provider_effect": "unclassified",
        "warning": "Line is not a recognized exact, wildcard, regex, or hosts mapping rule.",
    })
    return result


def build_rule_tier_report(lines: list[str], max_findings: int = 50) -> dict:
    counts: dict[str, int] = {}
    tiers: dict[str, int] = {}
    findings: list[dict] = []
    hosts_native = 0
    warning_count = 0
    for index, line in enumerate(lines, start=1):
        classification = classify_rule_tier_line(line)
        category = classification["category"]
        tier = classification["tier"]
        counts[category] = counts.get(category, 0) + 1
        tiers[tier] = tiers.get(tier, 0) + 1
        if classification.get("hosts_native"):
            hosts_native += 1
        if classification.get("severity") == "warning":
            warning_count += 1
        if category in RULE_TIER_FINDING_CATEGORIES and len(findings) < max_findings:
            findings.append({
                "line_number": index,
                "category": category,
                "tier": tier,
                "domain": classification.get("domain"),
                "hosts_effect": classification.get("hosts_effect"),
                "provider_effect": classification.get("provider_effect"),
                "warning": classification.get("warning"),
                "line": line,
            })
    return {
        "schema": "hostsfileget.rule-tier-report.v1",
        "total_lines": len(lines),
        "hosts_native": hosts_native,
        "warning_count": warning_count,
        "counts": counts,
        "tiers": tiers,
        "findings": findings,
        "finding_limit": max_findings,
        "truncated_findings": max(0, warning_count - len(findings)),
        "warnings": [
            "Windows hosts files are exact hostname mappings, not wildcard or regex rule engines.",
            "Wildcard, regex, path, exception, client, redirect, and private-domain semantics belong in DNS-provider or browser-filter exports.",
            "Subdomain-scoped DNS rules need explicit exact hostnames before they can be represented faithfully in a hosts file.",
        ],
    }


def format_rule_tier_report(report: dict) -> str:
    lines = [
        "Rule tier report",
        f"Lines: {int(report.get('total_lines') or 0):,}",
        f"Native hosts entries: {int(report.get('hosts_native') or 0):,}",
        f"Warning candidates: {int(report.get('warning_count') or 0):,}",
        "",
        "Tiers:",
    ]
    tiers = report.get("tiers") or {}
    for tier in sorted(tiers):
        lines.append(f"- {tier}: {int(tiers[tier]):,}")
    counts = report.get("counts") or {}
    lines.extend(["", "Categories:"])
    for category in sorted(counts):
        lines.append(f"- {category}: {int(counts[category]):,}")
    lines.extend(["", "Warnings:"])
    for warning in report.get("warnings") or []:
        lines.append(f"- {warning}")
    findings = report.get("findings") or []
    if findings:
        lines.extend(["", "Findings:"])
        for finding in findings:
            preview = str(finding.get("line") or "").strip()
            if len(preview) > 140:
                preview = preview[:137] + "..."
            warning = finding.get("warning") or finding.get("hosts_effect") or ""
            lines.append(
                f"- Line {finding.get('line_number')}: {finding.get('tier')} / {finding.get('category')} - "
                f"{warning} [{preview}]"
            )
        truncated = int(report.get("truncated_findings") or 0)
        if truncated:
            lines.append(f"- ... {truncated:,} additional warning candidate(s) omitted.")
    else:
        lines.extend(["", "Findings: none"])
    return "\n".join(lines)

# -------------------------------- Canonical Output Builder -----------------------------------

WINDOWS_HEADER = [
    "# Copyright (c) 1993-2009 Microsoft Corp.",
    "#",
    "# This is a sample HOSTS file used by Microsoft TCP/IP for Windows.",
    "#",
    "# This file contains the mappings of IP addresses to host names. Each",
    "# entry should be kept on an individual line. The IP address should",
    "# be placed in the first column followed by the corresponding host name.",
    "# The IP address and the host name should be separated by at least one space.",
    "#",
    "# Additionally, comments (such as these) may be inserted on individual",
    "# lines or following the machine name denoted by a '#' symbol.",
    "#",
    "# For example:",
    "#"
]


def _get_canonical_cleaned_output_and_stats(
    original_lines: list[str],
    whitelist_set: set,
    pinned_domains: set | None = None,
) -> tuple[list[str], dict]:
    stats = {
        "lines_total": len(original_lines),
        "removed_blanks": 0,
        "removed_comments": 0,
        "removed_whitelist": 0,
        "removed_duplicates": 0,
        "removed_invalid": 0,
        "transformed": 0,
        "pinned_preserved": 0,
    }

    pinned = {p.lstrip('.') for p in (pinned_domains or set())}
    seen_normalized = set()
    active_entries_to_keep = []

    for line in original_lines:
        stripped = line.strip()

        if not stripped:
            stats["removed_blanks"] += 1
            continue

        if _is_comment_line(stripped):
            stats["removed_comments"] += 1
            continue

        parsed_entries, transformed = parse_hosts_line_entries(line)
        if not parsed_entries:
            stats["removed_invalid"] += 1
            continue

        kept_from_line = 0
        for normalized, domain, is_block_entry in parsed_entries:
            bare_domain = domain.lstrip('.')
            if is_block_entry and (domain in whitelist_set or bare_domain in whitelist_set):
                # Pinned entries outrank the whitelist — a user who pinned
                # a domain wants it kept blocked even when the same domain
                # is (e.g.) on a shared whitelist feed.
                if bare_domain not in pinned:
                    stats["removed_whitelist"] += 1
                    continue

            if normalized in seen_normalized:
                stats["removed_duplicates"] += 1
                continue

            seen_normalized.add(normalized)
            active_entries_to_keep.append(normalized)
            kept_from_line += 1

        if kept_from_line > 0 and transformed:
            stats["transformed"] += 1

    # Ensure every pinned domain is present even if the editor never had it.
    for bare in sorted(pinned):
        synthetic = f"0.0.0.0 {bare}"
        if synthetic in seen_normalized:
            continue
        seen_normalized.add(synthetic)
        active_entries_to_keep.append(synthetic)
        stats["pinned_preserved"] += 1

    final_header = WINDOWS_HEADER + [
        f"#\t127.0.0.1       localhost ({len(active_entries_to_keep)} active entries prepared by editor)",
        "#\t::1             localhost",
        "",
        f"# --- Active Hosts Entries (Cleaned & Sorted by {APP_NAME} v{APP_VERSION}) ---"
    ]

    cleaned_lines = final_header + sorted(active_entries_to_keep)
    
    if cleaned_lines and cleaned_lines[-1].strip():
        cleaned_lines.append("")

    stats["final_active"] = len(active_entries_to_keep)
    stats["final_total"] = len(cleaned_lines)
    stats["total_discarded"] = (
        stats["removed_whitelist"] + 
        stats["removed_duplicates"] + 
        stats["removed_invalid"] +
        stats["removed_comments"] +
        stats["removed_blanks"]
    )

    return cleaned_lines, stats

def compute_clean_impact_stats(
    original_lines: list[str],
    whitelist_set: set,
    pinned_domains: set | None = None,
) -> dict:
    _, stats = _get_canonical_cleaned_output_and_stats(original_lines, whitelist_set, pinned_domains)
    return stats

TEXT_FILE_ENCODINGS = ("utf-8", "utf-8-sig", "cp1252", "latin-1")

def decode_text_bytes(raw_bytes: bytes) -> str:
    if raw_bytes.startswith(b'\xef\xbb\xbf'):
        return raw_bytes.decode("utf-8-sig")

    if raw_bytes.startswith((b'\xff\xfe', b'\xfe\xff')):
        return raw_bytes.decode("utf-16")

    null_bytes = raw_bytes.count(b"\x00")
    if raw_bytes and null_bytes and (null_bytes / len(raw_bytes)) > 0.15:
        for encoding in ("utf-16-le", "utf-16-be"):
            try:
                return raw_bytes.decode(encoding)
            except UnicodeDecodeError:
                continue

    for encoding in TEXT_FILE_ENCODINGS:
        try:
            return raw_bytes.decode(encoding)
        except UnicodeDecodeError:
            continue
    return raw_bytes.decode('utf-8', errors='ignore')

def read_text_file_lines(path: str) -> list[str]:
    with open(path, 'rb') as f:
        return decode_text_bytes(f.read()).splitlines()

def read_text_file_content(path: str) -> str:
    return '\n'.join(read_text_file_lines(path))

def write_text_file_atomic(path: str, content: str):
    directory = os.path.dirname(path) or "."
    fd, temp_path = tempfile.mkstemp(prefix="hosts_editor_", suffix=".tmp", dir=directory, text=True)
    try:
        with os.fdopen(fd, 'w', encoding='utf-8', newline='\n') as f:
            f.write(content)
            # Ensure a trailing newline. Some POSIX-style tools that consume
            # the hosts file expect one, and hash comparisons here go through
            # splitlines so an added terminator doesn't change equality.
            if content and not content.endswith('\n'):
                f.write('\n')
            f.flush()
            os.fsync(f.fileno())
        os.replace(temp_path, path)
    except Exception:
        if os.path.exists(temp_path):
            os.unlink(temp_path)
        raise


def write_bytes_file_atomic(path: str, content: bytes):
    directory = os.path.dirname(path) or "."
    fd, temp_path = tempfile.mkstemp(prefix="hosts_editor_", suffix=".tmp", dir=directory)
    try:
        with os.fdopen(fd, "wb") as f:
            f.write(content)
            f.flush()
            os.fsync(f.fileno())
        os.replace(temp_path, path)
    except Exception:
        if os.path.exists(temp_path):
            os.unlink(temp_path)
        raise


def _allocate_unique_sibling_temp_path(target_path: str, suffix: str) -> str:
    """Reserve a unique temp path next to ``target_path`` and return it."""
    directory = os.path.dirname(target_path) or "."
    prefix = os.path.basename(target_path) + "."
    fd, temp_path = tempfile.mkstemp(prefix=prefix, suffix=suffix, dir=directory)
    os.close(fd)
    try:
        os.unlink(temp_path)
    except OSError:
        pass
    return temp_path


def disable_hosts_file_transactionally(hosts_path: str, disabled_path: str, minimal_content: str) -> None:
    """Disable the hosts file without leaving a stale disabled marker on failure."""
    had_existing_hosts = os.path.exists(hosts_path)
    staged_disabled_path = None

    try:
        if had_existing_hosts:
            staged_disabled_path = _allocate_unique_sibling_temp_path(disabled_path, ".pending")
            shutil.copy2(hosts_path, staged_disabled_path)

        write_text_file_atomic(hosts_path, minimal_content)

        if staged_disabled_path:
            os.replace(staged_disabled_path, disabled_path)
    except Exception:
        if staged_disabled_path and os.path.exists(staged_disabled_path):
            if had_existing_hosts:
                try:
                    shutil.copy2(staged_disabled_path, hosts_path)
                except OSError:
                    pass
            try:
                os.unlink(staged_disabled_path)
            except OSError:
                pass
        raise


def enable_hosts_file_transactionally(hosts_path: str, disabled_path: str) -> None:
    """Re-enable the hosts file without leaving ``.disabled`` behind on success."""
    staged_restore_path = _allocate_unique_sibling_temp_path(disabled_path, ".restore")
    os.replace(disabled_path, staged_restore_path)

    try:
        shutil.copy2(staged_restore_path, hosts_path)
        try:
            os.unlink(staged_restore_path)
        except OSError:
            pass
    except Exception:
        if os.path.exists(staged_restore_path) and not os.path.exists(disabled_path):
            try:
                os.replace(staged_restore_path, disabled_path)
            except OSError:
                pass
        raise

def _format_size_limit(size_bytes: int) -> str:
    if size_bytes >= 1024 * 1024:
        return f"{size_bytes // (1024 * 1024)} MB"
    if size_bytes >= 1024:
        return f"{size_bytes // 1024} KB"
    return f"{size_bytes} bytes"


def read_http_body_limited(response, max_bytes: int = MAX_DOWNLOAD_BYTES) -> bytes:
    """Read an HTTP response with a hard ceiling on total bytes.

    ``response.read(max_bytes + 1)`` is used so we can detect overruns without
    paying for an unbounded read. Returning the body as-is lets callers decode
    and normalize it through the existing pipeline.
    """
    data = response.read(max_bytes + 1)
    if len(data) > max_bytes:
        raise ValueError(
            f"Response exceeded {_format_size_limit(max_bytes)} size cap "
            "(feed too large or server is streaming non-hosts content)."
        )
    return data


def decode_downloaded_lines(url: str, raw_bytes: bytes, content_encoding: str = "") -> list[str]:
    lowered_url = url.lower()
    lowered_encoding = content_encoding.lower()

    try:
        if lowered_url.endswith(".bz2"):
            raw_bytes = bz2.decompress(raw_bytes)
        elif lowered_url.endswith(".gz") or "gzip" in lowered_encoding:
            raw_bytes = gzip.decompress(raw_bytes)
    except OSError:
        # Some mirrors advertise compression inconsistently; fall back to raw bytes.
        pass

    # After decompression, re-check the size so a 1 KB gzip bomb can't expand
    # into hundreds of MB in memory undetected.
    if len(raw_bytes) > MAX_DOWNLOAD_BYTES:
        raise ValueError(
            f"Decompressed payload exceeded {MAX_DOWNLOAD_BYTES // (1024 * 1024)} MB size cap."
        )

    return decode_text_bytes(raw_bytes).splitlines()

def looks_like_html_document(lines: list[str]) -> bool:
    significant_lines = [line.strip().lower() for line in lines if line.strip()][:20]
    if not significant_lines:
        return False

    combined = '\n'.join(significant_lines[:10])
    html_markers = ("<!doctype html", "<html", "<head", "<body", "</html>", "<title", "<meta ")
    if significant_lines[0].startswith(("<!doctype html", "<html")):
        return True

    marker_hits = sum(1 for marker in html_markers if marker in combined)
    return marker_hits >= 2

def _portable_config_path_candidate(config_filename: str = CONFIG_FILENAME) -> str:
    """Return the path where a portable-mode config would live.

    Portable mode: if the user ships a ``hosts_editor_config.json`` next to
    the exe / script, we treat that sibling as the live config and skip
    ``%LOCALAPPDATA%`` entirely. Lets USB-stick / team-share deployments
    carry their settings with the binary.
    """
    return os.path.join(_EXE_DIR, config_filename)


def is_portable_mode() -> bool:
    return os.path.isfile(_portable_config_path_candidate())


def get_app_config_dir() -> str:
    if os.name == 'nt':
        base_dir = os.environ.get("LOCALAPPDATA") or os.environ.get("APPDATA") or os.path.expanduser("~")
        return os.path.join(base_dir, APP_SLUG)
    return os.path.join(os.path.expanduser("~"), f".{APP_SLUG.lower()}")

def get_primary_config_path(config_filename: str) -> str:
    if is_portable_mode():
        return _portable_config_path_candidate(config_filename)
    return _roaming_config_path(config_filename)


def _roaming_config_path(config_filename: str) -> str:
    return os.path.join(get_app_config_dir(), config_filename)


def get_config_root_dir(config_filename: str = CONFIG_FILENAME) -> str:
    return os.path.dirname(get_primary_config_path(config_filename)) or "."


def get_source_cache_dir() -> str:
    return os.path.join(get_config_root_dir(), SOURCE_CACHE_DIRNAME)


def source_cache_key(url: str) -> str:
    normalized = normalize_custom_source_url(url) or str(url).strip()
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()


def get_source_cache_body_path(url: str, cache_dir: str | None = None) -> str:
    return os.path.join(cache_dir or get_source_cache_dir(), f"{source_cache_key(url)}.bin")


def get_git_history_dir(base_dir: str | None = None) -> str:
    root = base_dir or get_config_root_dir()
    return os.path.join(root, GIT_HISTORY_DIRNAME)


def build_config_location_report(config_filename: str = CONFIG_FILENAME) -> dict:
    portable_path = _portable_config_path_candidate(config_filename)
    local_path = _roaming_config_path(config_filename)
    portable_active = os.path.isfile(portable_path)
    active_path = portable_path if portable_active else local_path
    active_root = os.path.dirname(active_path) or "."
    return {
        "schema_version": CONFIG_SCHEMA_VERSION,
        "mode": "portable" if portable_active else "local",
        "reason": (
            "portable config exists beside the executable/script"
            if portable_active
            else "no portable config exists beside the executable/script"
        ),
        "active_config_path": active_path,
        "portable_config_path": portable_path,
        "portable_config_exists": portable_active,
        "local_config_path": local_path,
        "local_config_exists": os.path.isfile(local_path),
        "sidecar_root": active_root,
        "source_cache_dir": os.path.join(active_root, SOURCE_CACHE_DIRNAME),
        "git_history_dir": os.path.join(active_root, GIT_HISTORY_DIRNAME),
        "cli_log_path": os.path.join(active_root, CLI_LOG_FILENAME),
        "cli_activity_path": os.path.join(active_root, CLI_ACTIVITY_FILENAME),
    }


def format_config_location_report(report: dict) -> str:
    return "\n".join([
        "Config Location",
        f"Mode: {report.get('mode', 'unknown')}",
        f"Reason: {report.get('reason') or '-'}",
        f"Active config: {report.get('active_config_path') or '-'}",
        "",
        "Candidates:",
        (
            f"  Portable: {report.get('portable_config_path') or '-'} "
            f"({'exists' if report.get('portable_config_exists') else 'missing'})"
        ),
        (
            f"  Local user: {report.get('local_config_path') or '-'} "
            f"({'exists' if report.get('local_config_exists') else 'missing'})"
        ),
        "",
        "Sidecar paths:",
        f"  Root: {report.get('sidecar_root') or '-'}",
        f"  Source cache: {report.get('source_cache_dir') or '-'}",
        f"  Git history: {report.get('git_history_dir') or '-'}",
        f"  CLI log: {report.get('cli_log_path') or '-'}",
        f"  CLI activity: {report.get('cli_activity_path') or '-'}",
    ])


def build_portable_bundle_readme(config_path: str) -> str:
    return "\n".join([
        "# HostsFileGet Portable Bundle",
        "",
        f"This directory contains `{CONFIG_FILENAME}` for portable mode.",
        "",
        "Portable mode becomes active only when the config file sits beside the executable or script that is launched.",
        f"Config path written: `{config_path}`",
        "",
        "Sidecar files such as source cache, optional Git history, CLI logs, and scheduler activity use the same directory when portable mode is active.",
        "Move or delete the config file to return to the normal per-user config under `%LOCALAPPDATA%\\HostsFileGet`.",
    ]) + "\n"


def write_portable_bundle_config(
    bundle_dir: str,
    config_payload: dict | None,
    default_last_open_dir: str,
    *,
    overwrite: bool = False,
) -> dict:
    if not isinstance(bundle_dir, str) or not bundle_dir.strip():
        raise ValueError("Portable bundle directory is required.")
    target_dir = os.path.abspath(os.path.expanduser(bundle_dir))
    config_path = os.path.join(target_dir, CONFIG_FILENAME)
    readme_path = os.path.join(target_dir, PORTABLE_BUNDLE_README_FILENAME)
    if os.path.exists(config_path) and not overwrite:
        raise FileExistsError(f"Portable config already exists: {config_path}")
    os.makedirs(target_dir, exist_ok=True)
    sanitized = sanitize_config_snapshot(config_payload or {}, default_last_open_dir)
    write_text_file_atomic(config_path, json.dumps(sanitized, indent=2))
    write_text_file_atomic(readme_path, build_portable_bundle_readme(config_path))
    return {
        "bundle_dir": target_dir,
        "config_path": config_path,
        "readme_path": readme_path,
        "profile_count": len(sanitized.get("profiles", [])),
        "active_profile_id": sanitized.get("active_profile_id", DEFAULT_PROFILE_ID),
    }


def format_portable_bundle_export_summary(result: dict) -> str:
    return "\n".join([
        "Portable Bundle Config",
        f"Directory: {result.get('bundle_dir') or '-'}",
        f"Config: {result.get('config_path') or '-'}",
        f"Readme: {result.get('readme_path') or '-'}",
        f"Active profile: {result.get('active_profile_id') or DEFAULT_PROFILE_ID}",
        f"Profiles: {result.get('profile_count', 0)}",
    ])


def resolve_git_executable(git_executable: str | None = None) -> str | None:
    if git_executable:
        return git_executable
    return shutil.which("git")


def sanitize_git_history_ref(ref: str) -> str:
    candidate = str(ref or "").strip()
    if (
        not GIT_HISTORY_REF_PATTERN.match(candidate)
        or ".." in candidate
        or "@{" in candidate
        or "\\" in candidate
        or candidate.startswith("-")
    ):
        raise ValueError("invalid Git history reference")
    return candidate


def _run_git_command(
    repo_dir: str,
    args: list[str],
    git_executable: str | None = None,
    runner=None,
    timeout: int = 15,
    strip_output: bool = True,
) -> str:
    git = resolve_git_executable(git_executable)
    if not git:
        raise OSError("git executable not found")
    run = runner or subprocess.run
    try:
        result = run(
            [git, *args],
            cwd=repo_dir,
            capture_output=True,
            text=True,
            timeout=timeout,
            check=False,
        )
    except FileNotFoundError as exc:
        raise OSError("git executable not found") from exc
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "").strip()
        raise OSError(f"git {' '.join(args)} failed: {detail}")
    output = result.stdout or ""
    return output.strip() if strip_output else output


def ensure_git_history_repo(
    repo_dir: str,
    git_executable: str | None = None,
    runner=None,
) -> str:
    os.makedirs(repo_dir, exist_ok=True)
    git = resolve_git_executable(git_executable)
    if not git:
        raise OSError("git executable not found")
    if not os.path.isdir(os.path.join(repo_dir, ".git")):
        _run_git_command(repo_dir, ["init"], git_executable=git, runner=runner)
    _run_git_command(repo_dir, ["config", "user.name", "HostsFileGet"], git_executable=git, runner=runner)
    _run_git_command(
        repo_dir,
        ["config", "user.email", "hostsfileget@localhost"],
        git_executable=git,
        runner=runner,
    )
    return repo_dir


def build_git_history_metadata(hosts_content: str, source_description: str = "manual snapshot") -> dict:
    lines = hosts_content.splitlines()
    return {
        "schema": "hostsfileget.git-history.v1",
        "app_version": APP_VERSION,
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "source": re.sub(r"\s+", " ", str(source_description or "manual snapshot")).strip()[:120],
        "line_count": len(lines),
        "nonempty_line_count": sum(1 for line in lines if line.strip()),
        "sha256": hashlib.sha256(hosts_content.encode("utf-8")).hexdigest(),
    }


def _git_history_commit_message(source_description: str) -> str:
    source = re.sub(r"[\r\n\t]+", " ", str(source_description or "manual snapshot")).strip()
    source = source[:72] or "manual snapshot"
    return f"hosts snapshot: {source}"


def write_git_history_snapshot(
    repo_dir: str,
    hosts_content: str,
    source_description: str = "manual snapshot",
    git_executable: str | None = None,
    runner=None,
) -> dict:
    ensure_git_history_repo(repo_dir, git_executable=git_executable, runner=runner)
    hosts_path = os.path.join(repo_dir, GIT_HISTORY_HOSTS_FILENAME)
    metadata_path = os.path.join(repo_dir, GIT_HISTORY_METADATA_FILENAME)
    if os.path.isfile(hosts_path):
        try:
            if read_text_file_content(hosts_path).splitlines() == hosts_content.splitlines():
                commit = _run_git_command(
                    repo_dir,
                    ["rev-parse", "--short=12", "HEAD"],
                    git_executable=git_executable,
                    runner=runner,
                )
                return {
                    "status": "unchanged",
                    "commit": commit,
                    "repo_dir": repo_dir,
                    "hosts_path": hosts_path,
                }
        except OSError:
            pass

    write_text_file_atomic(hosts_path, hosts_content)
    write_text_file_atomic(
        metadata_path,
        json.dumps(build_git_history_metadata(hosts_content, source_description), indent=2),
    )

    _run_git_command(
        repo_dir,
        ["add", "--", GIT_HISTORY_HOSTS_FILENAME, GIT_HISTORY_METADATA_FILENAME],
        git_executable=git_executable,
        runner=runner,
    )
    status = _run_git_command(
        repo_dir,
        ["status", "--porcelain", "--", GIT_HISTORY_HOSTS_FILENAME, GIT_HISTORY_METADATA_FILENAME],
        git_executable=git_executable,
        runner=runner,
    )
    if not status:
        commit = _run_git_command(repo_dir, ["rev-parse", "--short=12", "HEAD"], git_executable=git_executable, runner=runner)
        return {
            "status": "unchanged",
            "commit": commit,
            "repo_dir": repo_dir,
            "hosts_path": hosts_path,
        }

    _run_git_command(
        repo_dir,
        ["commit", "-m", _git_history_commit_message(source_description)],
        git_executable=git_executable,
        runner=runner,
    )
    commit = _run_git_command(repo_dir, ["rev-parse", "--short=12", "HEAD"], git_executable=git_executable, runner=runner)
    return {
        "status": "committed",
        "commit": commit,
        "repo_dir": repo_dir,
        "hosts_path": hosts_path,
    }


def list_git_history_snapshots(
    repo_dir: str,
    limit: int = GIT_HISTORY_DEFAULT_LIMIT,
    git_executable: str | None = None,
    runner=None,
) -> list[dict]:
    if not os.path.isdir(os.path.join(repo_dir, ".git")):
        return []
    limit = max(1, min(int(limit or GIT_HISTORY_DEFAULT_LIMIT), 200))
    output = _run_git_command(
        repo_dir,
        [f"--no-pager", "log", f"--max-count={limit}", "--format=%H%x09%cI%x09%s", "--", GIT_HISTORY_HOSTS_FILENAME],
        git_executable=git_executable,
        runner=runner,
    )
    snapshots: list[dict] = []
    for line in output.splitlines():
        parts = line.split("\t", 2)
        if len(parts) != 3:
            continue
        commit, committed_at, subject = parts
        snapshots.append({
            "commit": commit,
            "short_commit": commit[:12],
            "committed_at": committed_at,
            "subject": subject,
        })
    return snapshots


def read_git_history_snapshot(
    repo_dir: str,
    ref: str,
    git_executable: str | None = None,
    runner=None,
) -> str:
    safe_ref = sanitize_git_history_ref(ref)
    if not os.path.isdir(os.path.join(repo_dir, ".git")):
        raise OSError("Git history repository has not been initialized")
    return _run_git_command(
        repo_dir,
        ["show", f"{safe_ref}:{GIT_HISTORY_HOSTS_FILENAME}"],
        git_executable=git_executable,
        runner=runner,
        strip_output=False,
    )


def build_git_history_status_report(
    repo_dir: str,
    git_executable: str | None = None,
    limit: int = GIT_HISTORY_DEFAULT_LIMIT,
) -> dict:
    git = resolve_git_executable(git_executable)
    if not git:
        return {
            "available": False,
            "repo_dir": repo_dir,
            "diagnostic": "git executable not found",
            "snapshots": [],
        }
    if not os.path.isdir(os.path.join(repo_dir, ".git")):
        return {
            "available": True,
            "initialized": False,
            "repo_dir": repo_dir,
            "diagnostic": "history repository has not been initialized",
            "snapshots": [],
        }
    try:
        snapshots = list_git_history_snapshots(repo_dir, limit=limit, git_executable=git)
    except OSError as exc:
        return {
            "available": True,
            "initialized": True,
            "repo_dir": repo_dir,
            "diagnostic": str(exc),
            "snapshots": [],
        }
    return {
        "available": True,
        "initialized": True,
        "repo_dir": repo_dir,
        "diagnostic": "ok",
        "snapshots": snapshots,
    }


def format_git_history_status_report(report: dict) -> str:
    lines = [
        "Git History",
        f"Repository: {report.get('repo_dir') or '-'}",
    ]
    if not report.get("available"):
        lines.append(f"Status: unavailable ({report.get('diagnostic')})")
        return "\n".join(lines)
    if not report.get("initialized"):
        lines.append(f"Status: not initialized ({report.get('diagnostic')})")
        return "\n".join(lines)
    lines.append(f"Status: {report.get('diagnostic')}")
    snapshots = report.get("snapshots") or []
    if not snapshots:
        lines.append("Snapshots: none")
        return "\n".join(lines)
    lines.append("Snapshots:")
    for snapshot in snapshots:
        lines.append(
            f"- {snapshot.get('short_commit')}  {snapshot.get('committed_at')}  {snapshot.get('subject')}"
        )
    return "\n".join(lines)


def get_profile_sync_git_dir(base_dir: str | None = None) -> str:
    root = base_dir or get_config_root_dir()
    return os.path.join(root, PROFILE_SYNC_GIT_DIRNAME)


def resolve_gpg_executable(gpg_executable: str | None = None) -> str | None:
    if gpg_executable:
        return gpg_executable
    return shutil.which("gpg") or shutil.which("gpg.exe")


def sanitize_profile_sync_env_name(value: str | None) -> str:
    candidate = str(value or PROFILE_SYNC_PASSPHRASE_ENV).strip()
    if not PROFILE_SYNC_ENV_NAME_PATTERN.match(candidate):
        raise ValueError("sync passphrase environment variable name is invalid")
    return candidate


def sanitize_profile_sync_passphrase(value: str | None) -> str:
    if not isinstance(value, str):
        raise ValueError("sync passphrase is required")
    if len(value) < PROFILE_SYNC_MIN_PASSPHRASE_LENGTH or _contains_control_chars(value):
        raise ValueError(
            f"sync passphrase must be at least {PROFILE_SYNC_MIN_PASSPHRASE_LENGTH} characters "
            "and cannot contain control characters"
        )
    return value


def read_profile_sync_passphrase(env_name: str | None = None, environ=None) -> str:
    safe_name = sanitize_profile_sync_env_name(env_name)
    source = os.environ if environ is None else environ
    return sanitize_profile_sync_passphrase(source.get(safe_name))


def build_profile_sync_payload(config: dict, default_last_open_dir: str | None = None, now=None) -> dict:
    sanitized = sanitize_config_snapshot(config, default_last_open_dir or os.path.expanduser("~"))
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    payload = {
        "schema": PROFILE_SYNC_PAYLOAD_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "config_version": CONFIG_SCHEMA_VERSION,
        "profile_schema_version": PROFILE_SCHEMA_VERSION,
        "active_profile_id": sanitized["active_profile_id"],
        "profiles": sanitized["profiles"],
        "profile_activation_schedule_version": PROFILE_ACTIVATION_SCHEDULE_VERSION,
        "profile_activation_fallback_id": sanitized["profile_activation_fallback_id"],
        "profile_activation_schedule": sanitized["profile_activation_schedule"],
    }
    return sanitize_profile_sync_payload(payload)


def sanitize_profile_sync_payload(payload: dict) -> dict:
    if not isinstance(payload, dict):
        raise ValueError("profile sync payload must be a JSON object")
    if payload.get("schema") != PROFILE_SYNC_PAYLOAD_SCHEMA:
        raise ValueError(f"profile sync payload schema must be {PROFILE_SYNC_PAYLOAD_SCHEMA}")
    profiles, active_profile_id = sanitize_profiles_snapshot(
        payload.get("profiles", []),
        payload.get("active_profile_id", DEFAULT_PROFILE_ID),
    )
    profile_ids = {profile["id"] for profile in profiles}
    fallback_id = _sanitize_profile_id_strict(payload.get("profile_activation_fallback_id"))
    if fallback_id not in profile_ids:
        fallback_id = active_profile_id
    schedule = sanitize_profile_activation_schedule(
        payload.get("profile_activation_schedule", []),
        profile_ids,
    )
    created_at = str(payload.get("created_at") or "")
    if not created_at or _contains_control_chars(created_at) or len(created_at) > 80:
        created_at = datetime.datetime.now().isoformat(timespec="seconds")
    return {
        "schema": PROFILE_SYNC_PAYLOAD_SCHEMA,
        "app_version": str(payload.get("app_version") or APP_VERSION)[:40],
        "created_at": created_at,
        "config_version": CONFIG_SCHEMA_VERSION,
        "profile_schema_version": PROFILE_SCHEMA_VERSION,
        "active_profile_id": active_profile_id,
        "profiles": profiles,
        "profile_activation_schedule_version": PROFILE_ACTIVATION_SCHEDULE_VERSION,
        "profile_activation_fallback_id": fallback_id,
        "profile_activation_schedule": schedule,
    }


def apply_profile_sync_payload_to_config(
    config: dict,
    payload: dict,
    default_last_open_dir: str | None = None,
) -> dict:
    default_dir = default_last_open_dir or os.path.expanduser("~")
    current = sanitize_config_snapshot(config, default_dir)
    synced = sanitize_profile_sync_payload(payload)
    current["profiles"] = synced["profiles"]
    current["active_profile_id"] = synced["active_profile_id"]
    current["profile_activation_fallback_id"] = synced["profile_activation_fallback_id"]
    current["profile_activation_schedule"] = synced["profile_activation_schedule"]
    current["profile_activation_schedule_version"] = PROFILE_ACTIVATION_SCHEDULE_VERSION
    return set_active_profile_in_config(current, synced["active_profile_id"], default_dir)


def build_profile_sync_metadata(payload: dict, encrypted_filename: str = PROFILE_SYNC_BUNDLE_FILENAME) -> dict:
    sanitized = sanitize_profile_sync_payload(payload)
    canonical = json.dumps(sanitized, sort_keys=True, separators=(",", ":"))
    return {
        "schema": PROFILE_SYNC_METADATA_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "payload_schema": sanitized["schema"],
        "payload_created_at": sanitized["created_at"],
        "active_profile_id": sanitized["active_profile_id"],
        "profile_count": len(sanitized["profiles"]),
        "encrypted_file": encrypted_filename,
        "encryption": "gpg symmetric AES256",
        "payload_sha256": hashlib.sha256(canonical.encode("utf-8")).hexdigest(),
    }


def _run_gpg_transform(
    input_path: str,
    output_path: str,
    passphrase: str,
    decrypt: bool = False,
    gpg_executable: str | None = None,
    runner=None,
    timeout: int = 60,
) -> None:
    gpg = resolve_gpg_executable(gpg_executable)
    if not gpg:
        raise OSError("gpg executable not found")
    safe_passphrase = sanitize_profile_sync_passphrase(passphrase)
    args = [
        gpg,
        "--batch",
        "--yes",
        "--pinentry-mode",
        "loopback",
        "--passphrase-fd",
        "0",
        "--output",
        output_path,
    ]
    if decrypt:
        args.extend(["--decrypt", input_path])
    else:
        args.extend(["--symmetric", "--cipher-algo", "AES256", input_path])
    run = runner or subprocess.run
    try:
        result = run(
            args,
            input=f"{safe_passphrase}\n",
            capture_output=True,
            text=True,
            timeout=timeout,
            check=False,
        )
    except FileNotFoundError as exc:
        raise OSError("gpg executable not found") from exc
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "").strip()
        raise OSError(f"gpg {'decrypt' if decrypt else 'encrypt'} failed: {detail}")


def encrypt_profile_sync_payload(
    payload: dict,
    output_path: str,
    passphrase: str,
    gpg_executable: str | None = None,
    runner=None,
) -> dict:
    sanitized = sanitize_profile_sync_payload(payload)
    output_dir = os.path.dirname(os.path.abspath(output_path))
    if output_dir:
        os.makedirs(output_dir, exist_ok=True)
    with tempfile.TemporaryDirectory() as tmpdir:
        plain_path = os.path.join(tmpdir, "hostsfileget-profile-sync.json")
        write_text_file_atomic(plain_path, json.dumps(sanitized, indent=2, sort_keys=True))
        _run_gpg_transform(
            plain_path,
            output_path,
            passphrase,
            decrypt=False,
            gpg_executable=gpg_executable,
            runner=runner,
        )
    return build_profile_sync_metadata(sanitized, os.path.basename(output_path))


def decrypt_profile_sync_payload(
    input_path: str,
    passphrase: str,
    gpg_executable: str | None = None,
    runner=None,
) -> dict:
    if not os.path.isfile(input_path):
        raise OSError(f"profile sync bundle not found: {input_path}")
    with tempfile.TemporaryDirectory() as tmpdir:
        plain_path = os.path.join(tmpdir, "hostsfileget-profile-sync.json")
        _run_gpg_transform(
            input_path,
            plain_path,
            passphrase,
            decrypt=True,
            gpg_executable=gpg_executable,
            runner=runner,
        )
        try:
            payload = json.loads(read_text_file_content(plain_path))
        except json.JSONDecodeError as exc:
            raise ValueError(f"profile sync payload JSON is invalid: {exc}") from exc
    return sanitize_profile_sync_payload(payload)


def ensure_profile_sync_git_repo(
    repo_dir: str,
    git_executable: str | None = None,
    runner=None,
) -> str:
    return ensure_git_history_repo(repo_dir, git_executable=git_executable, runner=runner)


def _profile_sync_commit_message(payload: dict) -> str:
    synced = sanitize_profile_sync_payload(payload)
    return f"profile sync: {synced['active_profile_id']}"


def write_profile_sync_git_export(
    repo_dir: str,
    config: dict,
    passphrase: str,
    default_last_open_dir: str | None = None,
    git_executable: str | None = None,
    git_runner=None,
    gpg_executable: str | None = None,
    gpg_runner=None,
    push: bool = False,
) -> dict:
    ensure_profile_sync_git_repo(repo_dir, git_executable=git_executable, runner=git_runner)
    payload = build_profile_sync_payload(config, default_last_open_dir)
    bundle_path = os.path.join(repo_dir, PROFILE_SYNC_BUNDLE_FILENAME)
    metadata_path = os.path.join(repo_dir, PROFILE_SYNC_METADATA_FILENAME)
    metadata = encrypt_profile_sync_payload(
        payload,
        bundle_path,
        passphrase,
        gpg_executable=gpg_executable,
        runner=gpg_runner,
    )
    write_text_file_atomic(metadata_path, json.dumps(metadata, indent=2))
    _run_git_command(
        repo_dir,
        ["add", "--", PROFILE_SYNC_BUNDLE_FILENAME, PROFILE_SYNC_METADATA_FILENAME],
        git_executable=git_executable,
        runner=git_runner,
    )
    status = _run_git_command(
        repo_dir,
        ["status", "--porcelain", "--", PROFILE_SYNC_BUNDLE_FILENAME, PROFILE_SYNC_METADATA_FILENAME],
        git_executable=git_executable,
        runner=git_runner,
    )
    commit_status = "unchanged"
    if status:
        _run_git_command(
            repo_dir,
            ["commit", "-m", _profile_sync_commit_message(payload)],
            git_executable=git_executable,
            runner=git_runner,
        )
        commit_status = "committed"
    try:
        commit = _run_git_command(repo_dir, ["rev-parse", "--short=12", "HEAD"], git_executable=git_executable, runner=git_runner)
    except OSError:
        commit = None
    pushed = False
    if push:
        _run_git_command(repo_dir, ["push", "origin", "HEAD"], git_executable=git_executable, runner=git_runner, timeout=60)
        pushed = True
    return {
        "action": "export",
        "status": commit_status,
        "repo_dir": repo_dir,
        "bundle_path": bundle_path,
        "metadata_path": metadata_path,
        "commit": commit,
        "pushed": pushed,
        "active_profile_id": payload["active_profile_id"],
        "profile_count": len(payload["profiles"]),
    }


def read_profile_sync_git_import(
    repo_dir: str,
    current_config: dict,
    passphrase: str,
    default_last_open_dir: str | None = None,
    git_executable: str | None = None,
    git_runner=None,
    gpg_executable: str | None = None,
    gpg_runner=None,
    pull: bool = False,
) -> dict:
    if pull:
        if not os.path.isdir(os.path.join(repo_dir, ".git")):
            raise OSError("profile sync Git repository has not been initialized")
        _run_git_command(repo_dir, ["pull", "--ff-only"], git_executable=git_executable, runner=git_runner, timeout=60)
    bundle_path = os.path.join(repo_dir, PROFILE_SYNC_BUNDLE_FILENAME)
    payload = decrypt_profile_sync_payload(
        bundle_path,
        passphrase,
        gpg_executable=gpg_executable,
        runner=gpg_runner,
    )
    merged_config = apply_profile_sync_payload_to_config(
        current_config,
        payload,
        default_last_open_dir,
    )
    return {
        "action": "import",
        "status": "imported",
        "repo_dir": repo_dir,
        "bundle_path": bundle_path,
        "config": merged_config,
        "active_profile_id": payload["active_profile_id"],
        "profile_count": len(payload["profiles"]),
        "pulled": bool(pull),
    }


def format_profile_sync_report(report: dict) -> str:
    lines = [
        "Encrypted Profile Sync",
        f"Action: {report.get('action', '-')}",
        f"Status: {report.get('status', '-')}",
        f"Repository: {report.get('repo_dir') or '-'}",
        f"Encrypted bundle: {report.get('bundle_path') or '-'}",
        f"Active profile: {report.get('active_profile_id') or DEFAULT_PROFILE_ID}",
        f"Profiles: {report.get('profile_count', 0)}",
    ]
    if report.get("metadata_path"):
        lines.append(f"Metadata: {report.get('metadata_path')}")
    if report.get("commit"):
        lines.append(f"Commit: {report.get('commit')}")
    if report.get("pushed"):
        lines.append("Pushed: yes")
    if report.get("pulled"):
        lines.append("Pulled: yes")
    lines.append("Hosts file writes: none")
    return "\n".join(lines)


def _share_patch_timestamp(now=None) -> str:
    value = now or datetime.datetime.now()
    if isinstance(value, datetime.datetime):
        return value.isoformat(timespec="seconds")
    return str(value)


def _sanitize_share_patch_author(value) -> str:
    if not isinstance(value, str):
        return ""
    author = re.sub(r"\s+", " ", value.strip())
    if _contains_control_chars(author):
        return ""
    return author[:120]


def _normalize_allowlist_patch_domains(values) -> list[str]:
    if isinstance(values, str):
        raw_values = [line.strip() for line in values.splitlines()]
    elif isinstance(values, (list, tuple, set)):
        raw_values = [str(value).strip() for value in values]
    else:
        raw_values = []
    return sanitize_pinned_domains(raw_values)


def parse_allowlist_patch_text(text: str) -> list[str]:
    return _normalize_allowlist_patch_domains(_sanitize_whitelist_text(text).splitlines())


def build_allowlist_share_patch(domains, author: str | None = None, now=None) -> dict:
    normalized_domains = _normalize_allowlist_patch_domains(domains)
    if not normalized_domains:
        raise ValueError("allowlist patch must contain at least one valid domain")
    return {
        "schema": SHARE_PATCH_SCHEMA,
        "patch_type": "allowlist",
        "app_version": APP_VERSION,
        "created_at": _share_patch_timestamp(now),
        "author": _sanitize_share_patch_author(author),
        "domains": normalized_domains,
    }


def build_profile_share_patch(profile: dict, author: str | None = None, now=None) -> dict:
    sanitized = sanitize_profile_snapshot(
        profile,
        fallback_id=sanitize_profile_id(profile.get("id"), DEFAULT_PROFILE_ID) if isinstance(profile, dict) else DEFAULT_PROFILE_ID,
    )
    return {
        "schema": SHARE_PATCH_SCHEMA,
        "patch_type": "profile",
        "app_version": APP_VERSION,
        "created_at": _share_patch_timestamp(now),
        "author": _sanitize_share_patch_author(author),
        "profile": sanitized,
    }


def sanitize_share_patch_payload(payload: dict) -> dict:
    if not isinstance(payload, dict):
        raise ValueError("share patch must be a JSON object")
    if payload.get("schema") != SHARE_PATCH_SCHEMA:
        raise ValueError(f"share patch schema must be {SHARE_PATCH_SCHEMA}")
    patch_type = str(payload.get("patch_type") or "").strip().lower()
    if patch_type not in SHARE_PATCH_TYPES:
        raise ValueError(f"share patch type must be one of {', '.join(SHARE_PATCH_TYPES)}")
    created_at = str(payload.get("created_at") or "")
    if not created_at or _contains_control_chars(created_at) or len(created_at) > 80:
        created_at = datetime.datetime.now().isoformat(timespec="seconds")
    base = {
        "schema": SHARE_PATCH_SCHEMA,
        "patch_type": patch_type,
        "app_version": str(payload.get("app_version") or APP_VERSION)[:40],
        "created_at": created_at,
        "author": _sanitize_share_patch_author(payload.get("author")),
    }
    if patch_type == "allowlist":
        domains = _normalize_allowlist_patch_domains(payload.get("domains", []))
        if not domains:
            raise ValueError("allowlist patch must contain at least one valid domain")
        base["domains"] = domains
    else:
        profile_payload = payload.get("profile")
        if not isinstance(profile_payload, dict):
            raise ValueError("profile patch requires a profile object")
        base["profile"] = sanitize_profile_snapshot(
            profile_payload,
            fallback_id=sanitize_profile_id(profile_payload.get("id"), DEFAULT_PROFILE_ID),
        )
    return base


def _merge_domains_into_whitelist_text(whitelist_text: str, domains: list[str]) -> str:
    existing = [line for line in _sanitize_whitelist_text(whitelist_text).splitlines() if line.strip()]
    seen = {line.casefold() for line in existing}
    merged = list(existing)
    for domain in domains:
        key = domain.casefold()
        if key in seen:
            continue
        seen.add(key)
        merged.append(domain)
    return "\n".join(merged) + ("\n" if merged else "")


def apply_share_patch_payload_to_config(
    config: dict,
    payload: dict,
    default_last_open_dir: str | None = None,
) -> tuple[dict, dict]:
    default_dir = default_last_open_dir or os.path.expanduser("~")
    current = sanitize_config_snapshot(config, default_dir)
    patch = sanitize_share_patch_payload(payload)
    if patch["patch_type"] == "allowlist":
        before = len([line for line in current.get("whitelist", "").splitlines() if line.strip()])
        current["whitelist"] = _merge_domains_into_whitelist_text(current.get("whitelist", ""), patch["domains"])
        current["profiles"], current["active_profile_id"] = update_active_profile_snapshot(
            current.get("profiles", []),
            current.get("active_profile_id", DEFAULT_PROFILE_ID),
            current,
        )
        merged = sanitize_config_snapshot(current, default_dir)
        after = len([line for line in merged.get("whitelist", "").splitlines() if line.strip()])
        report = {
            "action": "apply",
            "patch_type": "allowlist",
            "status": "applied",
            "added_count": max(0, after - before),
            "domain_count": len(patch["domains"]),
            "active_profile_id": merged.get("active_profile_id"),
        }
        return merged, report
    merged = upsert_profile_in_config(current, patch["profile"], default_dir, activate=False)
    report = {
        "action": "apply",
        "patch_type": "profile",
        "status": "applied",
        "profile_id": patch["profile"]["id"],
        "active_profile_id": merged.get("active_profile_id"),
    }
    return merged, report


def format_share_patch_summary(report: dict) -> str:
    lines = [
        "Signed Share Patch",
        f"Action: {report.get('action', '-')}",
        f"Type: {report.get('patch_type', '-')}",
        f"Status: {report.get('status', '-')}",
    ]
    if report.get("patch_path"):
        lines.append(f"Patch: {report.get('patch_path')}")
    if report.get("signature_path"):
        lines.append(f"Signature: {report.get('signature_path')}")
    if report.get("verified") is not None:
        lines.append(f"Signature verified: {'yes' if report.get('verified') else 'no'}")
    if report.get("domain_count") is not None:
        lines.append(f"Domains: {report.get('domain_count')}")
    if report.get("added_count") is not None:
        lines.append(f"Added domains: {report.get('added_count')}")
    if report.get("profile_id"):
        lines.append(f"Profile: {report.get('profile_id')}")
    if report.get("active_profile_id"):
        lines.append(f"Active profile: {report.get('active_profile_id')}")
    if report.get("signer"):
        lines.append(f"Signer: {report.get('signer')}")
    lines.append("Hosts file writes: none")
    return "\n".join(lines)


def write_share_patch_payload(payload: dict, output_path: str) -> dict:
    sanitized = sanitize_share_patch_payload(payload)
    output_dir = os.path.dirname(os.path.abspath(output_path))
    if output_dir:
        os.makedirs(output_dir, exist_ok=True)
    write_text_file_atomic(output_path, json.dumps(sanitized, indent=2, sort_keys=True))
    summary = {
        "action": "build",
        "patch_type": sanitized["patch_type"],
        "status": "written",
        "patch_path": output_path,
    }
    if sanitized["patch_type"] == "allowlist":
        summary["domain_count"] = len(sanitized["domains"])
    else:
        summary["profile_id"] = sanitized["profile"]["id"]
    return summary


def load_share_patch_payload(path: str) -> dict:
    try:
        payload = json.loads(read_text_file_content(path))
    except json.JSONDecodeError as exc:
        raise ValueError(f"share patch JSON is invalid: {exc}") from exc
    return sanitize_share_patch_payload(payload)


def sign_share_patch_file(
    patch_path: str,
    signature_path: str,
    gpg_key: str | None = None,
    gpg_executable: str | None = None,
    runner=None,
) -> dict:
    if not os.path.isfile(patch_path):
        raise OSError(f"share patch not found: {patch_path}")
    gpg = resolve_gpg_executable(gpg_executable)
    if not gpg:
        raise OSError("gpg executable not found")
    output_dir = os.path.dirname(os.path.abspath(signature_path))
    if output_dir:
        os.makedirs(output_dir, exist_ok=True)
    args = [
        gpg,
        "--batch",
        "--yes",
        "--armor",
        "--detach-sign",
        "--output",
        signature_path,
    ]
    if gpg_key:
        args.extend(["--local-user", str(gpg_key)])
    args.append(patch_path)
    run = runner or subprocess.run
    try:
        result = run(args, capture_output=True, text=True, timeout=60, check=False)
    except FileNotFoundError as exc:
        raise OSError("gpg executable not found") from exc
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "").strip()
        raise OSError(f"gpg sign failed: {detail}")
    payload = load_share_patch_payload(patch_path)
    report = {
        "action": "sign",
        "patch_type": payload["patch_type"],
        "status": "signed",
        "patch_path": patch_path,
        "signature_path": signature_path,
    }
    if payload["patch_type"] == "allowlist":
        report["domain_count"] = len(payload["domains"])
    else:
        report["profile_id"] = payload["profile"]["id"]
    return report


def verify_share_patch_signature(
    patch_path: str,
    signature_path: str,
    gpg_executable: str | None = None,
    runner=None,
) -> dict:
    if not os.path.isfile(patch_path):
        raise OSError(f"share patch not found: {patch_path}")
    if not os.path.isfile(signature_path):
        raise OSError(f"share patch signature not found: {signature_path}")
    gpg = resolve_gpg_executable(gpg_executable)
    if not gpg:
        raise OSError("gpg executable not found")
    run = runner or subprocess.run
    args = [gpg, "--batch", "--verify", signature_path, patch_path]
    try:
        result = run(args, capture_output=True, text=True, timeout=60, check=False)
    except FileNotFoundError as exc:
        raise OSError("gpg executable not found") from exc
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "").strip()
        raise OSError(f"gpg verify failed: {detail}")
    payload = load_share_patch_payload(patch_path)
    signer = (result.stderr or result.stdout or "").strip()
    report = {
        "action": "verify",
        "patch_type": payload["patch_type"],
        "status": "verified",
        "patch_path": patch_path,
        "signature_path": signature_path,
        "verified": True,
        "signer": re.sub(r"\s+", " ", signer)[:240],
    }
    if payload["patch_type"] == "allowlist":
        report["domain_count"] = len(payload["domains"])
    else:
        report["profile_id"] = payload["profile"]["id"]
    return report


def sanitize_recovery_plan_description(value: str | None = None) -> str:
    description = re.sub(r"\s+", " ", str(value or "HostsFileGet before hosts apply").strip())
    if not description or _contains_control_chars(description):
        description = "HostsFileGet before hosts apply"
    return description[:RECOVERY_DESCRIPTION_MAX_LENGTH]


def _powershell_single_quote(value: str) -> str:
    return "'" + str(value).replace("'", "''") + "'"


def build_restore_point_command(description: str | None = None) -> list[str]:
    safe_description = sanitize_recovery_plan_description(description)
    command = (
        "Checkpoint-Computer "
        f"-Description {_powershell_single_quote(safe_description)} "
        "-RestorePointType 'MODIFY_SETTINGS'"
    )
    return [
        "powershell.exe",
        "-NoProfile",
        "-ExecutionPolicy",
        "Bypass",
        "-Command",
        command,
    ]


def build_recovery_apply_plan(hosts_path: str | None = None, description: str | None = None, now=None) -> dict:
    target_hosts = os.path.abspath(hosts_path or _default_hosts_file_path())
    drive, _tail = os.path.splitdrive(target_hosts)
    volume = drive + "\\" if drive else "%SystemDrive%\\"
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    safe_description = sanitize_recovery_plan_description(description)
    restore_point_command = build_restore_point_command(safe_description)
    return {
        "schema": RECOVERY_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "hosts_path": target_hosts,
        "volume": volume,
        "description": safe_description,
        "plan_only": True,
        "actions": [
            {
                "id": "hostsfileget-backup",
                "status": "implemented",
                "requires_admin": True,
                "description": "HostsFileGet already creates rolling and timestamped hosts backups before raw, cleaned, CLI apply, restore, and history restore writes.",
            },
            {
                "id": "system-restore-point",
                "status": "manual-command",
                "requires_admin": True,
                "description": "Create a Windows System Restore point before a high-risk hosts write when System Protection is enabled.",
                "command": restore_point_command,
            },
            {
                "id": "vss-shadow-copy",
                "status": "spike-only",
                "requires_admin": True,
                "description": "VSS snapshots are volume-scoped and require careful shadow lifecycle cleanup; HostsFileGet does not automate them yet.",
                "commands": [
                    ["vssadmin", "list", "shadows", f"/for={volume}"],
                    ["vssadmin", "create", "shadow", f"/for={volume}"],
                ],
            },
        ],
        "apply_contract": [
            "This plan does not execute restore-point or VSS commands.",
            "HostsFileGet hosts-file writes must remain explicit, previewed, and backup-backed.",
            "Use normal .bak, timestamped backups, and optional Git history restore before relying on system-wide rollback.",
        ],
    }


def _format_command_for_display(command) -> str:
    if isinstance(command, (list, tuple)):
        return subprocess.list2cmdline([str(part) for part in command])
    return str(command)


def format_recovery_apply_plan(plan: dict) -> str:
    lines = [
        "Recovery Apply Plan",
        f"Schema: {plan.get('schema')}",
        f"Hosts path: {plan.get('hosts_path')}",
        f"Volume: {plan.get('volume')}",
        f"Description: {plan.get('description')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        "",
        "Actions:",
    ]
    for action in plan.get("actions", []):
        lines.append(f"- {action.get('id')}: {action.get('status')}")
        if action.get("description"):
            lines.append(f"  {action.get('description')}")
        if action.get("command"):
            lines.append(f"  Command: {_format_command_for_display(action.get('command'))}")
        for command in action.get("commands", []) or []:
            lines.append(f"  Command: {_format_command_for_display(command)}")
    lines.extend(["", "Apply contract:"])
    for item in plan.get("apply_contract", []):
        lines.append(f"- {item}")
    return "\n".join(lines)


def sanitize_wfp_rule_prefix(value: str | None = None) -> str:
    prefix = re.sub(r"\s+", " ", str(value or WFP_BLOCKER_RULE_PREFIX).strip())
    if not prefix or _contains_control_chars(prefix):
        prefix = WFP_BLOCKER_RULE_PREFIX
    return prefix[:WFP_BLOCKER_PREFIX_MAX_LENGTH]


def _wfp_target_candidate(value: str) -> str:
    candidate = str(value or "").strip().strip("`'\"(),;")
    if candidate.startswith("[") and "]" in candidate:
        candidate = candidate[1:candidate.index("]")]
    elif candidate.startswith(("http://", "https://")):
        try:
            candidate = urllib.parse.urlsplit(candidate).hostname or ""
        except ValueError:
            candidate = ""
    if candidate.count(":") == 1 and "/" not in candidate:
        host, port = candidate.rsplit(":", 1)
        if port.isdigit() and IPV4_REGEX.match(host):
            candidate = host
    return candidate.strip()


def normalize_wfp_ip_cidr_target(value: str) -> str:
    candidate = _wfp_target_candidate(value)
    if not candidate:
        raise ValueError("empty target")
    if "-" in candidate:
        raise ValueError("IP ranges are not supported; convert ranges to CIDR first")
    try:
        if "/" in candidate:
            network = ipaddress.ip_network(candidate, strict=False)
            return network.with_prefixlen
        address = ipaddress.ip_address(candidate)
        return str(address)
    except ValueError as exc:
        raise ValueError("not an IP or CIDR target") from exc


def _wfp_target_network(target: str):
    if "/" in target:
        return ipaddress.ip_network(target, strict=False)
    address = ipaddress.ip_address(target)
    return ipaddress.ip_network(f"{address}/{address.max_prefixlen}", strict=False)


def _wfp_target_reject_reason(target: str) -> str:
    network = _wfp_target_network(target)
    if network.is_unspecified:
        return "unspecified address is not exported as a remote firewall target"
    if network.is_loopback:
        return "loopback address is not exported as a remote firewall target"
    if network.is_multicast:
        return "multicast address is not exported as a remote firewall target"
    return ""


def _wfp_target_risk_tags(target: str) -> list[str]:
    network = _wfp_target_network(target)
    tags = []
    if network.is_private:
        tags.append("private")
    if network.is_link_local:
        tags.append("link-local")
    if network.is_reserved:
        tags.append("reserved")
    if not network.is_global:
        tags.append("non-global")
    return sorted(set(tags))


def _token_may_be_ip_literal(token: str) -> bool:
    return any(ch.isdigit() for ch in token) or ":" in token or "/" in token


def parse_wfp_blocker_targets(text: str) -> dict:
    targets: list[str] = []
    rejected: list[dict[str, str | int]] = []
    seen: set[str] = set()
    for line_no, line in enumerate(str(text or "").splitlines(), 1):
        body = line.split("#", 1)[0].strip()
        if not body:
            continue
        for raw_token in TOKEN_SPLITTER.split(body):
            token = raw_token.strip()
            if not token:
                continue
            try:
                target = normalize_wfp_ip_cidr_target(token)
            except ValueError as exc:
                if _token_may_be_ip_literal(token):
                    rejected.append({"line": line_no, "token": token[:120], "reason": str(exc)})
                continue
            reject_reason = _wfp_target_reject_reason(target)
            if reject_reason:
                rejected.append({"line": line_no, "token": token[:120], "reason": reject_reason})
                continue
            if target in seen:
                continue
            seen.add(target)
            targets.append(target)
    return {"targets": targets, "rejected": rejected}


def _powershell_array_literal(values: list[str]) -> str:
    return "@(" + ", ".join(_powershell_single_quote(value) for value in values) + ")"


def build_wfp_blocker_rule_command(
    targets: list[str],
    *,
    rule_index: int,
    direction: str = "Outbound",
    rule_prefix: str | None = None,
    group: str = WFP_BLOCKER_RULE_GROUP,
) -> str:
    if not targets:
        raise ValueError("at least one target is required")
    safe_direction = "Inbound" if str(direction).strip().lower() == "inbound" else "Outbound"
    display_name = f"{sanitize_wfp_rule_prefix(rule_prefix)} {safe_direction} {rule_index:03d}"
    description = "Generated by HostsFileGet as a plan-only companion export; review before execution."
    return (
        "New-NetFirewallRule "
        f"-DisplayName {_powershell_single_quote(display_name)} "
        f"-Group {_powershell_single_quote(group)} "
        f"-Direction {safe_direction} "
        "-Action Block "
        f"-RemoteAddress {_powershell_array_literal(targets)} "
        "-Profile Any "
        f"-Description {_powershell_single_quote(description)}"
    )


def build_wfp_blocker_companion_plan(
    text: str,
    *,
    rule_prefix: str | None = None,
    now=None,
    chunk_size: int = WFP_BLOCKER_TARGET_CHUNK_SIZE,
) -> dict:
    parsed = parse_wfp_blocker_targets(text)
    targets = parsed["targets"]
    rejected = parsed["rejected"]
    safe_prefix = sanitize_wfp_rule_prefix(rule_prefix)
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    chunk_size = max(1, int(chunk_size or WFP_BLOCKER_TARGET_CHUNK_SIZE))
    chunks = [targets[index:index + chunk_size] for index in range(0, len(targets), chunk_size)]

    clear_command = (
        "Get-NetFirewallRule "
        f"-Group {_powershell_single_quote(WFP_BLOCKER_RULE_GROUP)} "
        "-ErrorAction SilentlyContinue | Remove-NetFirewallRule"
    )
    commands = [{
        "id": "clear-existing-group",
        "description": "Remove prior rules created for this companion group before adding the reviewed replacement set.",
        "command": ["powershell.exe", "-NoProfile", "-ExecutionPolicy", "Bypass", "-Command", clear_command],
    }]
    rule_commands = []
    for index, chunk in enumerate(chunks, 1):
        command = build_wfp_blocker_rule_command(chunk, rule_index=index, rule_prefix=safe_prefix)
        rule_commands.append(command)
        commands.append({
            "id": f"add-outbound-block-{index:03d}",
            "description": f"Add outbound block rule {index} for {len(chunk)} remote IP/CIDR target(s).",
            "target_count": len(chunk),
            "targets": chunk,
            "command": ["powershell.exe", "-NoProfile", "-ExecutionPolicy", "Bypass", "-Command", command],
        })

    risk_summary: dict[str, int] = {}
    for target in targets:
        tags = _wfp_target_risk_tags(target) or ["global"]
        for tag in tags:
            risk_summary[tag] = risk_summary.get(tag, 0) + 1

    warnings = [
        "Plan-only: HostsFileGet does not execute firewall or WFP commands.",
        "Windows Firewall with Advanced Security is implemented on WFP; this export uses firewall rules, not a driver.",
        "Review targets and rollback before running the script from an elevated PowerShell session.",
    ]
    if any(tag in risk_summary for tag in ("private", "link-local", "reserved", "non-global")):
        warnings.append("The plan includes non-global ranges; blocking LAN, VPN, or infrastructure ranges can break local workflows.")
    if rejected:
        warnings.append("Some tokens were rejected because they are not supported IP/CIDR remote-address targets.")

    script_lines = [
        "# HostsFileGet WFP IP/CIDR blocker companion plan",
        "# Review before running as Administrator. This file is not executed by HostsFileGet.",
        "$ErrorActionPreference = 'Stop'",
        clear_command,
    ]
    script_lines.extend(rule_commands)
    if not rule_commands:
        script_lines.append("# No firewall rules were generated because no valid IP/CIDR targets were found.")

    return {
        "schema": WFP_BLOCKER_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "plan_only": True,
        "companion_required": True,
        "enforcement_surface": "Windows Defender Firewall with Advanced Security via Windows Filtering Platform",
        "driver_boundary": "HostsFileGet does not ship or load a WFP callout driver; use a reviewed companion script or managed firewall deployment.",
        "rule_group": WFP_BLOCKER_RULE_GROUP,
        "rule_prefix": safe_prefix,
        "direction": "Outbound",
        "target_count": len(targets),
        "rejected_count": len(rejected),
        "risk_summary": risk_summary,
        "targets": targets,
        "rejected": rejected,
        "commands": commands,
        "powershell_script": "\n".join(script_lines),
        "rollback": [
            f"Get-NetFirewallRule -Group {_powershell_single_quote(WFP_BLOCKER_RULE_GROUP)} | Remove-NetFirewallRule",
            "Export local firewall policy before broad deployment when enterprise rollback is required.",
        ],
        "warnings": warnings,
        "references": ["S3", "K1"],
    }


def format_wfp_blocker_companion_plan(plan: dict) -> str:
    lines = [
        "WFP IP/CIDR Blocker Companion Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Surface: {plan.get('enforcement_surface')}",
        f"Rule group: {plan.get('rule_group')}",
        f"Direction: {plan.get('direction')}",
        f"Targets: {int(plan.get('target_count') or 0):,}",
        f"Rejected tokens: {int(plan.get('rejected_count') or 0):,}",
        "",
        "Risk summary:",
    ]
    risk_summary = plan.get("risk_summary") or {}
    if risk_summary:
        for key in sorted(risk_summary):
            lines.append(f"- {key}: {risk_summary[key]}")
    else:
        lines.append("- none")
    lines.extend(["", "Commands:"])
    for command in plan.get("commands") or []:
        lines.append(f"- {command.get('id')}: {_format_command_for_display(command.get('command'))}")
    rejected = plan.get("rejected") or []
    if rejected:
        lines.extend(["", "Rejected samples:"])
        for item in rejected[:5]:
            lines.append(f"- line {item.get('line')}: {item.get('token')} ({item.get('reason')})")
    lines.extend(["", "Boundary:", f"- {plan.get('driver_boundary')}"])
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def sanitize_nrpt_rule_prefix(value: str | None = None) -> str:
    prefix = re.sub(r"\s+", " ", str(value or NRPT_RULE_PREFIX).strip())
    if not prefix or _contains_control_chars(prefix):
        prefix = NRPT_RULE_PREFIX
    return prefix[:NRPT_PREFIX_MAX_LENGTH]


def _nrpt_optional_text(value: str | None, *, field_name: str, max_length: int = 120) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    if not text:
        return ""
    if _contains_control_chars(text):
        raise ValueError(f"{field_name} contains control characters")
    return text[:max_length]


def _nrpt_namespace_candidate(value: str) -> str:
    candidate = str(value or "").strip().strip("`'\"(),;")
    if candidate.lower().startswith(("http://", "https://", "ftp://")):
        try:
            candidate = urllib.parse.urlsplit(candidate).hostname or ""
        except ValueError:
            candidate = ""
    elif any(separator in candidate for separator in ("/", "?")):
        try:
            candidate = urllib.parse.urlsplit(f"http://{candidate}").hostname or ""
        except ValueError:
            candidate = ""
    return candidate.strip()


def normalize_nrpt_namespace(value: str) -> str:
    candidate = _nrpt_namespace_candidate(value)
    if not candidate:
        raise ValueError("empty namespace")
    if _contains_control_chars(candidate):
        raise ValueError("namespace contains control characters")
    lowered = candidate.lower()
    if lowered == "any":
        raise ValueError("the NRPT Any namespace is not exported by HostsFileGet")
    if lowered.startswith("*.") or "*" in lowered:
        raise ValueError("wildcard namespaces are not supported; enter the suffix without *")
    if "/" in lowered or _looks_like_ip_token(lowered):
        raise ValueError("IP/CIDR targets belong in WFP/firewall exports, not NRPT namespaces")

    candidate = lowered.strip(".")
    if not candidate:
        raise ValueError("empty namespace")
    encoded, error = _encode_idna_domain(candidate)
    if error or not encoded:
        raise ValueError(f"invalid IDN namespace: {error or 'encoding failed'}")
    if not looks_like_domain(encoded, allow_single_label=False):
        raise ValueError("not a DNS namespace")
    return encoded


def _token_may_be_nrpt_namespace(token: str) -> bool:
    stripped = str(token or "").strip()
    lowered = stripped.lower()
    return (
        lowered == "any"
        or "." in stripped
        or "*" in stripped
        or "/" in stripped
        or ":" in stripped
        or _contains_non_ascii(stripped)
        or lowered.startswith(("http://", "https://", "ftp://"))
    )


def parse_nrpt_policy_namespaces(text: str) -> dict:
    namespaces: list[str] = []
    rejected: list[dict[str, str | int]] = []
    seen: set[str] = set()
    for line_no, line in enumerate(str(text or "").splitlines(), 1):
        body = line.split("#", 1)[0].strip()
        if not body:
            continue
        for raw_token in TOKEN_SPLITTER.split(body):
            token = raw_token.strip()
            if not token:
                continue
            try:
                namespace = normalize_nrpt_namespace(token)
            except ValueError as exc:
                if _token_may_be_nrpt_namespace(token):
                    rejected.append({"line": line_no, "token": token[:120], "reason": str(exc)})
                continue
            if namespace in seen:
                continue
            seen.add(namespace)
            namespaces.append(namespace)
    return {"namespaces": namespaces, "rejected": rejected}


def normalize_nrpt_name_server(value: str) -> str:
    candidate = str(value or "").strip().strip("`'\"(),;")
    if not candidate:
        raise ValueError("empty NRPT name server")
    try:
        address = ipaddress.ip_address(candidate)
    except ValueError as exc:
        raise ValueError(f"NRPT name server is not an IP address: {candidate}") from exc
    if address.is_unspecified:
        raise ValueError("unspecified NRPT name server is not allowed")
    if address.is_multicast:
        raise ValueError("multicast NRPT name server is not allowed")
    return str(address)


def sanitize_nrpt_name_servers(values) -> list[str]:
    servers: list[str] = []
    seen: set[str] = set()
    for value in values or []:
        server = normalize_nrpt_name_server(str(value))
        if server in seen:
            continue
        seen.add(server)
        servers.append(server)
    if not servers:
        raise ValueError("at least one --nrpt-name-server value is required")
    return servers


def _nrpt_name_server_risk_tags(value: str) -> list[str]:
    address = ipaddress.ip_address(value)
    tags = []
    if address.is_private:
        tags.append("private")
    if address.is_loopback:
        tags.append("loopback")
    if address.is_link_local:
        tags.append("link-local")
    if address.is_reserved:
        tags.append("reserved")
    if not address.is_global:
        tags.append("non-global")
    return sorted(set(tags))


def _nrpt_scope_flags(gpo_name: str | None = None, server: str | None = None) -> str:
    safe_gpo = _nrpt_optional_text(gpo_name, field_name="NRPT GPO name") if gpo_name else ""
    safe_server = _nrpt_optional_text(server, field_name="NRPT GPO server") if server else ""
    if safe_server and not safe_gpo:
        raise ValueError("--nrpt-server requires --nrpt-gpo-name")
    flags = []
    if safe_gpo:
        flags.append(f"-GpoName {_powershell_single_quote(safe_gpo)}")
    if safe_server:
        flags.append(f"-Server {_powershell_single_quote(safe_server)}")
    return " ".join(flags)


def build_nrpt_rule_command(
    namespaces: list[str],
    name_servers: list[str],
    *,
    rule_index: int,
    rule_prefix: str | None = None,
    gpo_name: str | None = None,
    server: str | None = None,
    comment: str | None = None,
) -> str:
    if not namespaces:
        raise ValueError("at least one NRPT namespace is required")
    safe_servers = sanitize_nrpt_name_servers(name_servers)
    scope_flags = _nrpt_scope_flags(gpo_name, server)
    display_name = f"{sanitize_nrpt_rule_prefix(rule_prefix)} {rule_index:03d}"
    safe_comment = _nrpt_optional_text(
        comment or "Generated by HostsFileGet as a plan-only NRPT export; review before execution.",
        field_name="NRPT comment",
        max_length=180,
    )
    parts = ["Add-DnsClientNrptRule"]
    if scope_flags:
        parts.append(scope_flags)
    parts.extend([
        f"-Namespace {_powershell_array_literal(namespaces)}",
        "-NameEncoding 'Punycode'",
        f"-NameServers {_powershell_array_literal(safe_servers)}",
        f"-DisplayName {_powershell_single_quote(display_name)}",
        f"-Comment {_powershell_single_quote(safe_comment)}",
    ])
    return " ".join(parts)


def build_nrpt_policy_export_plan(
    text: str,
    name_servers,
    *,
    rule_prefix: str | None = None,
    gpo_name: str | None = None,
    server: str | None = None,
    now=None,
    chunk_size: int = NRPT_NAMESPACE_CHUNK_SIZE,
) -> dict:
    parsed = parse_nrpt_policy_namespaces(text)
    namespaces = parsed["namespaces"]
    rejected = parsed["rejected"]
    safe_servers = sanitize_nrpt_name_servers(name_servers)
    safe_prefix = sanitize_nrpt_rule_prefix(rule_prefix)
    safe_gpo = _nrpt_optional_text(gpo_name, field_name="NRPT GPO name") if gpo_name else ""
    safe_server = _nrpt_optional_text(server, field_name="NRPT GPO server") if server else ""
    scope_flags = _nrpt_scope_flags(safe_gpo, safe_server)
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    chunk_size = max(1, int(chunk_size or NRPT_NAMESPACE_CHUNK_SIZE))
    chunks = [namespaces[index:index + chunk_size] for index in range(0, len(namespaces), chunk_size)]

    get_command = "Get-DnsClientNrptRule"
    remove_command = "Remove-DnsClientNrptRule"
    if scope_flags:
        get_command += f" {scope_flags}"
        remove_command += f" {scope_flags}"
    clear_command = (
        f"{get_command} -ErrorAction SilentlyContinue | "
        f"Where-Object {{ $_.DisplayName -like {_powershell_single_quote(safe_prefix + '*')} "
        f"-and $_.Comment -like {_powershell_single_quote('*HostsFileGet*')} }} | "
        f"ForEach-Object {{ {remove_command} -Name $_.Name -Force }}"
    )

    commands = [{
        "id": "clear-existing-rules",
        "description": "Remove prior NRPT rules generated with this HostsFileGet display-name prefix.",
        "command": ["powershell.exe", "-NoProfile", "-ExecutionPolicy", "Bypass", "-Command", clear_command],
    }]
    rule_commands = []
    for index, chunk in enumerate(chunks, 1):
        command = build_nrpt_rule_command(
            chunk,
            safe_servers,
            rule_index=index,
            rule_prefix=safe_prefix,
            gpo_name=safe_gpo,
            server=safe_server,
        )
        rule_commands.append(command)
        commands.append({
            "id": f"add-nrpt-rule-{index:03d}",
            "description": f"Route {len(chunk)} DNS namespace(s) to the reviewed NRPT resolver set.",
            "namespace_count": len(chunk),
            "namespaces": chunk,
            "command": ["powershell.exe", "-NoProfile", "-ExecutionPolicy", "Bypass", "-Command", command],
        })

    resolver_risk_summary: dict[str, int] = {}
    for name_server in safe_servers:
        tags = _nrpt_name_server_risk_tags(name_server) or ["global"]
        for tag in tags:
            resolver_risk_summary[tag] = resolver_risk_summary.get(tag, 0) + 1

    warnings = [
        "Plan-only: HostsFileGet does not execute NRPT or Group Policy commands.",
        "NRPT changes can redirect DNS resolution below selected namespaces; review resolver ownership and rollback before use.",
    ]
    if safe_gpo:
        warnings.append("The plan targets a GPO scope; test in a lab OU before broad deployment.")
    else:
        warnings.append("The plan targets local client NRPT if the script is run without -GpoName.")
    if any(_contains_non_ascii(str(line)) for line in str(text or "").splitlines()):
        warnings.append("Unicode namespaces were encoded with IDNA/Punycode because the generated cmdlets use -NameEncoding Punycode.")
    if any(tag in resolver_risk_summary for tag in ("private", "loopback", "link-local", "reserved", "non-global")):
        warnings.append("The resolver set includes non-global addresses; this is common for enterprise DNS but can break roaming clients.")
    if rejected:
        warnings.append("Some tokens were rejected because they are not safe DNS namespaces for NRPT export.")

    script_lines = [
        "# HostsFileGet NRPT policy export plan",
        "# Review before running from an elevated PowerShell session or a managed policy workflow.",
        "$ErrorActionPreference = 'Stop'",
        clear_command,
    ]
    script_lines.extend(rule_commands)
    if not rule_commands:
        script_lines.append("# No NRPT rules were generated because no valid DNS namespaces were found.")

    return {
        "schema": NRPT_POLICY_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "plan_only": True,
        "policy_surface": "Windows DNS Client Name Resolution Policy Table via DnsClient PowerShell module",
        "scope": "group-policy" if safe_gpo else "local-client",
        "gpo_name": safe_gpo,
        "server": safe_server,
        "rule_prefix": safe_prefix,
        "name_servers": safe_servers,
        "namespace_count": len(namespaces),
        "rejected_count": len(rejected),
        "rule_count": len(rule_commands),
        "namespaces": namespaces,
        "rejected": rejected,
        "resolver_risk_summary": resolver_risk_summary,
        "commands": commands,
        "powershell_script": "\n".join(script_lines),
        "rollback": [
            clear_command,
            "Export or document existing NRPT/GPO policy before running generated commands.",
        ],
        "warnings": warnings,
        "references": ["S1", "S2", "S16"],
    }


def format_nrpt_policy_export_plan(plan: dict) -> str:
    lines = [
        "NRPT Policy Export Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Surface: {plan.get('policy_surface')}",
        f"Scope: {plan.get('scope')}",
        f"Rule prefix: {plan.get('rule_prefix')}",
        f"Name servers: {', '.join(plan.get('name_servers') or []) or 'none'}",
        f"Namespaces: {int(plan.get('namespace_count') or 0):,}",
        f"Rejected tokens: {int(plan.get('rejected_count') or 0):,}",
        "",
        "Resolver risk summary:",
    ]
    if plan.get("gpo_name"):
        lines.append(f"GPO: {plan.get('gpo_name')}")
    if plan.get("server"):
        lines.append(f"GPO server: {plan.get('server')}")
    resolver_risk_summary = plan.get("resolver_risk_summary") or {}
    if resolver_risk_summary:
        for key in sorted(resolver_risk_summary):
            lines.append(f"- {key}: {resolver_risk_summary[key]}")
    else:
        lines.append("- none")
    lines.extend(["", "Commands:"])
    for command in plan.get("commands") or []:
        lines.append(f"- {command.get('id')}: {_format_command_for_display(command.get('command'))}")
    rejected = plan.get("rejected") or []
    if rejected:
        lines.extend(["", "Rejected samples:"])
        for item in rejected[:5]:
            lines.append(f"- line {item.get('line')}: {item.get('token')} ({item.get('reason')})")
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def sanitize_sandbox_vm_plan_name(value: str | None = None) -> str:
    name = re.sub(r"\s+", " ", str(value or SANDBOX_VM_PLAN_NAME).strip())
    if not name or _contains_control_chars(name):
        name = SANDBOX_VM_PLAN_NAME
    return name[:SANDBOX_VM_PLAN_NAME_MAX_LENGTH]


def sanitize_sandbox_vm_names(values) -> list[str]:
    names: list[str] = []
    seen: set[str] = set()
    for value in values or []:
        name = re.sub(r"\s+", " ", str(value or "").strip())
        if not name:
            continue
        if _contains_control_chars(name):
            raise ValueError("VM name contains control characters")
        name = name[:SANDBOX_VM_PLAN_NAME_MAX_LENGTH]
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        names.append(name)
    return names


def normalize_sandbox_config_value(value: str | None, *, default: str = "Disable") -> str:
    allowed = {"enable": "Enable", "disable": "Disable", "default": "Default"}
    normalized = str(value or default).strip().lower()
    if normalized not in allowed:
        raise ValueError("sandbox config value must be Enable, Disable, or Default")
    return allowed[normalized]


def normalize_sandbox_memory_mb(value) -> int | None:
    if value in (None, ""):
        return None
    try:
        memory_mb = int(value)
    except (TypeError, ValueError) as exc:
        raise ValueError("sandbox memory must be an integer number of MB") from exc
    if memory_mb < 2048:
        raise ValueError("sandbox memory must be at least 2048 MB")
    if memory_mb > 65536:
        raise ValueError("sandbox memory must be 65536 MB or less")
    return memory_mb


def _xml_text(value: str) -> str:
    from xml.sax.saxutils import escape
    return escape(str(value), {"'": "&apos;", '"': "&quot;"})


def build_sandbox_hosts_setup_script(
    *,
    sandbox_folder: str = SANDBOX_VM_SANDBOX_FOLDER,
    target_hosts_path: str = SANDBOX_VM_TARGET_HOSTS_PATH,
) -> str:
    source_path = f"{sandbox_folder}\\{SANDBOX_VM_STAGED_HOSTS_NAME}"
    return "\n".join([
        "$ErrorActionPreference = 'Stop'",
        f"$Source = {_powershell_single_quote(source_path)}",
        f"$Target = {_powershell_single_quote(target_hosts_path)}",
        "$Backup = \"$Target.hostsfileget-lab.bak\"",
        "if (-not (Test-Path -LiteralPath $Source)) { throw \"Staged hosts file not found: $Source\" }",
        "Copy-Item -LiteralPath $Target -Destination $Backup -Force",
        "Copy-Item -LiteralPath $Source -Destination $Target -Force",
        "ipconfig /flushdns | Out-Null",
        "Write-Host \"HostsFileGet staged hosts file applied. Backup: $Backup\"",
        "",
    ])


def build_windows_sandbox_wsb_config(
    host_folder: str,
    *,
    sandbox_folder: str = SANDBOX_VM_SANDBOX_FOLDER,
    setup_script_name: str = SANDBOX_VM_SETUP_SCRIPT_NAME,
    networking: str = "Disable",
    vgpu: str = "Disable",
    memory_mb: int | None = None,
) -> str:
    safe_networking = normalize_sandbox_config_value(networking, default="Disable")
    safe_vgpu = normalize_sandbox_config_value(vgpu, default="Disable")
    safe_memory = normalize_sandbox_memory_mb(memory_mb)
    command = f"powershell.exe -NoProfile -ExecutionPolicy Bypass -File {sandbox_folder}\\{setup_script_name}"
    lines = [
        "<Configuration>",
        f"  <VGpu>{_xml_text(safe_vgpu)}</VGpu>",
        f"  <Networking>{_xml_text(safe_networking)}</Networking>",
    ]
    if safe_memory:
        lines.append(f"  <MemoryInMB>{safe_memory}</MemoryInMB>")
    lines.extend([
        "  <MappedFolders>",
        "    <MappedFolder>",
        f"      <HostFolder>{_xml_text(os.path.abspath(host_folder))}</HostFolder>",
        f"      <SandboxFolder>{_xml_text(sandbox_folder)}</SandboxFolder>",
        "      <ReadOnly>true</ReadOnly>",
        "    </MappedFolder>",
        "  </MappedFolders>",
        "  <LogonCommand>",
        f"    <Command>{_xml_text(command)}</Command>",
        "  </LogonCommand>",
        "</Configuration>",
        "",
    ])
    return "\n".join(lines)


def build_hyperv_hosts_stage_commands(
    vm_name: str,
    *,
    host_folder: str,
    guest_folder: str = SANDBOX_VM_SANDBOX_FOLDER,
) -> list[dict]:
    safe_name = sanitize_sandbox_vm_names([vm_name])
    if not safe_name:
        raise ValueError("VM name is required")
    name = safe_name[0]
    staged_hosts_path = os.path.join(os.path.abspath(host_folder), SANDBOX_VM_STAGED_HOSTS_NAME)
    setup_script_path = os.path.join(os.path.abspath(host_folder), SANDBOX_VM_SETUP_SCRIPT_NAME)
    guest_hosts_path = f"{guest_folder}\\{SANDBOX_VM_STAGED_HOSTS_NAME}"
    guest_setup_script_path = f"{guest_folder}\\{SANDBOX_VM_SETUP_SCRIPT_NAME}"
    return [
        {
            "id": f"enable-guest-service-{name}",
            "description": "Review enabling the Hyper-V Guest Service Interface required by Copy-VMFile.",
            "command": (
                "Enable-VMIntegrationService "
                f"-VMName {_powershell_single_quote(name)} "
                "-Name 'Guest Service Interface' -WhatIf"
            ),
        },
        {
            "id": f"stage-hosts-{name}",
            "description": "Review staging the hosts file inside the guest; remove -WhatIf only after VM snapshot/approval.",
            "command": (
                "Copy-VMFile "
                f"-Name {_powershell_single_quote(name)} "
                f"-SourcePath {_powershell_single_quote(staged_hosts_path)} "
                f"-DestinationPath {_powershell_single_quote(guest_hosts_path)} "
                "-CreateFullPath -FileSource Host -WhatIf"
            ),
        },
        {
            "id": f"stage-setup-script-{name}",
            "description": "Review staging the guest-side apply script; execute it inside the guest after review.",
            "command": (
                "Copy-VMFile "
                f"-Name {_powershell_single_quote(name)} "
                f"-SourcePath {_powershell_single_quote(setup_script_path)} "
                f"-DestinationPath {_powershell_single_quote(guest_setup_script_path)} "
                "-CreateFullPath -FileSource Host -WhatIf"
            ),
        },
    ]


def build_sandbox_vm_hosts_plan(
    hosts_text: str,
    output_dir: str,
    *,
    plan_name: str | None = None,
    vm_names=None,
    networking: str = "Disable",
    vgpu: str = "Disable",
    memory_mb=None,
    now=None,
) -> dict:
    safe_name = sanitize_sandbox_vm_plan_name(plan_name)
    safe_vm_names = sanitize_sandbox_vm_names(vm_names)
    safe_networking = normalize_sandbox_config_value(networking, default="Disable")
    safe_vgpu = normalize_sandbox_config_value(vgpu, default="Disable")
    safe_memory = normalize_sandbox_memory_mb(memory_mb)
    root = os.path.abspath(output_dir)
    staged_hosts_path = os.path.join(root, SANDBOX_VM_STAGED_HOSTS_NAME)
    setup_script_path = os.path.join(root, SANDBOX_VM_SETUP_SCRIPT_NAME)
    wsb_path = os.path.join(root, SANDBOX_VM_WSB_NAME)
    plan_json_path = os.path.join(root, SANDBOX_VM_PLAN_JSON_NAME)
    payload = str(hosts_text or "")
    if payload and not payload.endswith("\n"):
        payload += "\n"
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")

    setup_script = build_sandbox_hosts_setup_script()
    wsb_config = build_windows_sandbox_wsb_config(
        root,
        networking=safe_networking,
        vgpu=safe_vgpu,
        memory_mb=safe_memory,
    )

    hyperv_commands = []
    for vm_name in safe_vm_names:
        hyperv_commands.extend(build_hyperv_hosts_stage_commands(vm_name, host_folder=root))

    warnings = [
        "Bundle-only: HostsFileGet writes review artifacts but does not launch Windows Sandbox, start VMs, or copy files into guests.",
        "Opening the generated .wsb runs the mapped setup script inside the disposable sandbox and changes only that sandbox's hosts file.",
        "The Windows Sandbox mapped folder is read-only to reduce host exposure.",
        "Hyper-V commands include -WhatIf and stage files only; remove -WhatIf only after VM snapshot, backup, and operator approval.",
    ]
    if safe_networking != "Disable":
        warnings.append("Sandbox networking is not disabled; this can expose the sandbox to internal network paths.")
    if not payload.strip():
        warnings.append("The staged hosts file is empty; opening the bundle would replace the sandbox hosts file with an empty file.")

    powershell_script_lines = [
        "# HostsFileGet Sandbox/VM hosts staging plan",
        "# Review before running. Commands are not executed by HostsFileGet.",
    ]
    if hyperv_commands:
        powershell_script_lines.extend(command["command"] for command in hyperv_commands)
    else:
        powershell_script_lines.append("# No Hyper-V VM names were provided; only Windows Sandbox artifacts were generated.")

    return {
        "schema": SANDBOX_VM_HOSTS_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "plan_only": True,
        "bundle_only": True,
        "name": safe_name,
        "output_dir": root,
        "hosts_line_count": len(payload.splitlines()),
        "hosts_sha256": hashlib.sha256(payload.encode("utf-8")).hexdigest(),
        "artifacts": {
            "staged_hosts": staged_hosts_path,
            "setup_script": setup_script_path,
            "wsb_config": wsb_path,
            "plan_json": plan_json_path,
        },
        "windows_sandbox": {
            "enabled": True,
            "networking": safe_networking,
            "vgpu": safe_vgpu,
            "memory_mb": safe_memory,
            "sandbox_folder": SANDBOX_VM_SANDBOX_FOLDER,
            "mapped_folder_read_only": True,
            "wsb_config": wsb_config,
            "setup_script": setup_script,
            "launch_command": ["cmd.exe", "/c", wsb_path],
        },
        "hyperv": {
            "enabled": bool(safe_vm_names),
            "vm_names": safe_vm_names,
            "guest_folder": SANDBOX_VM_SANDBOX_FOLDER,
            "guest_apply_command": (
                f"powershell.exe -NoProfile -ExecutionPolicy Bypass -File "
                f"{SANDBOX_VM_SANDBOX_FOLDER}\\{SANDBOX_VM_SETUP_SCRIPT_NAME}"
            ),
            "commands": hyperv_commands,
        },
        "powershell_script": "\n".join(powershell_script_lines),
        "warnings": warnings,
        "references": ["S17", "S18", "S19"],
    }


def write_sandbox_vm_hosts_bundle(plan: dict, hosts_text: str) -> None:
    artifacts = plan.get("artifacts") or {}
    output_dir = plan.get("output_dir") or os.path.dirname(os.path.abspath(artifacts.get("plan_json") or "."))
    os.makedirs(output_dir, exist_ok=True)
    payload = str(hosts_text or "")
    if payload and not payload.endswith("\n"):
        payload += "\n"
    write_text_file_atomic(artifacts["staged_hosts"], payload)
    write_text_file_atomic(artifacts["setup_script"], plan["windows_sandbox"]["setup_script"])
    write_text_file_atomic(artifacts["wsb_config"], plan["windows_sandbox"]["wsb_config"])
    write_text_file_atomic(artifacts["plan_json"], json.dumps(plan, indent=2))


def format_sandbox_vm_hosts_plan(plan: dict) -> str:
    lines = [
        "Windows Sandbox / VM Hosts Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Bundle only: {'yes' if plan.get('bundle_only') else 'no'}",
        f"Output: {plan.get('output_dir')}",
        f"Hosts lines: {int(plan.get('hosts_line_count') or 0):,}",
        f"Hosts SHA-256: {plan.get('hosts_sha256')}",
        "",
        "Artifacts:",
    ]
    for name, path in (plan.get("artifacts") or {}).items():
        lines.append(f"- {name}: {path}")
    sandbox = plan.get("windows_sandbox") or {}
    lines.extend([
        "",
        "Windows Sandbox:",
        f"- networking: {sandbox.get('networking')}",
        f"- vGPU: {sandbox.get('vgpu')}",
        f"- mapped folder read-only: {'yes' if sandbox.get('mapped_folder_read_only') else 'no'}",
    ])
    if sandbox.get("memory_mb"):
        lines.append(f"- memory MB: {sandbox.get('memory_mb')}")
    hyperv = plan.get("hyperv") or {}
    lines.extend(["", "Hyper-V:"])
    if hyperv.get("vm_names"):
        lines.append(f"- VMs: {', '.join(hyperv.get('vm_names') or [])}")
        lines.append(f"- guest apply command: {hyperv.get('guest_apply_command')}")
        for command in hyperv.get("commands") or []:
            lines.append(f"- {command.get('id')}: {command.get('command')}")
    else:
        lines.append("- no VM staging commands requested")
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def _shell_single_quote(value: str) -> str:
    return "'" + str(value).replace("'", "'\"'\"'") + "'"


def normalize_router_gateway_adapter_id(adapter_id: str) -> str:
    normalized = (adapter_id or "").strip().lower().replace("_", "-")
    return ROUTER_GATEWAY_ADAPTER_ALIASES.get(normalized, normalized)


def list_router_gateway_adapters() -> list[dict[str, str]]:
    return [dict(adapter) for adapter in ROUTER_GATEWAY_ADAPTERS]


def find_router_gateway_adapter(adapter_id: str) -> dict[str, str]:
    normalized = normalize_router_gateway_adapter_id(adapter_id)
    for adapter in ROUTER_GATEWAY_ADAPTERS:
        if adapter["id"] == normalized:
            return dict(adapter)
    known = ", ".join(adapter["id"] for adapter in ROUTER_GATEWAY_ADAPTERS)
    raise ValueError(f"Unknown router/gateway adapter: {adapter_id!r}. Known adapters: {known}")


def sanitize_router_gateway_label(value: str | None, default: str) -> str:
    candidate = re.sub(r"\s+", " ", str(value or default).strip())
    if not candidate or _contains_control_chars(candidate):
        candidate = default
    return candidate[:ROUTER_GATEWAY_LABEL_MAX_LENGTH]


def sanitize_router_gateway_remote_host(value: str | None = None) -> str:
    candidate = str(value or ROUTER_GATEWAY_DEFAULT_REMOTE_HOST).strip()
    if (
        not candidate
        or _contains_control_chars(candidate)
        or len(candidate) > ROUTER_GATEWAY_REMOTE_HOST_MAX_LENGTH
        or candidate.startswith("-")
        or any(ch.isspace() for ch in candidate)
        or "/" in candidate
    ):
        raise ValueError("router host must be a hostname or IP literal without whitespace or path characters")
    return candidate


def sanitize_router_gateway_remote_user(value: str | None = None) -> str:
    candidate = str(value or ROUTER_GATEWAY_DEFAULT_REMOTE_USER).strip()
    if not candidate:
        return ""
    if (
        _contains_control_chars(candidate)
        or len(candidate) > 64
        or candidate.startswith("-")
        or any(ch.isspace() for ch in candidate)
        or "@" in candidate
        or "/" in candidate
    ):
        raise ValueError("router user must be a local SSH username without whitespace, @, or path characters")
    return candidate


def sanitize_router_gateway_remote_path(value: str | None, default: str) -> str:
    candidate = str(value or default).strip()
    if (
        not candidate
        or _contains_control_chars(candidate)
        or len(candidate) > ROUTER_GATEWAY_REMOTE_PATH_MAX_LENGTH
        or not candidate.startswith("/")
        or candidate.startswith("//")
        or "\x00" in candidate
    ):
        raise ValueError("router remote path must be an absolute POSIX path")
    return candidate


def _router_gateway_remote_identity(remote_host: str, remote_user: str | None = None) -> str:
    return f"{remote_user}@{remote_host}" if remote_user else remote_host


def _router_gateway_backup_stamp(created_at: str) -> str:
    stamp = re.sub(r"[^0-9]", "", str(created_at or ""))[:14]
    return stamp or "review"


def build_router_gateway_push_script(
    *,
    adapter_id: str,
    label: str,
    remote_identity: str,
    remote_path: str,
    stage_path: str,
    config_filename: str,
    remote_command: str,
) -> str:
    return "\n".join([
        "#!/bin/sh",
        "set -eu",
        "",
        "# HostsFileGet router/gateway push script",
        "# Review this script and the generated config before applying.",
        f"ADAPTER={_shell_single_quote(adapter_id)}",
        f"LABEL={_shell_single_quote(label)}",
        f"REMOTE={_shell_single_quote(remote_identity)}",
        f"REMOTE_PATH={_shell_single_quote(remote_path)}",
        f"STAGE_PATH={_shell_single_quote(stage_path)}",
        f"REMOTE_APPLY_COMMAND={_shell_single_quote(remote_command)}",
        f"CONFIG_FILE=${{HOSTSFILEGET_CONFIG_FILE:-./{config_filename}}}",
        "",
        'echo "HostsFileGet router/gateway push plan"',
        'echo "Adapter: $ADAPTER ($LABEL)"',
        'echo "Remote: $REMOTE"',
        'echo "Config: $CONFIG_FILE -> $REMOTE:$REMOTE_PATH"',
        'if [ "${HOSTSFILEGET_CONFIRM:-}" != "apply" ]; then',
        '  echo "Dry run only. Set HOSTSFILEGET_CONFIRM=apply after review to execute scp/ssh."',
        '  echo "Would run: scp -- $CONFIG_FILE $REMOTE:$STAGE_PATH"',
        '  echo "Would run: ssh -- $REMOTE $REMOTE_APPLY_COMMAND"',
        "  exit 0",
        "fi",
        "",
        'scp -- "$CONFIG_FILE" "$REMOTE:$STAGE_PATH"',
        'ssh -- "$REMOTE" "$REMOTE_APPLY_COMMAND"',
        'echo "Router/gateway push complete. Validate client DNS resolution before deleting backups."',
    ])


def build_router_gateway_push_plan(
    lines,
    adapter_id: str,
    *,
    remote_host: str | None = None,
    remote_user: str | None = None,
    remote_path: str | None = None,
    label: str | None = None,
    now=None,
) -> dict:
    source_lines = str(lines or "").splitlines() if isinstance(lines, str) else list(lines or [])
    adapter = find_router_gateway_adapter(adapter_id)
    safe_label = sanitize_router_gateway_label(label, adapter["label"])
    safe_host = sanitize_router_gateway_remote_host(remote_host)
    safe_user = sanitize_router_gateway_remote_user(remote_user)
    safe_remote_path = sanitize_router_gateway_remote_path(remote_path, adapter["remote_path"])
    stage_path = adapter["stage_path"]
    remote_identity = _router_gateway_remote_identity(safe_host, safe_user)
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    created_at = str(created_at)

    records = build_export_domain_records(source_lines)
    content = export_lines_as_format(source_lines, adapter["export_format"])
    if content and not content.endswith("\n"):
        content += "\n"
    remote_dir = safe_remote_path.rsplit("/", 1)[0] or "/"
    backup_path = f"{safe_remote_path}.bak.{_router_gateway_backup_stamp(created_at)}"
    new_path = f"{safe_remote_path}.new"
    remote_parts = [
        "set -eu",
        f"mkdir -p {_shell_single_quote(remote_dir)}",
        (
            f"if [ -f {_shell_single_quote(safe_remote_path)} ]; then "
            f"cp {_shell_single_quote(safe_remote_path)} {_shell_single_quote(backup_path)}; fi"
        ),
        f"cp {_shell_single_quote(stage_path)} {_shell_single_quote(new_path)}",
        f"mv {_shell_single_quote(new_path)} {_shell_single_quote(safe_remote_path)}",
        (
            f"if ! {adapter['validate_command']}; then "
            f"if [ -f {_shell_single_quote(backup_path)} ]; then "
            f"cp {_shell_single_quote(backup_path)} {_shell_single_quote(safe_remote_path)}; fi; "
            "exit 1; fi"
        ),
        adapter["reload_command"],
    ]
    remote_command = "; ".join(remote_parts)
    config_filename = adapter["config_filename"]
    shell_script = build_router_gateway_push_script(
        adapter_id=adapter["id"],
        label=safe_label,
        remote_identity=remote_identity,
        remote_path=safe_remote_path,
        stage_path=stage_path,
        config_filename=config_filename,
        remote_command=remote_command,
    )
    commands = [
        {
            "id": "stage-config",
            "description": "Copy the generated config artifact to a temporary path on the gateway.",
            "command": f"scp -- {_shell_single_quote(config_filename)} {_shell_single_quote(remote_identity + ':' + stage_path)}",
            "requires_operator_execution": True,
        },
        {
            "id": "backup-install-validate-reload",
            "description": "Backup the current gateway config, install the staged file, validate DNS config, and reload the DNS service.",
            "command": f"ssh -- {_shell_single_quote(remote_identity)} {_shell_single_quote(remote_command)}",
            "requires_operator_execution": True,
        },
    ]
    warnings = list(ROUTER_GATEWAY_PUSH_WARNINGS)
    if adapter.get("adapter_warning"):
        warnings.append(adapter["adapter_warning"])
    if not records:
        warnings.append("No blocking domains were exported; applying this adapter would stage an empty or header-only config.")

    return {
        "schema": ROUTER_GATEWAY_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": created_at,
        "plan_only": True,
        "bundle_only": True,
        "execution": "not-run",
        "adapter_id": adapter["id"],
        "label": safe_label,
        "target_system": adapter["target_system"],
        "export_format": adapter["export_format"],
        "rule_shape": adapter["rule_shape"],
        "domain_count": len(records),
        "line_count": len(content.splitlines()) if content else 0,
        "config_sha256": hashlib.sha256(content.encode("utf-8")).hexdigest(),
        "config_filename": config_filename,
        "script_filename": ROUTER_GATEWAY_SCRIPT_NAME,
        "plan_filename": ROUTER_GATEWAY_PLAN_JSON_NAME,
        "remote": {
            "host": safe_host,
            "user": safe_user,
            "identity": remote_identity,
            "remote_path": safe_remote_path,
            "stage_path": stage_path,
            "backup_path": backup_path,
        },
        "config_content": content,
        "shell_script": shell_script,
        "commands": commands,
        "warnings": warnings,
        "source_urls": list(adapter["source_urls"]),
        "references": list(adapter["references"]),
    }


def write_router_gateway_push_bundle(plan: dict, output_dir: str) -> dict:
    root = os.path.abspath(output_dir)
    os.makedirs(root, exist_ok=True)
    bundled = dict(plan)
    artifacts = {
        "config": os.path.join(root, bundled["config_filename"]),
        "script": os.path.join(root, bundled["script_filename"]),
        "plan_json": os.path.join(root, bundled["plan_filename"]),
    }
    bundled["output_dir"] = root
    bundled["artifacts"] = artifacts
    write_text_file_atomic(artifacts["config"], bundled["config_content"])
    write_text_file_atomic(artifacts["script"], bundled["shell_script"])
    write_text_file_atomic(artifacts["plan_json"], json.dumps(bundled, indent=2))
    return bundled


def format_router_gateway_adapter_catalog() -> str:
    lines = [
        "Router/gateway push adapters",
        "",
        "All adapters are local artifact generators. HostsFileGet does not execute router writes.",
        "",
        "Supported adapters:",
    ]
    for adapter in ROUTER_GATEWAY_ADAPTERS:
        lines.extend([
            f"- {adapter['id']}: {adapter['label']}",
            f"  Target: {adapter['target_system']}",
            f"  Format: {adapter['export_format']} ({adapter['rule_shape']})",
            f"  Default remote path: {adapter['remote_path']}",
            f"  Validate: {adapter['validate_command']}",
            f"  Reload: {adapter['reload_command']}",
            f"  Sources: {', '.join(adapter['source_urls'])}",
        ])
    lines.append("")
    lines.append("Warnings:")
    lines.extend(f"- {warning}" for warning in ROUTER_GATEWAY_PUSH_WARNINGS)
    return "\n".join(lines)


def format_router_gateway_push_plan(plan: dict) -> str:
    remote = plan.get("remote") or {}
    lines = [
        "Router/Gateway Push Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Bundle only: {'yes' if plan.get('bundle_only') else 'no'}",
        f"Execution: {plan.get('execution')}",
        f"Adapter: {plan.get('adapter_id')} - {plan.get('label')}",
        f"Target: {plan.get('target_system')}",
        f"Format: {plan.get('export_format')} ({plan.get('rule_shape')})",
        f"Domains: {int(plan.get('domain_count') or 0):,}",
        f"Lines: {int(plan.get('line_count') or 0):,}",
        f"Config SHA-256: {plan.get('config_sha256')}",
        f"Remote: {remote.get('identity')}:{remote.get('remote_path')}",
    ]
    if plan.get("output_dir"):
        lines.append(f"Output: {plan.get('output_dir')}")
    artifacts = plan.get("artifacts") or {}
    if artifacts:
        lines.extend(["", "Artifacts:"])
        for name, path in artifacts.items():
            lines.append(f"- {name}: {path}")
    lines.extend(["", "Commands:"])
    for command in plan.get("commands") or []:
        lines.append(f"- {command.get('id')}: {_format_command_for_display(command.get('command'))}")
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def normalize_managed_package_target_id(target_id: str) -> str:
    normalized = (target_id or "").strip().lower().replace("_", "-")
    return MANAGED_PACKAGE_TARGET_ALIASES.get(normalized, normalized)


def list_managed_package_targets() -> list[dict[str, str]]:
    return [dict(target) for target in MANAGED_PACKAGE_TARGETS]


def find_managed_package_target(target_id: str) -> dict[str, str]:
    normalized = normalize_managed_package_target_id(target_id)
    for target in MANAGED_PACKAGE_TARGETS:
        if target["id"] == normalized:
            return dict(target)
    known = ", ".join(target["id"] for target in MANAGED_PACKAGE_TARGETS)
    raise ValueError(f"Unknown managed package target: {target_id!r}. Known targets: {known}")


def sanitize_managed_package_label(value: str | None = None) -> str:
    candidate = re.sub(r"\s+", " ", str(value or MANAGED_PACKAGE_DEFAULT_LABEL).strip())
    if not candidate or _contains_control_chars(candidate):
        candidate = MANAGED_PACKAGE_DEFAULT_LABEL
    return candidate[:MANAGED_PACKAGE_LABEL_MAX_LENGTH]


def sanitize_managed_package_version(value: str | None = None) -> str:
    candidate = str(value or APP_VERSION).strip().lstrip("v")
    if not MANAGED_PACKAGE_VERSION_RE.match(candidate):
        raise ValueError("managed package version must look like MAJOR.MINOR.PATCH")
    return candidate


def sanitize_managed_package_sha256(value: str) -> str:
    candidate = str(value or "").strip()
    if not MANAGED_PACKAGE_SHA256_RE.match(candidate):
        raise ValueError("managed package SHA-256 must be a 64-character hex digest")
    return candidate.upper()


def sanitize_managed_package_installer_url(value: str) -> str:
    candidate = str(value or "").strip()
    if not candidate or _contains_control_chars(candidate) or len(candidate) > 2083:
        raise ValueError("managed package installer URL is required and must not contain control characters")
    try:
        parsed = urllib.parse.urlsplit(candidate)
    except ValueError as exc:
        raise ValueError("managed package installer URL is invalid") from exc
    if parsed.scheme.lower() != "https" or not parsed.hostname:
        raise ValueError("managed package installer URL must use https and include a host")
    return candidate


def sanitize_managed_package_install_dir(value: str | None = None) -> str:
    candidate = str(value or MANAGED_PACKAGE_DEFAULT_INSTALL_DIR).strip()
    if (
        not candidate
        or _contains_control_chars(candidate)
        or len(candidate) > MANAGED_PACKAGE_INSTALL_DIR_MAX_LENGTH
        or candidate.startswith("\\\\")
    ):
        raise ValueError("managed package install dir must be a local Windows path without control characters")
    return candidate


def sanitize_managed_package_exe_name(value: str | None = None) -> str:
    candidate = str(value or MANAGED_PACKAGE_DEFAULT_EXE_NAME).strip()
    if (
        not candidate
        or _contains_control_chars(candidate)
        or len(candidate) > 80
        or "/" in candidate
        or "\\" in candidate
        or candidate in (".", "..")
        or not candidate.lower().endswith(".exe")
    ):
        raise ValueError("managed package executable name must be a simple .exe filename")
    return candidate


def build_managed_hosts_block(lines, label: str | None = None) -> list[str]:
    source_lines = str(lines or "").splitlines() if isinstance(lines, str) else list(lines or [])
    safe_label = sanitize_managed_package_label(label)
    normalized_entries: list[str] = []
    seen: set[str] = set()
    for line in source_lines:
        entries, _, _ = normalize_line_to_hosts_entries(str(line))
        for entry in entries:
            clean = entry.strip()
            key = clean.lower()
            if clean and key not in seen:
                normalized_entries.append(clean)
                seen.add(key)
    return [
        MANAGED_HOSTS_START_TEMPLATE.format(label=safe_label),
        *normalized_entries,
        MANAGED_HOSTS_END_TEMPLATE.format(label=safe_label),
    ]


def build_managed_package_install_script(plan: dict) -> str:
    release = plan.get("release") or {}
    managed_hosts = plan.get("managed_hosts") or {}
    install_dir = release.get("install_dir") or MANAGED_PACKAGE_DEFAULT_INSTALL_DIR
    exe_name = release.get("exe_name") or MANAGED_PACKAGE_DEFAULT_EXE_NAME
    sha256 = release.get("sha256") or ""
    version = release.get("version") or APP_VERSION
    managed_hosts_filename = managed_hosts.get("filename") or MANAGED_PACKAGE_MANAGED_HOSTS_NAME
    return "\n".join([
        "[CmdletBinding()]",
        "param(",
        f"  [string]$InstallDir = {_powershell_single_quote(install_dir)},",
        f"  [string]$StagedExecutablePath = (Join-Path $PSScriptRoot {_powershell_single_quote(exe_name)}),",
        f"  [string]$ManagedHostsPath = (Join-Path $PSScriptRoot {_powershell_single_quote(managed_hosts_filename)}),",
        f"  [string]$ExpectedSha256 = {_powershell_single_quote(sha256)},",
        "  [switch]$ApplyManagedHosts",
        ")",
        "$ErrorActionPreference = 'Stop'",
        "",
        "function Expand-ManagedPath {",
        "  param([string]$PathValue)",
        "  return [Environment]::ExpandEnvironmentVariables($PathValue)",
        "}",
        "",
        "function Assert-Administrator {",
        "  $identity = [Security.Principal.WindowsIdentity]::GetCurrent()",
        "  $principal = [Security.Principal.WindowsPrincipal]::new($identity)",
        "  if (-not $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {",
        "    throw 'HostsFileGet managed installation must run elevated or as LocalSystem.'",
        "  }",
        "}",
        "",
        "function Set-ManagedHostsBlock {",
        "  param([string]$BlockPath)",
        "  if (-not (Test-Path -LiteralPath $BlockPath)) { throw \"Managed hosts block not found: $BlockPath\" }",
        "  $hostsPath = Join-Path $env:SystemRoot 'System32\\drivers\\etc\\hosts'",
        "  $blockLines = @(Get-Content -LiteralPath $BlockPath -ErrorAction Stop)",
        "  if ($blockLines.Count -lt 2 -or $blockLines[0] -notlike '# --- HostsFileGet Managed Start:*') {",
        "    throw 'Managed hosts block is missing the HostsFileGet start marker.'",
        "  }",
        "  $current = @()",
        "  if (Test-Path -LiteralPath $hostsPath) { $current = @(Get-Content -LiteralPath $hostsPath -ErrorAction Stop) }",
        "  $kept = [System.Collections.Generic.List[string]]::new()",
        "  $skip = $false",
        "  foreach ($line in $current) {",
        "    if ($line -like '# --- HostsFileGet Managed Start:*') { $skip = $true; continue }",
        "    if ($skip -and $line -like '# --- HostsFileGet Managed End:*') { $skip = $false; continue }",
        "    if (-not $skip) { [void]$kept.Add($line) }",
        "  }",
        "  if ($kept.Count -gt 0 -and $kept[$kept.Count - 1].Trim().Length -ne 0) { [void]$kept.Add('') }",
        "  foreach ($line in $blockLines) { [void]$kept.Add($line) }",
        "  Set-Content -LiteralPath $hostsPath -Value $kept -Encoding ASCII",
        "}",
        "",
        "Assert-Administrator",
        "$resolvedInstallDir = Expand-ManagedPath $InstallDir",
        "if (-not (Test-Path -LiteralPath $StagedExecutablePath)) { throw \"Staged executable not found: $StagedExecutablePath\" }",
        "$actualHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $StagedExecutablePath).Hash.ToUpperInvariant()",
        "if ($actualHash -ne $ExpectedSha256.ToUpperInvariant()) { throw \"SHA-256 mismatch for $StagedExecutablePath\" }",
        "New-Item -ItemType Directory -Path $resolvedInstallDir -Force | Out-Null",
        "$installedExe = Join-Path $resolvedInstallDir " + _powershell_single_quote(exe_name),
        "Copy-Item -LiteralPath $StagedExecutablePath -Destination $installedExe -Force",
        "$bundleFiles = @(",
        f"  {_powershell_single_quote(MANAGED_PACKAGE_INSTALL_SCRIPT_NAME)},",
        f"  {_powershell_single_quote(MANAGED_PACKAGE_DETECT_SCRIPT_NAME)},",
        f"  {_powershell_single_quote(MANAGED_PACKAGE_UNINSTALL_SCRIPT_NAME)},",
        f"  {_powershell_single_quote(managed_hosts_filename)}",
        ")",
        "foreach ($bundleFile in $bundleFiles) {",
        "  $sourcePath = Join-Path $PSScriptRoot $bundleFile",
        "  if (Test-Path -LiteralPath $sourcePath) {",
        "    Copy-Item -LiteralPath $sourcePath -Destination (Join-Path $resolvedInstallDir $bundleFile) -Force",
        "  }",
        "}",
        f"$installedUninstallScript = Join-Path $resolvedInstallDir {_powershell_single_quote(MANAGED_PACKAGE_UNINSTALL_SCRIPT_NAME)}",
        "$uninstallKey = 'HKLM:\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\HostsFileGet'",
        "New-Item -Path $uninstallKey -Force | Out-Null",
        "Set-ItemProperty -Path $uninstallKey -Name DisplayName -Value 'HostsFileGet'",
        f"Set-ItemProperty -Path $uninstallKey -Name DisplayVersion -Value {_powershell_single_quote(version)}",
        f"Set-ItemProperty -Path $uninstallKey -Name Publisher -Value {_powershell_single_quote(MANAGED_PACKAGE_DEFAULT_PUBLISHER)}",
        "Set-ItemProperty -Path $uninstallKey -Name InstallLocation -Value $resolvedInstallDir",
        "Set-ItemProperty -Path $uninstallKey -Name DisplayIcon -Value $installedExe",
        "Set-ItemProperty -Path $uninstallKey -Name UninstallString -Value \"powershell.exe -NoProfile -ExecutionPolicy Bypass -File `\"$installedUninstallScript`\"\"",
        "if ($ApplyManagedHosts) { Set-ManagedHostsBlock -BlockPath $ManagedHostsPath }",
        "Write-Host \"HostsFileGet managed install complete: $installedExe\"",
    ]) + "\n"


def build_managed_package_detect_script(plan: dict) -> str:
    release = plan.get("release") or {}
    install_dir = release.get("install_dir") or MANAGED_PACKAGE_DEFAULT_INSTALL_DIR
    exe_name = release.get("exe_name") or MANAGED_PACKAGE_DEFAULT_EXE_NAME
    sha256 = release.get("sha256") or ""
    return "\n".join([
        "[CmdletBinding()]",
        "param(",
        f"  [string]$InstallDir = {_powershell_single_quote(install_dir)},",
        f"  [string]$ExeName = {_powershell_single_quote(exe_name)},",
        f"  [string]$ExpectedSha256 = {_powershell_single_quote(sha256)}",
        ")",
        "$ErrorActionPreference = 'Stop'",
        "$resolvedInstallDir = [Environment]::ExpandEnvironmentVariables($InstallDir)",
        "$installedExe = Join-Path $resolvedInstallDir $ExeName",
        "if (-not (Test-Path -LiteralPath $installedExe)) { exit 1 }",
        "$actualHash = (Get-FileHash -Algorithm SHA256 -LiteralPath $installedExe).Hash.ToUpperInvariant()",
        "if ($actualHash -ne $ExpectedSha256.ToUpperInvariant()) { exit 1 }",
        "exit 0",
    ]) + "\n"


def build_managed_package_uninstall_script(plan: dict) -> str:
    release = plan.get("release") or {}
    install_dir = release.get("install_dir") or MANAGED_PACKAGE_DEFAULT_INSTALL_DIR
    return "\n".join([
        "[CmdletBinding()]",
        "param(",
        f"  [string]$InstallDir = {_powershell_single_quote(install_dir)},",
        "  [switch]$RemoveManagedHosts",
        ")",
        "$ErrorActionPreference = 'Stop'",
        "",
        "function Assert-Administrator {",
        "  $identity = [Security.Principal.WindowsIdentity]::GetCurrent()",
        "  $principal = [Security.Principal.WindowsPrincipal]::new($identity)",
        "  if (-not $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)) {",
        "    throw 'HostsFileGet managed uninstall must run elevated or as LocalSystem.'",
        "  }",
        "}",
        "",
        "function Remove-ManagedHostsBlock {",
        "  $hostsPath = Join-Path $env:SystemRoot 'System32\\drivers\\etc\\hosts'",
        "  if (-not (Test-Path -LiteralPath $hostsPath)) { return }",
        "  $current = @(Get-Content -LiteralPath $hostsPath -ErrorAction Stop)",
        "  $kept = [System.Collections.Generic.List[string]]::new()",
        "  $skip = $false",
        "  foreach ($line in $current) {",
        "    if ($line -like '# --- HostsFileGet Managed Start:*') { $skip = $true; continue }",
        "    if ($skip -and $line -like '# --- HostsFileGet Managed End:*') { $skip = $false; continue }",
        "    if (-not $skip) { [void]$kept.Add($line) }",
        "  }",
        "  Set-Content -LiteralPath $hostsPath -Value $kept -Encoding ASCII",
        "}",
        "",
        "Assert-Administrator",
        "$resolvedInstallDir = [Environment]::ExpandEnvironmentVariables($InstallDir)",
        "if (Test-Path -LiteralPath $resolvedInstallDir) { Remove-Item -LiteralPath $resolvedInstallDir -Recurse -Force }",
        "$uninstallKey = 'HKLM:\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Uninstall\\HostsFileGet'",
        "if (Test-Path -LiteralPath $uninstallKey) { Remove-Item -LiteralPath $uninstallKey -Recurse -Force }",
        "if ($RemoveManagedHosts) { Remove-ManagedHostsBlock }",
        "Write-Host 'HostsFileGet managed uninstall complete.'",
    ]) + "\n"


def _managed_package_common_commands() -> dict[str, str]:
    return {
        "install": (
            "powershell.exe -NoProfile -ExecutionPolicy Bypass "
            f"-File .\\{MANAGED_PACKAGE_INSTALL_SCRIPT_NAME} -ApplyManagedHosts"
        ),
        "uninstall": (
            "powershell.exe -NoProfile -ExecutionPolicy Bypass "
            f"-File .\\{MANAGED_PACKAGE_UNINSTALL_SCRIPT_NAME} -RemoveManagedHosts"
        ),
        "detect": (
            "powershell.exe -NoProfile -ExecutionPolicy Bypass "
            f"-File .\\{MANAGED_PACKAGE_DETECT_SCRIPT_NAME}"
        ),
    }


def build_managed_package_target_export(plan: dict) -> str:
    target = plan.get("target") or {}
    release = plan.get("release") or {}
    commands = plan.get("commands") or _managed_package_common_commands()
    target_id = target.get("id")
    if target_id == "intune-win32":
        payload = {
            "schema": "hostsfileget.intune-win32-fields.v1",
            "app_name": "HostsFileGet",
            "publisher": MANAGED_PACKAGE_DEFAULT_PUBLISHER,
            "version": release.get("version"),
            "content_prep": {
                "tool": "IntuneWinAppUtil.exe",
                "source_folder": ".",
                "setup_file": MANAGED_PACKAGE_INSTALL_SCRIPT_NAME,
                "example_command": (
                    "IntuneWinAppUtil.exe -c . "
                    f"-s {MANAGED_PACKAGE_INSTALL_SCRIPT_NAME} -o .\\intune-output -q"
                ),
            },
            "program": {
                "install_command": commands["install"],
                "uninstall_command": commands["uninstall"],
                "install_behavior": "system",
                "device_restart_behavior": "no specific action",
            },
            "detection": {
                "type": "PowerShell script",
                "script_file": MANAGED_PACKAGE_DETECT_SCRIPT_NAME,
                "success_exit_code": 0,
            },
            "assignments": "Create assignments in Intune after pilot testing; this export does not call Graph or store tenant credentials.",
        }
        return json.dumps(payload, indent=2) + "\n"
    if target_id == "gpo-startup":
        return "\n".join([
            "# HostsFileGet GPO Startup Script Export",
            "",
            "Copy this bundle to a read-only UNC share available to target computer accounts.",
            "",
            "Startup script command:",
            "",
            "```powershell",
            commands["install"],
            "```",
            "",
            "Removal script command:",
            "",
            "```powershell",
            commands["uninstall"],
            "```",
            "",
            "Notes:",
            "- Group Policy Software Installation is MSI-oriented; this bundle uses a computer startup script because HostsFileGet ships as a signed executable artifact.",
            "- Assign to a pilot OU first and confirm the managed hosts block can be removed with the uninstall script.",
            "- Keep the staged executable and generated scripts together in the same share folder.",
        ]) + "\n"
    if target_id == "pdq-deploy":
        payload = {
            "schema": "hostsfileget.pdq-deploy-fields.v1",
            "package_name": "HostsFileGet",
            "version": release.get("version"),
            "package_source": "custom",
            "steps": [
                {
                    "name": "Install HostsFileGet managed bundle",
                    "type": "PowerShell",
                    "command": commands["install"],
                    "success_codes": [0],
                },
                {
                    "name": "Detect HostsFileGet managed bundle",
                    "type": "PowerShell",
                    "command": commands["detect"],
                    "success_codes": [0],
                },
            ],
            "uninstall_step": {
                "type": "PowerShell",
                "command": commands["uninstall"],
                "success_codes": [0],
            },
            "operator_notes": [
                "Create or import a custom PDQ package, attach/copy this bundle into the PDQ repository, and paste these commands into PowerShell steps.",
                "PDQ XML exports contain package definitions only; this JSON is an auditable field map rather than a proprietary XML schema guess.",
            ],
        }
        return json.dumps(payload, indent=2) + "\n"
    if target_id == "sccm-application":
        payload = {
            "schema": "hostsfileget.configmgr-application-fields.v1",
            "application": {
                "name": "HostsFileGet",
                "publisher": MANAGED_PACKAGE_DEFAULT_PUBLISHER,
                "software_version": release.get("version"),
            },
            "deployment_type": {
                "type": "Script Installer",
                "content_location": "Copy this bundle to a Configuration Manager content source share.",
                "install_command": commands["install"],
                "uninstall_command": commands["uninstall"],
                "installation_behavior": "Install for system",
                "logon_requirement": "Whether or not a user is logged on",
                "user_interaction_mode": "Hidden",
            },
            "detection": {
                "type": "PowerShell script",
                "script_file": MANAGED_PACKAGE_DETECT_SCRIPT_NAME,
                "success_exit_code": 0,
            },
            "operator_notes": [
                "Create the Configuration Manager application and deployment type from these fields or translate them into ConfigurationManager PowerShell cmdlets.",
                "Distribute content to a pilot distribution point before broad deployment.",
            ],
        }
        return json.dumps(payload, indent=2) + "\n"
    raise ValueError(f"Unsupported managed package target export: {target_id!r}")


def build_managed_package_readme(plan: dict) -> str:
    target = plan.get("target") or {}
    release = plan.get("release") or {}
    artifacts = plan.get("artifacts") or {}
    commands = plan.get("commands") or {}
    lines = [
        "# HostsFileGet Managed Package Export",
        "",
        f"Target: {target.get('id')} - {target.get('label')}",
        f"Version: {release.get('version')}",
        f"Installer URL: {release.get('installer_url')}",
        f"Expected SHA-256: {release.get('sha256')}",
        "",
        "Boundary: this directory is a deployment handoff bundle. HostsFileGet has not uploaded, assigned, imported, or executed anything.",
        "",
        "Required operator steps:",
        f"1. Download the signed release executable and save it beside these scripts as `{release.get('exe_name')}`.",
        "2. Confirm the file hash matches the expected SHA-256.",
        f"3. Review `{MANAGED_PACKAGE_MANAGED_HOSTS_NAME}` and the install/uninstall scripts.",
        f"4. Use `{target.get('artifact_name')}` to populate the deployment tool fields.",
        "",
        "Commands:",
        f"- Install: `{commands.get('install')}`",
        f"- Detect: `{commands.get('detect')}`",
        f"- Uninstall: `{commands.get('uninstall')}`",
    ]
    if artifacts:
        lines.extend(["", "Artifacts:"])
        for name, path in artifacts.items():
            lines.append(f"- {name}: {path}")
    warnings = plan.get("warnings") or []
    if warnings:
        lines.extend(["", "Warnings:"])
        lines.extend(f"- {warning}" for warning in warnings)
    return "\n".join(lines) + "\n"


def build_managed_package_export_plan(
    lines,
    target_id: str,
    *,
    version: str | None = None,
    installer_url: str,
    sha256: str,
    label: str | None = None,
    install_dir: str | None = None,
    exe_name: str | None = None,
    now=None,
) -> dict:
    source_lines = str(lines or "").splitlines() if isinstance(lines, str) else list(lines or [])
    target = find_managed_package_target(target_id)
    safe_version = sanitize_managed_package_version(version)
    safe_url = sanitize_managed_package_installer_url(installer_url)
    safe_sha256 = sanitize_managed_package_sha256(sha256)
    safe_label = sanitize_managed_package_label(label)
    safe_install_dir = sanitize_managed_package_install_dir(install_dir)
    safe_exe_name = sanitize_managed_package_exe_name(exe_name)
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    created_at = str(created_at)

    managed_block = build_managed_hosts_block(source_lines, safe_label)
    managed_content = "\n".join(managed_block) + "\n"
    managed_entries = [
        line for line in managed_block
        if line and not line.startswith("# --- HostsFileGet Managed ")
    ]
    commands = _managed_package_common_commands()
    plan = {
        "schema": MANAGED_PACKAGE_PLAN_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": created_at,
        "plan_only": True,
        "bundle_only": True,
        "execution": "not-run",
        "target": {
            "id": target["id"],
            "label": target["label"],
            "target_system": target["target_system"],
            "command_shape": target["command_shape"],
            "artifact_name": target["artifact_name"],
        },
        "release": {
            "version": safe_version,
            "installer_url": safe_url,
            "sha256": safe_sha256,
            "install_dir": safe_install_dir,
            "exe_name": safe_exe_name,
            "publisher": MANAGED_PACKAGE_DEFAULT_PUBLISHER,
            "signed_artifact_required": True,
        },
        "managed_hosts": {
            "label": safe_label,
            "filename": MANAGED_PACKAGE_MANAGED_HOSTS_NAME,
            "entry_count": len(managed_entries),
            "line_count": len(managed_block),
            "sha256": hashlib.sha256(managed_content.encode("utf-8")).hexdigest(),
            "start_marker": managed_block[0],
            "end_marker": managed_block[-1],
            "content": managed_content,
        },
        "commands": commands,
        "warnings": list(MANAGED_PACKAGE_WARNINGS),
        "source_urls": list(target["source_urls"]),
        "references": list(target["references"]),
        "plan_filename": MANAGED_PACKAGE_PLAN_JSON_NAME,
        "readme_filename": MANAGED_PACKAGE_README_NAME,
        "install_script_filename": MANAGED_PACKAGE_INSTALL_SCRIPT_NAME,
        "detect_script_filename": MANAGED_PACKAGE_DETECT_SCRIPT_NAME,
        "uninstall_script_filename": MANAGED_PACKAGE_UNINSTALL_SCRIPT_NAME,
    }
    if not managed_entries:
        plan["warnings"].append("No managed hosts entries were exported; the wrapper will only install the app unless the block file is updated.")
    plan["install_script"] = build_managed_package_install_script(plan)
    plan["detect_script"] = build_managed_package_detect_script(plan)
    plan["uninstall_script"] = build_managed_package_uninstall_script(plan)
    plan["target_export_content"] = build_managed_package_target_export(plan)
    plan["readme_content"] = build_managed_package_readme(plan)
    return plan


def write_managed_package_export_bundle(plan: dict, output_dir: str) -> dict:
    root = os.path.abspath(output_dir)
    os.makedirs(root, exist_ok=True)
    bundled = dict(plan)
    target = bundled.get("target") or {}
    managed_hosts = bundled.get("managed_hosts") or {}
    artifacts = {
        "plan_json": os.path.join(root, bundled["plan_filename"]),
        "readme": os.path.join(root, bundled["readme_filename"]),
        "install_script": os.path.join(root, bundled["install_script_filename"]),
        "detect_script": os.path.join(root, bundled["detect_script_filename"]),
        "uninstall_script": os.path.join(root, bundled["uninstall_script_filename"]),
        "managed_hosts": os.path.join(root, managed_hosts.get("filename") or MANAGED_PACKAGE_MANAGED_HOSTS_NAME),
        "target_export": os.path.join(root, target.get("artifact_name") or "managed-package-target.json"),
    }
    bundled["output_dir"] = root
    bundled["artifacts"] = artifacts
    write_text_file_atomic(artifacts["install_script"], bundled["install_script"])
    write_text_file_atomic(artifacts["detect_script"], bundled["detect_script"])
    write_text_file_atomic(artifacts["uninstall_script"], bundled["uninstall_script"])
    write_text_file_atomic(artifacts["managed_hosts"], managed_hosts.get("content") or "")
    write_text_file_atomic(artifacts["target_export"], bundled["target_export_content"])
    bundled["readme_content"] = build_managed_package_readme(bundled)
    write_text_file_atomic(artifacts["readme"], bundled["readme_content"])
    write_text_file_atomic(artifacts["plan_json"], json.dumps(bundled, indent=2))
    return bundled


def format_managed_package_target_catalog() -> str:
    lines = [
        "Managed package export targets",
        "",
        "All targets are local artifact generators. HostsFileGet does not deploy, import, assign, or upload packages.",
        "",
        "Supported targets:",
    ]
    for target in MANAGED_PACKAGE_TARGETS:
        lines.extend([
            f"- {target['id']}: {target['label']}",
            f"  Target: {target['target_system']}",
            f"  Shape: {target['command_shape']}",
            f"  Artifact: {target['artifact_name']}",
            f"  Sources: {', '.join(target['source_urls'])}",
        ])
    lines.append("")
    lines.append("Warnings:")
    lines.extend(f"- {warning}" for warning in MANAGED_PACKAGE_WARNINGS)
    return "\n".join(lines)


def format_managed_package_export_plan(plan: dict) -> str:
    target = plan.get("target") or {}
    release = plan.get("release") or {}
    managed_hosts = plan.get("managed_hosts") or {}
    lines = [
        "Managed Package Export Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Bundle only: {'yes' if plan.get('bundle_only') else 'no'}",
        f"Execution: {plan.get('execution')}",
        f"Target: {target.get('id')} - {target.get('label')}",
        f"System: {target.get('target_system')}",
        f"Version: {release.get('version')}",
        f"Install dir: {release.get('install_dir')}",
        f"Executable: {release.get('exe_name')}",
        f"Release SHA-256: {release.get('sha256')}",
        f"Managed hosts entries: {int(managed_hosts.get('entry_count') or 0):,}",
        f"Managed hosts SHA-256: {managed_hosts.get('sha256')}",
    ]
    if plan.get("output_dir"):
        lines.append(f"Output: {plan.get('output_dir')}")
    artifacts = plan.get("artifacts") or {}
    if artifacts:
        lines.extend(["", "Artifacts:"])
        for name, path in artifacts.items():
            lines.append(f"- {name}: {path}")
    lines.extend(["", "Commands:"])
    for name, command in (plan.get("commands") or {}).items():
        lines.append(f"- {name}: {_format_command_for_display(command)}")
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def sanitize_vscode_companion_extension_name(name: str | None = None) -> str:
    value = str(name or VSCODE_COMPANION_DEFAULT_NAME).strip().lower()
    if not VSCODE_COMPANION_NAME_RE.match(value):
        raise ValueError(
            "VS Code extension name must be 3-50 lowercase letters, digits, or hyphens, "
            "and must start/end with a letter or digit."
        )
    return value


def sanitize_vscode_companion_version(version: str | None = None) -> str:
    value = str(version or VSCODE_COMPANION_DEFAULT_VERSION).strip()
    if value.startswith("v"):
        value = value[1:]
    if not VSCODE_COMPANION_VERSION_RE.match(value):
        raise ValueError("VS Code extension version must be semantic version form MAJOR.MINOR.PATCH.")
    return value


def sanitize_vscode_companion_api_base_url(url: str | None = None) -> str:
    value = str(url or f"http://{LOCAL_API_DEFAULT_HOST}:{LOCAL_API_DEFAULT_PORT}").strip()
    parsed = urllib.parse.urlparse(value)
    if parsed.scheme not in {"http", "https"}:
        raise ValueError("VS Code companion API base URL must use http or https.")
    if not parsed.hostname or not is_loopback_api_host(parsed.hostname):
        raise ValueError("VS Code companion API base URL must point at localhost, 127.0.0.1, or ::1.")
    if parsed.path not in ("", "/") or parsed.params or parsed.query or parsed.fragment:
        raise ValueError("VS Code companion API base URL must not include a path, query, or fragment.")
    return value.rstrip("/")


def build_vscode_companion_package_json(name: str, version: str, api_base_url: str) -> dict:
    commands = [
        {"command": "hostsfileget.showStatus", "title": "HostsFileGet: Show Local API Status"},
        {"command": "hostsfileget.cleanPreviewSelection", "title": "HostsFileGet: Clean Preview Selection"},
        {"command": "hostsfileget.setApiToken", "title": "HostsFileGet: Set API Token"},
        {"command": "hostsfileget.clearApiToken", "title": "HostsFileGet: Clear API Token"},
    ]
    return {
        "name": name,
        "displayName": VSCODE_COMPANION_DEFAULT_DISPLAY_NAME,
        "description": "Read-only companion commands for the HostsFileGet local API.",
        "version": version,
        "publisher": VSCODE_COMPANION_DEFAULT_PUBLISHER,
        "license": "MIT",
        "engines": {"vscode": "^1.74.0"},
        "categories": ["Other"],
        "main": f"./{VSCODE_COMPANION_EXTENSION_JS_NAME}",
        "activationEvents": [f"onCommand:{command['command']}" for command in commands],
        "contributes": {
            "commands": commands,
            "configuration": {
                "title": "HostsFileGet",
                "properties": {
                    "hostsfileget.apiBaseUrl": {
                        "type": "string",
                        "default": api_base_url,
                        "description": "Loopback HostsFileGet local API base URL.",
                    },
                    "hostsfileget.requestTimeoutMs": {
                        "type": "number",
                        "default": 5000,
                        "minimum": 1000,
                        "maximum": 60000,
                        "description": "Timeout for local API requests.",
                    },
                },
            },
        },
    }


def build_vscode_companion_extension_js(api_base_url: str) -> str:
    default_url = json.dumps(api_base_url)
    return "\n".join([
        '"use strict";',
        "",
        'const http = require("http");',
        'const https = require("https");',
        'const vscode = require("vscode");',
        "",
        'const SECRET_KEY = "hostsfileget.apiToken";',
        f"const DEFAULT_API_BASE_URL = {default_url};",
        "",
        "function activate(context) {",
        '  const output = vscode.window.createOutputChannel("HostsFileGet");',
        "  context.subscriptions.push(output);",
        "",
        '  context.subscriptions.push(vscode.commands.registerCommand("hostsfileget.showStatus", async () => {',
        "    try {",
        "      const client = await createClient(context);",
        '      const payload = await client.requestJson("GET", "/v1/status");',
        "      output.clear();",
        '      output.appendLine("HostsFileGet Local API Status");',
        '      output.appendLine(`Version: ${payload.version}`);',
        '      output.appendLine(`Hosts path: ${payload.hosts_path}`);',
        '      output.appendLine(`Write endpoints enabled: ${payload.write_endpoints_enabled}`);',
        "      output.show(true);",
        '      vscode.window.showInformationMessage(`HostsFileGet API ${payload.version} is reachable.`);',
        "    } catch (error) {",
        "      showError(error);",
        "    }",
        "  }));",
        "",
        '  context.subscriptions.push(vscode.commands.registerCommand("hostsfileget.cleanPreviewSelection", async () => {',
        "    try {",
        "      const editor = vscode.window.activeTextEditor;",
        "      if (!editor) {",
        '        throw new Error("Open a hosts-like document before running clean preview.");',
        "      }",
        "      const selection = editor.selection;",
        "      const text = selection.isEmpty ? editor.document.getText() : editor.document.getText(selection);",
        "      if (!text.trim()) {",
        '        throw new Error("The selected text is empty.");',
        "      }",
        "      const client = await createClient(context);",
        '      const payload = await client.requestJson("POST", "/v1/clean-preview", { text });',
        '      const cleanedText = `${payload.cleaned_lines.join("\\n")}\\n`;',
        "      const document = await vscode.workspace.openTextDocument({ content: cleanedText, language: editor.document.languageId || \"plaintext\" });",
        "      await vscode.window.showTextDocument(document, { preview: false });",
        '      vscode.window.showInformationMessage(`HostsFileGet clean preview produced ${payload.cleaned_line_count} lines without writing hosts.`);',
        "    } catch (error) {",
        "      showError(error);",
        "    }",
        "  }));",
        "",
        '  context.subscriptions.push(vscode.commands.registerCommand("hostsfileget.setApiToken", async () => {',
        "    const token = await vscode.window.showInputBox({",
        '      prompt: "HostsFileGet local API bearer token",',
        "      password: true,",
        "      ignoreFocusOut: true,",
        "      validateInput: value => value && value.length >= 16 ? undefined : \"Token must be at least 16 characters.\"",
        "    });",
        "    if (token) {",
        "      await context.secrets.store(SECRET_KEY, token);",
        '      vscode.window.showInformationMessage("HostsFileGet API token saved to VS Code SecretStorage.");',
        "    }",
        "  }));",
        "",
        '  context.subscriptions.push(vscode.commands.registerCommand("hostsfileget.clearApiToken", async () => {',
        "    await context.secrets.delete(SECRET_KEY);",
        '    vscode.window.showInformationMessage("HostsFileGet API token cleared from VS Code SecretStorage.");',
        "  }));",
        "}",
        "",
        "function deactivate() {}",
        "",
        "async function createClient(context) {",
        '  const config = vscode.workspace.getConfiguration("hostsfileget");',
        '  const baseUrl = normalizeBaseUrl(config.get("apiBaseUrl", DEFAULT_API_BASE_URL));',
        '  const timeoutMs = Number(config.get("requestTimeoutMs", 5000));',
        "  const token = await getApiToken(context);",
        "  return {",
        "    requestJson(method, path, body) {",
        "      return requestJson(baseUrl, method, path, body, token, timeoutMs);",
        "    }",
        "  };",
        "}",
        "",
        "async function getApiToken(context) {",
        "  const stored = await context.secrets.get(SECRET_KEY);",
        "  if (stored) {",
        "    return stored;",
        "  }",
        "  if (process.env.HOSTSFILEGET_API_TOKEN) {",
        "    return process.env.HOSTSFILEGET_API_TOKEN;",
        "  }",
        '  throw new Error("Set a HostsFileGet API token with the HostsFileGet: Set API Token command or HOSTSFILEGET_API_TOKEN.");',
        "}",
        "",
        "function normalizeBaseUrl(value) {",
        "  const url = new URL(value || DEFAULT_API_BASE_URL);",
        '  if (url.protocol !== "http:" && url.protocol !== "https:") {',
        '    throw new Error("HostsFileGet API URL must use http or https.");',
        "  }",
        '  if (!["localhost", "127.0.0.1", "::1", "[::1]"].includes(url.hostname)) {',
        '    throw new Error("HostsFileGet API URL must point at localhost, 127.0.0.1, or ::1.");',
        "  }",
        '  url.pathname = "";',
        '  url.search = "";',
        '  url.hash = "";',
        '  return url.toString().replace(/\\/$/, "");',
        "}",
        "",
        "function requestJson(baseUrl, method, path, body, token, timeoutMs) {",
        "  return new Promise((resolve, reject) => {",
        "    const url = new URL(path, baseUrl);",
        "    const serialized = body ? JSON.stringify(body) : undefined;",
        '    const transport = url.protocol === "https:" ? https : http;',
        "    const request = transport.request(url, {",
        "      method,",
        "      timeout: Number.isFinite(timeoutMs) ? timeoutMs : 5000,",
        "      headers: {",
        '        "Accept": "application/json",',
        '        "Authorization": `Bearer ${token}`,',
        "        ...(serialized ? {",
        '          "Content-Type": "application/json",',
        '          "Content-Length": Buffer.byteLength(serialized)',
        "        } : {})",
        "      }",
        "    }, response => {",
        "      const chunks = [];",
        "      let size = 0;",
        '      response.on("data", chunk => {',
        "        size += chunk.length;",
        "        if (size > 1024 * 1024) {",
        '          request.destroy(new Error("HostsFileGet API response is too large."));',
        "          return;",
        "        }",
        "        chunks.push(chunk);",
        "      });",
        '      response.on("end", () => {',
        '        const text = Buffer.concat(chunks).toString("utf8");',
        "        let payload;",
        "        try {",
        "          payload = text ? JSON.parse(text) : {};",
        "        } catch (error) {",
        "          reject(new Error(`HostsFileGet API returned invalid JSON: ${error.message}`));",
        "          return;",
        "        }",
        "        if (response.statusCode < 200 || response.statusCode >= 300) {",
        "          reject(new Error(payload.error || `HostsFileGet API request failed with ${response.statusCode}.`));",
        "          return;",
        "        }",
        "        resolve(payload);",
        "      });",
        "    });",
        '    request.on("timeout", () => request.destroy(new Error("HostsFileGet API request timed out.")));',
        '    request.on("error", reject);',
        "    if (serialized) {",
        "      request.write(serialized);",
        "    }",
        "    request.end();",
        "  });",
        "}",
        "",
        "function showError(error) {",
        "  const message = error && error.message ? error.message : String(error);",
        "  vscode.window.showErrorMessage(`HostsFileGet: ${message}`);",
        "}",
        "",
        "module.exports = { activate, deactivate };",
        "",
    ]) + "\n"


def build_vscode_companion_readme(plan: dict) -> str:
    extension = plan.get("extension") or {}
    return "\n".join([
        "# HostsFileGet Companion",
        "",
        "This exported VS Code extension scaffold provides read-only companion commands for the HostsFileGet local API.",
        "",
        "Commands:",
        "",
        "- `HostsFileGet: Show Local API Status` calls `GET /v1/status`.",
        "- `HostsFileGet: Clean Preview Selection` sends the current selection or document to `POST /v1/clean-preview` and opens the cleaned result in an unsaved editor.",
        "- `HostsFileGet: Set API Token` stores the bearer token in VS Code SecretStorage.",
        "- `HostsFileGet: Clear API Token` removes the stored bearer token.",
        "",
        "Before use:",
        "",
        "```powershell",
        "$env:HOSTSFILEGET_API_TOKEN = \"replace-with-at-least-16-random-chars\"",
        "python hosts_editor.py --api-serve",
        "```",
        "",
        "Default API base URL:",
        "",
        f"```text\n{extension.get('api_base_url')}\n```",
        "",
        "Safety boundary:",
        "",
        "- The scaffold is export-only. HostsFileGet does not install, package, publish, or run the extension.",
        "- The generated extension enforces a loopback API base URL.",
        "- Commands are read-only and do not write the Windows hosts file.",
        "- Review, package, and publish with normal VS Code extension tooling after local testing.",
    ]) + "\n"


def build_vscode_companion_export_plan(
    *,
    output_name: str | None = None,
    version: str | None = None,
    api_base_url: str | None = None,
    now=None,
) -> dict:
    safe_name = sanitize_vscode_companion_extension_name(output_name)
    safe_version = sanitize_vscode_companion_version(version)
    safe_api_base_url = sanitize_vscode_companion_api_base_url(api_base_url)
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    created_at = str(created_at)
    package_json = build_vscode_companion_package_json(safe_name, safe_version, safe_api_base_url)
    extension_js = build_vscode_companion_extension_js(safe_api_base_url)
    plan = {
        "schema": VSCODE_COMPANION_EXPORT_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": created_at,
        "plan_only": True,
        "bundle_only": True,
        "execution": "not-run",
        "extension": {
            "name": safe_name,
            "display_name": VSCODE_COMPANION_DEFAULT_DISPLAY_NAME,
            "version": safe_version,
            "publisher": VSCODE_COMPANION_DEFAULT_PUBLISHER,
            "api_base_url": safe_api_base_url,
        },
        "files": [
            VSCODE_COMPANION_PACKAGE_JSON_NAME,
            VSCODE_COMPANION_EXTENSION_JS_NAME,
            VSCODE_COMPANION_README_NAME,
            VSCODE_COMPANION_VSCODEIGNORE_NAME,
        ],
        "commands": [
            "hostsfileget.showStatus",
            "hostsfileget.cleanPreviewSelection",
            "hostsfileget.setApiToken",
            "hostsfileget.clearApiToken",
        ],
        "warnings": list(VSCODE_COMPANION_WARNINGS),
        "references": list(VSCODE_COMPANION_REFERENCES),
        "plan_filename": VSCODE_COMPANION_PLAN_JSON_NAME,
        "package_json_filename": VSCODE_COMPANION_PACKAGE_JSON_NAME,
        "extension_js_filename": VSCODE_COMPANION_EXTENSION_JS_NAME,
        "readme_filename": VSCODE_COMPANION_README_NAME,
        "vscodeignore_filename": VSCODE_COMPANION_VSCODEIGNORE_NAME,
        "package_json": package_json,
        "extension_js": extension_js,
        "vscodeignore": "\n".join([
            ".vscode/**",
            ".gitignore",
            VSCODE_COMPANION_PLAN_JSON_NAME,
            "",
        ]),
    }
    plan["readme"] = build_vscode_companion_readme(plan)
    return plan


def write_vscode_companion_export(plan: dict, output_dir: str) -> dict:
    root = os.path.abspath(output_dir)
    os.makedirs(root, exist_ok=True)
    bundled = dict(plan)
    artifacts = {
        "plan_json": os.path.join(root, bundled["plan_filename"]),
        "package_json": os.path.join(root, bundled["package_json_filename"]),
        "extension_js": os.path.join(root, bundled["extension_js_filename"]),
        "readme": os.path.join(root, bundled["readme_filename"]),
        "vscodeignore": os.path.join(root, bundled["vscodeignore_filename"]),
    }
    bundled["output_dir"] = root
    bundled["artifacts"] = artifacts
    write_text_file_atomic(artifacts["package_json"], json.dumps(bundled["package_json"], indent=2))
    write_text_file_atomic(artifacts["extension_js"], bundled["extension_js"])
    write_text_file_atomic(artifacts["readme"], bundled["readme"])
    write_text_file_atomic(artifacts["vscodeignore"], bundled["vscodeignore"])
    write_text_file_atomic(artifacts["plan_json"], json.dumps(bundled, indent=2))
    return bundled


def format_vscode_companion_export_plan(plan: dict) -> str:
    extension = plan.get("extension") or {}
    lines = [
        "VS Code Companion Export Plan",
        f"Schema: {plan.get('schema')}",
        f"Plan only: {'yes' if plan.get('plan_only') else 'no'}",
        f"Bundle only: {'yes' if plan.get('bundle_only') else 'no'}",
        f"Execution: {plan.get('execution')}",
        f"Extension: {extension.get('name')} {extension.get('version')}",
        f"API base URL: {extension.get('api_base_url')}",
        "",
        "Commands:",
    ]
    for command in plan.get("commands") or []:
        lines.append(f"- {command}")
    artifacts = plan.get("artifacts") or {}
    if artifacts:
        lines.extend(["", "Artifacts:"])
        for name, path in artifacts.items():
            lines.append(f"- {name}: {path}")
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or []:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def probe_prompt_toolkit_dependency(importer=importlib.import_module) -> dict:
    try:
        module = importer("prompt_toolkit")
    except Exception as exc:
        return {
            "package": "prompt_toolkit",
            "requirement": TUI_OPTIONAL_REQUIREMENT,
            "available": False,
            "version": None,
            "error": str(exc) or exc.__class__.__name__,
        }
    return {
        "package": "prompt_toolkit",
        "requirement": TUI_OPTIONAL_REQUIREMENT,
        "available": True,
        "version": str(getattr(module, "__version__", "unknown")),
        "error": None,
    }


def build_tui_launch_report(prompt_toolkit_probe: dict | None = None, now=None) -> dict:
    created_at = now or datetime.datetime.now()
    if isinstance(created_at, datetime.datetime):
        created_at = created_at.isoformat(timespec="seconds")
    probe = dict(prompt_toolkit_probe or probe_prompt_toolkit_dependency())
    probe.setdefault("package", "prompt_toolkit")
    probe.setdefault("requirement", TUI_OPTIONAL_REQUIREMENT)
    probe["available"] = bool(probe.get("available"))
    return {
        "schema": TUI_SCHEMA,
        "app_version": APP_VERSION,
        "created_at": str(created_at),
        "launch_flag": "--tui",
        "status_flag": "--tui-status",
        "optional_dependency": True,
        "dependency": probe,
        "writes_hosts_file": False,
        "requires_admin": False,
        "commands": [dict(command) for command in TUI_COMMANDS],
        "warnings": list(TUI_WARNINGS),
        "references": list(TUI_REFERENCES),
    }


def format_tui_launch_report(report: dict) -> str:
    dependency = report.get("dependency") or {}
    lines = [
        "HostsFileGet prompt_toolkit TUI",
        f"Schema: {report.get('schema')}",
        f"Launch flag: {report.get('launch_flag')}",
        f"Status flag: {report.get('status_flag')}",
        f"Optional dependency: {dependency.get('requirement')}",
        f"Dependency available: {'yes' if dependency.get('available') else 'no'}",
    ]
    if dependency.get("version"):
        lines.append(f"Dependency version: {dependency.get('version')}")
    if dependency.get("error"):
        lines.append(f"Dependency error: {dependency.get('error')}")
    lines.extend([
        f"Writes hosts file: {'yes' if report.get('writes_hosts_file') else 'no'}",
        f"Requires admin: {'yes' if report.get('requires_admin') else 'no'}",
        "",
        "Commands:",
    ])
    for command in report.get("commands") or []:
        lines.append(f"- {command.get('command')}: {command.get('description')}")
    lines.extend(["", "Warnings:"])
    for warning in report.get("warnings") or []:
        lines.append(f"- {warning}")
    references = report.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    if not dependency.get("available"):
        lines.extend(["", "Install:", "python -m pip install -r requirements-tui.txt"])
    return "\n".join(lines)


def _format_tui_clean_preview_result(input_path: str, payload: dict, limit: int = 12) -> str:
    cleaned_lines = payload.get("cleaned_lines") or []
    stats = payload.get("stats") or {}
    summary = summarize_clean_changes(payload.get("discarded_line_count", 0), stats.get("transformed", 0))
    lines = [
        f"Clean preview: {input_path}",
        f"Input lines: {payload.get('input_line_count')}",
        f"Cleaned lines: {payload.get('cleaned_line_count')}",
        f"Summary: {summary}",
    ]
    if cleaned_lines:
        lines.extend(["", f"First {min(limit, len(cleaned_lines))} cleaned line(s):"])
        lines.extend(cleaned_lines[:limit])
        if len(cleaned_lines) > limit:
            lines.append(f"... {len(cleaned_lines) - limit} more line(s) not shown.")
    return "\n".join(lines)


def run_prompt_toolkit_tui(hosts_path: str | None = None) -> int:
    try:
        prompt_toolkit = importlib.import_module("prompt_toolkit")
        completion = importlib.import_module("prompt_toolkit.completion")
        formatted_text = importlib.import_module("prompt_toolkit.formatted_text")
    except Exception as exc:
        raise RuntimeError(f"prompt_toolkit is unavailable: {exc}") from exc

    PromptSession = getattr(prompt_toolkit, "PromptSession")
    print_formatted_text = getattr(prompt_toolkit, "print_formatted_text")
    WordCompleter = getattr(completion, "WordCompleter")
    HTML = getattr(formatted_text, "HTML")

    command_names = [command["command"].split()[0] for command in TUI_COMMANDS]
    session = PromptSession(
        completer=WordCompleter(command_names, ignore_case=True),
        complete_while_typing=True,
    )

    print_formatted_text(HTML(f"<b>{APP_NAME} TUI</b>"))
    print_formatted_text("Type help for commands. This TUI is read-only/config-only and never writes the hosts file.")

    while True:
        try:
            raw = session.prompt("hostsfileget> ", bottom_toolbar="quit exits; clean-preview <path> previews local text only")
        except KeyboardInterrupt:
            print_formatted_text("Use quit to exit.")
            continue
        except EOFError:
            print_formatted_text("")
            return 0

        try:
            parts = shlex.split(raw.strip()) if raw.strip() else []
        except ValueError as exc:
            print_formatted_text(f"Could not parse command: {exc}")
            continue
        if not parts:
            continue
        command = parts[0].lower()

        if command in {"quit", "exit", "q"}:
            return 0
        if command in {"help", "?"}:
            print_formatted_text(format_tui_launch_report(build_tui_launch_report()))
            continue
        if command == "status":
            print_formatted_text(format_tui_launch_report(build_tui_launch_report()))
            continue
        if command == "profiles":
            config_path = get_primary_config_path(CONFIG_FILENAME)
            print_formatted_text(format_profile_list_summary(_read_cli_config_payload(config_path)))
            continue
        if command == "config":
            print_formatted_text(format_config_location_report(build_config_location_report()))
            continue
        if command in {"sources", "bundles"}:
            print_formatted_text(format_source_bundle_catalog(load_source_bundle_catalog()))
            continue
        if command == "health":
            print_formatted_text("Run outside the TUI: python hosts_editor.py --source-health --source-health-output source-health-report.json")
            continue
        if command == "api":
            print_formatted_text('Set HOSTSFILEGET_API_TOKEN, then run outside the TUI: python hosts_editor.py --api-serve')
            continue
        if command == "clean-preview":
            if len(parts) < 2:
                print_formatted_text("Usage: clean-preview <path>")
                continue
            input_path = parts[1]
            try:
                payload = build_local_api_clean_preview_payload({"lines": read_text_file_lines(input_path)})
            except (OSError, ValueError) as exc:
                print_formatted_text(f"Clean preview failed: {exc}")
                continue
            print_formatted_text(_format_tui_clean_preview_result(input_path, payload))
            continue

        print_formatted_text(f"Unknown command: {command}. Type help for commands.")


def _parse_valid_http_source_url(url: str):
    """Return a parsed URL only when it is a direct http(s) URL with a host."""
    try:
        parsed = urllib.parse.urlsplit(url)
    except ValueError:
        return None

    if parsed.scheme.lower() not in ("http", "https"):
        return None
    if not parsed.hostname:
        return None
    return parsed


def normalize_custom_source_url(url: str) -> str:
    candidate = url.strip()
    if not candidate:
        return ""

    try:
        parsed = urllib.parse.urlsplit(candidate)
    except ValueError:
        return candidate.rstrip('/').lower()

    if not parsed.scheme or not parsed.netloc:
        return candidate.rstrip('/').lower()

    normalized_path = parsed.path.rstrip('/')

    return urllib.parse.urlunsplit((
        parsed.scheme.lower(),
        parsed.netloc.lower(),
        normalized_path,
        parsed.query,
        "",
    ))


def _contains_control_chars(value: str) -> bool:
    return any(ord(ch) < 32 for ch in value)


def sanitize_custom_sources(custom_sources) -> list[dict[str, str]]:
    if not isinstance(custom_sources, list):
        return []

    sanitized_sources = []
    seen_names = set()
    seen_urls = set()

    for source in custom_sources:
        if not isinstance(source, dict):
            continue

        name = str(source.get("name", "")).strip()
        url = str(source.get("url", "")).strip()
        if not name or not url or not url.lower().startswith(("http://", "https://")):
            continue

        # Reject names or URLs containing control bytes (tab, newline, ESC,
        # etc.). A legacy config with a malformed entry could otherwise
        # corrupt the import marker comments or the sidebar layout.
        if _contains_control_chars(name) or _contains_control_chars(url):
            continue

        # Cap sizes defensively; see AddSourceDialog for rationale.
        if len(name) > 120 or len(url) > 2083:
            continue
        if _parse_valid_http_source_url(url) is None:
            continue

        normalized_name = name.lower()
        normalized_url = normalize_custom_source_url(url)
        if normalized_name in seen_names or normalized_url in seen_urls:
            continue

        seen_names.add(normalized_name)
        seen_urls.add(normalized_url)
        sanitized_sources.append({"name": name, "url": url})

    return sanitized_sources


def _source_badge(label: str, tone: str, detail: str, url: str = "") -> dict[str, str]:
    return {"label": label, "tone": tone, "detail": detail, "url": url}


def _github_repo_from_source_url(parsed) -> tuple[str, str] | None:
    host = parsed.netloc.lower()
    parts = [part for part in parsed.path.strip("/").split("/") if part]
    if host == "raw.githubusercontent.com" and len(parts) >= 2:
        return parts[0], parts[1]
    if host in {"github.com", "www.github.com"} and len(parts) >= 2:
        return parts[0], parts[1]
    if host == "cdn.jsdelivr.net" and len(parts) >= 3 and parts[0] == "gh":
        owner = parts[1]
        repo = parts[2].split("@", 1)[0]
        if owner and repo:
            return owner, repo
    return None


def _gitlab_repo_from_source_url(parsed) -> tuple[str, str] | None:
    host = parsed.netloc.lower()
    if host not in {"gitlab.com", "www.gitlab.com"}:
        return None
    parts = [part for part in parsed.path.strip("/").split("/") if part]
    if "-/raw" in parsed.path and "-" in parts:
        dash_index = parts.index("-")
        repo_parts = parts[:dash_index]
    elif "raw" in parts:
        raw_index = parts.index("raw")
        repo_parts = parts[:raw_index]
    else:
        repo_parts = parts
    if len(repo_parts) >= 2:
        namespace = "/".join(repo_parts[:-1])
        return namespace, repo_parts[-1]
    return None


def source_trust_report_url(url: str) -> str:
    try:
        parsed = urllib.parse.urlparse(url)
    except ValueError:
        return ""
    github_repo = _github_repo_from_source_url(parsed)
    if github_repo:
        owner, repo = github_repo
        return f"https://github.com/{owner}/{repo}/issues"
    gitlab_repo = _gitlab_repo_from_source_url(parsed)
    if gitlab_repo:
        namespace, repo = gitlab_repo
        return f"https://gitlab.com/{namespace}/{repo}/-/issues"
    return ""


def _source_origin_badge(url: str) -> dict[str, str]:
    try:
        parsed = urllib.parse.urlparse(url)
    except ValueError:
        return _source_badge("Unknown origin", "warning", "The source URL could not be parsed.")
    host = parsed.netloc.lower()
    if _github_repo_from_source_url(parsed):
        if host == "cdn.jsdelivr.net":
            return _source_badge(
                "CDN mirror",
                "info",
                "Served through jsDelivr, backed by a GitHub repository path.",
                source_trust_report_url(url),
            )
        return _source_badge(
            "GitHub-backed",
            "info",
            "The feed path maps to a GitHub repository; use the issue path for upstream complaints.",
            source_trust_report_url(url),
        )
    if _gitlab_repo_from_source_url(parsed):
        return _source_badge(
            "GitLab-backed",
            "info",
            "The feed path maps to a GitLab repository; use the issue path for upstream complaints.",
            source_trust_report_url(url),
        )
    if host:
        return _source_badge("Direct host", "neutral", f"Feed is served directly from {host}.")
    return _source_badge("Unknown origin", "warning", "The source URL has no host.")


def build_source_trust_badges(
    name: str,
    url: str,
    description: str = "",
    category: str = "",
    source_kind: str = "curated",
    last_fetched: str = "",
    cache_metadata: dict | None = None,
    license_id: str = "",
) -> list[dict[str, str]]:
    """Return transparent trust badges for display near source import controls."""
    badges: list[dict[str, str]] = []
    kind = str(source_kind or "").strip().lower()
    if kind == "curated":
        badges.append(
            _source_badge(
                "Curated",
                "info",
                "This feed is listed in the bundled catalog. This is not an endorsement of upstream content.",
            )
        )
    elif kind == "saved":
        badges.append(
            _source_badge(
                "Saved",
                "neutral",
                "This is a user-saved feed. Review its upstream project before relying on it.",
            )
        )
    else:
        badges.append(_source_badge("External", "neutral", "This feed is outside the bundled catalog."))

    try:
        parsed = urllib.parse.urlparse(url)
    except ValueError:
        parsed = urllib.parse.urlparse("")
    if parsed.scheme.lower() == "https":
        badges.append(_source_badge("HTTPS", "success", "Transport uses HTTPS. Content can still change upstream."))
    elif parsed.scheme.lower() == "http":
        badges.append(
            _source_badge(
                "HTTP",
                "warning",
                "Transport is not encrypted. Prefer HTTPS or verify content before importing.",
            )
        )
    else:
        badges.append(_source_badge("Bad URL", "danger", "The source URL does not use HTTP or HTTPS."))

    badges.append(_source_origin_badge(url))

    clean_license = str(license_id or "").strip()
    if clean_license:
        badges.append(_source_badge(f"License {clean_license[:24]}", "success", "License metadata is recorded in the source catalog."))
    else:
        badges.append(
            _source_badge(
                "License untracked",
                "warning",
                "The catalog does not yet record an upstream license for this feed.",
            )
        )

    report_url = source_trust_report_url(url)
    if report_url:
        badges.append(_source_badge("Issue path", "success", f"Upstream complaint path: {report_url}", report_url))
    else:
        host = parsed.netloc or str(url).strip()
        badges.append(
            _source_badge(
                "Report manually",
                "neutral",
                f"No repository issue path could be derived; report problems through {host or 'the source owner'}.",
            )
        )

    risk_haystack = f"{name} {description} {category}".lower()
    if any(word in risk_haystack for word in SOURCE_TRUST_RISK_WORDS):
        badges.append(
            _source_badge(
                "Review scope",
                "warning",
                "Name, category, or description suggests a broad/aggressive/special-format feed.",
            )
        )

    if last_fetched:
        freshness = classify_source_freshness(last_fetched)
        relative = format_relative_time(last_fetched)
        tone = "success" if freshness in {"fresh", "warm"} else "warning"
        badges.append(_source_badge("Fetched", tone, f"Last fetched: {relative or last_fetched}."))
    else:
        badges.append(_source_badge("Not fetched", "neutral", "This install has not fetched the source yet."))

    if isinstance(cache_metadata, dict) and _normalize_sha256(cache_metadata.get("content_sha256")):
        badges.append(
            _source_badge(
                "Cache verified",
                "success",
                "A cached source body exists and is guarded by a SHA-256 content hash.",
            )
        )

    return badges


def format_source_trust_badges(badges: list[dict[str, str]], max_badges: int = 8) -> str:
    labels = [str(badge.get("label", "")).strip() for badge in badges if isinstance(badge, dict)]
    labels = [label for label in labels if label]
    if len(labels) > max_badges:
        labels = labels[:max_badges] + [f"+{len(labels) - max_badges}"]
    return " | ".join(labels)


def format_source_trust_details(badges: list[dict[str, str]]) -> str:
    lines = []
    for badge in badges:
        if not isinstance(badge, dict):
            continue
        label = str(badge.get("label", "")).strip()
        detail = str(badge.get("detail", "")).strip()
        if label and detail:
            lines.append(f"{label}: {detail}")
    return "\n".join(lines)


def _valid_iso_timestamp(value: str) -> bool:
    try:
        datetime.datetime.fromisoformat(value.replace("Z", "+00:00"))
        return True
    except (TypeError, ValueError):
        return False


def _normalize_cache_header(value, max_length: int = 512) -> str:
    if not isinstance(value, str):
        return ""
    value = value.strip()
    if not value or len(value) > max_length or _contains_control_chars(value):
        return ""
    return value


def _normalize_sha256(value) -> str:
    if not isinstance(value, str):
        return ""
    value = value.strip().lower()
    if len(value) != 64 or not all(ch in "0123456789abcdef" for ch in value):
        return ""
    return value


def sanitize_source_cache_metadata(metadata) -> dict[str, dict[str, str | int]]:
    if not isinstance(metadata, dict):
        return {}

    sanitized: dict[str, dict[str, str | int]] = {}
    for url, entry in metadata.items():
        if not isinstance(url, str) or _parse_valid_http_source_url(url) is None:
            continue
        if not isinstance(entry, dict):
            continue

        content_sha256 = _normalize_sha256(entry.get("content_sha256"))
        if not content_sha256:
            continue

        try:
            byte_count = int(entry.get("bytes", 0))
        except (TypeError, ValueError):
            byte_count = 0
        if byte_count < 0 or byte_count > MAX_DOWNLOAD_BYTES:
            byte_count = 0

        fetched_at = entry.get("fetched_at", "")
        if not isinstance(fetched_at, str) or len(fetched_at) > 64 or not _valid_iso_timestamp(fetched_at):
            fetched_at = ""
        validated_at = entry.get("validated_at", "")
        if not isinstance(validated_at, str) or len(validated_at) > 64 or not _valid_iso_timestamp(validated_at):
            validated_at = ""

        sanitized[url] = {
            "cache_key": source_cache_key(url),
            "content_sha256": content_sha256,
            "bytes": byte_count,
            "etag": _normalize_cache_header(entry.get("etag")),
            "last_modified": _normalize_cache_header(entry.get("last_modified")),
            "content_encoding": _normalize_cache_header(entry.get("content_encoding"), max_length=120),
            "fetched_at": fetched_at,
            "validated_at": validated_at,
        }

    return sanitized


def build_source_request_headers(cache_metadata: dict | None = None) -> dict[str, str]:
    headers = {"User-Agent": f"Mozilla/5.0 ({APP_SLUG}/{APP_VERSION})"}
    cache_metadata = cache_metadata if isinstance(cache_metadata, dict) else {}
    etag = _normalize_cache_header(cache_metadata.get("etag"))
    last_modified = _normalize_cache_header(cache_metadata.get("last_modified"))
    if etag:
        headers["If-None-Match"] = etag
    if last_modified:
        headers["If-Modified-Since"] = last_modified
    return headers


def build_source_cache_metadata(url: str, response, raw_bytes: bytes, fetched_at: str | None = None) -> dict[str, str | int]:
    fetched_at = fetched_at or datetime.datetime.now().isoformat(timespec="seconds")
    return {
        "cache_key": source_cache_key(url),
        "content_sha256": hashlib.sha256(raw_bytes).hexdigest(),
        "bytes": len(raw_bytes),
        "etag": _normalize_cache_header(_response_header(response, "ETag")),
        "last_modified": _normalize_cache_header(_response_header(response, "Last-Modified")),
        "content_encoding": _normalize_cache_header(_response_header(response, "Content-Encoding"), max_length=120),
        "fetched_at": fetched_at,
        "validated_at": fetched_at,
    }


def write_source_cache_body(url: str, raw_bytes: bytes, cache_dir: str | None = None) -> None:
    path = get_source_cache_body_path(url, cache_dir)
    os.makedirs(os.path.dirname(path), exist_ok=True)
    fd, temp_path = tempfile.mkstemp(prefix="source_cache_", suffix=".tmp", dir=os.path.dirname(path))
    try:
        with os.fdopen(fd, "wb") as f:
            f.write(raw_bytes)
            f.flush()
            os.fsync(f.fileno())
        os.replace(temp_path, path)
    except Exception:
        if os.path.exists(temp_path):
            os.unlink(temp_path)
        raise


def read_source_cache_body(url: str, metadata: dict, cache_dir: str | None = None) -> bytes:
    content_sha256 = _normalize_sha256(metadata.get("content_sha256") if isinstance(metadata, dict) else None)
    if not content_sha256:
        raise FileNotFoundError("source cache metadata does not include a valid content hash")
    path = get_source_cache_body_path(url, cache_dir)
    with open(path, "rb") as f:
        raw_bytes = f.read(MAX_DOWNLOAD_BYTES + 1)
    if len(raw_bytes) > MAX_DOWNLOAD_BYTES:
        raise ValueError("cached source body exceeds the download size cap")
    actual_sha256 = hashlib.sha256(raw_bytes).hexdigest()
    if actual_sha256 != content_sha256:
        raise ValueError("cached source body hash does not match metadata")
    return raw_bytes


def fetch_source_with_cache(
    url: str,
    metadata_store: dict[str, dict] | None = None,
    cache_dir: str | None = None,
    timeout: float = 15,
    opener=None,
) -> tuple[list[str], dict[str, str | int], str]:
    if opener is None:
        opener = urllib.request.urlopen
    metadata_store = metadata_store if isinstance(metadata_store, dict) else {}
    cache_metadata = metadata_store.get(url, {})
    request = urllib.request.Request(url, headers=build_source_request_headers(cache_metadata))
    try:
        with opener(request, timeout=timeout) as response:
            status = _response_status_code(response)
            if status == 304:
                raw_bytes = read_source_cache_body(url, cache_metadata, cache_dir)
                refreshed_metadata = dict(cache_metadata)
                refreshed_metadata["validated_at"] = datetime.datetime.now().isoformat(timespec="seconds")
                lines = decode_downloaded_lines(url, raw_bytes, str(refreshed_metadata.get("content_encoding", "")))
                return lines, refreshed_metadata, "not_modified"
            if status != 200:
                raise urllib.error.HTTPError(url, status or 0, f"HTTP {status}", response.info(), response.fp)
            raw_bytes = read_http_body_limited(response)
            metadata = build_source_cache_metadata(url, response, raw_bytes)
            lines = decode_downloaded_lines(url, raw_bytes, str(metadata.get("content_encoding", "")))
            write_source_cache_body(url, raw_bytes, cache_dir)
            return lines, metadata, "network"
    except urllib.error.HTTPError as e:
        if getattr(e, "code", None) == 304:
            raw_bytes = read_source_cache_body(url, cache_metadata, cache_dir)
            refreshed_metadata = dict(cache_metadata)
            refreshed_metadata["validated_at"] = datetime.datetime.now().isoformat(timespec="seconds")
            lines = decode_downloaded_lines(url, raw_bytes, str(refreshed_metadata.get("content_encoding", "")))
            return lines, refreshed_metadata, "not_modified"
        raise
    except Exception:
        if cache_metadata:
            try:
                raw_bytes = read_source_cache_body(url, cache_metadata, cache_dir)
                lines = decode_downloaded_lines(url, raw_bytes, str(cache_metadata.get("content_encoding", "")))
                return lines, dict(cache_metadata), "cache_fallback"
            except Exception:
                pass
        raise


def resolve_import_fetch_worker_count(source_count, max_workers=IMPORT_FETCH_MAX_WORKERS) -> int:
    try:
        source_count = int(source_count)
    except (TypeError, ValueError):
        return 0
    if source_count <= 0:
        return 0
    try:
        max_workers = int(max_workers)
    except (TypeError, ValueError):
        max_workers = IMPORT_FETCH_MAX_WORKERS
    return max(1, min(source_count, max_workers))


def fetch_source_with_retries(
    url: str,
    metadata_store: dict[str, dict] | None = None,
    cache_dir: str | None = None,
    timeout: float = 15,
    max_attempts: int = IMPORT_FETCH_MAX_ATTEMPTS,
    retry_delay: float = IMPORT_FETCH_RETRY_DELAY_SECONDS,
    sleep_fn=time.sleep,
    fetch_fn=fetch_source_with_cache,
) -> tuple[list[str], dict[str, str | int], str, int]:
    try:
        attempt_limit = int(max_attempts)
    except (TypeError, ValueError):
        attempt_limit = IMPORT_FETCH_MAX_ATTEMPTS
    attempt_limit = max(1, attempt_limit)
    metadata_snapshot = dict(metadata_store) if isinstance(metadata_store, dict) else {}

    for attempt in range(1, attempt_limit + 1):
        try:
            raw_lines, cache_metadata, cache_status = fetch_fn(
                url,
                metadata_snapshot,
                cache_dir=cache_dir,
                timeout=timeout,
            )
            return raw_lines, cache_metadata, cache_status, attempt
        except Exception:
            if attempt >= attempt_limit:
                raise
            try:
                delay = float(retry_delay)
            except (TypeError, ValueError):
                delay = 0
            if delay > 0 and sleep_fn is not None:
                sleep_fn(delay)

    raise RuntimeError("source fetch retry loop exited unexpectedly")


def _coerce_source_manifest_schema_version(value) -> int:
    if isinstance(value, bool):
        return 0
    try:
        return int(value)
    except (TypeError, ValueError):
        return 0


def sanitize_source_manifest(manifest) -> dict[str, list[tuple[str, str, str]]]:
    """Validate and normalize the bundled curated-source manifest."""
    if not isinstance(manifest, dict):
        raise ValueError("Source manifest must be a JSON object.")

    version = _coerce_source_manifest_schema_version(manifest.get("schema_version"))
    if version != SOURCE_MANIFEST_SCHEMA_VERSION:
        raise ValueError(
            f"Unsupported source manifest schema_version {manifest.get('schema_version')!r}; "
            f"expected {SOURCE_MANIFEST_SCHEMA_VERSION}."
        )

    categories = manifest.get("categories")
    if not isinstance(categories, list) or not categories:
        raise ValueError("Source manifest must contain a non-empty categories list.")

    sanitized: dict[str, list[tuple[str, str, str]]] = {}
    seen_categories = set()
    seen_source_names = set()
    seen_source_urls = set()

    for category_index, category_payload in enumerate(categories, start=1):
        if not isinstance(category_payload, dict):
            raise ValueError(f"Source manifest category {category_index} must be an object.")

        category_name = str(category_payload.get("name", "")).strip()
        if not category_name:
            raise ValueError(f"Source manifest category {category_index} is missing a name.")
        if len(category_name) > 120 or _contains_control_chars(category_name):
            raise ValueError(f"Source manifest category {category_name!r} has an invalid name.")

        normalized_category_name = category_name.lower()
        if normalized_category_name in seen_categories:
            raise ValueError(f"Source manifest category {category_name!r} is duplicated.")
        seen_categories.add(normalized_category_name)

        sources = category_payload.get("sources")
        if not isinstance(sources, list) or not sources:
            raise ValueError(f"Source manifest category {category_name!r} must contain sources.")

        sanitized_sources: list[tuple[str, str, str]] = []
        for source_index, source_payload in enumerate(sources, start=1):
            if not isinstance(source_payload, dict):
                raise ValueError(
                    f"Source manifest entry {category_name!r} #{source_index} must be an object."
                )

            source_name = str(source_payload.get("name", "")).strip()
            source_url = str(source_payload.get("url", "")).strip()
            source_description = str(source_payload.get("description", "")).strip()

            if not source_name or len(source_name) > 120 or _contains_control_chars(source_name):
                raise ValueError(
                    f"Source manifest entry {category_name!r} #{source_index} has an invalid name."
                )
            if (
                not source_url
                or len(source_url) > 2083
                or _contains_control_chars(source_url)
                or _parse_valid_http_source_url(source_url) is None
            ):
                raise ValueError(
                    f"Source manifest entry {source_name!r} has an invalid URL."
                )
            if len(source_description) > 500 or _contains_control_chars(source_description):
                raise ValueError(
                    f"Source manifest entry {source_name!r} has an invalid description."
                )

            normalized_source_name = source_name.lower()
            normalized_source_url = normalize_custom_source_url(source_url)
            if normalized_source_name in seen_source_names:
                raise ValueError(f"Source manifest entry {source_name!r} is duplicated.")
            if normalized_source_url in seen_source_urls:
                raise ValueError(f"Source manifest URL {source_url!r} is duplicated.")

            seen_source_names.add(normalized_source_name)
            seen_source_urls.add(normalized_source_url)
            sanitized_sources.append((source_name, source_url, source_description))

        sanitized[category_name] = sanitized_sources

    return sanitized


def load_blocklist_sources_manifest(path: str | None = None) -> dict[str, list[tuple[str, str, str]]]:
    manifest_path = path or os.path.join(_BUNDLE_DIR, SOURCE_MANIFEST_RELATIVE_PATH)
    try:
        payload = json.loads(read_text_file_content(manifest_path))
    except json.JSONDecodeError as e:
        raise ValueError(f"Source manifest JSON is invalid: {e}") from e
    except OSError as e:
        raise ValueError(f"Source manifest could not be read from {manifest_path!r}: {e}") from e

    return sanitize_source_manifest(payload)


def build_source_manifest_index(blocklist_sources) -> dict[str, dict]:
    """Index sanitized curated source tuples by their display name."""
    index: dict[str, dict] = {}
    if not isinstance(blocklist_sources, dict):
        return index
    for category, sources in blocklist_sources.items():
        if not isinstance(sources, (list, tuple)):
            continue
        for source in sources:
            if not isinstance(source, (list, tuple)) or len(source) < 2:
                continue
            name = str(source[0]).strip()
            url = str(source[1]).strip()
            description = str(source[2]).strip() if len(source) > 2 else ""
            if not name or name in index:
                continue
            index[name] = {
                "name": name,
                "url": url,
                "description": description,
                "category": str(category),
            }
    return index


def sanitize_source_bundle_id(value) -> str:
    bundle_id = str(value or "").strip().lower()
    if not SOURCE_BUNDLE_ID_PATTERN.match(bundle_id):
        raise ValueError(f"Source bundle id {value!r} is invalid.")
    return bundle_id


def sanitize_source_bundle_catalog(manifest, blocklist_sources=None) -> list[dict]:
    """Validate optional import bundles that reference manifest source names."""
    if not isinstance(manifest, dict):
        raise ValueError("Source manifest must be a JSON object.")

    version = _coerce_source_manifest_schema_version(manifest.get("schema_version"))
    if version != SOURCE_MANIFEST_SCHEMA_VERSION:
        raise ValueError(
            f"Unsupported source manifest schema_version {manifest.get('schema_version')!r}; "
            f"expected {SOURCE_MANIFEST_SCHEMA_VERSION}."
        )

    if blocklist_sources is None:
        blocklist_sources = sanitize_source_manifest(manifest)
    source_index = build_source_manifest_index(blocklist_sources)
    source_index_by_name = {name.lower(): record for name, record in source_index.items()}

    bundles = manifest.get("bundles", [])
    if bundles in (None, ""):
        return []
    if not isinstance(bundles, list):
        raise ValueError("Source manifest bundles must be a list when present.")

    sanitized: list[dict] = []
    seen_bundle_ids = set()
    seen_bundle_names = set()
    for bundle_index, bundle_payload in enumerate(bundles, start=1):
        if not isinstance(bundle_payload, dict):
            raise ValueError(f"Source bundle {bundle_index} must be an object.")

        bundle_id = sanitize_source_bundle_id(bundle_payload.get("id"))
        name = str(bundle_payload.get("name", "")).strip()
        description = str(bundle_payload.get("description", "")).strip()
        risk = str(bundle_payload.get("risk", "medium")).strip().lower()

        if not name or len(name) > 120 or _contains_control_chars(name):
            raise ValueError(f"Source bundle {bundle_id!r} has an invalid name.")
        if len(description) > 700 or _contains_control_chars(description):
            raise ValueError(f"Source bundle {bundle_id!r} has an invalid description.")
        if risk not in SOURCE_BUNDLE_RISK_LEVELS:
            raise ValueError(
                f"Source bundle {bundle_id!r} has unsupported risk {risk!r}; "
                f"expected one of {', '.join(SOURCE_BUNDLE_RISK_LEVELS)}."
            )

        normalized_name = name.lower()
        if bundle_id in seen_bundle_ids:
            raise ValueError(f"Source bundle id {bundle_id!r} is duplicated.")
        if normalized_name in seen_bundle_names:
            raise ValueError(f"Source bundle name {name!r} is duplicated.")
        seen_bundle_ids.add(bundle_id)
        seen_bundle_names.add(normalized_name)

        source_names = bundle_payload.get("source_names")
        if not isinstance(source_names, list) or not source_names:
            raise ValueError(f"Source bundle {bundle_id!r} must contain source_names.")

        sources: list[dict] = []
        seen_sources = set()
        for source_index_in_bundle, raw_source_name in enumerate(source_names, start=1):
            source_name = str(raw_source_name or "").strip()
            if (
                not source_name
                or len(source_name) > 120
                or _contains_control_chars(source_name)
            ):
                raise ValueError(
                    f"Source bundle {bundle_id!r} source #{source_index_in_bundle} "
                    "has an invalid name."
                )
            normalized_source_name = source_name.lower()
            if normalized_source_name in seen_sources:
                raise ValueError(
                    f"Source bundle {bundle_id!r} repeats source {source_name!r}."
                )
            source_record = source_index_by_name.get(normalized_source_name)
            if source_record is None:
                raise ValueError(
                    f"Source bundle {bundle_id!r} references unknown source {source_name!r}."
                )
            seen_sources.add(normalized_source_name)
            sources.append(dict(source_record))

        sanitized.append({
            "id": bundle_id,
            "name": name,
            "description": description,
            "risk": risk,
            "source_count": len(sources),
            "sources": sources,
        })

    return sanitized


def load_source_bundle_catalog(path: str | None = None, blocklist_sources=None) -> list[dict]:
    manifest_path = path or os.path.join(_BUNDLE_DIR, SOURCE_MANIFEST_RELATIVE_PATH)
    try:
        payload = json.loads(read_text_file_content(manifest_path))
    except json.JSONDecodeError as e:
        raise ValueError(f"Source manifest JSON is invalid: {e}") from e
    except OSError as e:
        raise ValueError(f"Source manifest could not be read from {manifest_path!r}: {e}") from e

    return sanitize_source_bundle_catalog(payload, blocklist_sources=blocklist_sources)


def find_source_bundle(bundle_catalog, bundle_id_or_name: str) -> dict | None:
    needle = str(bundle_id_or_name or "").strip().lower()
    if not needle:
        return None
    for bundle in bundle_catalog or []:
        if not isinstance(bundle, dict):
            continue
        if str(bundle.get("id", "")).lower() == needle:
            return bundle
        if str(bundle.get("name", "")).lower() == needle:
            return bundle
    return None


def source_bundle_to_import_sources(bundle: dict) -> list[tuple[str, str]]:
    return [
        (str(source.get("name", "")), str(source.get("url", "")))
        for source in (bundle or {}).get("sources", [])
        if isinstance(source, dict) and source.get("name") and source.get("url")
    ]


def format_source_bundle_catalog(bundle_catalog) -> str:
    bundles = [bundle for bundle in (bundle_catalog or []) if isinstance(bundle, dict)]
    lines = [
        "Source Bundle Catalog",
        f"Bundles: {len(bundles)}",
    ]
    if not bundles:
        lines.extend(["", "- No source bundles are configured."])
        return "\n".join(lines)

    for bundle in bundles:
        lines.append("")
        lines.append(
            f"- {bundle.get('name', 'Unnamed bundle')} "
            f"({bundle.get('id', '')}; risk: {bundle.get('risk', 'medium')}; "
            f"sources: {int(bundle.get('source_count') or 0)})"
        )
        description = str(bundle.get("description", "")).strip()
        if description:
            lines.append(f"  {description}")
        source_names = [
            str(source.get("name", "")).strip()
            for source in bundle.get("sources", [])
            if isinstance(source, dict) and source.get("name")
        ]
        if source_names:
            lines.append(f"  Sources: {', '.join(source_names)}")
    return "\n".join(lines)


def format_source_bundle_report(bundle: dict | None) -> str:
    if not bundle:
        return "Source Bundle\n(no bundle selected)"

    lines = [
        f"Source Bundle: {bundle.get('name', 'Unnamed bundle')}",
        f"ID: {bundle.get('id', '')}",
        f"Risk: {bundle.get('risk', 'medium')}",
        f"Sources: {int(bundle.get('source_count') or 0)}",
    ]
    description = str(bundle.get("description", "")).strip()
    if description:
        lines.extend(["", description])

    lines.append("")
    lines.append("Import sources:")
    sources = [source for source in bundle.get("sources", []) if isinstance(source, dict)]
    if not sources:
        lines.append("- None")
        return "\n".join(lines)
    for source in sources:
        category = str(source.get("category", "")).strip()
        suffix = f" [{category}]" if category else ""
        lines.append(f"- {source.get('name', 'Unnamed source')}{suffix}")
        source_description = str(source.get("description", "")).strip()
        if source_description:
            lines.append(f"  {source_description}")
    return "\n".join(lines)


def get_source_adapter_plugin_dirs(config_root_dir: str | None = None) -> list[str]:
    root = config_root_dir or get_config_root_dir()
    return [os.path.join(root, SOURCE_ADAPTER_PLUGIN_DIRNAME)]


def normalize_source_adapter_plugin_dirs(plugin_dirs=None) -> list[str]:
    if plugin_dirs in (None, "", []):
        plugin_dirs = get_source_adapter_plugin_dirs()
    if isinstance(plugin_dirs, (str, os.PathLike)):
        plugin_dirs = [plugin_dirs]
    normalized: list[str] = []
    seen = set()
    for raw_path in plugin_dirs or []:
        try:
            path = os.path.abspath(os.fspath(raw_path)).strip()
        except TypeError:
            continue
        if not path:
            continue
        key = os.path.normcase(path)
        if key in seen:
            continue
        seen.add(key)
        normalized.append(path)
    return normalized


def discover_source_adapter_plugin_files(plugin_dirs=None) -> tuple[list[str], list[dict[str, str]]]:
    paths: list[str] = []
    errors: list[dict[str, str]] = []
    for directory in normalize_source_adapter_plugin_dirs(plugin_dirs):
        try:
            names = sorted(os.listdir(directory), key=str.lower)
        except FileNotFoundError:
            continue
        except OSError as e:
            errors.append({"path": directory, "error": str(e)})
            continue
        for name in names:
            if not name.lower().endswith(".json"):
                continue
            path = os.path.join(directory, name)
            if os.path.isfile(path):
                paths.append(path)
    return paths, errors


def sanitize_source_adapter_plugin_manifest(manifest, source_path: str = "") -> dict:
    if not isinstance(manifest, dict):
        raise ValueError("Source adapter plugin manifest must be a JSON object.")

    version = _coerce_source_manifest_schema_version(manifest.get("schema_version"))
    if version != SOURCE_ADAPTER_PLUGIN_SCHEMA_VERSION:
        raise ValueError(
            f"Unsupported source adapter plugin schema_version {manifest.get('schema_version')!r}; "
            f"expected {SOURCE_ADAPTER_PLUGIN_SCHEMA_VERSION}."
        )

    plugin_id = sanitize_source_bundle_id(manifest.get("id"))
    name = str(manifest.get("name", "")).strip()
    description = str(manifest.get("description", "")).strip()
    homepage = str(manifest.get("homepage", "")).strip()
    maintainer = str(manifest.get("maintainer", "")).strip()
    license_id = str(manifest.get("license", "")).strip()

    if not name or len(name) > 120 or _contains_control_chars(name):
        raise ValueError(f"Source adapter plugin {plugin_id!r} has an invalid name.")
    if len(description) > 700 or _contains_control_chars(description):
        raise ValueError(f"Source adapter plugin {plugin_id!r} has an invalid description.")
    if homepage and (
        len(homepage) > 2083
        or _contains_control_chars(homepage)
        or _parse_valid_http_source_url(homepage) is None
    ):
        raise ValueError(f"Source adapter plugin {plugin_id!r} has an invalid homepage URL.")
    if len(maintainer) > 160 or _contains_control_chars(maintainer):
        raise ValueError(f"Source adapter plugin {plugin_id!r} has an invalid maintainer.")
    if len(license_id) > 80 or _contains_control_chars(license_id):
        raise ValueError(f"Source adapter plugin {plugin_id!r} has an invalid license.")

    sources = manifest.get("sources")
    if not isinstance(sources, list) or not sources:
        raise ValueError(f"Source adapter plugin {plugin_id!r} must contain sources.")
    if len(sources) > SOURCE_ADAPTER_PLUGIN_MAX_SOURCES:
        raise ValueError(
            f"Source adapter plugin {plugin_id!r} has too many sources; "
            f"maximum is {SOURCE_ADAPTER_PLUGIN_MAX_SOURCES}."
        )

    sanitized_sources: list[dict[str, str]] = []
    seen_source_names = set()
    seen_source_urls = set()
    for source_index, source_payload in enumerate(sources, start=1):
        if not isinstance(source_payload, dict):
            raise ValueError(f"Source adapter plugin {plugin_id!r} source #{source_index} must be an object.")
        source_name = str(source_payload.get("name", "")).strip()
        source_url = str(source_payload.get("url", "")).strip()
        source_description = str(source_payload.get("description", "")).strip()
        source_category = str(source_payload.get("category", "")).strip() or name

        if not source_name or len(source_name) > 120 or _contains_control_chars(source_name):
            raise ValueError(f"Source adapter plugin {plugin_id!r} source #{source_index} has an invalid name.")
        if (
            not source_url
            or len(source_url) > 2083
            or _contains_control_chars(source_url)
            or _parse_valid_http_source_url(source_url) is None
        ):
            raise ValueError(f"Source adapter plugin {plugin_id!r} source {source_name!r} has an invalid URL.")
        if len(source_description) > 500 or _contains_control_chars(source_description):
            raise ValueError(f"Source adapter plugin {plugin_id!r} source {source_name!r} has an invalid description.")
        if len(source_category) > 120 or _contains_control_chars(source_category):
            raise ValueError(f"Source adapter plugin {plugin_id!r} source {source_name!r} has an invalid category.")

        normalized_source_name = source_name.lower()
        normalized_source_url = normalize_custom_source_url(source_url)
        if normalized_source_name in seen_source_names:
            raise ValueError(f"Source adapter plugin {plugin_id!r} source {source_name!r} is duplicated.")
        if normalized_source_url in seen_source_urls:
            raise ValueError(f"Source adapter plugin {plugin_id!r} URL {source_url!r} is duplicated.")

        seen_source_names.add(normalized_source_name)
        seen_source_urls.add(normalized_source_url)
        sanitized_sources.append({
            "name": source_name,
            "url": source_url,
            "description": source_description,
            "category": source_category,
        })

    return {
        "schema": SOURCE_ADAPTER_PLUGIN_SCHEMA,
        "schema_version": SOURCE_ADAPTER_PLUGIN_SCHEMA_VERSION,
        "id": plugin_id,
        "name": name,
        "description": description,
        "homepage": homepage,
        "maintainer": maintainer,
        "license": license_id,
        "source_path": source_path,
        "source_count": len(sanitized_sources),
        "sources": sanitized_sources,
    }


def load_source_adapter_plugin_manifest(path: str) -> dict:
    try:
        payload = json.loads(read_text_file_content(path))
    except json.JSONDecodeError as e:
        raise ValueError(f"Source adapter plugin JSON is invalid: {e}") from e
    except OSError as e:
        raise ValueError(f"Source adapter plugin could not be read from {path!r}: {e}") from e
    return sanitize_source_adapter_plugin_manifest(payload, source_path=path)


def build_source_adapter_plugin_sources(plugins) -> dict[str, list[tuple[str, str, str]]]:
    grouped: dict[str, list[tuple[str, str, str]]] = {}
    for plugin in plugins or []:
        if not isinstance(plugin, dict):
            continue
        plugin_name = str(plugin.get("name", "")).strip() or str(plugin.get("id", "")).strip() or "Plugin"
        for source in plugin.get("sources", []):
            if not isinstance(source, dict):
                continue
            name = str(source.get("name", "")).strip()
            url = str(source.get("url", "")).strip()
            if not name or not url:
                continue
            category = str(source.get("category", "")).strip() or plugin_name
            description = str(source.get("description", "")).strip()
            if description:
                description = f"{description} Plugin: {plugin_name}."
            else:
                description = f"Plugin: {plugin_name}."
            grouped.setdefault(f"Plugin: {category}", []).append((name, url, description))
    return grouped


def merge_source_adapter_plugin_sources(blocklist_sources, plugin_sources) -> dict[str, list[tuple[str, str, str]]]:
    merged: dict[str, list[tuple[str, str, str]]] = {}
    for category, sources in (blocklist_sources or {}).items():
        merged[str(category)] = list(sources or [])
    for category, sources in (plugin_sources or {}).items():
        if not sources:
            continue
        merged.setdefault(str(category), [])
        merged[str(category)].extend(list(sources))
    return merged


def load_source_adapter_plugin_catalog(plugin_dirs=None) -> dict:
    normalized_dirs = normalize_source_adapter_plugin_dirs(plugin_dirs)
    paths, errors = discover_source_adapter_plugin_files(normalized_dirs)
    plugins: list[dict] = []
    seen_ids = set()
    for path in paths[:SOURCE_ADAPTER_PLUGIN_MAX_PLUGINS]:
        try:
            plugin = load_source_adapter_plugin_manifest(path)
            if plugin["id"] in seen_ids:
                raise ValueError(f"Source adapter plugin id {plugin['id']!r} is duplicated.")
            seen_ids.add(plugin["id"])
            plugins.append(plugin)
        except ValueError as e:
            errors.append({"path": path, "error": str(e)})
    if len(paths) > SOURCE_ADAPTER_PLUGIN_MAX_PLUGINS:
        errors.append({
            "path": "; ".join(normalized_dirs),
            "error": (
                f"Only the first {SOURCE_ADAPTER_PLUGIN_MAX_PLUGINS} source adapter plugin "
                f"manifest(s) were loaded."
            ),
        })
    sources_by_category = build_source_adapter_plugin_sources(plugins)
    return {
        "schema": SOURCE_ADAPTER_PLUGIN_SCHEMA,
        "schema_version": SOURCE_ADAPTER_PLUGIN_SCHEMA_VERSION,
        "plugin_dirs": normalized_dirs,
        "plugins": plugins,
        "errors": errors,
        "source_count": sum(len(sources) for sources in sources_by_category.values()),
        "sources_by_category": sources_by_category,
    }


def format_source_adapter_plugin_catalog(catalog: dict) -> str:
    catalog = catalog if isinstance(catalog, dict) else load_source_adapter_plugin_catalog([])
    plugins = [plugin for plugin in catalog.get("plugins", []) if isinstance(plugin, dict)]
    errors = [error for error in catalog.get("errors", []) if isinstance(error, dict)]
    lines = [
        "Source Adapter Plugins",
        f"Schema: {SOURCE_ADAPTER_PLUGIN_SCHEMA}",
        f"Directories: {', '.join(catalog.get('plugin_dirs', [])) or '(none)'}",
        f"Plugins: {len(plugins)}",
        f"Sources: {int(catalog.get('source_count') or 0)}",
        "",
        "Sandbox: JSON manifests only. Plugin code is not imported or executed.",
    ]
    if plugins:
        lines.extend(["", "Loaded plugins:"])
        for plugin in plugins:
            lines.append(
                f"- {plugin.get('name', 'Unnamed plugin')} "
                f"({plugin.get('id', '')}; sources: {int(plugin.get('source_count') or 0)})"
            )
            description = str(plugin.get("description", "")).strip()
            if description:
                lines.append(f"  {description}")
            homepage = str(plugin.get("homepage", "")).strip()
            if homepage:
                lines.append(f"  Homepage: {homepage}")
            for source in plugin.get("sources", [])[:8]:
                if isinstance(source, dict):
                    lines.append(
                        f"  - {source.get('name', 'Unnamed source')} "
                        f"[{source.get('category', plugin.get('name', 'Plugin'))}]"
                    )
            remaining = int(plugin.get("source_count") or 0) - min(8, int(plugin.get("source_count") or 0))
            if remaining > 0:
                lines.append(f"  - ...and {remaining} more")
    else:
        lines.extend(["", "- No valid source adapter plugin manifests were found."])
    if errors:
        lines.extend(["", "Skipped manifests:"])
        for error in errors[:10]:
            lines.append(f"- {error.get('path', '(unknown)')}: {error.get('error', 'unknown error')}")
        remaining = len(errors) - min(10, len(errors))
        if remaining > 0:
            lines.append(f"- ...and {remaining} more")
    return "\n".join(lines)


def normalize_locale_code(value: str) -> str:
    if not isinstance(value, str):
        raise ValueError("Locale must be a string.")
    locale = value.strip()
    if not locale or len(locale) > 35 or _contains_control_chars(locale):
        raise ValueError("Locale is empty or invalid.")
    if not I18N_LOCALE_PATTERN.match(locale):
        raise ValueError(f"Locale {value!r} is not a supported BCP-47-style tag.")
    parts = re.split(r"[-_]", locale)
    normalized = [parts[0].lower()]
    for part in parts[1:]:
        if len(part) == 2 and part.isalpha():
            normalized.append(part.upper())
        elif len(part) == 4 and part.isalpha():
            normalized.append(part.title())
        else:
            normalized.append(part)
    return "-".join(normalized)


def _coerce_i18n_catalog_schema_version(value) -> int:
    if isinstance(value, bool):
        return 0
    try:
        return int(value)
    except (TypeError, ValueError):
        return 0


def build_default_i18n_catalog(source: str = "built-in fallback", source_path: str | None = None) -> dict:
    return {
        "schema_version": I18N_CATALOG_SCHEMA_VERSION,
        "locale": DEFAULT_LOCALE,
        "messages": dict(DEFAULT_I18N_MESSAGES),
        "source": source,
        "source_path": source_path,
    }


def sanitize_i18n_catalog(catalog) -> dict:
    """Validate a versioned UI string catalog without applying fallbacks."""
    if not isinstance(catalog, dict):
        raise ValueError("i18n catalog must be a JSON object.")

    version = _coerce_i18n_catalog_schema_version(catalog.get("schema_version"))
    if version != I18N_CATALOG_SCHEMA_VERSION:
        raise ValueError(
            f"Unsupported i18n catalog schema_version {catalog.get('schema_version')!r}; "
            f"expected {I18N_CATALOG_SCHEMA_VERSION}."
        )

    locale = normalize_locale_code(catalog.get("locale", ""))
    messages = catalog.get("messages")
    if not isinstance(messages, dict) or not messages:
        raise ValueError("i18n catalog must contain a non-empty messages object.")

    sanitized_messages: dict[str, str] = {}
    for raw_key, raw_value in messages.items():
        key = str(raw_key).strip()
        if not key or len(key) > 120 or not I18N_KEY_PATTERN.match(key):
            raise ValueError(f"i18n message key {raw_key!r} is invalid.")
        if key in sanitized_messages:
            raise ValueError(f"i18n message key {key!r} is duplicated.")
        if not isinstance(raw_value, str):
            raise ValueError(f"i18n message {key!r} must be a string.")
        value = raw_value.strip()
        if not value or len(value) > 1000 or _contains_control_chars(value):
            raise ValueError(f"i18n message {key!r} has invalid text.")
        sanitized_messages[key] = value

    return {
        "schema_version": I18N_CATALOG_SCHEMA_VERSION,
        "locale": locale,
        "messages": sanitized_messages,
    }


def load_i18n_catalog(path: str | None = None) -> dict:
    catalog_path = path or os.path.join(_BUNDLE_DIR, I18N_CATALOG_RELATIVE_PATH)
    try:
        payload = json.loads(read_text_file_content(catalog_path))
    except json.JSONDecodeError as e:
        raise ValueError(f"i18n catalog JSON is invalid: {e}") from e
    except OSError as e:
        if path is None:
            fallback = build_default_i18n_catalog(source_path=catalog_path)
            fallback["load_error"] = str(e)
            return fallback
        raise ValueError(f"i18n catalog could not be read from {catalog_path!r}: {e}") from e

    sanitized = sanitize_i18n_catalog(payload)
    messages = dict(DEFAULT_I18N_MESSAGES)
    messages.update(sanitized["messages"])
    return {
        "schema_version": sanitized["schema_version"],
        "locale": sanitized["locale"],
        "messages": messages,
        "source": "file",
        "source_path": catalog_path,
    }


def translate_message(catalog: dict, key: str, fallback: str | None = None, **values) -> str:
    messages = catalog.get("messages", {}) if isinstance(catalog, dict) else {}
    text = messages.get(key)
    if text is None:
        text = DEFAULT_I18N_MESSAGES.get(key, fallback if fallback is not None else key)
    if values:
        try:
            return text.format(**values)
        except (IndexError, KeyError, ValueError):
            return text
    return text


def build_i18n_catalog_report(catalog: dict, fallback_messages: dict[str, str] | None = None) -> dict:
    fallback_messages = fallback_messages or DEFAULT_I18N_MESSAGES
    messages = catalog.get("messages", {}) if isinstance(catalog, dict) else {}
    if not isinstance(messages, dict):
        messages = {}
    message_keys = set(messages)
    required_keys = set(fallback_messages)
    return {
        "schema_version": catalog.get("schema_version") if isinstance(catalog, dict) else None,
        "locale": catalog.get("locale", DEFAULT_LOCALE) if isinstance(catalog, dict) else DEFAULT_LOCALE,
        "source": catalog.get("source", "unknown") if isinstance(catalog, dict) else "unknown",
        "source_path": catalog.get("source_path") if isinstance(catalog, dict) else None,
        "load_error": catalog.get("load_error") if isinstance(catalog, dict) else None,
        "message_count": len(message_keys),
        "required_count": len(required_keys),
        "missing_required_keys": sorted(required_keys - message_keys),
        "extra_keys": sorted(message_keys - required_keys),
        "key_rules": [
            "Catalogs are JSON with schema_version, locale, and messages.",
            "Message keys use dotted lowercase namespaces such as dialog.accessibility.title.",
            "Runtime translation falls back to built-in English for missing keys.",
        ],
    }


def format_i18n_catalog_report(report: dict) -> str:
    lines = [
        "Translation catalog",
        f"Locale: {report.get('locale', DEFAULT_LOCALE)}",
        f"Schema version: {report.get('schema_version')}",
        f"Source: {report.get('source', 'unknown')}",
    ]
    if report.get("source_path"):
        lines.append(f"Source path: {report.get('source_path')}")
    if report.get("load_error"):
        lines.append(f"Load fallback reason: {report.get('load_error')}")
    lines.extend([
        "",
        f"Messages: {report.get('message_count', 0)}",
        f"Required fallback keys: {report.get('required_count', 0)}",
        f"Missing required keys: {len(report.get('missing_required_keys', []))}",
        f"Extra locale-specific keys: {len(report.get('extra_keys', []))}",
        "",
        "Key rules:",
    ])
    for item in report.get("key_rules", []):
        lines.append(f"  - {item}")
    if report.get("missing_required_keys"):
        lines.append("")
        lines.append("Missing required keys:")
        for key in report["missing_required_keys"]:
            lines.append(f"  - {key}")
    if report.get("extra_keys"):
        lines.append("")
        lines.append("Extra keys:")
        for key in report["extra_keys"]:
            lines.append(f"  - {key}")
    return "\n".join(lines)


def build_i18n_contribution_template(locale: str, fallback_messages: dict[str, str] | None = None) -> dict:
    fallback_messages = fallback_messages or DEFAULT_I18N_MESSAGES
    normalized_locale = normalize_locale_code(locale)
    return {
        "schema_version": I18N_CATALOG_SCHEMA_VERSION,
        "locale": normalized_locale,
        "messages": {
            key: fallback_messages[key]
            for key in sorted(fallback_messages)
        },
    }


def _i18n_format_signature(text: str) -> dict:
    fields: list[str] = []
    try:
        for _literal, field_name, _format_spec, _conversion in string.Formatter().parse(text):
            if field_name is None:
                continue
            root = re.split(r"[.\[]", field_name, maxsplit=1)[0]
            fields.append(root)
    except ValueError as exc:
        return {"valid": False, "fields": [], "error": str(exc)}
    return {"valid": True, "fields": sorted(set(fields)), "error": None}


def build_i18n_contribution_report(catalog: dict, fallback_messages: dict[str, str] | None = None) -> dict:
    fallback_messages = fallback_messages or DEFAULT_I18N_MESSAGES
    sanitized = sanitize_i18n_catalog(catalog)
    messages = sanitized["messages"]
    required_keys = set(fallback_messages)
    message_keys = set(messages)
    missing_keys = sorted(required_keys - message_keys)
    extra_keys = sorted(message_keys - required_keys)
    placeholder_mismatches = []
    for key in sorted(required_keys & message_keys):
        expected = _i18n_format_signature(fallback_messages[key])
        actual = _i18n_format_signature(messages[key])
        if not actual["valid"] or expected["fields"] != actual["fields"]:
            placeholder_mismatches.append({
                "key": key,
                "expected_fields": expected["fields"],
                "actual_fields": actual["fields"],
                "error": actual["error"],
            })
    unchanged_english = []
    if sanitized["locale"] != DEFAULT_LOCALE:
        unchanged_english = sorted(
            key for key in required_keys & message_keys
            if messages[key] == fallback_messages[key]
        )
    provided_required = len(required_keys - set(missing_keys))
    completion_percent = 100.0
    if required_keys:
        completion_percent = round((provided_required / len(required_keys)) * 100, 1)
    ready = not missing_keys and not extra_keys and not placeholder_mismatches
    return {
        "schema_version": sanitized["schema_version"],
        "locale": sanitized["locale"],
        "required_count": len(required_keys),
        "message_count": len(message_keys),
        "provided_required_count": provided_required,
        "completion_percent": completion_percent,
        "missing_required_keys": missing_keys,
        "extra_keys": extra_keys,
        "placeholder_mismatches": placeholder_mismatches,
        "unchanged_english_keys": unchanged_english,
        "ready": ready,
        "status": "ready" if ready else "needs-work",
    }


def format_i18n_contribution_report(report: dict) -> str:
    lines = [
        "Translation contribution",
        f"Locale: {report.get('locale', DEFAULT_LOCALE)}",
        f"Schema version: {report.get('schema_version')}",
        f"Status: {report.get('status', 'needs-work')}",
        "",
        f"Required keys: {report.get('required_count', 0)}",
        f"Provided required keys: {report.get('provided_required_count', 0)}",
        f"All messages: {report.get('message_count', 0)}",
        f"Completion: {report.get('completion_percent', 0)}%",
        f"Missing required keys: {len(report.get('missing_required_keys', []))}",
        f"Extra keys: {len(report.get('extra_keys', []))}",
        f"Placeholder mismatches: {len(report.get('placeholder_mismatches', []))}",
        f"Unchanged English strings: {len(report.get('unchanged_english_keys', []))}",
    ]
    if report.get("missing_required_keys"):
        lines.append("")
        lines.append("Missing required keys:")
        for key in report["missing_required_keys"][:50]:
            lines.append(f"  - {key}")
        if len(report["missing_required_keys"]) > 50:
            lines.append(f"  - ...and {len(report['missing_required_keys']) - 50} more")
    if report.get("extra_keys"):
        lines.append("")
        lines.append("Extra keys:")
        for key in report["extra_keys"][:50]:
            lines.append(f"  - {key}")
        if len(report["extra_keys"]) > 50:
            lines.append(f"  - ...and {len(report['extra_keys']) - 50} more")
    if report.get("placeholder_mismatches"):
        lines.append("")
        lines.append("Placeholder mismatches:")
        for item in report["placeholder_mismatches"][:50]:
            expected = ", ".join(item.get("expected_fields", [])) or "(none)"
            actual = ", ".join(item.get("actual_fields", [])) or "(none)"
            suffix = f"; {item['error']}" if item.get("error") else ""
            lines.append(f"  - {item.get('key')}: expected {expected}; found {actual}{suffix}")
        if len(report["placeholder_mismatches"]) > 50:
            lines.append(f"  - ...and {len(report['placeholder_mismatches']) - 50} more")
    if report.get("unchanged_english_keys"):
        lines.append("")
        lines.append("Unchanged English strings to review:")
        for key in report["unchanged_english_keys"][:25]:
            lines.append(f"  - {key}")
        if len(report["unchanged_english_keys"]) > 25:
            lines.append(f"  - ...and {len(report['unchanged_english_keys']) - 25} more")
    return "\n".join(lines)


def iter_curated_source_records(blocklist_sources: dict[str, list[tuple[str, str, str]]]):
    for category, sources in blocklist_sources.items():
        for name, url, description in sources:
            yield {
                "category": category,
                "name": name,
                "url": url,
                "description": description,
            }


def _utc_timestamp() -> str:
    return datetime.datetime.now(datetime.timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def _response_status_code(response) -> int | None:
    try:
        status = response.getcode()
    except Exception:
        status = getattr(response, "status", None)
    try:
        return int(status) if status is not None else None
    except (TypeError, ValueError):
        return None


def _response_header(response, name: str) -> str:
    headers = getattr(response, "headers", None)
    if headers is None:
        return ""
    try:
        value = headers.get(name, "")
    except Exception:
        return ""
    return str(value or "")


def _sample_contains_host_like_content(lines: list[str]) -> bool:
    for line in lines[:200]:
        entries, domains, _ = normalize_line_to_hosts_entries(line)
        if entries or domains:
            return True
    return False


def _source_health_base_result(source: dict, checked_at: str) -> dict:
    return {
        "category": str(source.get("category", "")).strip(),
        "name": str(source.get("name", "")).strip(),
        "url": str(source.get("url", "")).strip(),
        "checked_at": checked_at,
        "status": "failed",
        "http_status": None,
        "content_type": "",
        "bytes_read": 0,
        "sample_lines": 0,
        "elapsed_ms": 0,
        "diagnostic": "",
    }


def check_source_health_record(
    source: dict,
    opener=None,
    timeout: float = SOURCE_HEALTH_TIMEOUT_SECONDS,
    sample_bytes: int = SOURCE_HEALTH_SAMPLE_BYTES,
) -> dict:
    """Fetch a bounded sample from one curated source and classify reachability."""
    if opener is None:
        opener = urllib.request.urlopen
    checked_at = _utc_timestamp()
    result = _source_health_base_result(source, checked_at)
    started = time.monotonic()

    def finish(status: str, diagnostic: str) -> dict:
        result["status"] = status
        result["diagnostic"] = diagnostic
        result["elapsed_ms"] = max(0, int((time.monotonic() - started) * 1000))
        return result

    parsed = _parse_valid_http_source_url(result["url"])
    if parsed is None:
        return finish("failed", "Invalid source URL.")

    try:
        timeout = max(1.0, float(timeout))
    except (TypeError, ValueError):
        timeout = SOURCE_HEALTH_TIMEOUT_SECONDS
    try:
        sample_bytes = max(1024, int(sample_bytes))
    except (TypeError, ValueError):
        sample_bytes = SOURCE_HEALTH_SAMPLE_BYTES

    request = urllib.request.Request(
        result["url"],
        headers={
            "User-Agent": f"{APP_SLUG}/{APP_VERSION} source-health",
            "Accept": "text/plain,*/*;q=0.5",
            "Range": f"bytes=0-{sample_bytes - 1}",
        },
    )

    try:
        with opener(request, timeout=timeout) as response:
            result["http_status"] = _response_status_code(response)
            result["content_type"] = _response_header(response, "Content-Type")
            content_encoding = _response_header(response, "Content-Encoding")
            if result["http_status"] and result["http_status"] >= 400:
                return finish("failed", f"HTTP {result['http_status']}.")

            try:
                raw = read_http_body_limited(response, sample_bytes)
            except ValueError as e:
                return finish("warning", f"Source is reachable, but the sample exceeded the cap: {e}")
            result["bytes_read"] = len(raw)
            if not raw:
                return finish("warning", "Source responded with an empty sample.")

            try:
                lines = decode_downloaded_lines(result["url"], raw, content_encoding)
            except Exception:
                lines = decode_text_bytes(raw).splitlines()

            result["sample_lines"] = len(lines)
            if looks_like_html_document(lines):
                return finish("failed", "Source returned an HTML page instead of a list sample.")
            if not _sample_contains_host_like_content(lines):
                return finish("warning", "Source is reachable, but the sample did not contain host-like entries.")

            return finish("healthy", "Source is reachable and returned host-like content.")
    except urllib.error.HTTPError as e:
        result["http_status"] = getattr(e, "code", None)
        return finish("failed", f"HTTP {getattr(e, 'code', 'error')}.")
    except urllib.error.URLError as e:
        return finish("failed", f"Network error: {getattr(e, 'reason', e)}")
    except TimeoutError:
        return finish("failed", "Network timeout.")
    except Exception as e:
        return finish("failed", f"Health check failed: {e}")


def check_source_health_records(
    records: list[dict],
    opener=None,
    timeout: float = SOURCE_HEALTH_TIMEOUT_SECONDS,
    sample_bytes: int = SOURCE_HEALTH_SAMPLE_BYTES,
    max_workers: int = SOURCE_HEALTH_DEFAULT_WORKERS,
) -> list[dict]:
    records = list(records)
    if not records:
        return []
    try:
        worker_count = int(max_workers)
    except (TypeError, ValueError):
        worker_count = SOURCE_HEALTH_DEFAULT_WORKERS
    worker_count = max(1, min(worker_count, len(records)))

    if worker_count == 1:
        return [
            check_source_health_record(record, opener=opener, timeout=timeout, sample_bytes=sample_bytes)
            for record in records
        ]

    results: list[dict | None] = [None] * len(records)
    with concurrent.futures.ThreadPoolExecutor(max_workers=worker_count) as executor:
        future_to_index = {
            executor.submit(
                check_source_health_record,
                record,
                opener,
                timeout,
                sample_bytes,
            ): index
            for index, record in enumerate(records)
        }
        for future in concurrent.futures.as_completed(future_to_index):
            results[future_to_index[future]] = future.result()

    return [result for result in results if result is not None]


def summarize_source_health_results(results: list[dict]) -> dict:
    summary = {"total": len(results), "healthy": 0, "warning": 0, "failed": 0}
    for result in results:
        status = result.get("status")
        if status in summary:
            summary[status] += 1
        else:
            summary["failed"] += 1
    return summary


def build_source_health_report(
    blocklist_sources: dict[str, list[tuple[str, str, str]]],
    opener=None,
    timeout: float = SOURCE_HEALTH_TIMEOUT_SECONDS,
    sample_bytes: int = SOURCE_HEALTH_SAMPLE_BYTES,
    max_workers: int = SOURCE_HEALTH_DEFAULT_WORKERS,
) -> dict:
    records = list(iter_curated_source_records(blocklist_sources))
    results = check_source_health_records(
        records,
        opener=opener,
        timeout=timeout,
        sample_bytes=sample_bytes,
        max_workers=max_workers,
    )
    return {
        "schema_version": SOURCE_HEALTH_REPORT_SCHEMA_VERSION,
        "checked_at": _utc_timestamp(),
        "summary": summarize_source_health_results(results),
        "sources": results,
    }


def _sanitize_whitelist_text(value) -> str:
    if isinstance(value, str):
        return value
    if isinstance(value, (list, tuple, set)):
        return '\n'.join(
            item.strip()
            for item in (str(entry) for entry in value)
            if item.strip()
        )
    return ""


def sanitize_profile_id(value, fallback: str = DEFAULT_PROFILE_ID) -> str:
    candidate = str(value).strip().lower() if isinstance(value, str) else ""
    if PROFILE_ID_PATTERN.match(candidate):
        return candidate

    fallback_candidate = str(fallback).strip().lower() if isinstance(fallback, str) else ""
    if PROFILE_ID_PATTERN.match(fallback_candidate):
        return fallback_candidate

    return DEFAULT_PROFILE_ID


def _sanitize_profile_id_strict(value) -> str:
    candidate = str(value).strip().lower() if isinstance(value, str) else ""
    return candidate if PROFILE_ID_PATTERN.match(candidate) else ""


def _unique_profile_id(profile_id: str, used_ids: set[str]) -> str:
    if profile_id not in used_ids:
        return profile_id

    base = profile_id[:56].rstrip("-_") or DEFAULT_PROFILE_ID
    suffix = 2
    while True:
        suffix_text = f"-{suffix}"
        candidate = f"{base[:64 - len(suffix_text)]}{suffix_text}"
        if candidate not in used_ids:
            return candidate
        suffix += 1


def _profile_name_from_id(profile_id: str) -> str:
    label = profile_id.replace("-", " ").replace("_", " ").strip()
    return label.title() if label else "Default"


def _sanitize_profile_name(value, fallback_id: str) -> str:
    if isinstance(value, str):
        name = re.sub(r"\s+", " ", value.strip())
        if name and not _contains_control_chars(name):
            return name[:80]
    return _profile_name_from_id(fallback_id)


def _profile_preferred_sink(value) -> str:
    return value if value in BLOCK_SINK_IPS else "0.0.0.0"


def build_default_profile_snapshot(config) -> dict:
    if not isinstance(config, dict):
        config = {}
    return {
        "schema_version": PROFILE_SCHEMA_VERSION,
        "id": DEFAULT_PROFILE_ID,
        "name": "Default",
        "whitelist": _sanitize_whitelist_text(config.get("whitelist", "")),
        "custom_sources": sanitize_custom_sources(config.get("custom_sources", [])),
        "pinned_domains": sanitize_pinned_domains(config.get("pinned_domains", [])),
        "preferred_block_sink": _profile_preferred_sink(config.get("preferred_block_sink", "0.0.0.0")),
    }


def sanitize_profile_snapshot(profile, fallback_id: str = DEFAULT_PROFILE_ID, used_ids: set[str] | None = None) -> dict:
    if not isinstance(profile, dict):
        profile = {}
    used_ids = used_ids if used_ids is not None else set()

    profile_id = sanitize_profile_id(profile.get("id"), fallback_id)
    profile_id = _unique_profile_id(profile_id, used_ids)
    used_ids.add(profile_id)

    return {
        "schema_version": PROFILE_SCHEMA_VERSION,
        "id": profile_id,
        "name": _sanitize_profile_name(profile.get("name"), profile_id),
        "whitelist": _sanitize_whitelist_text(profile.get("whitelist", "")),
        "custom_sources": sanitize_custom_sources(profile.get("custom_sources", [])),
        "pinned_domains": sanitize_pinned_domains(profile.get("pinned_domains", [])),
        "preferred_block_sink": _profile_preferred_sink(profile.get("preferred_block_sink", "0.0.0.0")),
    }


def _iter_profile_candidates(profiles):
    if isinstance(profiles, list):
        for profile in profiles:
            if isinstance(profile, dict):
                yield profile
        return

    if isinstance(profiles, dict):
        for profile_id, profile in profiles.items():
            if not isinstance(profile, dict):
                continue
            candidate = dict(profile)
            candidate.setdefault("id", profile_id)
            yield candidate


def sanitize_profiles_snapshot(
    profiles,
    active_profile_id: str | None = None,
    fallback_profile: dict | None = None,
) -> tuple[list[dict], str]:
    sanitized_profiles: list[dict] = []
    used_ids: set[str] = set()

    for candidate in _iter_profile_candidates(profiles):
        fallback_id = DEFAULT_PROFILE_ID if not sanitized_profiles else f"profile-{len(sanitized_profiles) + 1}"
        sanitized_profiles.append(
            sanitize_profile_snapshot(candidate, fallback_id=fallback_id, used_ids=used_ids)
        )

    if not sanitized_profiles:
        sanitized_profiles.append(
            sanitize_profile_snapshot(
                fallback_profile or build_default_profile_snapshot({}),
                fallback_id=DEFAULT_PROFILE_ID,
                used_ids=used_ids,
            )
        )

    active_id = sanitize_profile_id(active_profile_id, "")
    profile_ids = {profile["id"] for profile in sanitized_profiles}
    if active_id not in profile_ids:
        active_id = sanitized_profiles[0]["id"]

    return sanitized_profiles, active_id


def update_active_profile_snapshot(
    profiles,
    active_profile_id: str | None,
    current_config: dict,
) -> tuple[list[dict], str]:
    current_profile = build_default_profile_snapshot(current_config)
    sanitized_profiles, active_id = sanitize_profiles_snapshot(
        profiles,
        active_profile_id,
        fallback_profile=current_profile,
    )

    for index, profile in enumerate(sanitized_profiles):
        if profile["id"] != active_id:
            continue
        updated = dict(profile)
        for key in ("whitelist", "custom_sources", "pinned_domains", "preferred_block_sink"):
            updated[key] = current_profile[key]
        sanitized_profiles[index] = updated
        break

    return sanitized_profiles, active_id


def normalize_profile_activation_time(value) -> str:
    if isinstance(value, datetime.time):
        return f"{value.hour:02d}:{value.minute:02d}"
    candidate = str(value or "").strip()
    match = re.fullmatch(r"([01]?\d|2[0-3]):([0-5]\d)", candidate)
    if not match:
        raise ValueError("profile activation time must use HH:MM in 24-hour local time")
    hour = int(match.group(1))
    minute = int(match.group(2))
    return f"{hour:02d}:{minute:02d}"


def _profile_activation_minutes(value: str) -> int:
    hour, minute = normalize_profile_activation_time(value).split(":", 1)
    return int(hour) * 60 + int(minute)


def normalize_profile_activation_days(value) -> list[str]:
    if value is None or value == "":
        return list(PROFILE_ACTIVATION_WEEKDAYS)

    if isinstance(value, str):
        candidate = value.strip().lower()
        if candidate in PROFILE_ACTIVATION_DAY_GROUPS:
            return list(PROFILE_ACTIVATION_DAY_GROUPS[candidate])
        parts = [part for part in re.split(r"[\s,;/|]+", candidate) if part]
    elif isinstance(value, (list, tuple, set)):
        parts = []
        for item in value:
            if isinstance(item, str) and item.strip().lower() in PROFILE_ACTIVATION_DAY_GROUPS:
                parts.extend(PROFILE_ACTIVATION_DAY_GROUPS[item.strip().lower()])
            else:
                parts.append(str(item).strip().lower())
    else:
        raise ValueError("profile activation days must be a weekday list or named group")

    normalized: list[str] = []
    for part in parts:
        day = PROFILE_ACTIVATION_DAY_ALIASES.get(part)
        if day is None:
            raise ValueError(f"unsupported profile activation day: {part}")
        if day not in normalized:
            normalized.append(day)

    if not normalized:
        raise ValueError("profile activation days cannot be empty")
    order = {day: index for index, day in enumerate(PROFILE_ACTIVATION_WEEKDAYS)}
    return sorted(normalized, key=order.get)


def parse_profile_activation_when(value) -> datetime.datetime:
    if value is None or value == "":
        return datetime.datetime.now()
    if isinstance(value, datetime.datetime):
        return value
    if isinstance(value, datetime.date):
        return datetime.datetime.combine(value, datetime.time.min)

    candidate = str(value).strip()
    if candidate.endswith("Z"):
        candidate = candidate[:-1] + "+00:00"
    try:
        return datetime.datetime.fromisoformat(candidate)
    except ValueError as exc:
        raise ValueError("profile schedule evaluation time must be an ISO local datetime") from exc


def _sanitize_profile_activation_window_id(value, fallback: str, used_ids: set[str] | None = None) -> str:
    candidate = ""
    if isinstance(value, str):
        candidate = re.sub(r"[^a-z0-9_-]+", "-", value.strip().lower()).strip("-_")
    if not candidate:
        candidate = fallback
    window_id = sanitize_profile_id(candidate, fallback)
    if used_ids is None:
        return window_id
    window_id = _unique_profile_id(window_id, used_ids)
    used_ids.add(window_id)
    return window_id


def _coerce_profile_activation_enabled(value) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, str):
        candidate = value.strip().lower()
        if candidate in {"0", "false", "no", "off", "disabled"}:
            return False
        if candidate in {"1", "true", "yes", "on", "enabled"}:
            return True
    return bool(value)


def sanitize_profile_activation_window(
    window,
    valid_profile_ids,
    fallback_index: int = 1,
    used_window_ids: set[str] | None = None,
) -> dict | None:
    if not isinstance(window, dict):
        return None

    valid_ids = {_sanitize_profile_id_strict(profile_id) for profile_id in valid_profile_ids}
    profile_id = _sanitize_profile_id_strict(window.get("profile_id"))
    if profile_id not in valid_ids:
        return None

    try:
        days = normalize_profile_activation_days(window.get("days", "daily"))
        start_time = normalize_profile_activation_time(window.get("start_time"))
        end_time = normalize_profile_activation_time(window.get("end_time"))
    except ValueError:
        return None
    if start_time == end_time:
        return None

    fallback_id = f"schedule-{max(1, fallback_index)}"
    default_id = f"{profile_id}-{'-'.join(days)}-{start_time.replace(':', '')}-{end_time.replace(':', '')}"
    window_id = _sanitize_profile_activation_window_id(
        window.get("id") or default_id,
        fallback_id,
        used_window_ids,
    )
    name = _sanitize_profile_name(
        window.get("name"),
        window_id,
    )

    return {
        "id": window_id,
        "name": name,
        "profile_id": profile_id,
        "days": days,
        "start_time": start_time,
        "end_time": end_time,
        "enabled": _coerce_profile_activation_enabled(window.get("enabled", True)),
    }


def sanitize_profile_activation_schedule(schedule, valid_profile_ids) -> list[dict]:
    if isinstance(schedule, dict):
        schedule = schedule.get("windows", [])
    if not isinstance(schedule, list):
        return []

    sanitized: list[dict] = []
    used_ids: set[str] = set()
    for candidate in schedule:
        window = sanitize_profile_activation_window(
            candidate,
            valid_profile_ids,
            fallback_index=len(sanitized) + 1,
            used_window_ids=used_ids,
        )
        if window is not None:
            sanitized.append(window)
        if len(sanitized) >= PROFILE_ACTIVATION_MAX_WINDOWS:
            break
    return sanitized


def profile_activation_window_matches(window: dict, when) -> bool:
    try:
        evaluated_at = parse_profile_activation_when(when)
        days = normalize_profile_activation_days(window.get("days", []))
        start_minutes = _profile_activation_minutes(window.get("start_time"))
        end_minutes = _profile_activation_minutes(window.get("end_time"))
    except (ValueError, AttributeError):
        return False

    if not _coerce_profile_activation_enabled(window.get("enabled", True)):
        return False

    current_day = PROFILE_ACTIVATION_WEEKDAYS[evaluated_at.weekday()]
    previous_day = PROFILE_ACTIVATION_WEEKDAYS[(evaluated_at.weekday() - 1) % 7]
    current_minutes = evaluated_at.hour * 60 + evaluated_at.minute
    if start_minutes < end_minutes:
        return current_day in days and start_minutes <= current_minutes < end_minutes

    return (
        (current_day in days and current_minutes >= start_minutes)
        or (previous_day in days and current_minutes < end_minutes)
    )


def detect_declarative_config_format(path_or_hint: str) -> str:
    hint = str(path_or_hint or "").strip().lower()
    if not hint:
        raise ValueError("declarative config format is required")
    if hint in DECLARATIVE_CONFIG_FORMATS:
        return hint
    suffix = pathlib.Path(hint).suffix.lower()
    detected = DECLARATIVE_CONFIG_EXTENSION_FORMATS.get(suffix)
    if detected:
        return detected
    raise ValueError("supported declarative config formats are .json, .yaml, .yml, and .toml")


def _parse_declarative_scalar(value: str):
    value = value.strip()
    if value == "":
        return ""
    if value == "[]":
        return []
    if value in {"true", "false"}:
        return value == "true"
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {'"', "'"}:
        if value[0] == '"':
            try:
                return json.loads(value)
            except ValueError:
                return value[1:-1]
        return value[1:-1].replace("''", "'")
    return value


def _parse_declarative_key_value(text: str) -> tuple[str, object]:
    if ":" not in text:
        raise ValueError(f"invalid declarative YAML line: {text}")
    key, value = text.split(":", 1)
    key = key.strip()
    if not key:
        raise ValueError("declarative YAML key cannot be empty")
    return key, _parse_declarative_scalar(value)


def parse_declarative_yaml_text(text: str) -> dict:
    """Parse the supported no-dependency YAML subset for profile source-of-truth files.

    The parser is intentionally narrow: top-level scalars, a ``profile`` mapping,
    scalar profile fields, list fields, and ``custom_sources`` objects.
    """
    payload: dict = {}
    profile: dict | None = None
    current_list: str | None = None
    current_source: dict | None = None

    for raw_line in text.splitlines():
        if not raw_line.strip() or raw_line.lstrip().startswith("#"):
            continue
        if "\t" in raw_line:
            raise ValueError("declarative YAML must use spaces for indentation")

        indent = len(raw_line) - len(raw_line.lstrip(" "))
        stripped = raw_line.strip()
        if indent == 0:
            current_list = None
            current_source = None
            if stripped == "profile:":
                profile = {}
                payload["profile"] = profile
                continue
            key, value = _parse_declarative_key_value(stripped)
            payload[key] = value
            continue

        if profile is None:
            raise ValueError("declarative YAML nested fields must be under profile")

        if indent == 2:
            current_source = None
            if stripped.startswith("- "):
                raise ValueError("profile must be a mapping, not a list")
            key, value = _parse_declarative_key_value(stripped)
            if value == "" and key in {"whitelist", "pinned_domains", "custom_sources"}:
                profile[key] = []
                current_list = key
            else:
                profile[key] = value
                current_list = None
            continue

        if indent == 4:
            if current_list in {"whitelist", "pinned_domains"} and stripped.startswith("- "):
                profile[current_list].append(_parse_declarative_scalar(stripped[2:]))
                continue
            if current_list == "custom_sources" and stripped.startswith("- "):
                source: dict = {}
                rest = stripped[2:].strip()
                if rest:
                    key, value = _parse_declarative_key_value(rest)
                    source[key] = value
                profile["custom_sources"].append(source)
                current_source = source
                continue
            raise ValueError(f"unsupported declarative YAML list entry: {stripped}")

        if indent == 6 and current_list == "custom_sources" and current_source is not None:
            key, value = _parse_declarative_key_value(stripped)
            current_source[key] = value
            continue

        raise ValueError(f"unsupported declarative YAML indentation at line: {raw_line}")

    return payload


def _parse_toml_scalar(value: str):
    value = value.strip()
    if value.startswith("[") and value.endswith("]"):
        try:
            parsed = json.loads(value)
            return parsed if isinstance(parsed, list) else value
        except ValueError:
            return [
                _parse_declarative_scalar(part.strip())
                for part in value[1:-1].split(",")
                if part.strip()
            ]
    return _parse_declarative_scalar(value)


def parse_declarative_toml_text(text: str) -> dict:
    if tomllib is not None:
        try:
            return tomllib.loads(text)
        except tomllib.TOMLDecodeError as exc:
            raise ValueError(f"invalid declarative TOML: {exc}") from exc

    payload: dict = {}
    profile: dict | None = None
    current_source: dict | None = None
    section: str | None = None
    for raw_line in text.splitlines():
        stripped = raw_line.strip()
        if not stripped or stripped.startswith("#"):
            continue
        if stripped == "[profile]":
            profile = payload.setdefault("profile", {})
            section = "profile"
            current_source = None
            continue
        if stripped == "[[profile.custom_sources]]":
            profile = payload.setdefault("profile", {})
            custom_sources = profile.setdefault("custom_sources", [])
            current_source = {}
            custom_sources.append(current_source)
            section = "custom_source"
            continue
        if "=" not in stripped:
            raise ValueError(f"invalid declarative TOML line: {stripped}")
        key, value = stripped.split("=", 1)
        key = key.strip()
        value = _parse_toml_scalar(value)
        if section == "profile" and profile is not None:
            profile[key] = value
        elif section == "custom_source" and current_source is not None:
            current_source[key] = value
        else:
            payload[key] = value
    return payload


def load_declarative_config_text(text: str, format_hint: str) -> dict:
    fmt = detect_declarative_config_format(format_hint)
    if fmt == "json":
        try:
            payload = json.loads(text)
        except ValueError as exc:
            raise ValueError(f"invalid declarative JSON: {exc}") from exc
    elif fmt == "yaml":
        payload = parse_declarative_yaml_text(text)
    elif fmt == "toml":
        payload = parse_declarative_toml_text(text)
    else:  # pragma: no cover - guarded by detect_declarative_config_format
        raise ValueError(f"unsupported declarative config format: {fmt}")

    if not isinstance(payload, dict):
        raise ValueError("declarative config must be a mapping")
    return payload


def parse_declarative_config_text(text: str, format_hint: str) -> dict:
    payload = load_declarative_config_text(text, format_hint)
    schema = payload.get("schema")
    if schema != DECLARATIVE_CONFIG_SCHEMA:
        raise ValueError(f"declarative config schema must be {DECLARATIVE_CONFIG_SCHEMA}")
    profile = payload.get("profile")
    if not isinstance(profile, dict):
        raise ValueError("declarative config requires a profile mapping")
    fallback_id = sanitize_profile_id(profile.get("id"), DEFAULT_PROFILE_ID)
    return sanitize_profile_snapshot(profile, fallback_id=fallback_id)


def load_declarative_config_file(path: str) -> dict:
    return parse_declarative_config_text(read_text_file_content(path), path)


def build_declarative_config_payload(profile: dict) -> dict:
    sanitized = sanitize_profile_snapshot(
        profile,
        fallback_id=sanitize_profile_id(profile.get("id"), DEFAULT_PROFILE_ID),
    )
    return {
        "schema": DECLARATIVE_CONFIG_SCHEMA,
        "profile": sanitized,
    }


def _declarative_profile_lists(profile: dict) -> tuple[list[str], list[str], list[dict]]:
    whitelist = [line.strip() for line in profile.get("whitelist", "").splitlines() if line.strip()]
    pinned_domains = list(profile.get("pinned_domains", []))
    custom_sources = list(profile.get("custom_sources", []))
    return whitelist, pinned_domains, custom_sources


def _json_string(value) -> str:
    return json.dumps(str(value), ensure_ascii=True)


def format_declarative_config_yaml(profile: dict) -> str:
    payload = build_declarative_config_payload(profile)
    profile = payload["profile"]
    whitelist, pinned_domains, custom_sources = _declarative_profile_lists(profile)
    lines = [
        f"schema: {_json_string(payload['schema'])}",
        "profile:",
        f"  id: {_json_string(profile['id'])}",
        f"  name: {_json_string(profile['name'])}",
        f"  preferred_block_sink: {_json_string(profile['preferred_block_sink'])}",
    ]
    if whitelist:
        lines.append("  whitelist:")
        lines.extend(f"    - {_json_string(value)}" for value in whitelist)
    else:
        lines.append("  whitelist: []")
    if pinned_domains:
        lines.append("  pinned_domains:")
        lines.extend(f"    - {_json_string(value)}" for value in pinned_domains)
    else:
        lines.append("  pinned_domains: []")
    if custom_sources:
        lines.append("  custom_sources:")
        for source in custom_sources:
            lines.append(f"    - name: {_json_string(source['name'])}")
            lines.append(f"      url: {_json_string(source['url'])}")
    else:
        lines.append("  custom_sources: []")
    return "\n".join(lines) + "\n"


def _format_toml_array(values: list[str]) -> str:
    if not values:
        return "[]"
    return "[" + ", ".join(_json_string(value) for value in values) + "]"


def format_declarative_config_toml(profile: dict) -> str:
    payload = build_declarative_config_payload(profile)
    profile = payload["profile"]
    whitelist, pinned_domains, custom_sources = _declarative_profile_lists(profile)
    lines = [
        f"schema = {_json_string(payload['schema'])}",
        "",
        "[profile]",
        f"id = {_json_string(profile['id'])}",
        f"name = {_json_string(profile['name'])}",
        f"preferred_block_sink = {_json_string(profile['preferred_block_sink'])}",
        f"whitelist = {_format_toml_array(whitelist)}",
        f"pinned_domains = {_format_toml_array(pinned_domains)}",
    ]
    for source in custom_sources:
        lines.extend([
            "",
            "[[profile.custom_sources]]",
            f"name = {_json_string(source['name'])}",
            f"url = {_json_string(source['url'])}",
        ])
    return "\n".join(lines) + "\n"


def format_declarative_config_payload(profile: dict, format_hint: str) -> str:
    fmt = detect_declarative_config_format(format_hint)
    payload = build_declarative_config_payload(profile)
    if fmt == "json":
        return json.dumps(payload, indent=2) + "\n"
    if fmt == "yaml":
        return format_declarative_config_yaml(payload["profile"])
    if fmt == "toml":
        return format_declarative_config_toml(payload["profile"])
    raise ValueError(f"unsupported declarative config format: {fmt}")  # pragma: no cover


def upsert_profile_in_config(
    config: dict,
    profile: dict,
    default_last_open_dir: str,
    activate: bool = False,
) -> dict:
    snapshot = sanitize_config_snapshot(config, default_last_open_dir)
    target = sanitize_profile_snapshot(
        profile,
        fallback_id=sanitize_profile_id(profile.get("id"), DEFAULT_PROFILE_ID),
    )
    profiles: list[dict] = []
    replaced = False
    for existing in snapshot.get("profiles", []):
        if existing.get("id") == target["id"]:
            profiles.append(target)
            replaced = True
        else:
            profiles.append(existing)
    if not replaced:
        profiles.append(target)

    snapshot["profiles"] = profiles
    if activate or snapshot.get("active_profile_id") == target["id"]:
        snapshot.update({
            "whitelist": target["whitelist"],
            "custom_sources": target["custom_sources"],
            "pinned_domains": target["pinned_domains"],
            "preferred_block_sink": target["preferred_block_sink"],
            "active_profile_id": target["id"],
        })
    return sanitize_config_snapshot(snapshot, default_last_open_dir)


def apply_declarative_profile_to_config(config: dict, profile: dict, default_last_open_dir: str) -> dict:
    return upsert_profile_in_config(config, profile, default_last_open_dir, activate=True)


def find_profile_snapshot(config: dict, profile_id: str, default_last_open_dir: str | None = None) -> dict:
    sanitized = sanitize_config_snapshot(config, default_last_open_dir or os.path.expanduser("~"))
    safe_id = sanitize_profile_id(profile_id, "")
    for profile in sanitized.get("profiles", []):
        if profile.get("id") == safe_id:
            return sanitize_profile_snapshot(profile, fallback_id=safe_id)
    raise ValueError(f"profile not found: {profile_id}")


def find_active_profile_snapshot(config: dict) -> dict:
    sanitized = sanitize_config_snapshot(config, os.path.expanduser("~"))
    active_id = sanitized.get("active_profile_id", DEFAULT_PROFILE_ID)
    for profile in sanitized.get("profiles", []):
        if profile.get("id") == active_id:
            return sanitize_profile_snapshot(profile, fallback_id=active_id)
    return build_default_profile_snapshot(sanitized)


def set_active_profile_in_config(config: dict, profile_id: str, default_last_open_dir: str) -> dict:
    snapshot = sanitize_config_snapshot(config, default_last_open_dir)
    profile = find_profile_snapshot(snapshot, profile_id, default_last_open_dir)
    snapshot.update({
        "whitelist": profile["whitelist"],
        "custom_sources": profile["custom_sources"],
        "pinned_domains": profile["pinned_domains"],
        "preferred_block_sink": profile["preferred_block_sink"],
        "active_profile_id": profile["id"],
    })
    return sanitize_config_snapshot(snapshot, default_last_open_dir)


def evaluate_profile_activation_schedule(config: dict, when=None, home_dir: str | None = None) -> dict:
    default_home = home_dir or os.path.expanduser("~")
    evaluated_at = parse_profile_activation_when(when)
    snapshot = sanitize_config_snapshot(config, default_home)
    windows = list(snapshot.get("profile_activation_schedule", []))
    active_id = snapshot.get("active_profile_id", DEFAULT_PROFILE_ID)
    fallback_id = snapshot.get("profile_activation_fallback_id", active_id)
    profile_ids = {profile["id"] for profile in snapshot.get("profiles", [])}
    warnings: list[str] = []

    if fallback_id not in profile_ids:
        warnings.append("Configured fallback profile is missing; keeping the current active profile.")
        fallback_id = active_id

    matching_window = None
    for window in windows:
        if profile_activation_window_matches(window, evaluated_at):
            matching_window = window
            break

    if not windows:
        target_id = active_id
        target_reason = "no-schedule"
        warnings.append("No profile activation windows are configured.")
    elif matching_window is not None:
        target_id = matching_window["profile_id"]
        target_reason = "matching-window"
    else:
        target_id = fallback_id
        target_reason = "fallback"

    return {
        "schema": "hostsfileget.profile-activation-report.v1",
        "evaluated_at": evaluated_at.isoformat(timespec="seconds"),
        "active_profile_id": active_id,
        "fallback_profile_id": fallback_id,
        "target_profile_id": target_id,
        "target_reason": target_reason,
        "switch_required": target_id != active_id,
        "will_write_hosts_file": False,
        "matching_window": matching_window,
        "windows": windows,
        "warnings": warnings,
    }


def apply_profile_activation_schedule(config: dict, when=None, home_dir: str | None = None) -> tuple[dict, dict]:
    default_home = home_dir or os.path.expanduser("~")
    snapshot = sanitize_config_snapshot(config, default_home)
    report = evaluate_profile_activation_schedule(snapshot, when=when, home_dir=default_home)
    if report["switch_required"]:
        snapshot = set_active_profile_in_config(snapshot, report["target_profile_id"], default_home)
    return snapshot, report


def format_profile_activation_schedule_report(report: dict) -> str:
    lines = [
        "Profile Activation Schedule",
        f"Evaluated at: {report.get('evaluated_at', '')}",
        f"Active profile: {report.get('active_profile_id', '')}",
        f"Fallback profile: {report.get('fallback_profile_id', '')}",
        f"Target profile: {report.get('target_profile_id', '')} ({report.get('target_reason', '')})",
        "Hosts-file write: no",
    ]
    if report.get("switch_required"):
        lines.append("Config switch required: yes")
    else:
        lines.append("Config switch required: no")

    matching_window = report.get("matching_window")
    if matching_window:
        lines.append(f"Matching window: {matching_window['name']} ({matching_window['id']})")

    warnings = report.get("warnings") or []
    if warnings:
        lines.append("")
        lines.append("Warnings:")
        lines.extend(f"- {warning}" for warning in warnings)

    lines.append("")
    lines.append("Windows:")
    windows = report.get("windows") or []
    if not windows:
        lines.append("- None configured.")
    for window in windows:
        status = "enabled" if window.get("enabled", True) else "disabled"
        days = ",".join(window.get("days", []))
        lines.append(
            f"- {window.get('id')}: {window.get('name')} -> {window.get('profile_id')} "
            f"{days} {window.get('start_time')}-{window.get('end_time')} ({status})"
        )
    return "\n".join(lines)


def format_profile_list_summary(config: dict, default_last_open_dir: str | None = None) -> str:
    sanitized = sanitize_config_snapshot(config, default_last_open_dir or os.path.expanduser("~"))
    active_id = sanitized.get("active_profile_id", DEFAULT_PROFILE_ID)
    lines = ["Profiles:"]
    for profile in sanitized.get("profiles", []):
        marker = "*" if profile.get("id") == active_id else " "
        whitelist, pinned_domains, custom_sources = _declarative_profile_lists(profile)
        lines.append(
            f"{marker} {profile['id']}  {profile['name']}  "
            f"whitelist={len(whitelist)} sources={len(custom_sources)} pins={len(pinned_domains)}"
        )
    return "\n".join(lines)


def build_profile_quick_switch_report(
    config: dict,
    default_last_open_dir: str | None = None,
    target_profile_id: str | None = None,
) -> dict:
    default_home = default_last_open_dir or os.path.expanduser("~")
    sanitized = sanitize_config_snapshot(config, default_home)
    active_id = sanitized.get("active_profile_id", DEFAULT_PROFILE_ID)
    profile_rows = []
    profile_ids = set()
    for profile in sanitized.get("profiles", []):
        whitelist, pinned_domains, custom_sources = _declarative_profile_lists(profile)
        profile_id = profile["id"]
        profile_ids.add(profile_id)
        profile_rows.append({
            "id": profile_id,
            "name": profile["name"],
            "active": profile_id == active_id,
            "whitelist_count": len(whitelist),
            "source_count": len(custom_sources),
            "pinned_count": len(pinned_domains),
            "preferred_block_sink": profile["preferred_block_sink"],
        })

    warnings: list[str] = []
    target_id = ""
    target_found = False
    if target_profile_id is not None:
        target_id = _sanitize_profile_id_strict(target_profile_id)
        if not target_id:
            warnings.append(f"Invalid profile id: {target_profile_id}")
        elif target_id in profile_ids:
            target_found = True
        else:
            warnings.append(f"Profile not found: {target_profile_id}")

    return {
        "schema": "hostsfileget.profile-quick-switch.v1",
        "active_profile_id": active_id,
        "target_profile_id": target_id,
        "target_found": target_found,
        "switch_required": bool(target_found and target_id != active_id),
        "will_write_hosts_file": False,
        "profiles": profile_rows,
        "profile_count": len(profile_rows),
        "warnings": warnings,
    }


def apply_profile_quick_switch(
    config: dict,
    profile_id: str,
    default_last_open_dir: str | None = None,
) -> tuple[dict, dict]:
    default_home = default_last_open_dir or os.path.expanduser("~")
    report = build_profile_quick_switch_report(config, default_home, profile_id)
    if not report["target_found"]:
        raise ValueError(f"profile not found: {profile_id}")
    snapshot = sanitize_config_snapshot(config, default_home)
    if report["switch_required"]:
        snapshot = set_active_profile_in_config(snapshot, report["target_profile_id"], default_home)
    return snapshot, report


def format_profile_quick_switch_report(report: dict) -> str:
    lines = [
        "Profile Quick Switch",
        f"Active profile: {report.get('active_profile_id', DEFAULT_PROFILE_ID)}",
        f"Profiles: {report.get('profile_count', 0)}",
        "Hosts-file write: no",
    ]
    target_id = report.get("target_profile_id") or ""
    if target_id:
        lines.append(f"Target profile: {target_id}")
        lines.append(f"Config switch required: {'yes' if report.get('switch_required') else 'no'}")

    warnings = report.get("warnings") or []
    if warnings:
        lines.append("")
        lines.append("Warnings:")
        lines.extend(f"- {warning}" for warning in warnings)

    lines.append("")
    lines.append("Saved profiles:")
    profiles = report.get("profiles") or []
    if not profiles:
        lines.append("- None configured.")
    for profile in profiles:
        marker = "*" if profile.get("active") else " "
        lines.append(
            f"{marker} {profile.get('id')}  {profile.get('name')}  "
            f"whitelist={profile.get('whitelist_count', 0)} "
            f"sources={profile.get('source_count', 0)} "
            f"pins={profile.get('pinned_count', 0)} "
            f"sink={profile.get('preferred_block_sink', '0.0.0.0')}"
        )
    return "\n".join(lines)


def build_profile_tray_availability_report(importer=None) -> dict:
    importer = importer or importlib.import_module
    required_modules = [
        ("pystray", "pystray"),
        ("Pillow Image", "PIL.Image"),
        ("Pillow ImageDraw", "PIL.ImageDraw"),
    ]
    missing = []
    for label, module_name in required_modules:
        try:
            importer(module_name)
        except Exception as exc:
            missing.append({
                "package": label,
                "module": module_name,
                "error": str(exc) or exc.__class__.__name__,
            })

    available = not missing
    return {
        "schema": "hostsfileget.profile-tray-availability.v1",
        "available": available,
        "required_modules": [module_name for _, module_name in required_modules],
        "missing": missing,
        "install_hint": "" if available else "python -m pip install pystray Pillow",
        "message": (
            "Optional tray quick switch support is available."
            if available
            else "Optional tray quick switch support requires pystray and Pillow."
        ),
    }


def load_optional_profile_tray_modules() -> tuple[dict | None, dict]:
    report = build_profile_tray_availability_report()
    if not report["available"]:
        return None, report
    modules = {
        "pystray": importlib.import_module("pystray"),
        "Image": importlib.import_module("PIL.Image"),
        "ImageDraw": importlib.import_module("PIL.ImageDraw"),
    }
    return modules, report


def format_profile_tray_availability_report(report: dict) -> str:
    lines = [
        "Profile Tray Quick Switch",
        f"Available: {'yes' if report.get('available') else 'no'}",
        report.get("message", ""),
    ]
    if report.get("install_hint"):
        lines.append(f"Install hint: {report['install_hint']}")
    missing = report.get("missing") or []
    if missing:
        lines.append("")
        lines.append("Missing modules:")
        for item in missing:
            lines.append(f"- {item.get('module')} ({item.get('package')}): {item.get('error')}")
    return "\n".join(lines)


def format_declarative_profile_summary(profile: dict, action: str | None = None) -> str:
    sanitized = sanitize_profile_snapshot(
        profile,
        fallback_id=sanitize_profile_id(profile.get("id"), DEFAULT_PROFILE_ID),
    )
    whitelist, pinned_domains, custom_sources = _declarative_profile_lists(sanitized)
    lines = [
        f"Profile: {sanitized['name']} ({sanitized['id']})",
        f"Whitelist entries: {len(whitelist)}",
        f"Custom sources: {len(custom_sources)}",
        f"Pinned domains: {len(pinned_domains)}",
        f"Preferred block sink: {sanitized['preferred_block_sink']}",
    ]
    if action:
        lines.append(f"Config action: {action}")
    return "\n".join(lines)


def _coerce_config_schema_version(value) -> int:
    if isinstance(value, bool):
        return 0
    try:
        version = int(value)
    except (TypeError, ValueError):
        return 0
    if version < 0 or version > CONFIG_SCHEMA_VERSION:
        return 0
    return version


def migrate_config_snapshot(config) -> dict:
    """Return a config payload upgraded to the current schema shape.

    Older builds did not write an explicit schema version. This migration layer
    keeps the sanitizer as the single gate for persisted config while giving
    future changes a stable place to translate renamed keys.
    """
    if not isinstance(config, dict):
        config = {}

    migrated = dict(config)
    source_version = _coerce_config_schema_version(migrated.get("config_version", 0))

    if source_version == 0:
        legacy_aliases = {
            "sources": "custom_sources",
            "whitelist_domains": "whitelist",
            "last_fetched": "source_last_fetched",
            "block_sink": "preferred_block_sink",
        }
        for legacy_key, current_key in legacy_aliases.items():
            if current_key not in migrated and legacy_key in migrated:
                migrated[current_key] = migrated[legacy_key]

    migrated["config_version"] = CONFIG_SCHEMA_VERSION
    return migrated


def sanitize_config_snapshot(config, default_last_open_dir: str) -> dict:
    config = migrate_config_snapshot(config)
    if not isinstance(config, dict):
        config = {}

    fallback_last_open_dir = default_last_open_dir if isinstance(default_last_open_dir, str) and os.path.isdir(default_last_open_dir) else os.path.expanduser("~")
    if not os.path.isdir(fallback_last_open_dir):
        fallback_last_open_dir = os.getcwd()

    whitelist_text = _sanitize_whitelist_text(config.get("whitelist", ""))

    def _normalize_hash(value):
        # SHA-256 hex digests are exactly 64 lowercase hex characters.
        # Rejecting anything else prevents a corrupted config from putting
        # arbitrary strings into the saved-state comparator where they
        # would never match a real editor hash and would quietly confuse
        # the "unsaved changes" badge.
        if not isinstance(value, str):
            return None
        value = value.strip().lower()
        if len(value) != 64:
            return None
        if not all(ch in "0123456789abcdef" for ch in value):
            return None
        return value

    last_open_dir = config.get("last_open_dir", fallback_last_open_dir)
    if not isinstance(last_open_dir, str) or not os.path.isdir(last_open_dir):
        last_open_dir = fallback_last_open_dir

    raw_last_fetched = config.get("source_last_fetched", {})
    source_last_fetched: dict[str, str] = {}
    if isinstance(raw_last_fetched, dict):
        for url, stamp in raw_last_fetched.items():
            if not isinstance(url, str) or _parse_valid_http_source_url(url) is None:
                continue
            if not isinstance(stamp, str) or len(stamp) > 64:
                continue
            # Reject garbage timestamps so a corrupt config can't poison
            # tooltips with arbitrary strings.
            try:
                datetime.datetime.fromisoformat(stamp)
            except (TypeError, ValueError):
                continue
            source_last_fetched[url] = stamp

    custom_sources = sanitize_custom_sources(config.get("custom_sources", []))
    source_cache_metadata = sanitize_source_cache_metadata(config.get("source_cache_metadata", {}))
    source_metrics_history = sanitize_source_metrics_history(config.get("source_metrics_history", {}))
    filter_query_history = sanitize_filter_query_history(config.get("filter_query_history", []))
    watch_expressions = sanitize_watch_expressions(config.get("watch_expressions", []))

    preferred_sink_raw = config.get("preferred_block_sink", "0.0.0.0")
    preferred_sink = _profile_preferred_sink(preferred_sink_raw)

    raw_retention = config.get("backup_retention", BACKUP_RETENTION)
    try:
        backup_retention = int(raw_retention)
    except (TypeError, ValueError):
        backup_retention = BACKUP_RETENTION
    backup_retention = max(0, min(50, backup_retention))

    has_completed_first_run = bool(config.get("has_completed_first_run", False))
    pinned_domains = sanitize_pinned_domains(config.get("pinned_domains", []))
    fallback_profile = build_default_profile_snapshot({
        "whitelist": whitelist_text,
        "custom_sources": custom_sources,
        "pinned_domains": pinned_domains,
        "preferred_block_sink": preferred_sink,
    })
    profiles, active_profile_id = sanitize_profiles_snapshot(
        config.get("profiles", []),
        config.get("active_profile_id", DEFAULT_PROFILE_ID),
        fallback_profile=fallback_profile,
    )
    profile_ids = {profile["id"] for profile in profiles}
    profile_activation_fallback_id = _sanitize_profile_id_strict(
        config.get("profile_activation_fallback_id")
    )
    if profile_activation_fallback_id not in profile_ids:
        profile_activation_fallback_id = active_profile_id
    profile_activation_schedule = sanitize_profile_activation_schedule(
        config.get("profile_activation_schedule", []),
        profile_ids,
    )

    return {
        "config_version": CONFIG_SCHEMA_VERSION,
        "whitelist": whitelist_text,
        "custom_sources": custom_sources,
        "last_applied_raw_hash": _normalize_hash(config.get("last_applied_raw_hash")),
        "last_applied_cleaned_hash": _normalize_hash(config.get("last_applied_cleaned_hash")),
        "last_open_dir": last_open_dir,
        "source_last_fetched": source_last_fetched,
        "source_cache_metadata": source_cache_metadata,
        "source_metrics_history": source_metrics_history,
        "filter_query_history": filter_query_history,
        "watch_expressions": watch_expressions,
        "preferred_block_sink": preferred_sink,
        "backup_retention": backup_retention,
        "has_completed_first_run": has_completed_first_run,
        "pinned_domains": pinned_domains,
        "update_on_launch": bool(config.get("update_on_launch", False)),
        "lock_after_save": bool(config.get("lock_after_save", False)),
        "profile_schema_version": PROFILE_SCHEMA_VERSION,
        "active_profile_id": active_profile_id,
        "profiles": profiles,
        "profile_activation_schedule_version": PROFILE_ACTIVATION_SCHEDULE_VERSION,
        "profile_activation_fallback_id": profile_activation_fallback_id,
        "profile_activation_schedule": profile_activation_schedule,
    }

def resolve_saved_state_hashes(current_hash: str, saved_raw_hash, saved_cleaned_hash) -> tuple[str | None, str | None]:
    normalized_raw_hash = saved_raw_hash if isinstance(saved_raw_hash, str) and saved_raw_hash else None
    normalized_cleaned_hash = saved_cleaned_hash if isinstance(saved_cleaned_hash, str) and saved_cleaned_hash else None

    if normalized_cleaned_hash and current_hash == normalized_cleaned_hash:
        return None, normalized_cleaned_hash

    if normalized_raw_hash and current_hash == normalized_raw_hash:
        return normalized_raw_hash, None

    return current_hash, None

def find_keyword_match_line_indices(lines: list[str], query: str) -> list[int]:
    normalized_query = query.strip().lower()
    if not normalized_query:
        return []

    return [
        index
        for index, line in enumerate(lines)
        if line.strip() and not _is_comment_line(line.strip()) and normalized_query in line.lower()
    ]

def remove_lines_by_indices(lines: list[str], line_indices: set[int]) -> list[str]:
    return [line for index, line in enumerate(lines) if index not in line_indices]

def summarize_clean_changes(total_discarded: int, transformed: int) -> str:
    if total_discarded > 0 and transformed > 0:
        return f"Removed {total_discarded} entries and normalized {transformed} line(s)."
    if total_discarded > 0:
        return f"Removed {total_discarded} entries."
    if transformed > 0:
        return f"Normalized {transformed} line(s)."
    return "No normalization changes were needed."

def count_nonempty_lines(text: str) -> int:
    return sum(1 for line in text.splitlines() if line.strip())


def rewrite_block_sink_ip(lines: list[str], target_ip: str) -> tuple[list[str], int]:
    """Rewrite loopback-style mapping IPs to ``target_ip``.

    Only touches lines that already start with a recognized blocking-sink IP
    (``BLOCK_SINK_IPS``). Custom-IP mappings like ``192.168.1.10 nas`` are
    untouched so LAN aliases survive the conversion. Returns the new line
    list and the number of lines that actually changed.
    """
    if target_ip not in BLOCK_SINK_IPS:
        raise ValueError(f"Unsupported target IP: {target_ip!r}")

    changed = 0
    new_lines: list[str] = []
    for line in lines:
        stripped = line.lstrip()
        leading_ws = line[: len(line) - len(stripped)]
        if not stripped or _is_comment_line(stripped):
            new_lines.append(line)
            continue

        content, sep, trailing_comment = stripped.partition('#')
        tokens = content.split(None, 1)
        if len(tokens) < 2:
            new_lines.append(line)
            continue

        first_ip = tokens[0].lower() if ':' in tokens[0] else tokens[0]
        if first_ip not in BLOCK_SINK_IPS or first_ip == target_ip:
            new_lines.append(line)
            continue

        remainder = tokens[1]
        rebuilt = f"{target_ip} {remainder}"
        if sep:
            rebuilt = f"{rebuilt} #{trailing_comment}".rstrip() if trailing_comment.strip() else f"{rebuilt} #"
        new_lines.append(f"{leading_ws}{rebuilt}")
        changed += 1

    return new_lines, changed


def scan_suspicious_redirects(lines: list[str]) -> list[tuple[int, str, str]]:
    """Flag entries that map well-known domains to non-loopback IPs.

    A hosts file with an entry like ``1.2.3.4 www.google.com`` is a classic
    malware-or-hijack indicator: the attacker steers traffic to a server
    they control. We return ``(line_index, ip, domain)`` for every mapping
    whose IP is NOT a loopback/blocking sink and NOT a private LAN range
    (those are intentional local aliases that we must not false-flag).
    """
    private_prefixes = ("10.", "172.", "192.168.", "127.", "169.254.", "0.0.0.0")
    findings: list[tuple[int, str, str]] = []

    for idx, line in enumerate(lines):
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue

        content = stripped.split('#', 1)[0].strip()
        tokens = [token for token in TOKEN_SPLITTER.split(content) if token]
        if len(tokens) < 2:
            continue

        ip_token = tokens[0]
        if not _looks_like_ip_token(ip_token):
            continue

        ip_lower = ip_token.lower() if ':' in ip_token else ip_token
        if ip_lower in BLOCK_SINK_IPS:
            continue

        if ip_token.startswith(private_prefixes):
            # 172.16.0.0/12 is the classic RFC1918 block, but we can't tell
            # from a prefix alone - treat the full 172.x as private-ish to
            # avoid false positives on home LAN mappings.
            if ip_token.startswith("172."):
                try:
                    second = int(ip_token.split('.')[1])
                    if 16 <= second <= 31:
                        continue
                except (IndexError, ValueError):
                    pass
            else:
                continue

        for token in tokens[1:]:
            domain, _ = _extract_domain_from_token(token, allow_single_label=False)
            if domain:
                findings.append((idx, ip_token, domain))

    return findings


def _normalize_dns_rebinding_suffix(suffix: str) -> str:
    normalized = str(suffix or "").strip().lower().strip()
    if not normalized:
        return ""
    if normalized.startswith("*."):
        normalized = normalized[1:]
    elif not normalized.startswith("."):
        normalized = f".{normalized}"
    return normalized.rstrip(".")


def normalize_dns_rebinding_trusted_suffixes(extra_suffixes: list[str] | tuple[str, ...] | None = None) -> tuple[str, ...]:
    seen: set[str] = set()
    suffixes: list[str] = []
    for suffix in (*DNS_REBINDING_LOCAL_SUFFIXES, *(extra_suffixes or ())):
        normalized = _normalize_dns_rebinding_suffix(suffix)
        if normalized and normalized not in seen:
            seen.add(normalized)
            suffixes.append(normalized)
    return tuple(suffixes)


def is_dns_rebinding_local_domain(domain: str, trusted_suffixes: list[str] | tuple[str, ...] | None = None) -> bool:
    normalized = str(domain or "").strip().lower().rstrip(".")
    if not normalized:
        return False
    if normalized in LOCAL_DOMAINS:
        return True
    if "." not in normalized:
        return True

    suffixes = normalize_dns_rebinding_trusted_suffixes(trusted_suffixes)
    for suffix in suffixes:
        suffix_root = suffix.lstrip(".")
        if normalized == suffix_root or normalized.endswith(suffix):
            return True
    return False


def _dns_rebinding_ip_profile(ip_token: str) -> dict:
    token = str(ip_token or "").strip()
    lowered = token.lower()
    if lowered in BLOCK_SINK_IPS:
        return {
            "category": "block-sink",
            "label": "Standard hosts blocking sink",
            "risk": "none",
            "network": None,
            "normalized": lowered,
        }

    try:
        address = ipaddress.ip_address(token)
    except ValueError:
        return {
            "category": "invalid",
            "label": "Invalid IP",
            "risk": "none",
            "network": None,
            "normalized": token,
        }

    for group in DNS_REBINDING_IP_RANGES:
        for network in group["networks"]:
            if address in network:
                return {
                    "category": group["category"],
                    "label": group["label"],
                    "risk": group["risk"],
                    "network": str(network),
                    "normalized": str(address),
                }

    if address.is_multicast:
        category = "multicast"
        label = "Multicast"
        risk = "medium"
    elif address.is_reserved:
        category = "reserved"
        label = "Reserved/special-purpose"
        risk = "medium"
    elif address.is_global:
        category = "public"
        label = "Publicly routable"
        risk = "medium"
    else:
        category = "special-use"
        label = "Special-use non-global"
        risk = "medium"

    return {
        "category": category,
        "label": label,
        "risk": risk,
        "network": None,
        "normalized": str(address),
    }


def classify_dns_rebinding_mapping(
    ip_token: str,
    domain: str,
    trusted_suffixes: list[str] | tuple[str, ...] | None = None,
) -> dict:
    ip_profile = _dns_rebinding_ip_profile(ip_token)
    local_domain = is_dns_rebinding_local_domain(domain, trusted_suffixes)
    classification = {
        "domain": str(domain or "").strip().lower().rstrip("."),
        "ip": str(ip_token or "").strip(),
        "normalized_ip": ip_profile["normalized"],
        "ip_category": ip_profile["category"],
        "ip_category_label": ip_profile["label"],
        "network": ip_profile["network"],
        "risk": ip_profile["risk"],
        "local_domain": local_domain,
        "status": "ignored",
        "reason": "",
    }

    category = ip_profile["category"]
    if category == "invalid":
        classification.update({
            "status": "invalid",
            "reason": "The mapping IP could not be parsed.",
            "risk": "none",
        })
    elif category == "block-sink":
        classification.update({
            "status": "blocking_sink",
            "reason": "Standard hosts-file blocking sinks are counted separately from rebinding candidates.",
            "risk": "none",
        })
    elif category in DNS_REBINDING_CANDIDATE_CATEGORIES:
        if local_domain:
            classification.update({
                "status": "trusted_local_mapping",
                "reason": "Private or special-range target is scoped to a local-looking domain suffix.",
                "risk": "low",
            })
        else:
            classification.update({
                "status": "rebinding_candidate",
                "reason": "External-looking domain maps to a private, local, or special-use IP range.",
            })
    elif category == "public":
        if local_domain:
            classification.update({
                "status": "public_mapping",
                "reason": "Local-looking domain maps to a public IP; review only if unexpected.",
                "risk": "low",
            })
        else:
            classification.update({
                "status": "public_redirect",
                "reason": "External-looking domain maps to a public IP instead of a blocking sink.",
            })
    else:
        classification.update({
            "status": "ignored",
            "reason": "Mapping did not match a rebinding-sensitive range.",
            "risk": "low",
        })
    return classification


def _iter_hosts_mapping_records(lines: list[str]) -> list[dict]:
    records: list[dict] = []
    for line_number, line in enumerate(lines, start=1):
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue
        content = stripped.split("#", 1)[0].strip()
        tokens = [token for token in TOKEN_SPLITTER.split(content) if token]
        if len(tokens) < 2 or not _looks_like_ip_token(tokens[0]):
            continue
        for token in tokens[1:]:
            domain, _ = _extract_domain_from_token(token, allow_single_label=True)
            if not domain:
                continue
            records.append({
                "line_number": line_number,
                "line": line,
                "ip": tokens[0],
                "domain": domain,
            })
    return records


def build_dns_rebinding_report(
    lines: list[str],
    trusted_suffixes: list[str] | tuple[str, ...] | None = None,
    max_findings: int = 100,
) -> dict:
    effective_suffixes = normalize_dns_rebinding_trusted_suffixes(trusted_suffixes)
    records = _iter_hosts_mapping_records(lines)
    buckets = {
        "rebinding_candidates": [],
        "trusted_local_mappings": [],
        "public_redirects": [],
        "blocking_sink_mappings": [],
        "other_mappings": [],
    }
    status_counts: dict[str, int] = {}

    for record in records:
        classification = classify_dns_rebinding_mapping(
            record["ip"],
            record["domain"],
            trusted_suffixes=effective_suffixes,
        )
        finding = {**record, **classification}
        status = classification["status"]
        status_counts[status] = status_counts.get(status, 0) + 1
        if status == "rebinding_candidate":
            bucket_name = "rebinding_candidates"
        elif status == "trusted_local_mapping":
            bucket_name = "trusted_local_mappings"
        elif status == "public_redirect":
            bucket_name = "public_redirects"
        elif status == "blocking_sink":
            bucket_name = "blocking_sink_mappings"
        else:
            bucket_name = "other_mappings"
        if len(buckets[bucket_name]) < max_findings:
            buckets[bucket_name].append(finding)

    summary = {
        "total_mappings": len(records),
        "rebinding_candidates": status_counts.get("rebinding_candidate", 0),
        "trusted_local_mappings": status_counts.get("trusted_local_mapping", 0),
        "public_redirects": status_counts.get("public_redirect", 0),
        "blocking_sink_mappings": status_counts.get("blocking_sink", 0),
        "other_mappings": len(records)
        - status_counts.get("rebinding_candidate", 0)
        - status_counts.get("trusted_local_mapping", 0)
        - status_counts.get("public_redirect", 0)
        - status_counts.get("blocking_sink", 0),
    }

    return {
        "schema": "hostsfileget.dns-rebinding-report.v1",
        "schema_version": DNS_REBINDING_REPORT_SCHEMA_VERSION,
        "summary": summary,
        "status_counts": status_counts,
        "trusted_suffixes": list(effective_suffixes),
        "max_findings_per_bucket": max_findings,
        "omitted_counts": {
            bucket_name: max(0, summary.get(bucket_name, len(records)) - len(items))
            for bucket_name, items in buckets.items()
            if bucket_name in summary
        },
        "warnings": [
            "This is a static hosts-file review; it does not observe live DNS answers or enforce resolver policy.",
            "Standard hosts-file blocking sinks are not treated as DNS rebinding findings.",
            "Internal lab domains should use explicit trusted suffixes before private-range findings are acted on.",
        ],
        "references": list(DNS_REBINDING_SOURCE_IDS),
        **buckets,
    }


def _format_dns_rebinding_finding(finding: dict) -> str:
    network = f"; network {finding['network']}" if finding.get("network") else ""
    return (
        f"- Line {finding['line_number']}: {finding['domain']} -> {finding['ip']} "
        f"({finding['ip_category_label']}{network}; risk: {finding['risk']})"
    )


def format_dns_rebinding_report(report: dict) -> str:
    summary = report.get("summary") or {}
    lines = [
        "DNS Rebinding Protection Check",
        "",
        "Summary:",
        f"- Hosts mappings scanned: {int(summary.get('total_mappings') or 0):,}",
        f"- Rebinding candidates: {int(summary.get('rebinding_candidates') or 0):,}",
        f"- Trusted local mappings: {int(summary.get('trusted_local_mappings') or 0):,}",
        f"- Public redirects: {int(summary.get('public_redirects') or 0):,}",
        f"- Standard blocking sinks: {int(summary.get('blocking_sink_mappings') or 0):,}",
        "",
        "Boundary:",
        "- HostsFileGet reports risky static mappings; it does not enforce DNS resolver rebinding protection.",
        "- Normal blocking entries that use 0.0.0.0, 127.0.0.1, ::, or ::1 are separated from findings.",
        "- Private lab names can be trusted by suffix instead of deleting legitimate LAN aliases.",
        "",
        "Trusted local suffixes:",
        "- " + ", ".join(report.get("trusted_suffixes") or []),
        "",
        "Rebinding candidates:",
    ]

    candidates = report.get("rebinding_candidates") or []
    if candidates:
        lines.extend(_format_dns_rebinding_finding(finding) for finding in candidates)
    else:
        lines.append("- None found.")

    lines.extend(["", "Trusted local/private mappings:"])
    trusted = report.get("trusted_local_mappings") or []
    if trusted:
        lines.extend(_format_dns_rebinding_finding(finding) for finding in trusted[:25])
        omitted = max(0, int(summary.get("trusted_local_mappings") or 0) - len(trusted[:25]))
        if omitted:
            lines.append(f"- ... {omitted:,} additional trusted local mapping(s) omitted.")
    else:
        lines.append("- None found.")

    lines.extend(["", "Public redirects:"])
    public_redirects = report.get("public_redirects") or []
    if public_redirects:
        lines.extend(_format_dns_rebinding_finding(finding) for finding in public_redirects[:25])
        omitted = max(0, int(summary.get("public_redirects") or 0) - len(public_redirects[:25]))
        if omitted:
            lines.append(f"- ... {omitted:,} additional public redirect(s) omitted.")
    else:
        lines.append("- None found.")

    lines.extend([
        "",
        "Review guidance:",
        "- Investigate external-looking domains that map to RFC1918, link-local, loopback, ULA, or CGNAT ranges.",
        "- Keep intentional lab mappings under a clear suffix such as .lan, .home.arpa, .internal, or a trusted suffix.",
        "- Use resolver/router rebinding protection for live DNS answers; the hosts file can only express static A/AAAA overrides.",
        "",
        "Roadmap source IDs:",
        "- " + ", ".join(report.get("references") or DNS_REBINDING_SOURCE_IDS),
    ])
    return "\n".join(lines)


def find_sources_containing_domain(domain: str, source_corpus: dict[str, object]) -> list[str]:
    """Return source names whose cached corpus contains ``domain``.

    ``source_corpus`` may be either the legacy ``{name: text}`` shape or the
    newer ``{cache_key: {"name": name, "text": text}}`` shape used to avoid
    collisions between sources that share the same display label.
    """
    target = domain.strip().lower().lstrip('.')
    if not target:
        return []

    needle = re.compile(
        rf'(?:^|[\s\t,/|^=])(?:\*\.)?(?:[a-z0-9][a-z0-9-]*\.)*{re.escape(target)}(?:$|[\s\t,/|^#$])',
        re.IGNORECASE | re.MULTILINE,
    )
    matches: list[str] = []
    seen_names: set[str] = set()
    for cache_key, payload in source_corpus.items():
        if isinstance(payload, dict):
            name = str(payload.get("name") or cache_key)
            text = payload.get("text", "")
        else:
            name = str(cache_key)
            text = payload
        if not text:
            continue
        lowered = text.lower()
        # Fast-path substring check first; confirm with a word-boundary
        # pass so we don't hit "notexample.com" when searching "example.com".
        if target not in lowered:
            continue
        if needle.search(text) and name not in seen_names:
            seen_names.add(name)
            matches.append(name)
    return matches


def normalize_whitelist_domain(candidate: str, allow_single_label: bool = False) -> tuple[str, str]:
    """Return a normalized whitelist domain, or an error string."""
    raw = str(candidate or "").strip()
    if not raw:
        return "", "Enter a domain to check."
    domain, _ = _extract_domain_from_token(raw, allow_single_label=allow_single_label)
    if not domain:
        cleaned = raw.lower().lstrip(".")
        label = "domain" if allow_single_label else "multi-label domain"
        return "", f"'{cleaned}' does not look like a valid {label}."
    return domain.lstrip("."), ""


def normalize_false_positive_domain(candidate: str) -> tuple[str, str]:
    """Return a normalized multi-label domain, or an error string."""
    return normalize_whitelist_domain(candidate, allow_single_label=False)


def _triage_domain_matches(query_domain: str, entry_domain: str) -> bool:
    """Return true when a hosts entry blocks the queried domain or child."""
    return entry_domain == query_domain or entry_domain.endswith("." + query_domain)


def _whitelist_covers_domain(domain: str, whitelist_set: set[str]) -> bool:
    return domain in whitelist_set or any(domain.endswith("." + item) for item in whitelist_set)


def build_false_positive_triage_report(
    domain: str,
    editor_lines: list[str],
    whitelist_set: set | None = None,
    pinned_domains: set | None = None,
    source_corpus: dict[str, object] | None = None,
) -> dict:
    """Build a deterministic false-positive report for one candidate domain."""
    normalized, error = normalize_false_positive_domain(domain)
    report = {
        "domain": normalized,
        "valid": not error,
        "error": error,
        "blocked_on_lines": [],
        "on_whitelist": False,
        "is_pinned": False,
        "source_matches": [],
        "recommended_actions": [],
    }
    if error:
        return report

    blocked_on_lines = []
    for idx, line in enumerate(editor_lines or []):
        parsed, _ = parse_hosts_line_entries(line)
        for _, entry_domain, is_block in parsed:
            if is_block and _triage_domain_matches(normalized, entry_domain):
                blocked_on_lines.append({
                    "line_no": idx + 1,
                    "matched_domain": entry_domain,
                    "line": str(line).strip(),
                })

    whitelist = {str(item).strip().lower().lstrip(".") for item in (whitelist_set or set()) if str(item).strip()}
    pinned = {str(item).strip().lower().lstrip(".") for item in (pinned_domains or set()) if str(item).strip()}
    source_matches = find_sources_containing_domain(normalized, source_corpus or {})

    actions = []
    if blocked_on_lines:
        actions.append({
            "id": "remove_matching_lines",
            "label": "Preview-remove matching editor lines",
            "reason": "The current editor contains blocking entries for this domain.",
        })
    if _whitelist_covers_domain(normalized, whitelist):
        actions.append({
            "id": "review_whitelist",
            "label": "Review whitelist coverage",
            "reason": "The domain is already covered by the whitelist; cleaned saves should omit it unless pinned.",
        })
    else:
        actions.append({
            "id": "add_to_whitelist",
            "label": "Add to whitelist",
            "reason": "A whitelist entry keeps cleaned saves from reintroducing this block.",
        })
    if normalized in pinned:
        actions.append({
            "id": "unpin_domain",
            "label": "Unpin domain if this should be allowed",
            "reason": "Pinned domains are preserved even when whitelist filtering would remove them.",
        })
    else:
        actions.append({
            "id": "pin_domain",
            "label": "Pin only if this block is intentional",
            "reason": "Pinning overrides whitelist cleanup for the exact domain.",
        })
    if source_matches:
        actions.append({
            "id": "report_upstream",
            "label": "Report upstream source match",
            "reason": "One or more fetched sources contain this domain.",
        })

    report.update({
        "blocked_on_lines": blocked_on_lines,
        "on_whitelist": _whitelist_covers_domain(normalized, whitelist),
        "is_pinned": normalized in pinned,
        "source_matches": source_matches,
        "recommended_actions": actions,
    })
    return report


def format_false_positive_triage_report(
    report: dict,
    not_yet_fetched_count: int = 0,
    source_issue_urls: dict[str, str] | None = None,
) -> str:
    """Render a false-positive report for the Check Domain dialog."""
    if not report or not report.get("valid"):
        return str((report or {}).get("error") or "Enter a domain to check.")

    source_issue_urls = source_issue_urls or {}
    domain = report["domain"]
    blocked_on_lines = report.get("blocked_on_lines", [])
    source_matches = report.get("source_matches", [])

    lines = [f"Domain: {domain}", ""]
    if blocked_on_lines:
        lines.append(f"BLOCKED in current editor on {len(blocked_on_lines)} line(s):")
        for item in blocked_on_lines[:FALSE_POSITIVE_REPORT_MATCH_LIMIT]:
            lines.append(
                f"  line {item['line_no']}: {item['line']}  ({item['matched_domain']})"
            )
        remaining = len(blocked_on_lines) - FALSE_POSITIVE_REPORT_MATCH_LIMIT
        if remaining > 0:
            lines.append(f"  ...and {remaining} more")
    else:
        lines.append("NOT blocked in current editor.")

    lines.extend([
        "",
        f"Whitelist: {'YES' if report.get('on_whitelist') else 'no'}",
        f"Pinned: {'YES - preserved across cleaned saves' if report.get('is_pinned') else 'no'}",
        "",
    ])

    if source_matches:
        lines.append(f"Found in {len(source_matches)} previously-fetched source(s):")
        for name in source_matches:
            issue_url = source_issue_urls.get(name, "")
            suffix = f" - report: {issue_url}" if issue_url else ""
            lines.append(f"  - {name}{suffix}")
    else:
        lines.append("Not present in any previously-fetched source.")
    if not_yet_fetched_count:
        lines.extend([
            "",
            f"({not_yet_fetched_count} source(s) not yet fetched this session - import them to include in this lookup.)",
        ])

    lines.extend(["", "Recommended actions:"])
    for action in report.get("recommended_actions", []):
        lines.append(f"  - {action['label']}: {action['reason']}")
    lines.extend([
        "",
        "Copy Report creates a concise note suitable for an upstream false-positive issue.",
    ])
    return "\n".join(lines)


def extract_whitelist_domains_from_text(text: str) -> set[str]:
    """Return normalized whitelist-style domains from plain text."""
    domains: set[str] = set()
    for raw_line in (text or "").splitlines():
        line = raw_line.split("#", 1)[0].strip()
        if not line:
            continue
        parsed, _ = parse_hosts_line_entries(line)
        for _, domain, _is_block in parsed:
            if domain:
                domains.add(domain.lstrip("."))
        if parsed:
            continue
        normalized, error = normalize_whitelist_domain(line, allow_single_label=False)
        if not error and normalized:
            domains.add(normalized.lstrip("."))
    return domains


def _why_blocked_source_issue_urls(source_matches: list[str], source_issue_urls: dict[str, str] | None) -> dict[str, str]:
    if not source_matches or not source_issue_urls:
        return {}
    return {
        str(name): str(source_issue_urls[name])
        for name in source_matches
        if name in source_issue_urls and str(source_issue_urls[name]).strip()
    }


def _why_blocked_event_domains(event: dict) -> list[str]:
    values: list[str] = []
    for key in ("domain", "matched_domain"):
        value = event.get(key)
        if isinstance(value, str) and value.strip():
            values.append(value.strip())
    list_value = event.get("domains")
    if isinstance(list_value, (list, tuple, set)):
        values.extend(str(item).strip() for item in list_value if str(item).strip())
    normalized: list[str] = []
    seen: set[str] = set()
    for value in values:
        domain, error = normalize_whitelist_domain(value, allow_single_label=False)
        if not error and domain not in seen:
            seen.add(domain)
            normalized.append(domain)
    return normalized


def _why_blocked_event_matches(domain: str, event: dict) -> bool:
    for event_domain in _why_blocked_event_domains(event):
        if (
            event_domain == domain
            or event_domain.endswith("." + domain)
            or domain.endswith("." + event_domain)
        ):
            return True
    return False


def _why_blocked_provenance_events(domain: str, events: list[dict] | tuple[dict, ...] | None) -> list[dict]:
    matches: list[dict] = []
    for event in events or []:
        if not isinstance(event, dict) or not _why_blocked_event_matches(domain, event):
            continue
        matches.append({
            "ts": str(event.get("ts") or ""),
            "kind": str(event.get("kind") or ""),
            "domain": str(event.get("domain") or ""),
            "source": str(event.get("source") or ""),
            "user": str(event.get("user") or ""),
        })
        if len(matches) >= WHY_BLOCKED_SUMMARY_PROVENANCE_LIMIT:
            break
    return matches


def _why_blocked_line_preview(line: str) -> str:
    preview = " ".join(str(line or "").strip().split())
    if len(preview) <= 180:
        return preview
    return preview[:177].rstrip() + "..."


def _build_why_blocked_llm_prompt(summary: dict) -> str:
    evidence = summary.get("evidence") or {}
    lines = [
        "You are helping review a local hosts-file block decision.",
        "Use only the evidence below. Do not infer browsing history, user intent, or threat verdicts that are not present.",
        "Return a concise explanation of why the domain appears blocked and list safe next review steps.",
        "",
        f"Domain: {summary.get('domain') or ''}",
        f"Status: {summary.get('status') or ''}",
        f"Primary local reason: {summary.get('primary_reason') or ''}",
        f"Confidence: {summary.get('confidence') or ''}",
        f"Blocked line count: {evidence.get('blocked_line_count', 0)}",
        f"Whitelist coverage: {'yes' if evidence.get('on_whitelist') else 'no'}",
        f"Pinned block: {'yes' if evidence.get('is_pinned') else 'no'}",
    ]
    blocked_lines = evidence.get("blocked_on_lines") or []
    if blocked_lines:
        lines.extend(["", "Matched editor entries:"])
        for item in blocked_lines[:WHY_BLOCKED_SUMMARY_EVIDENCE_LIMIT]:
            lines.append(
                f"- line {item.get('line_no')}: matched {item.get('matched_domain')}"
            )
    source_matches = evidence.get("source_matches") or []
    if source_matches:
        lines.extend(["", "Previously fetched source matches:"])
        for name in source_matches[:WHY_BLOCKED_SUMMARY_EVIDENCE_LIMIT]:
            issue_url = (evidence.get("source_issue_urls") or {}).get(name, "")
            suffix = f" ({issue_url})" if issue_url else ""
            lines.append(f"- {name}{suffix}")
    events = evidence.get("provenance_events") or []
    if events:
        lines.extend(["", "Relevant local provenance events:"])
        for event in events[:WHY_BLOCKED_SUMMARY_PROVENANCE_LIMIT]:
            lines.append(
                f"- {event.get('ts') or 'unknown time'} {event.get('kind') or 'event'} "
                f"{event.get('domain') or ''} source={event.get('source') or ''}"
            )
    actions = summary.get("recommended_actions") or []
    if actions:
        lines.extend(["", "Local recommended actions already generated by HostsFileGet:"])
        for action in actions[:WHY_BLOCKED_SUMMARY_EVIDENCE_LIMIT]:
            lines.append(f"- {action.get('label')}: {action.get('reason')}")
    lines.extend([
        "",
        "Privacy guardrails:",
        "- Do not request raw hosts files, full DNS logs, private source URLs, API keys, or unrelated domains.",
        "- Treat this as a review aid, not as authorization to change hosts-file policy.",
    ])
    return "\n".join(lines)


def build_why_blocked_summary(
    domain: str,
    editor_lines: list[str],
    whitelist_set: set | None = None,
    pinned_domains: set | None = None,
    source_corpus: dict[str, object] | None = None,
    source_issue_urls: dict[str, str] | None = None,
    provenance_events: list[dict] | tuple[dict, ...] | None = None,
    include_llm_prompt: bool = True,
) -> dict:
    """Build an offline explanation of why a domain appears blocked."""
    triage = build_false_positive_triage_report(
        domain,
        editor_lines,
        whitelist_set=whitelist_set,
        pinned_domains=pinned_domains,
        source_corpus=source_corpus,
    )
    if not triage.get("valid"):
        return {
            "schema": WHY_BLOCKED_SUMMARY_SCHEMA,
            "plan_only": True,
            "offline": True,
            "network_calls": False,
            "llm_api_calls": False,
            "domain": triage.get("domain") or "",
            "valid": False,
            "error": triage.get("error") or "Enter a domain to check.",
            "status": "invalid",
            "primary_reason": triage.get("error") or "The input was not a valid multi-label domain.",
            "confidence": "none",
            "evidence": {},
            "recommended_actions": [],
            "controls": [
                "Fix the domain input before generating a review prompt.",
            ],
            "warnings": list(WHY_BLOCKED_SUMMARY_WARNINGS),
            "llm_handoff": {
                "available": False,
                "plan_only": True,
                "external_execution_required": True,
                "prompt_text": "",
                "redaction_notes": [
                    "No prompt was generated because the domain is invalid.",
                ],
            },
            "references": list(WHY_BLOCKED_SUMMARY_SOURCE_IDS),
        }

    blocked_on_lines = [
        {
            "line_no": item.get("line_no"),
            "matched_domain": item.get("matched_domain"),
            "line_preview": _why_blocked_line_preview(item.get("line", "")),
        }
        for item in (triage.get("blocked_on_lines") or [])[:WHY_BLOCKED_SUMMARY_EVIDENCE_LIMIT]
    ]
    source_matches = list(triage.get("source_matches") or [])
    provenance = _why_blocked_provenance_events(triage["domain"], provenance_events)
    issue_urls = _why_blocked_source_issue_urls(source_matches, source_issue_urls)

    if triage.get("blocked_on_lines"):
        status = "blocked"
        confidence = "direct-hosts-entry"
        primary_reason = "The current editor contains block-style hosts entries matching this domain or one of its subdomains."
    elif source_matches:
        status = "source-only"
        confidence = "fetched-source-match"
        primary_reason = "The domain is not blocked in the current editor, but it appears in previously fetched source metadata."
    else:
        status = "not-blocked"
        confidence = "no-local-block-evidence"
        primary_reason = "No block-style hosts entry in the current editor matches this domain."

    evidence = {
        "blocked_line_count": len(triage.get("blocked_on_lines") or []),
        "blocked_on_lines": blocked_on_lines,
        "on_whitelist": bool(triage.get("on_whitelist")),
        "is_pinned": bool(triage.get("is_pinned")),
        "source_matches": source_matches,
        "source_issue_urls": issue_urls,
        "provenance_event_count": len(provenance),
        "provenance_events": provenance,
    }
    controls = [
        "Summary generation is deterministic and local; no LLM or provider API is called.",
        "The handoff prompt omits raw full hosts-file content and uses only bounded evidence.",
        "Review whitelist coverage and pinned-domain status before removing or preserving a block.",
        "When a source match exists, use the upstream report URL before changing local policy.",
    ]
    summary = {
        "schema": WHY_BLOCKED_SUMMARY_SCHEMA,
        "plan_only": True,
        "offline": True,
        "network_calls": False,
        "llm_api_calls": False,
        "domain": triage["domain"],
        "valid": True,
        "status": status,
        "primary_reason": primary_reason,
        "confidence": confidence,
        "evidence": evidence,
        "recommended_actions": list(triage.get("recommended_actions") or []),
        "controls": controls,
        "warnings": list(WHY_BLOCKED_SUMMARY_WARNINGS),
        "llm_handoff": {
            "available": bool(include_llm_prompt),
            "plan_only": True,
            "external_execution_required": True,
            "prompt_text": "",
            "redaction_notes": [
                "Prompt excludes raw full hosts-file content.",
                "Review domain, source names, issue URLs, and provenance metadata before external use.",
                "Do not add API keys, private DNS logs, or unrelated hostnames to the prompt.",
            ],
        },
        "references": list(WHY_BLOCKED_SUMMARY_SOURCE_IDS),
    }
    if include_llm_prompt:
        summary["llm_handoff"]["prompt_text"] = _build_why_blocked_llm_prompt(summary)
    return summary


def format_why_blocked_summary(summary: dict) -> str:
    if not summary or not summary.get("valid"):
        return str((summary or {}).get("error") or "Enter a domain to check.")

    evidence = summary.get("evidence") or {}
    lines = [
        "Why Blocked Summary",
        f"Schema: {summary.get('schema')}",
        f"Plan only: {'yes' if summary.get('plan_only') else 'no'}",
        f"Offline: {'yes' if summary.get('offline') else 'no'}",
        f"LLM/API calls: {'yes' if summary.get('llm_api_calls') else 'no'}",
        "",
        f"Domain: {summary.get('domain')}",
        f"Status: {summary.get('status')}",
        f"Confidence: {summary.get('confidence')}",
        f"Why: {summary.get('primary_reason')}",
        "",
        "Evidence:",
        f"- Blocked editor lines: {int(evidence.get('blocked_line_count') or 0):,}",
    ]
    for item in evidence.get("blocked_on_lines") or []:
        lines.append(
            f"  line {item.get('line_no')}: {item.get('line_preview')} ({item.get('matched_domain')})"
        )
    lines.extend([
        f"- Whitelist coverage: {'yes' if evidence.get('on_whitelist') else 'no'}",
        f"- Pinned block: {'yes' if evidence.get('is_pinned') else 'no'}",
    ])
    source_matches = evidence.get("source_matches") or []
    if source_matches:
        lines.append(f"- Source matches: {len(source_matches):,}")
        for name in source_matches[:WHY_BLOCKED_SUMMARY_EVIDENCE_LIMIT]:
            issue_url = (evidence.get("source_issue_urls") or {}).get(name, "")
            suffix = f" - report: {issue_url}" if issue_url else ""
            lines.append(f"  - {name}{suffix}")
    else:
        lines.append("- Source matches: none in previously fetched sources")
    events = evidence.get("provenance_events") or []
    if events:
        lines.append(f"- Local provenance events: {len(events):,}")
        for event in events:
            lines.append(
                f"  - {event.get('ts') or 'unknown time'} {event.get('kind') or 'event'} "
                f"{event.get('domain') or ''} source={event.get('source') or ''}"
            )
    else:
        lines.append("- Local provenance events: none provided")

    lines.extend(["", "Recommended actions:"])
    for action in summary.get("recommended_actions") or []:
        lines.append(f"- {action.get('label')}: {action.get('reason')}")

    lines.extend(["", "LLM handoff:"])
    handoff = summary.get("llm_handoff") or {}
    if handoff.get("available") and handoff.get("prompt_text"):
        lines.extend([
            "- Prompt generated locally; no provider was called.",
            "- Review and redact before external use.",
        ])
    else:
        lines.append("- No prompt generated.")

    lines.extend(["", "Controls:"])
    for control in summary.get("controls") or []:
        lines.append(f"- {control}")
    lines.extend(["", "Warnings:"])
    for warning in summary.get("warnings") or WHY_BLOCKED_SUMMARY_WARNINGS:
        lines.append(f"- {warning}")
    lines.extend(["", "Roadmap source IDs:", f"- {', '.join(summary.get('references') or WHY_BLOCKED_SUMMARY_SOURCE_IDS)}"])
    return "\n".join(lines)


def format_why_blocked_summary_catalog() -> str:
    lines = [
        'LLM-assisted "why blocked" summaries',
        "",
        "HostsFileGet builds an offline explanation from the current editor, whitelist coverage, pinned status, fetched-source matches, and optional local provenance events.",
        "",
        "Boundary:",
        "- No LLM API calls are made.",
        "- No network requests are made.",
        "- The optional handoff prompt is a review artifact that must be inspected and redacted before external use.",
        "",
        "CLI:",
        "- python hosts_editor.py --why-blocked-summary ads.example.com .\\hosts.txt .\\why-blocked.json",
        "- Add --why-blocked-whitelist .\\allowlist.txt to include allowlist coverage.",
        "",
        "Warnings:",
    ]
    lines.extend(f"- {warning}" for warning in WHY_BLOCKED_SUMMARY_WARNINGS)
    lines.extend(["", "Roadmap source IDs:", f"- {', '.join(WHY_BLOCKED_SUMMARY_SOURCE_IDS)}"])
    return "\n".join(lines)


def add_domain_to_whitelist_text(
    whitelist_text: str,
    domain: str,
    allow_single_label: bool = False,
) -> tuple[str, bool]:
    """Append a domain to whitelist text, preserving existing content."""
    normalized, error = normalize_whitelist_domain(domain, allow_single_label=allow_single_label)
    if error:
        raise ValueError(error)

    current = str(whitelist_text or "").rstrip()
    existing = set()
    for line in current.splitlines():
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue
        _, domains, _ = normalize_line_to_hosts_entries(line)
        if domains:
            existing.update(item.lstrip(".") for item in domains)
            continue
        parsed_domain, _ = _extract_domain_from_token(stripped, allow_single_label=True)
        if parsed_domain:
            existing.add(parsed_domain.lstrip("."))

    if _whitelist_covers_domain(normalized, existing):
        return (current + "\n") if current else "", False
    if not current:
        return normalized + "\n", True
    return current + "\n" + normalized + "\n", True


def remove_false_positive_matches_from_lines(
    editor_lines: list[str],
    domain: str,
) -> tuple[list[str], list[dict]]:
    """Remove whole editor lines that currently block the queried domain."""
    normalized, error = normalize_false_positive_domain(domain)
    if error:
        raise ValueError(error)

    new_lines = []
    removed = []
    for idx, line in enumerate(editor_lines or []):
        parsed, _ = parse_hosts_line_entries(line)
        matched = [
            entry_domain
            for _, entry_domain, is_block in parsed
            if is_block and _triage_domain_matches(normalized, entry_domain)
        ]
        if matched:
            removed.append({
                "line_no": idx + 1,
                "matched_domains": sorted(set(matched)),
                "line": line,
            })
        else:
            new_lines.append(line)
    return new_lines, removed


SCHEDULE_WEEKDAYS = ("MON", "TUE", "WED", "THU", "FRI", "SAT", "SUN")
SCHEDULE_WEEKDAY_LABELS = {
    "MON": "Monday",
    "TUE": "Tuesday",
    "WED": "Wednesday",
    "THU": "Thursday",
    "FRI": "Friday",
    "SAT": "Saturday",
    "SUN": "Sunday",
}


def normalize_scheduler_start_time(value: str, default: str = "03:30") -> str:
    candidate = (value or "").strip()
    if not candidate:
        candidate = default

    match = re.fullmatch(r"(\d{1,2}):(\d{2})", candidate)
    if not match:
        raise ValueError("Use a valid 24-hour time in HH:MM format.")

    hour = int(match.group(1))
    minute = int(match.group(2))
    if not (0 <= hour <= 23 and 0 <= minute <= 59):
        raise ValueError("Time must be between 00:00 and 23:59.")

    return f"{hour:02d}:{minute:02d}"


def build_schtasks_create_command(
    task_name: str,
    task_command: str,
    frequency: str,
    *,
    start_time: str = "03:30",
    weekday: str = "MON",
) -> tuple[list[str], str]:
    task_name = (task_name or "").strip()
    task_command = (task_command or "").strip()
    frequency = (frequency or "").strip().upper()

    if not task_name:
        raise ValueError("Task name is required.")
    if _contains_control_chars(task_name):
        raise ValueError("Task name cannot contain control characters.")
    if not task_command:
        raise ValueError("Task command is required.")
    if _contains_control_chars(task_command):
        raise ValueError("Task command cannot contain control characters.")
    if frequency not in {"DAILY", "WEEKLY", "ONLOGON"}:
        raise ValueError("Unsupported schedule frequency.")

    args = [
        "schtasks", "/Create", "/TN", task_name, "/TR", task_command,
        "/SC", frequency, "/RL", "HIGHEST", "/F",
    ]

    if frequency == "ONLOGON":
        return args, "Runs at sign-in."

    normalized_time = normalize_scheduler_start_time(start_time)
    args += ["/ST", normalized_time]

    if frequency == "WEEKLY":
        normalized_weekday = (weekday or "").strip().upper()
        if normalized_weekday not in SCHEDULE_WEEKDAYS:
            raise ValueError("Choose a weekday for weekly schedules.")
        args += ["/D", normalized_weekday]
        return args, f"Runs every {SCHEDULE_WEEKDAY_LABELS[normalized_weekday]} at {normalized_time}."

    return args, f"Runs daily at {normalized_time}."


def build_scheduler_update_command(
    interpreter: str,
    script: str,
    *,
    frozen: bool = False,
) -> str:
    interpreter = (interpreter or "").strip()
    script = (script or "").strip()
    if not script:
        raise ValueError("Updater script path is required.")
    if _contains_control_chars(script) or _contains_control_chars(interpreter):
        raise ValueError("Updater command paths cannot contain control characters.")

    if frozen:
        parts = [script, "--update", "--silent"]
    else:
        if not interpreter:
            raise ValueError("Python interpreter path is required.")
        parts = [interpreter, script, "--update", "--silent"]
    return subprocess.list2cmdline(parts)


def get_cli_log_path(config_dir: str | None = None) -> str:
    base_dir = config_dir or get_config_root_dir()
    return os.path.join(base_dir, CLI_LOG_FILENAME)


def get_cli_activity_log_path(config_dir: str | None = None) -> str:
    base_dir = config_dir or get_config_root_dir()
    return os.path.join(base_dir, CLI_ACTIVITY_FILENAME)


def _activity_text(value, max_length: int = 500) -> str:
    text = str(value or "").replace("\r", " ").replace("\n", " ").replace("\t", " ").strip()
    if len(text) > max_length:
        return text[: max_length - 3].rstrip() + "..."
    return text


def sanitize_cli_activity_event(event: dict | None) -> dict:
    event = event if isinstance(event, dict) else {}
    try:
        exit_code = int(event.get("exit_code", 0))
    except (TypeError, ValueError):
        exit_code = 0
    try:
        duration_seconds = round(float(event.get("duration_seconds") or 0), 3)
    except (TypeError, ValueError):
        duration_seconds = 0.0
    details = event.get("details", {})
    if not isinstance(details, dict):
        details = {}
    sanitized_details = {}
    for key, value in details.items():
        if not isinstance(key, str) or not key or len(key) > 80 or _contains_control_chars(key):
            continue
        if isinstance(value, bool):
            sanitized_details[key] = value
        elif isinstance(value, int):
            sanitized_details[key] = value
        elif isinstance(value, float):
            sanitized_details[key] = round(value, 3)
        elif value is None:
            sanitized_details[key] = None
        else:
            sanitized_details[key] = _activity_text(value)

    return {
        "schema_version": CLI_ACTIVITY_SCHEMA_VERSION,
        "action": _activity_text(event.get("action") or "unknown", 80) or "unknown",
        "started_at": _activity_text(event.get("started_at"), 80),
        "finished_at": _activity_text(event.get("finished_at"), 80),
        "duration_seconds": duration_seconds,
        "exit_code": exit_code,
        "outcome": _activity_text(event.get("outcome") or ("success" if exit_code == 0 else "failed"), 40),
        "summary": _activity_text(event.get("summary"), 500),
        "details": sanitized_details,
    }


def append_cli_activity_event(
    event: dict,
    activity_path: str | None = None,
    *,
    max_events: int = CLI_ACTIVITY_MAX_EVENTS,
) -> str:
    path = activity_path or get_cli_activity_log_path()
    os.makedirs(os.path.dirname(os.path.abspath(path)), exist_ok=True)
    sanitized = sanitize_cli_activity_event(event)
    line = json.dumps(sanitized, sort_keys=True) + "\n"
    keep_count = max(1, int(max_events or CLI_ACTIVITY_MAX_EVENTS))
    existing: list[str] = []
    try:
        if os.path.isfile(path):
            with open(path, "r", encoding="utf-8") as fp:
                existing = fp.readlines()[-(keep_count - 1):]
    except OSError:
        existing = []
    write_text_file_atomic(path, "".join(existing + [line]))
    return path


def read_cli_activity_events(activity_path: str | None = None, *, limit: int = CLI_ACTIVITY_MAX_EVENTS) -> list[dict]:
    path = activity_path or get_cli_activity_log_path()
    try:
        with open(path, "r", encoding="utf-8") as fp:
            lines = fp.readlines()
    except OSError:
        return []
    events = []
    for line in lines[-max(1, limit):]:
        try:
            payload = json.loads(line)
        except ValueError:
            continue
        if isinstance(payload, dict):
            events.append(sanitize_cli_activity_event(payload))
    return events


def read_cli_log_tail(log_path: str | None = None, *, lines: int = CLI_ACTIVITY_LOG_TAIL_LINES) -> list[str]:
    path = log_path or get_cli_log_path()
    try:
        with open(path, "r", encoding="utf-8") as fp:
            raw_lines = fp.readlines()
    except OSError:
        return []
    return [line.rstrip("\r\n") for line in raw_lines[-max(1, lines):]]


def parse_schtasks_query_output(output: str) -> dict[str, str]:
    fields: dict[str, str] = {}
    for raw_line in str(output or "").splitlines():
        if ":" not in raw_line:
            continue
        key, value = raw_line.split(":", 1)
        normalized_key = re.sub(r"\s+", " ", key.strip()).lower()
        if not normalized_key:
            continue
        fields[normalized_key] = value.strip()
    return fields


def query_scheduled_task_status(
    task_name: str = SCHEDULED_TASK_NAME,
    *,
    runner=None,
) -> dict:
    task_name = (task_name or SCHEDULED_TASK_NAME).strip()
    if not task_name or _contains_control_chars(task_name):
        return {"available": False, "registered": False, "diagnostic": "Invalid scheduled task name."}
    if runner is None and os.name != "nt":
        return {
            "available": False,
            "registered": False,
            "task_name": task_name,
            "diagnostic": "Windows Task Scheduler is only available on Windows.",
        }
    runner = runner or subprocess.run
    kwargs = {"capture_output": True, "text": True}
    if hasattr(subprocess, "CREATE_NO_WINDOW"):
        kwargs["creationflags"] = subprocess.CREATE_NO_WINDOW
    try:
        proc = runner(["schtasks", "/Query", "/TN", task_name, "/FO", "LIST", "/V"], **kwargs)
    except Exception as exc:
        return {
            "available": False,
            "registered": False,
            "task_name": task_name,
            "diagnostic": f"Could not query scheduled task: {exc}",
        }

    combined = "\n".join(
        part for part in (getattr(proc, "stdout", ""), getattr(proc, "stderr", "")) if part
    ).strip()
    if getattr(proc, "returncode", 1) != 0:
        lowered = combined.lower()
        if "cannot find" in lowered or "does not exist" in lowered:
            return {
                "available": True,
                "registered": False,
                "task_name": task_name,
                "diagnostic": "No scheduled auto-update task is registered.",
            }
        return {
            "available": False,
            "registered": False,
            "task_name": task_name,
            "diagnostic": combined or f"schtasks exit {getattr(proc, 'returncode', '?')}",
        }

    fields = parse_schtasks_query_output(combined)
    last_result = fields.get("last result", "")
    result_normalized = str(last_result).strip().lower()
    last_result_ok = result_normalized in {"0", "0x0", "the operation completed successfully. (0x0)"}
    return {
        "available": True,
        "registered": True,
        "task_name": task_name,
        "status": fields.get("status", ""),
        "schedule": fields.get("schedule type", "") or fields.get("schedule", ""),
        "next_run_time": fields.get("next run time", ""),
        "last_run_time": fields.get("last run time", ""),
        "last_result": last_result,
        "last_result_ok": last_result_ok,
        "task_to_run": fields.get("task to run", ""),
        "diagnostic": "registered",
    }


def build_scheduler_activity_report(
    *,
    activity_path: str | None = None,
    log_path: str | None = None,
    task_name: str = SCHEDULED_TASK_NAME,
    task_query_runner=None,
    limit: int = 25,
) -> dict:
    events = read_cli_activity_events(activity_path, limit=limit)
    success_count = sum(1 for event in events if int(event.get("exit_code", 1)) == 0)
    failed_count = sum(1 for event in events if int(event.get("exit_code", 0)) != 0)
    task_status = query_scheduled_task_status(task_name, runner=task_query_runner)
    return {
        "schema_version": CLI_ACTIVITY_SCHEMA_VERSION,
        "generated_at": _utc_timestamp(),
        "task": task_status,
        "activity_path": activity_path or get_cli_activity_log_path(),
        "log_path": log_path or get_cli_log_path(),
        "summary": {
            "events": len(events),
            "success": success_count,
            "failed": failed_count,
            "last_outcome": events[-1].get("outcome") if events else "",
            "last_finished_at": events[-1].get("finished_at") if events else "",
        },
        "events": events,
        "log_tail": read_cli_log_tail(log_path, lines=CLI_ACTIVITY_LOG_TAIL_LINES),
    }


def format_scheduler_activity_report(report: dict) -> str:
    task = report.get("task", {}) if isinstance(report, dict) else {}
    summary = report.get("summary", {}) if isinstance(report, dict) else {}
    lines = [
        "Scheduler Activity",
        f"Task: {task.get('task_name') or SCHEDULED_TASK_NAME}",
    ]
    if task.get("registered"):
        lines.append(
            "Task status: registered"
            f" ({task.get('status') or 'unknown'})"
            f"; schedule={task.get('schedule') or '-'}"
        )
        lines.append(
            f"Last run: {task.get('last_run_time') or '-'}"
            f"; last result: {task.get('last_result') or '-'}"
            f"; next run: {task.get('next_run_time') or '-'}"
        )
    else:
        availability = "available" if task.get("available") else "unavailable"
        lines.append(f"Task status: not registered ({availability}: {task.get('diagnostic') or '-'})")

    lines.extend([
        "",
        f"Activity log: {report.get('activity_path') or '-'}",
        f"CLI log: {report.get('log_path') or '-'}",
        (
            f"Events: {summary.get('events', 0)} total, "
            f"{summary.get('success', 0)} success, {summary.get('failed', 0)} failed"
        ),
    ])

    events = report.get("events") or []
    if events:
        lines.append("")
        lines.append("Recent events:")
        for event in events[-10:]:
            lines.append(
                f"  {event.get('finished_at') or event.get('started_at') or '-'}  "
                f"{event.get('action')}  {event.get('outcome')}  "
                f"exit={event.get('exit_code')}  {event.get('summary') or ''}"
            )
    else:
        lines.append("Recent events: none")

    log_tail = report.get("log_tail") or []
    if log_tail:
        lines.append("")
        lines.append("CLI log tail:")
        for line in log_tail[-CLI_ACTIVITY_LOG_TAIL_LINES:]:
            lines.append(f"  {line}")
    return "\n".join(lines)


