def format_safesearch_template_plan(plan: dict) -> str:
    lines = [
        "SafeSearch / Restricted Mode Template Plan",
        f"Template: {plan.get('template_id')} - {plan.get('label')}",
        f"Risk: {plan.get('risk')} ({plan.get('review_level')} review)",
        f"Enforcement: {plan.get('enforcement')}",
        f"Hosts-native: {'yes' if plan.get('hosts_native') else 'no'} ({plan.get('hosts_file_fit')})",
        f"Sources: {int(plan.get('source_count') or 0):,}",
        "",
        "Hosts line templates:",
    ]
    hosts_lines = plan.get("hosts_line_templates") or []
    if hosts_lines:
        lines.extend(f"- {line}" for line in hosts_lines)
    else:
        lines.append("- (none; use DNS/provider configuration)")
    lines.extend(["", "DNS CNAME records:"])
    cname_records = plan.get("dns_cname_records") or []
    if cname_records:
        for record in cname_records:
            lines.append(f"- {record.get('hostname')} -> {record.get('target')} ({record.get('scope')})")
    else:
        lines.append("- (none)")
    excluded_hosts = plan.get("excluded_hosts") or []
    if excluded_hosts:
        lines.extend(["", "Do not CNAME unless provider docs explicitly allow it:"])
        lines.extend(f"- {hostname}" for hostname in excluded_hosts)
    lines.extend(["", "Controls:"])
    for control in plan.get("controls") or []:
        lines.append(f"- {control}")
    lines.extend(["", "Source URLs:"])
    for source in plan.get("sources") or []:
        lines.append(
            f"- {source.get('id')}: {source.get('url')} "
            f"({source.get('provider')}, {source.get('mode')}, hosts={source.get('hosts_file_fit')})"
        )
    lines.extend(["", "Warnings:"])
    for warning in plan.get("warnings") or SAFESEARCH_TEMPLATE_WARNINGS:
        lines.append(f"- {warning}")
    references = plan.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", f"- {', '.join(references)}"])
    return "\n".join(lines)


def build_export_domain_records(lines: list[str]) -> list[dict[str, str]]:
    records: list[dict[str, str]] = []
    seen: set[str] = set()
    for line in lines:
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue
        parsed, _ = parse_hosts_line_entries(line)
        for normalized, domain, is_block_entry in parsed:
            if not is_block_entry:
                continue
            if domain in seen:
                continue
            seen.add(domain)
            records.append({"domain": domain, "entry": normalized})
    return records


def _zone_safe_domain(domain: str) -> str:
    return domain.rstrip(".").lower()


def _fqdn(domain: str) -> str:
    return f"{_zone_safe_domain(domain)}."


def export_lines_as_format(lines: list[str], export_format: str) -> str:
    """Convert cleaned hosts lines to one of the supported export formats.

    Supported formats:
        hosts       - as-is hosts file content (what Cleaned Save writes)
        domains     - one domain per line, no IP
        adblock     - ``||domain^`` uBlock/AdGuard syntax
        dnsmasq     - ``address=/domain/0.0.0.0``
        pihole      - pi-hole gravity-style plain domain list (same as domains)
        adguard     - AdGuard Home/DNS Adblock-style DNS rules
        technitium  - Technitium-compatible plain domain list
        blocky      - blocky-compatible plain domain list
        rpz         - BIND/Unbound Response Policy Zone using CNAME .
        unbound     - Unbound local-zone always_nxdomain entries
        privoxy     - Privoxy user.action +block section
    """
    export_format = normalize_export_format(export_format)
    if export_format in BINARY_EXPORT_FORMATS:
        raise ValueError(f"{export_format!r} is a binary export format; use export_lines_as_bytes.")
    if export_format == "hosts":
        return '\n'.join(lines)

    records = build_export_domain_records(lines)
    domains = [record["domain"] for record in records]

    if export_format in ("domains", "pihole", "technitium", "blocky"):
        return '\n'.join(domains)
    if export_format in ("adblock", "adguard"):
        return '\n'.join(f"||{domain}^" for domain in domains)
    if export_format == "dnsmasq":
        return '\n'.join(f"address=/{domain}/0.0.0.0" for domain in domains)
    if export_format == "rpz":
        output = [
            f"; Generated by {APP_NAME} v{APP_VERSION}",
            "$TTL 2h",
            "@ IN SOA localhost. hostmaster.localhost. (1 1h 15m 30d 2h)",
            "@ IN NS localhost.",
            "",
        ]
        output.extend(f"{_zone_safe_domain(domain)} CNAME ." for domain in domains)
        return '\n'.join(output)
    if export_format == "unbound":
        output = [
            f"# Generated by {APP_NAME} v{APP_VERSION}",
            "server:",
        ]
        output.extend(f'  local-zone: "{_fqdn(domain)}" always_nxdomain' for domain in domains)
        return '\n'.join(output)
    if export_format == "privoxy":
        output = [
            f"# Generated by {APP_NAME} v{APP_VERSION}",
            "{+block{HostsFileGet blocked domain}}",
        ]
        output.extend(f"{_zone_safe_domain(domain)}/" for domain in domains)
        return '\n'.join(output)
    raise ValueError(f"Unknown export format: {export_format!r}")


def export_lines_as_bytes(lines: list[str], export_format: str) -> bytes:
    export_format = normalize_export_format(export_format)
    if export_format == "hosts-gzip":
        payload = export_lines_as_format(lines, "hosts").encode("utf-8")
        return gzip.compress(payload, compresslevel=9, mtime=0)
    if export_format == "hosts-bzip2":
        payload = export_lines_as_format(lines, "hosts").encode("utf-8")
        return bz2.compress(payload, compresslevel=9)
    return export_lines_as_format(lines, export_format).encode("utf-8")


