def strip_lines_by_category(
    lines: list[str],
    drop_comments: bool = False,
    drop_blanks: bool = False,
    drop_invalid: bool = False,
) -> tuple[list[str], dict[str, int]]:
    """Return ``lines`` with selected noise categories removed, plus counts.

    Unlike the full Cleaned Save, this is surgical - the caller picks which
    category to remove and nothing else. Normalization and deduplication are
    intentionally skipped. Returned stats:
        ``{"removed_comments": int, "removed_blanks": int, "removed_invalid": int}``
    An "invalid" line is anything that isn't a comment, isn't blank, and
    produces zero parsed hosts entries.
    """
    kept: list[str] = []
    stats = {"removed_comments": 0, "removed_blanks": 0, "removed_invalid": 0}
    for line in lines:
        stripped = line.strip()
        if not stripped:
            if drop_blanks:
                stats["removed_blanks"] += 1
                continue
            kept.append(line)
            continue
        if _is_comment_line(stripped):
            if drop_comments:
                stats["removed_comments"] += 1
                continue
            kept.append(line)
            continue
        if drop_invalid:
            parsed, _ = parse_hosts_line_entries(line)
            if not parsed:
                stats["removed_invalid"] += 1
                continue
        kept.append(line)
    return kept, stats


IMPORT_START_RE = re.compile(
    r'^#\s*---\s*(Raw|Normalized)\s+Import\s+Start:\s*(.+?)\s*---\s*$',
    re.IGNORECASE,
)
IMPORT_END_RE = re.compile(
    r'^#\s*---\s*(Raw|Normalized)\s+Import\s+End:\s*(.+?)\s*---\s*$',
    re.IGNORECASE,
)


def summarize_source_contributions(lines: list[str]) -> list[dict]:
    """Report per-import-section contribution stats.

    For every `# --- Start/End ---` marker pair in ``lines``, tally how many
    lines are inside the block and how many of those are blocking entries.
    Lines outside any marker are collected under a synthetic "(outside
    imports)" entry so the editor's manual edits and pre-existing hosts
    entries are still visible. Used by the Sources Report dialog.
    """
    sections_info = discover_import_sections(lines)
    buckets: list[dict] = []
    covered: set[int] = set()

    for section in sections_info:
        inside = lines[section["start"] + 1 : section["end"]]
        block_count = 0
        total = len(inside)
        for line in inside:
            parsed, _ = parse_hosts_line_entries(line)
            if any(entry[2] for entry in parsed):
                block_count += 1
        buckets.append({
            "name": f"{section['name']} [{section['mode']}]",
            "total_lines": total,
            "blocking_entries": block_count,
            "start": section["start"],
            "end": section["end"],
        })
        covered.update(range(section["start"], section["end"] + 1))

    outside_lines = [line for idx, line in enumerate(lines) if idx not in covered]
    outside_block_count = 0
    outside_total = 0
    for line in outside_lines:
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue
        outside_total += 1
        parsed, _ = parse_hosts_line_entries(line)
        if any(entry[2] for entry in parsed):
            outside_block_count += 1

    if outside_total:
        buckets.insert(0, {
            "name": "(outside imports / manual edits)",
            "total_lines": outside_total,
            "blocking_entries": outside_block_count,
            "start": None,
            "end": None,
        })

    buckets.sort(key=lambda b: b["blocking_entries"], reverse=True)
    return buckets


def extract_blocking_domains_from_lines(lines: list[str]) -> set[str]:
    """Return normalized blocking domains from hosts/filter-style text lines."""
    domains: set[str] = set()
    for line in lines or []:
        parsed, _ = parse_hosts_line_entries(line)
        for _, domain, is_block in parsed:
            if is_block:
                domains.add(domain)
    return domains


def _dedupe_source_index_label(label: str, used: set[str], url: str = "", fallback: str = "") -> str:
    clean = str(label or "").strip() or str(fallback or "").strip() or "Unnamed source"
    if clean not in used:
        used.add(clean)
        return clean

    host = ""
    try:
        host = urllib.parse.urlparse(url).netloc
    except ValueError:
        host = ""
    if host:
        candidate = f"{clean} ({host})"
        if candidate not in used:
            used.add(candidate)
            return candidate

    suffix = 2
    while True:
        candidate = f"{clean} #{suffix}"
        if candidate not in used:
            used.add(candidate)
            return candidate
        suffix += 1


def build_source_domain_index(source_corpus: dict[str, object]) -> dict[str, set[str]]:
    """Build a source-name -> blocking-domain index from cached source bodies."""
    index: dict[str, set[str]] = {}
    used_labels: set[str] = set()
    for cache_key, payload in (source_corpus or {}).items():
        if isinstance(payload, dict):
            name = str(payload.get("name") or cache_key)
            url = str(payload.get("url") or "")
            text = payload.get("text", "")
        else:
            name = str(cache_key)
            url = ""
            text = payload
        if not text:
            continue
        domains = extract_blocking_domains_from_lines(str(text).splitlines())
        if not domains:
            continue
        label = _dedupe_source_index_label(name, used_labels, url=url, fallback=str(cache_key))
        index[label] = domains
    return index


def build_source_overlap_report(
    source_corpus: dict[str, object],
    sample_limit: int = 5,
    pair_limit: int = 100,
) -> dict:
    """Return source uniqueness and pairwise overlap stats for fetched sources."""
    index = build_source_domain_index(source_corpus)
    source_names = list(index.keys())
    domain_to_sources: dict[str, set[str]] = {}
    for source_name, domains in index.items():
        for domain in domains:
            domain_to_sources.setdefault(domain, set()).add(source_name)

    source_rows = []
    for source_name, domains in index.items():
        unique_count = sum(1 for domain in domains if len(domain_to_sources.get(domain, set())) == 1)
        overlap_count = len(domains) - unique_count
        source_rows.append({
            "source": source_name,
            "domains": len(domains),
            "unique_domains": unique_count,
            "overlap_domains": overlap_count,
            "overlap_percent": (100.0 * overlap_count / len(domains)) if domains else 0.0,
        })
    source_rows.sort(key=lambda row: (-row["domains"], row["source"].lower()))

    pairs = []
    for left_idx, left_name in enumerate(source_names):
        left_domains = index[left_name]
        for right_name in source_names[left_idx + 1:]:
            right_domains = index[right_name]
            shared = left_domains & right_domains
            if not shared:
                continue
            pairs.append({
                "source_a": left_name,
                "source_b": right_name,
                "shared_domains": len(shared),
                "a_overlap_percent": 100.0 * len(shared) / len(left_domains) if left_domains else 0.0,
                "b_overlap_percent": 100.0 * len(shared) / len(right_domains) if right_domains else 0.0,
                "sample_domains": sorted(shared)[:max(0, sample_limit)],
            })
    pairs.sort(key=lambda row: (-row["shared_domains"], row["source_a"].lower(), row["source_b"].lower()))
    if pair_limit and len(pairs) > pair_limit:
        truncated_pairs = len(pairs) - pair_limit
        pairs = pairs[:pair_limit]
    else:
        truncated_pairs = 0

    return {
        "source_count": len(source_names),
        "total_unique_domains": len(domain_to_sources),
        "domains_seen_in_multiple_sources": sum(1 for names in domain_to_sources.values() if len(names) > 1),
        "source_rows": source_rows,
        "pairs": pairs,
        "truncated_pairs": truncated_pairs,
    }


def format_source_overlap_report(
    report: dict,
    max_sources: int = 20,
    max_pairs: int = 30,
) -> str:
    """Format source overlap stats for the Sources Report dialog."""
    source_count = int(report.get("source_count") or 0)
    if source_count == 0:
        return (
            "Fetched source overlap matrix\n"
            "(no fetched source corpus is available yet - import sources this session to build the overlap matrix)"
        )
    if source_count == 1:
        return (
            "Fetched source overlap matrix\n"
            "(only one fetched source is indexed; import at least two sources to compare overlap)"
        )

    lines = [
        "Fetched source overlap matrix",
        f"Sources indexed: {source_count:,}",
        f"Unique normalized blocking domains: {int(report.get('total_unique_domains') or 0):,}",
        f"Domains present in 2+ sources: {int(report.get('domains_seen_in_multiple_sources') or 0):,}",
        "",
        "Per-source uniqueness",
        f"{'Source':<44} {'Domains':>10} {'Unique':>10} {'Overlap':>10} {'Overlap %':>10}",
        "-" * 90,
    ]
    source_rows = report.get("source_rows") or []
    for row in source_rows[:max_sources]:
        name = str(row.get("source", ""))[:43]
        lines.append(
            f"{name:<44} "
            f"{int(row.get('domains') or 0):>10,} "
            f"{int(row.get('unique_domains') or 0):>10,} "
            f"{int(row.get('overlap_domains') or 0):>10,} "
            f"{float(row.get('overlap_percent') or 0.0):>9.1f}%"
        )
    if len(source_rows) > max_sources:
        lines.append(f"...and {len(source_rows) - max_sources:,} more source(s)")

    lines.extend([
        "",
        "Top overlapping pairs",
        f"{'Source A':<30} {'Source B':<30} {'Shared':>8} {'A %':>7} {'B %':>7}  Sample domains",
        "-" * 110,
    ])
    pairs = report.get("pairs") or []
    if not pairs:
        lines.append("(no overlapping pairs found)")
    for row in pairs[:max_pairs]:
        left = str(row.get("source_a", ""))[:29]
        right = str(row.get("source_b", ""))[:29]
        sample = ", ".join(row.get("sample_domains") or [])
        lines.append(
            f"{left:<30} {right:<30} "
            f"{int(row.get('shared_domains') or 0):>8,} "
            f"{float(row.get('a_overlap_percent') or 0.0):>6.1f}% "
            f"{float(row.get('b_overlap_percent') or 0.0):>6.1f}%  "
            f"{sample}"
        )
    hidden_pairs = max(0, len(pairs) - max_pairs) + int(report.get("truncated_pairs") or 0)
    if hidden_pairs:
        lines.append(f"...and {hidden_pairs:,} more overlapping pair(s)")

    lines.extend([
        "",
        "Matrix basis: normalized blocking domains from sources fetched during the current session.",
    ])
    return "\n".join(lines)


def _sanitize_source_metric_text(value, max_length: int = 160) -> str:
    return " ".join(str(value or "").replace("\r", " ").replace("\n", " ").replace("\t", " ").split())[:max_length]


def _source_metric_epoch(value) -> float | None:
    text = _sanitize_source_metric_text(value, 80)
    if not text:
        return None
    if text.endswith("Z"):
        text = text[:-1] + "+00:00"
    try:
        parsed = datetime.datetime.fromisoformat(text)
        return parsed.timestamp()
    except (TypeError, ValueError, OSError, OverflowError):
        return None


def _source_metric_int(value, default: int = 0, upper: int = 100_000_000) -> int:
    try:
        number = int(value)
    except (TypeError, ValueError):
        number = default
    return max(0, min(upper, number))


def sanitize_source_metrics_history(
    history,
    *,
    max_sources: int = SOURCE_METRICS_HISTORY_MAX_SOURCES,
    max_points: int = SOURCE_METRICS_HISTORY_MAX_POINTS,
) -> dict[str, list[dict]]:
    """Sanitize compact per-source freshness/growth history."""
    try:
        source_limit = max(0, min(int(max_sources), SOURCE_METRICS_HISTORY_MAX_SOURCES))
    except (TypeError, ValueError):
        source_limit = SOURCE_METRICS_HISTORY_MAX_SOURCES
    try:
        point_limit = max(0, min(int(max_points), SOURCE_METRICS_HISTORY_MAX_POINTS))
    except (TypeError, ValueError):
        point_limit = SOURCE_METRICS_HISTORY_MAX_POINTS
    if source_limit == 0 or point_limit == 0 or not isinstance(history, dict):
        return {}

    sanitized_rows: list[tuple[float, str, list[dict]]] = []
    for raw_url, points in history.items():
        if not isinstance(raw_url, str):
            continue
        url = normalize_custom_source_url(raw_url) or raw_url.strip()
        if _parse_valid_http_source_url(url) is None or not isinstance(points, (list, tuple)):
            continue
        clean_points = []
        for point in points:
            if not isinstance(point, dict):
                continue
            ts = _sanitize_source_metric_text(point.get("ts"), 80)
            epoch = _source_metric_epoch(ts)
            if epoch is None:
                continue
            clean_points.append({
                "ts": ts,
                "name": _sanitize_source_metric_text(point.get("name"), 120),
                "domain_count": _source_metric_int(point.get("domain_count")),
                "line_count": _source_metric_int(point.get("line_count")),
                "bytes": _source_metric_int(point.get("bytes"), upper=MAX_DOWNLOAD_BYTES),
                "cache_status": _sanitize_source_metric_text(point.get("cache_status"), 40),
            })
        if not clean_points:
            continue
        clean_points.sort(key=lambda row: _source_metric_epoch(row.get("ts")) or 0.0)
        clean_points = clean_points[-point_limit:]
        sanitized_rows.append((_source_metric_epoch(clean_points[-1].get("ts")) or 0.0, url, clean_points))

    sanitized_rows.sort(key=lambda row: (-row[0], row[1]))
    return {url: points for _epoch, url, points in sanitized_rows[:source_limit]}


def record_source_metrics_snapshot(
    history,
    name: str,
    url: str,
    raw_lines: list[str] | tuple[str, ...] | None,
    *,
    cache_status: str = "",
    fetched_at: str | None = None,
) -> dict[str, list[dict]]:
    """Append one compact source metrics point after a successful fetch."""
    normalized_url = normalize_custom_source_url(url) or str(url or "").strip()
    if _parse_valid_http_source_url(normalized_url) is None:
        return sanitize_source_metrics_history(history)
    lines = [str(line) for line in (raw_lines or [])]
    text = "\n".join(lines)
    timestamp = fetched_at or datetime.datetime.now().isoformat(timespec="seconds")
    domains = extract_blocking_domains_from_lines(lines)
    snapshot = sanitize_source_metrics_history(history)
    points = list(snapshot.get(normalized_url, []))
    points.append({
        "ts": _sanitize_source_metric_text(timestamp, 80),
        "name": _sanitize_source_metric_text(name, 120),
        "domain_count": len(domains),
        "line_count": len(lines),
        "bytes": min(MAX_DOWNLOAD_BYTES, len(text.encode("utf-8", errors="replace"))),
        "cache_status": _sanitize_source_metric_text(cache_status, 40),
    })
    snapshot[normalized_url] = points
    return sanitize_source_metrics_history(snapshot)


def format_source_growth_sparkline(values: list[int] | tuple[int, ...], width: int = 12) -> str:
    """Return a compact ASCII chart for source domain-count history."""
    numbers = [_source_metric_int(value) for value in (values or [])]
    if not numbers:
        return "-"
    try:
        chart_width = max(1, int(width))
    except (TypeError, ValueError):
        chart_width = 12
    if len(numbers) > chart_width:
        step = len(numbers) / chart_width
        numbers = [numbers[min(len(numbers) - 1, int(idx * step))] for idx in range(chart_width)]
    lo = min(numbers)
    hi = max(numbers)
    alphabet = "._:-=+*#%@"
    if hi == lo:
        return alphabet[0] * len(numbers)
    return "".join(alphabet[round((value - lo) * (len(alphabet) - 1) / (hi - lo))] for value in numbers)


def _source_name_lookup(blocklist_sources, source_corpus: dict[str, object] | None = None) -> dict[str, str]:
    lookup: dict[str, str] = {}
    if isinstance(blocklist_sources, dict):
        for _category, sources in blocklist_sources.items():
            if not isinstance(sources, (list, tuple)):
                continue
            for source in sources:
                if isinstance(source, (list, tuple)) and len(source) >= 2:
                    url = normalize_custom_source_url(source[1]) or str(source[1])
                    lookup[url] = str(source[0])
    for cache_key, payload in (source_corpus or {}).items():
        if not isinstance(payload, dict):
            continue
        url = normalize_custom_source_url(payload.get("url", "")) or str(payload.get("url", ""))
        if _parse_valid_http_source_url(url) is None:
            continue
        lookup[url] = str(payload.get("name") or cache_key)
    return lookup


def build_source_metrics_report(
    source_last_fetched: dict | None = None,
    source_cache_metadata: dict | None = None,
    source_metrics_history: dict | None = None,
    source_corpus: dict[str, object] | None = None,
    blocklist_sources=None,
    *,
    now: float | None = None,
    max_sources: int = SOURCE_METRICS_REPORT_MAX_SOURCES,
) -> dict:
    """Build a local freshness and growth report from compact source history."""
    last_fetched = source_last_fetched if isinstance(source_last_fetched, dict) else {}
    cache_metadata = source_cache_metadata if isinstance(source_cache_metadata, dict) else {}
    history = sanitize_source_metrics_history(source_metrics_history or {})
    name_lookup = _source_name_lookup(blocklist_sources, source_corpus)
    normalized_last_fetched = {
        normalize_custom_source_url(url) or str(url): stamp
        for url, stamp in last_fetched.items()
        if isinstance(url, str) and _parse_valid_http_source_url(normalize_custom_source_url(url) or url) is not None
    }
    normalized_cache_metadata = {
        normalize_custom_source_url(url) or str(url): entry
        for url, entry in cache_metadata.items()
        if isinstance(url, str) and _parse_valid_http_source_url(normalize_custom_source_url(url) or url) is not None
    }
    urls = set(history) | set(normalized_last_fetched) | set(normalized_cache_metadata)

    rows = []
    freshness_counts = {"fresh": 0, "warm": 0, "stale": 0, "never": 0}
    for url in sorted(urls):
        points = history.get(url, [])
        latest = points[-1] if points else {}
        first = points[0] if points else {}
        previous = points[-2] if len(points) >= 2 else {}
        last_stamp = str(normalized_last_fetched.get(url) or latest.get("ts") or "")
        freshness = classify_source_freshness(last_stamp, now=now)
        freshness_counts[freshness] = freshness_counts.get(freshness, 0) + 1
        values = [int(point.get("domain_count") or 0) for point in points]
        latest_domains = int(latest.get("domain_count") or 0) if latest else None
        previous_domains = int(previous.get("domain_count") or 0) if previous else None
        first_domains = int(first.get("domain_count") or 0) if first else None
        metadata = normalized_cache_metadata.get(url, {}) if isinstance(normalized_cache_metadata.get(url, {}), dict) else {}
        name = (
            str(latest.get("name") or "")
            or name_lookup.get(url, "")
            or urllib.parse.urlparse(url).netloc
            or url
        )
        rows.append({
            "url": url,
            "name": name,
            "freshness": freshness,
            "last_fetched": last_stamp,
            "history_points": len(points),
            "latest_domain_count": latest_domains,
            "latest_line_count": int(latest.get("line_count") or 0) if latest else None,
            "latest_bytes": int(latest.get("bytes") or 0) if latest else None,
            "delta_previous": (
                latest_domains - previous_domains
                if latest_domains is not None and previous_domains is not None
                else None
            ),
            "delta_first": (
                latest_domains - first_domains
                if latest_domains is not None and first_domains is not None
                else None
            ),
            "sparkline": format_source_growth_sparkline(values),
            "cache_status": str(latest.get("cache_status") or metadata.get("cache_status") or ""),
            "validated_at": str(metadata.get("validated_at") or ""),
        })

    freshness_order = {"stale": 0, "never": 1, "warm": 2, "fresh": 3}
    rows.sort(key=lambda row: (freshness_order.get(row["freshness"], 4), row["name"].lower()))
    try:
        limit = max(1, int(max_sources))
    except (TypeError, ValueError):
        limit = SOURCE_METRICS_REPORT_MAX_SOURCES
    displayed_rows = rows[:limit]
    return {
        "schema": "hostsfileget.source-metrics.v1",
        "source_count": len(rows),
        "displayed_count": len(displayed_rows),
        "freshness_counts": freshness_counts,
        "history_point_count": sum(row["history_points"] for row in rows),
        "history_retention_points": SOURCE_METRICS_HISTORY_MAX_POINTS,
        "rows": displayed_rows,
        "truncated_count": max(0, len(rows) - len(displayed_rows)),
        "references": ["C4", "O6"],
    }


def format_source_metrics_report(report: dict) -> str:
    """Render source freshness and growth as a local text dashboard."""
    if not report:
        return "Source Freshness & Growth\n(no report)"
    counts = report.get("freshness_counts") or {}
    lines = [
        "Source Freshness & Growth",
        f"Sources tracked: {int(report.get('source_count') or 0):,}",
        f"Displayed: {int(report.get('displayed_count') or 0):,}",
        (
            "Freshness: "
            f"fresh={int(counts.get('fresh') or 0):,}, "
            f"warm={int(counts.get('warm') or 0):,}, "
            f"stale={int(counts.get('stale') or 0):,}, "
            f"never={int(counts.get('never') or 0):,}"
        ),
        f"History points: {int(report.get('history_point_count') or 0):,}",
        f"Retention: last {int(report.get('history_retention_points') or 0):,} points per source",
        "",
    ]
    rows = report.get("rows") or []
    if not rows:
        lines.extend([
            "No source freshness or growth history is available yet.",
            "Import or update a source to record the first local metrics point.",
        ])
    else:
        lines.append(
            f"{'Source':<30} {'Fresh':<6} {'Last fetched':<19} {'Domains':>9} {'dPrev':>7} {'dFirst':>7} {'Pts':>4}  Chart"
        )
        lines.append("-" * 104)
        for row in rows:
            latest_domains = row.get("latest_domain_count")
            domains_text = "-" if latest_domains is None else f"{int(latest_domains):,}"
            delta_previous = row.get("delta_previous")
            delta_first = row.get("delta_first")
            prev_text = "-" if delta_previous is None else f"{int(delta_previous):+}"
            first_text = "-" if delta_first is None else f"{int(delta_first):+}"
            lines.append(
                f"{str(row.get('name') or '-')[:29]:<30} "
                f"{str(row.get('freshness') or '-'):<6} "
                f"{str(row.get('last_fetched') or '-')[:19]:<19} "
                f"{domains_text:>9} "
                f"{prev_text:>7} "
                f"{first_text:>7} "
                f"{int(row.get('history_points') or 0):>4}  "
                f"{row.get('sparkline') or '-'}"
            )
        if report.get("truncated_count"):
            lines.append(f"...and {int(report.get('truncated_count') or 0):,} more tracked source(s)")
    references = report.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", "- " + ", ".join(references)])
    lines.extend([
        "",
        "Boundary: local metrics only. No telemetry is uploaded; charts are derived from successful imports and CLI updates.",
    ])
    return "\n".join(lines)


def _normalize_filter_query_text(value: str) -> str:
    candidate = str(value or "").replace("\r", " ").replace("\n", " ").replace("\t", " ")
    candidate = " ".join(candidate.split())
    return candidate[:FILTER_QUERY_MAX_LENGTH]


def sanitize_filter_query_history(history, max_items: int = FILTER_QUERY_HISTORY_MAX_ITEMS) -> list[str]:
    """Return recent filter-builder queries in deterministic, safe display order."""
    try:
        limit = int(max_items)
    except (TypeError, ValueError):
        limit = FILTER_QUERY_HISTORY_MAX_ITEMS
    limit = max(0, min(limit, FILTER_QUERY_HISTORY_MAX_ITEMS))
    if limit == 0 or not isinstance(history, (list, tuple)):
        return []

    sanitized: list[str] = []
    seen: set[str] = set()
    for item in history:
        if not isinstance(item, str):
            continue
        query = _normalize_filter_query_text(item)
        if not query:
            continue
        key = query.casefold()
        if key in seen:
            continue
        seen.add(key)
        sanitized.append(query)
        if len(sanitized) >= limit:
            break
    return sanitized


def record_filter_query_history(
    history,
    query: str,
    max_items: int = FILTER_QUERY_HISTORY_MAX_ITEMS,
) -> list[str]:
    """Move ``query`` to the front of filter-builder history if it is valid."""
    try:
        limit = int(max_items)
    except (TypeError, ValueError):
        limit = FILTER_QUERY_HISTORY_MAX_ITEMS
    limit = max(0, min(limit, FILTER_QUERY_HISTORY_MAX_ITEMS))
    current = sanitize_filter_query_history(history, max_items=limit)
    normalized = _normalize_filter_query_text(query)
    if not normalized or limit == 0:
        return current
    key = normalized.casefold()
    return [normalized] + [item for item in current if item.casefold() != key][: max(0, limit - 1)]


def _normalize_watch_expression_name(value: str, fallback: str = "") -> str:
    name = _normalize_filter_query_text(value)[:WATCH_EXPRESSION_NAME_MAX_LENGTH]
    if name:
        return name
    fallback_name = _normalize_filter_query_text(fallback)[:WATCH_EXPRESSION_NAME_MAX_LENGTH]
    return fallback_name or "Watch expression"


def sanitize_watch_expressions(watches, max_items: int = WATCH_EXPRESSIONS_MAX_ITEMS) -> list[dict]:
    """Return app-level watch expressions in safe, deterministic order."""
    try:
        limit = int(max_items)
    except (TypeError, ValueError):
        limit = WATCH_EXPRESSIONS_MAX_ITEMS
    limit = max(0, min(limit, WATCH_EXPRESSIONS_MAX_ITEMS))
    if limit == 0 or not isinstance(watches, (list, tuple)):
        return []

    sanitized: list[dict] = []
    seen_queries: set[str] = set()
    for item in watches:
        if isinstance(item, str):
            query = _normalize_filter_query_text(item)
            name = _normalize_watch_expression_name("", query)
            enabled = True
        elif isinstance(item, dict):
            query = _normalize_filter_query_text(item.get("query") or item.get("expression") or "")
            name = _normalize_watch_expression_name(item.get("name", ""), query)
            enabled = bool(item.get("enabled", True))
        else:
            continue
        if not query:
            continue
        key = query.casefold()
        if key in seen_queries:
            continue
        seen_queries.add(key)
        sanitized.append({
            "name": name,
            "query": query,
            "enabled": enabled,
        })
        if len(sanitized) >= limit:
            break
    return sanitized


def upsert_watch_expression(
    watches,
    query: str,
    name: str = "",
    *,
    enabled: bool = True,
    index: int | None = None,
    max_items: int = WATCH_EXPRESSIONS_MAX_ITEMS,
) -> list[dict]:
    """Add or replace one watch expression, deduped by query."""
    current = sanitize_watch_expressions(watches, max_items=max_items)
    candidate_rows = sanitize_watch_expressions([{
        "name": name,
        "query": query,
        "enabled": enabled,
    }], max_items=1)
    if not candidate_rows:
        return current
    candidate = candidate_rows[0]

    if isinstance(index, int) and 0 <= index < len(current):
        current[index] = candidate
    else:
        current = [candidate] + [
            item for item in current
            if item.get("query", "").casefold() != candidate["query"].casefold()
        ]
    return sanitize_watch_expressions(current, max_items=max_items)


def remove_watch_expression(watches, index: int) -> list[dict]:
    """Remove a watch expression by display index."""
    current = sanitize_watch_expressions(watches)
    try:
        idx = int(index)
    except (TypeError, ValueError):
        return current
    if 0 <= idx < len(current):
        del current[idx]
    return current


def parse_filter_builder_query(query: str) -> dict:
    """Parse a local filter-builder query into fielded terms.

    Supported fields are ``domain:``, ``source:``, ``line:``, and
    ``history:``. Bare terms search editor lines, fetched-source labels, and
    catalog source metadata; bare multi-label domains also become domain terms.
    """
    normalized = _normalize_filter_query_text(query)
    parsed = {
        "query": normalized,
        "valid": bool(normalized),
        "tokens": [],
        "domain_terms": [],
        "source_terms": [],
        "line_terms": [],
        "history_terms": [],
        "warnings": [],
    }
    if not normalized:
        parsed["warnings"].append("Enter a domain, source name, line term, or fielded query.")
        return parsed

    try:
        raw_tokens = shlex.split(normalized)
    except ValueError as exc:
        raw_tokens = normalized.split()
        parsed["warnings"].append(f"Quoted term could not be parsed ({exc}); using whitespace tokens.")

    known_fields = {"domain", "source", "line", "history"}
    seen_domains: set[str] = set()
    seen_source_terms: set[str] = set()
    seen_line_terms: set[str] = set()
    seen_history_terms: set[str] = set()

    def add_domain(value: str, *, strict: bool) -> None:
        domain, error = normalize_whitelist_domain(value, allow_single_label=False)
        if error:
            if strict:
                parsed["warnings"].append(error)
            return
        key = domain.casefold()
        if key not in seen_domains:
            seen_domains.add(key)
            parsed["domain_terms"].append(domain)

    def add_text_term(collection: list[str], seen: set[str], value: str) -> None:
        term = _normalize_filter_query_text(value).lower()
        if not term or term.casefold() in seen:
            return
        seen.add(term.casefold())
        collection.append(term)

    for raw_token in raw_tokens:
        if ":" in raw_token:
            field, value = raw_token.split(":", 1)
            field = field.lower().strip()
            value = value.strip()
            if field in known_fields:
                parsed["tokens"].append({"field": field, "value": value})
                if field == "domain":
                    add_domain(value, strict=True)
                elif field == "source":
                    add_text_term(parsed["source_terms"], seen_source_terms, value)
                elif field == "line":
                    add_text_term(parsed["line_terms"], seen_line_terms, value)
                elif field == "history":
                    add_text_term(parsed["history_terms"], seen_history_terms, value)
                continue

        parsed["tokens"].append({"field": "text", "value": raw_token})
        add_text_term(parsed["line_terms"], seen_line_terms, raw_token)
        add_text_term(parsed["source_terms"], seen_source_terms, raw_token)
        if "." in raw_token:
            add_domain(raw_token, strict=False)

    if (
        not parsed["domain_terms"]
        and not parsed["source_terms"]
        and not parsed["line_terms"]
        and not parsed["history_terms"]
    ):
        parsed["warnings"].append("No usable query terms were found.")
    return parsed


def _iter_source_catalog_rows(blocklist_sources) -> list[dict]:
    rows: list[dict] = []
    if not isinstance(blocklist_sources, dict):
        return rows
    for category, sources in blocklist_sources.items():
        if not isinstance(sources, (list, tuple)):
            continue
        for source in sources:
            if not isinstance(source, (list, tuple)) or len(source) < 2:
                continue
            name = str(source[0])
            url = str(source[1])
            tooltip = str(source[2]) if len(source) > 2 else ""
            rows.append({
                "name": name,
                "category": str(category),
                "url": url,
                "tooltip": tooltip,
            })
    return rows


def _filter_term_matches_all(haystack: str, terms: list[str]) -> bool:
    lowered = haystack.lower()
    return all(term.lower() in lowered for term in terms)


def _domain_terms_match_domain(domain_terms: list[str], candidate: str) -> list[str]:
    matched: list[str] = []
    target = str(candidate or "").strip().lower().lstrip(".")
    if not target:
        return matched
    for term in domain_terms:
        if _triage_domain_matches(term, target):
            matched.append(term)
    return matched


def build_filter_builder_report(
    query: str,
    editor_lines: list[str] | None = None,
    source_corpus: dict[str, object] | None = None,
    blocklist_sources=None,
    query_history=None,
    match_limit: int = FILTER_BUILDER_MATCH_LIMIT,
) -> dict:
    """Build a local filter/query report from editor, source, and history state."""
    parsed = parse_filter_builder_query(query)
    editor_lines = editor_lines or []
    source_corpus = source_corpus or {}
    history = sanitize_filter_query_history(query_history or [])
    try:
        limit = max(1, int(match_limit))
    except (TypeError, ValueError):
        limit = FILTER_BUILDER_MATCH_LIMIT

    domain_terms = parsed["domain_terms"]
    source_terms = parsed["source_terms"]
    line_terms = parsed["line_terms"]
    if parsed["history_terms"]:
        history_terms = parsed["history_terms"]
    elif parsed["query"]:
        history_terms = domain_terms + source_terms + line_terms + [parsed["query"].lower()]
    else:
        history_terms = []

    editor_matches = []
    editor_total = 0
    for idx, line in enumerate(editor_lines):
        matched_by: list[str] = []
        matched_domains: list[str] = []
        line_text = str(line)
        if line_terms and _filter_term_matches_all(line_text, line_terms):
            matched_by.append("line")
        parsed_entries, _ = parse_hosts_line_entries(line_text)
        for _, entry_domain, is_block in parsed_entries:
            if not is_block:
                continue
            matches = _domain_terms_match_domain(domain_terms, entry_domain)
            if matches:
                matched_by.append("domain")
                matched_domains.append(entry_domain)
        if matched_by:
            editor_total += 1
            if len(editor_matches) < limit:
                editor_matches.append({
                    "line_no": idx + 1,
                    "line": line_text.strip(),
                    "matched_by": sorted(set(matched_by)),
                    "matched_domains": sorted(set(matched_domains)),
                })

    source_matches: list[dict] = []
    seen_sources: set[tuple[str, str]] = set()
    source_index = build_source_domain_index(source_corpus)
    for source_name, domains in source_index.items():
        matched_domains: list[str] = []
        if domain_terms:
            for domain in sorted(domains):
                if _domain_terms_match_domain(domain_terms, domain):
                    matched_domains.append(domain)
        label_match = bool(source_terms and _filter_term_matches_all(source_name, source_terms))
        if not matched_domains and not label_match:
            continue
        key = ("fetched", source_name.casefold())
        if key in seen_sources:
            continue
        seen_sources.add(key)
        source_matches.append({
            "kind": "fetched",
            "name": source_name,
            "category": "fetched this session",
            "url": "",
            "matched_domains": matched_domains[:5],
            "domain_count": len(domains),
            "matched_by": sorted(set((["domain"] if matched_domains else []) + (["source"] if label_match else []))),
        })

    for row in _iter_source_catalog_rows(blocklist_sources):
        haystack = f"{row['category']} {row['name']} {row['url']} {row['tooltip']}"
        if not source_terms or not _filter_term_matches_all(haystack, source_terms):
            continue
        key = ("catalog", row["name"].casefold())
        if key in seen_sources:
            continue
        seen_sources.add(key)
        source_matches.append({
            "kind": "catalog",
            "name": row["name"],
            "category": row["category"],
            "url": row["url"],
            "matched_domains": [],
            "domain_count": None,
            "matched_by": ["source"],
        })
    source_total = len(source_matches)
    source_matches = source_matches[:limit]

    history_matches = []
    if history_terms:
        for item in history:
            if item.casefold() == parsed["query"].casefold():
                continue
            if any(term in item.lower() for term in history_terms):
                history_matches.append(item)
            if len(history_matches) >= min(limit, 10):
                break
    elif history:
        history_matches = history[: min(limit, 10)]

    warnings = list(parsed["warnings"])
    if editor_total > len(editor_matches):
        warnings.append(f"Editor matches truncated to {len(editor_matches)} of {editor_total}.")
    if source_total > len(source_matches):
        warnings.append(f"Source matches truncated to {len(source_matches)} of {source_total}.")

    return {
        "schema": "hostsfileget.filter-builder.v1",
        "query": parsed["query"],
        "valid": bool(parsed["valid"]),
        "tokens": parsed["tokens"],
        "domain_terms": domain_terms,
        "source_terms": source_terms,
        "line_terms": line_terms,
        "history_terms": parsed["history_terms"],
        "editor_match_count": editor_total,
        "editor_matches": editor_matches,
        "source_match_count": source_total,
        "source_matches": source_matches,
        "history_matches": history_matches,
        "warnings": warnings,
        "references": ["C4", "O7"],
    }


def build_watch_expression_report(
    watches,
    editor_lines: list[str] | None = None,
    source_corpus: dict[str, object] | None = None,
    blocklist_sources=None,
    *,
    match_limit: int = WATCH_EXPRESSION_REPORT_MATCH_LIMIT,
) -> dict:
    """Evaluate saved watch expressions against current local state."""
    sanitized_watches = sanitize_watch_expressions(watches)
    rows: list[dict] = []
    enabled_count = 0
    triggered_count = 0
    total_editor_matches = 0
    total_source_matches = 0
    for watch in sanitized_watches:
        row = {
            "name": watch["name"],
            "query": watch["query"],
            "enabled": bool(watch.get("enabled", True)),
            "valid": True,
            "triggered": False,
            "editor_match_count": 0,
            "source_match_count": 0,
            "hit_count": 0,
            "editor_matches": [],
            "source_matches": [],
            "warnings": [],
        }
        if not row["enabled"]:
            row["warnings"].append("Watch is disabled.")
            rows.append(row)
            continue
        enabled_count += 1
        filter_report = build_filter_builder_report(
            watch["query"],
            editor_lines or [],
            source_corpus or {},
            blocklist_sources,
            [],
            match_limit=match_limit,
        )
        editor_count = int(filter_report.get("editor_match_count") or 0)
        source_count = int(filter_report.get("source_match_count") or 0)
        hit_count = editor_count + source_count
        row.update({
            "valid": bool(filter_report.get("valid")),
            "triggered": hit_count > 0,
            "editor_match_count": editor_count,
            "source_match_count": source_count,
            "hit_count": hit_count,
            "editor_matches": filter_report.get("editor_matches", [])[:match_limit],
            "source_matches": filter_report.get("source_matches", [])[:match_limit],
            "warnings": filter_report.get("warnings", []),
        })
        if row["triggered"]:
            triggered_count += 1
        total_editor_matches += editor_count
        total_source_matches += source_count
        rows.append(row)

    return {
        "schema": "hostsfileget.watch-expressions.v1",
        "watch_count": len(sanitized_watches),
        "enabled_count": enabled_count,
        "triggered_count": triggered_count,
        "editor_match_count": total_editor_matches,
        "source_match_count": total_source_matches,
        "watches": rows,
        "references": ["C4", "O7"],
    }


def format_watch_expression_report(report: dict) -> str:
    """Render saved watch expression status for the GUI."""
    if not report:
        return "Watch Expressions\n(no report)"
    lines = [
        "Watch Expressions",
        f"Configured: {int(report.get('watch_count') or 0):,}",
        f"Enabled: {int(report.get('enabled_count') or 0):,}",
        f"Triggered: {int(report.get('triggered_count') or 0):,}",
        f"Editor matches: {int(report.get('editor_match_count') or 0):,}",
        f"Source matches: {int(report.get('source_match_count') or 0):,}",
        "",
    ]
    watches = report.get("watches") or []
    if not watches:
        lines.extend([
            "No watch expressions are configured.",
            "",
            "Add a saved Filter Builder query to track domains, source labels, or line text over time.",
        ])
    for watch in watches:
        state = "triggered" if watch.get("triggered") else "clear"
        if not watch.get("enabled", True):
            state = "disabled"
        lines.append(f"- {watch.get('name')} [{state}]")
        lines.append(f"  Query: {watch.get('query')}")
        lines.append(
            "  Hits: "
            f"{int(watch.get('hit_count') or 0):,} "
            f"(editor {int(watch.get('editor_match_count') or 0):,}, "
            f"sources {int(watch.get('source_match_count') or 0):,})"
        )
        editor_matches = watch.get("editor_matches") or []
        if editor_matches:
            lines.append("  Editor samples:")
            for item in editor_matches[:3]:
                lines.append(f"    line {item.get('line_no')}: {item.get('line')}")
        source_matches = watch.get("source_matches") or []
        if source_matches:
            lines.append("  Source samples:")
            for item in source_matches[:3]:
                domains = ", ".join(item.get("matched_domains") or [])
                suffix = f" ({domains})" if domains else ""
                lines.append(f"    {item.get('name')} [{item.get('kind')}]{suffix}")
        warnings = watch.get("warnings") or []
        if warnings:
            lines.append("  Warnings:")
            for warning in warnings[:3]:
                lines.append(f"    {warning}")
    references = report.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", "- " + ", ".join(references)])
    lines.extend([
        "",
        "Boundary: local watch report only. It reuses Filter Builder syntax and never fetches sources or writes the hosts file.",
    ])
    return "\n".join(lines)


def format_filter_builder_report(report: dict) -> str:
    """Render a filter-builder report for the GUI."""
    if not report:
        return "Filter Builder\n(no report)"

    lines = [
        "Filter Builder",
        f"Query: {report.get('query') or '(empty)'}",
        "",
        "Parsed terms:",
    ]
    for label, key in (
        ("Domains", "domain_terms"),
        ("Sources", "source_terms"),
        ("Lines", "line_terms"),
        ("History", "history_terms"),
    ):
        values = report.get(key) or []
        lines.append(f"- {label}: {', '.join(values) if values else '-'}")

    lines.extend([
        "",
        f"Editor matches: {int(report.get('editor_match_count') or 0):,}",
    ])
    editor_matches = report.get("editor_matches") or []
    if editor_matches:
        for item in editor_matches:
            domains = ", ".join(item.get("matched_domains") or [])
            suffix = f" ({domains})" if domains else ""
            lines.append(f"- line {item.get('line_no')}: {item.get('line')}{suffix}")
    else:
        lines.append("- None found in the current editor.")

    lines.extend([
        "",
        f"Source matches: {int(report.get('source_match_count') or 0):,}",
    ])
    source_matches = report.get("source_matches") or []
    if source_matches:
        for item in source_matches:
            details = []
            if item.get("domain_count") is not None:
                details.append(f"{int(item.get('domain_count') or 0):,} indexed domain(s)")
            if item.get("matched_domains"):
                details.append("matches " + ", ".join(item.get("matched_domains") or []))
            detail_text = f" - {'; '.join(details)}" if details else ""
            lines.append(
                f"- {item.get('name')} [{item.get('kind')}, {item.get('category')}]{detail_text}"
            )
    else:
        lines.append("- None found in fetched sources or the curated catalog.")

    lines.extend(["", "Recent matching query history:"])
    history_matches = report.get("history_matches") or []
    if history_matches:
        lines.extend(f"- {item}" for item in history_matches)
    else:
        lines.append("- None.")

    warnings = report.get("warnings") or []
    if warnings:
        lines.extend(["", "Warnings:"])
        lines.extend(f"- {warning}" for warning in warnings)

    references = report.get("references") or []
    if references:
        lines.extend(["", "Roadmap source IDs:", "- " + ", ".join(references)])
    lines.extend([
        "",
        "Boundary: local report only. It does not fetch sources, contact DNS providers, or write the hosts file.",
    ])
    return "\n".join(lines)


def fuzzy_score(query: str, target: str) -> int:
    """Score a target string against a query, higher = better match.

    Ordered-subsequence scorer - every query character must appear in the
    target in order. Consecutive matches and matches at word boundaries are
    weighted higher. Returns -1 on no match.
    """
    if not query:
        return 0
    q = query.lower()
    t = target.lower()
    score = 0
    qi = 0
    prev_matched = False
    for ti, ch in enumerate(t):
        if qi < len(q) and ch == q[qi]:
            bonus = 3 if ti == 0 or not t[ti - 1].isalnum() else 1
            if prev_matched:
                bonus += 2
            score += bonus
            qi += 1
            prev_matched = True
        else:
            prev_matched = False
    if qi < len(q):
        return -1
    return score


STALE_FRESH_HOURS = 24
STALE_WARN_HOURS = 7 * 24


# Deterministic keyword-to-category rules used by the live stats panel
# breakdown. Order matters: the first match wins so "malware" beats
# "ads" for a domain named "malware-ads.example". The "other" bucket
# catches anything we can't confidently classify.
DOMAIN_CATEGORY_RULES: tuple[tuple[str, tuple[str, ...]], ...] = (
    ("malware", ("malware", "threat", "trojan", "botnet", "maltrail", "phish", "scam", "fraud", "ransom", "urlhaus")),
    ("tracking", ("tracker", "analytics", "metric", "telemetry", "beacon", "pixel", "stat", "collect", "logger", "matomo", "hotjar", "fullstory")),
    ("ads", ("ads", "adserver", "doubleclick", "adroll", "criteo", "adnxs", "pubmatic", "taboola", "outbrain", "admob", "popad", "banner", "partnerad", "ad-delivery", "yieldmo")),
    ("crypto", ("coin", "miner", "cryptoloot", "cryptoni", "webminepool", "coinhive")),
    ("social", ("facebook", "instagram", "twitter", "tiktok", "snapchat", "pinterest")),
)


def categorize_entries_by_domain_hint(lines: list[str]) -> dict[str, int]:
    """Bucket active block entries by keyword hints in the domain name.

    Returns a dict with keys ``"ads"``, ``"tracking"``, ``"malware"``,
    ``"crypto"``, ``"social"``, ``"other"`` whose values are unique-entry
    counts. Custom-IP mappings (LAN aliases) are excluded. This is a
    heuristic — not a classification truth — but good enough to drive a
    "47k ads, 12k tracking, 8k malware" style live readout.
    """
    counts = {"ads": 0, "tracking": 0, "malware": 0, "crypto": 0, "social": 0, "other": 0}
    seen: set[str] = set()
    for line in lines:
        stripped = line.strip()
        if not stripped or _is_comment_line(stripped):
            continue
        parsed, _ = parse_hosts_line_entries(line)
        for _, domain, is_block in parsed:
            if not is_block:
                continue
            if domain in seen:
                continue
            seen.add(domain)
            bucket = "other"
            for category, keywords in DOMAIN_CATEGORY_RULES:
                if any(kw in domain for kw in keywords):
                    bucket = category
                    break
            counts[bucket] += 1
    return counts


def classify_source_freshness(iso_timestamp: str, now: float | None = None) -> str:
    """Bucket a source's last-fetched timestamp into a freshness tier.

    Returns one of:
        "never"  — never fetched in this install
        "fresh"  — fetched within the last 24 hours
        "warm"   — fetched 1-7 days ago
        "stale"  — fetched more than 7 days ago

    The caller is expected to map these to UI colours. We keep the helper
    pure and string-valued so tests don't need Tk.
    """
    if not iso_timestamp:
        return "never"
    try:
        when = datetime.datetime.fromisoformat(iso_timestamp)
    except (TypeError, ValueError):
        return "never"
    if now is not None:
        reference = (
            datetime.datetime.fromtimestamp(now, when.tzinfo)
            if when.tzinfo
            else datetime.datetime.fromtimestamp(now)
        )
    else:
        reference = datetime.datetime.now(when.tzinfo) if when.tzinfo else datetime.datetime.now()
    delta_hours = (reference - when).total_seconds() / 3600.0
    if delta_hours < 0:
        # Clock skew — treat future timestamps as freshly fetched rather
        # than raising; they're harmless aside from being a bit odd.
        return "fresh"
    if delta_hours < STALE_FRESH_HOURS:
        return "fresh"
    if delta_hours < STALE_WARN_HOURS:
        return "warm"
    return "stale"


PROVENANCE_FILENAME = "hosts_editor_provenance.jsonl"
PROVENANCE_MAX_BYTES = 2 * 1024 * 1024  # soft cap; rotates when exceeded
PROVENANCE_EVENT_KINDS = frozenset({"pin", "unpin", "whitelist_add", "whitelist_remove"})
PROVENANCE_LOG_READ_LIMIT = 5000
PROVENANCE_LOG_DISPLAY_LIMIT = 200
PROVENANCE_EXPORT_SCHEMA = "hostsfileget.provenance-export.v1"
PROVENANCE_EXPORT_FORMATS = frozenset({"json", "jsonl", "csv"})
PROVENANCE_EXPORT_FIELDS = ("ts", "kind", "user", "domain", "domains", "source", "note", "app_version")


def append_provenance_event(path: str, event: dict) -> None:
    """Append a sanitized event record to the provenance JSONL file.

    Each event is a single JSON object on its own line. We intentionally
    keep the schema tiny and additive so existing files stay readable when
    fields are added later. Safely no-ops on IO errors — a broken audit
    log should never break a save.
    """
    kind = event.get("kind")
    if kind not in PROVENANCE_EVENT_KINDS:
        return
    safe = {
        "ts": datetime.datetime.now().isoformat(timespec="seconds"),
        "kind": kind,
        "user": str(os.environ.get("USERNAME") or os.environ.get("USER") or ""),
        "app_version": APP_VERSION,
    }
    for key in ("domain", "domains", "source", "note"):
        if key in event:
            value = event[key]
            if isinstance(value, (list, tuple)):
                safe[key] = [str(item) for item in value][:500]
            else:
                safe[key] = str(value)
    try:
        os.makedirs(os.path.dirname(path) or ".", exist_ok=True)
    except OSError:
        return

    try:
        # Rotate once the file grows past PROVENANCE_MAX_BYTES: keep the
        # previous generation as .1 so the current file stays quickly
        # readable. Only one rotation is kept — this is an audit log, not
        # a shipping dataset.
        if os.path.exists(path) and os.path.getsize(path) > PROVENANCE_MAX_BYTES:
            rotated = path + ".1"
            try:
                if os.path.exists(rotated):
                    os.unlink(rotated)
            except OSError:
                pass
            try:
                os.replace(path, rotated)
            except OSError:
                pass
        with open(path, "a", encoding="utf-8") as fp:
            fp.write(json.dumps(safe, ensure_ascii=False) + "\n")
    except OSError:
        # Audit log unavailable; caller's primary action is unaffected.
        return


def read_provenance_events(path: str, limit: int = 500) -> list[dict]:
    """Return the most recent ``limit`` well-formed events from the log."""
    if not os.path.isfile(path):
        return []
    out: list[dict] = []
    try:
        with open(path, "r", encoding="utf-8") as fp:
            for line in fp:
                line = line.strip()
                if not line:
                    continue
                try:
                    obj = json.loads(line)
                except ValueError:
                    continue
                if isinstance(obj, dict) and obj.get("kind") in PROVENANCE_EVENT_KINDS:
                    out.append(obj)
    except OSError:
        return []
    if limit and len(out) > limit:
        out = out[-limit:]
    return out


def build_pinned_export_payload(app_version: str, pinned: set[str]) -> dict:
    """Shape a JSON export of the pin set for team sharing.

    Schema is versioned so future readers can upgrade without guessing. We
    pin the list sorted so diffs remain reviewable in source control.
    """
    return {
        "schema": "hostsfileget.pinned.v1",
        "exported_by_version": app_version,
        "exported_at": datetime.datetime.now().isoformat(timespec="seconds"),
        "pinned_domains": sorted(sanitize_pinned_domains(pinned)),
    }


def parse_pinned_import_payload(payload) -> list[str]:
    """Validate a pinned-export JSON blob and return sanitized domains.

    Accepts either the full ``build_pinned_export_payload`` schema or a
    bare list of domain strings (for hand-rolled team files).
    """
    if isinstance(payload, dict):
        schema = payload.get("schema")
        if isinstance(schema, str) and not schema.startswith("hostsfileget.pinned."):
            raise ValueError(f"Unrecognized schema: {schema!r}")
        domains = payload.get("pinned_domains", [])
    elif isinstance(payload, list):
        domains = payload
    else:
        raise ValueError("Expected a JSON object with `pinned_domains` or a list of domains.")
    return sanitize_pinned_domains(domains)


def sanitize_pinned_domains(value) -> list[str]:
    """Return a deduplicated, lowercase list of valid domain strings.

    Pinned entries are persisted in config. We accept raw domains only
    (not full hosts lines) to keep the stored shape simple. Invalid
    entries are dropped silently so a hand-edited config can't poison
    the list.
    """
    if not isinstance(value, (list, tuple, set)):
        return []
    seen: set[str] = set()
    pinned: list[str] = []
    for candidate in value:
        if not isinstance(candidate, str):
            continue
        normalized = candidate.strip().lower().lstrip('.')
        if not normalized or normalized in seen:
            continue
        if not looks_like_domain(normalized, allow_single_label=False):
            continue
        seen.add(normalized)
        pinned.append(normalized)
    return pinned


WINDOWS_DNS_CLIENT_CHANNEL = "Microsoft-Windows-DNS-Client/Operational"
WINDOWS_DNS_CLIENT_DEFAULT_EVENTS = 500
WINDOWS_DNS_CLIENT_MAX_EVENTS = 5_000


def _extract_domains_from_dns_event_value(value: str) -> list[str]:
    domains: list[str] = []
    seen: set[str] = set()
    raw = str(value or "").strip()
    candidates = [raw]
    candidates.extend(token for token in TOKEN_SPLITTER.split(raw) if token)
    for candidate in candidates:
        clean = candidate.strip().strip('"\'').rstrip(".")
        if not clean:
            continue
        domain, _ = _extract_domain_from_token(clean, allow_single_label=False)
        if not domain or domain in seen:
            continue
        seen.add(domain)
        domains.append(domain)
    return domains


def parse_windows_dns_client_events_xml(text: str, max_domains: int = 50_000) -> list[str]:
    """Extract query hostnames from Windows DNS Client event XML."""
    import xml.etree.ElementTree as ET

    xml_text = str(text or "").lstrip("\ufeff").strip()
    if not xml_text:
        return []
    try:
        root = ET.fromstring(xml_text)
    except ET.ParseError:
        try:
            root = ET.fromstring(f"<Events>{xml_text}</Events>")
        except ET.ParseError as exc:
            raise ValueError("Could not parse Windows DNS Client XML.") from exc

    domains: list[str] = []
    seen: set[str] = set()
    for elem in root.iter():
        local_name = str(elem.tag).rsplit("}", 1)[-1].lower()
        attr_name = str(elem.attrib.get("Name") or elem.attrib.get("name") or "").lower()
        if not any(token in local_name or token in attr_name for token in ("query", "qname", "hostname", "host", "name")):
            continue
        value = "".join(elem.itertext()).strip()
        for domain in _extract_domains_from_dns_event_value(value):
            if domain in seen:
                continue
            seen.add(domain)
            domains.append(domain)
            if len(domains) >= max_domains:
                return domains
    return domains


def build_windows_dns_client_wevtutil_command(max_events: int = WINDOWS_DNS_CLIENT_DEFAULT_EVENTS) -> list[str]:
    """Return a bounded wevtutil query for recent DNS Client Operational events."""
    try:
        count = int(max_events)
    except (TypeError, ValueError):
        count = WINDOWS_DNS_CLIENT_DEFAULT_EVENTS
    count = max(1, min(count, WINDOWS_DNS_CLIENT_MAX_EVENTS))
    return [
        "wevtutil",
        "qe",
        WINDOWS_DNS_CLIENT_CHANNEL,
        "/rd:true",
        f"/c:{count}",
        "/f:xml",
    ]


def collect_recent_windows_dns_client_queries(
    max_events: int = WINDOWS_DNS_CLIENT_DEFAULT_EVENTS,
    timeout: int = 15,
    runner=None,
) -> list[str]:
    """Read recent Windows DNS Client Operational events through wevtutil."""
    runner = runner or subprocess.run
    command = build_windows_dns_client_wevtutil_command(max_events)
    completed = runner(
        command,
        capture_output=True,
        text=True,
        timeout=timeout,
        encoding="utf-8",
        errors="replace",
    )
    if getattr(completed, "returncode", 1) != 0:
        detail = (getattr(completed, "stderr", "") or getattr(completed, "stdout", "") or "").strip()
        raise RuntimeError(detail or "wevtutil could not read the DNS Client Operational log.")
    return parse_windows_dns_client_events_xml(getattr(completed, "stdout", ""))


DNS_BYPASS_POLICY_LOCATIONS = (
    ("Chrome", "HKCU", r"Software\Policies\Google\Chrome", ("DnsOverHttpsMode", "DnsOverHttpsTemplates")),
    ("Chrome", "HKLM", r"Software\Policies\Google\Chrome", ("DnsOverHttpsMode", "DnsOverHttpsTemplates")),
    ("Edge", "HKCU", r"Software\Policies\Microsoft\Edge", ("DnsOverHttpsMode", "DnsOverHttpsTemplates")),
    ("Edge", "HKLM", r"Software\Policies\Microsoft\Edge", ("DnsOverHttpsMode", "DnsOverHttpsTemplates")),
    ("Firefox", "HKCU", r"Software\Policies\Mozilla\Firefox\DNSOverHTTPS", ("Enabled", "ProviderURL", "Locked")),
    ("Firefox", "HKLM", r"Software\Policies\Mozilla\Firefox\DNSOverHTTPS", ("Enabled", "ProviderURL", "Locked")),
)


def _read_windows_registry_value(root_name: str, path: str, value_name: str):
    if os.name != "nt":
        return None
    import winreg

    roots = {
        "HKCU": winreg.HKEY_CURRENT_USER,
        "HKLM": winreg.HKEY_LOCAL_MACHINE,
    }
    root = roots.get(root_name)
    if root is None:
        return None
    try:
        with winreg.OpenKey(root, path) as key:
            value, _value_type = winreg.QueryValueEx(key, value_name)
            return value
    except OSError:
        return None


def collect_dns_bypass_policy_snapshot(reader=None) -> list[dict[str, str]]:
    """Read known browser encrypted-DNS policy values, when present."""
    reader = reader or _read_windows_registry_value
    items: list[dict[str, str]] = []
    for browser, root_name, path, value_names in DNS_BYPASS_POLICY_LOCATIONS:
        for value_name in value_names:
            value = reader(root_name, path, value_name)
            if value is None or value == "":
                continue
            items.append({
                "browser": browser,
                "scope": root_name,
                "path": path,
                "name": value_name,
                "value": str(value),
            })
    return items


def dns_bypass_policy_status(name: str, value: str) -> str:
    """Classify a browser encrypted-DNS policy value for display."""
    clean_name = str(name or "").lower()
    clean_value = str(value or "").strip().lower()
    if clean_name == "dnsoverhttpsmode":
        if clean_value in {"secure", "automatic"}:
            return "encrypted DNS enabled or opportunistic; browser queries may bypass OS resolver expectations"
        if clean_value in {"off", "disabled", "false", "0"}:
            return "browser encrypted DNS is disabled by policy"
        return "browser encrypted DNS mode policy present; review the value"
    if clean_name in {"dnsoverhttpstemplates", "providerurl"}:
        return "custom encrypted DNS endpoint configured"
    if clean_name == "enabled":
        if clean_value in {"1", "true", "yes"}:
            return "Firefox DNS-over-HTTPS appears enabled by policy"
        if clean_value in {"0", "false", "no"}:
            return "Firefox DNS-over-HTTPS appears disabled by policy"
    if clean_name == "locked":
        return "Firefox DNS-over-HTTPS policy lock is configured"
    return "policy value present"


def format_dns_bypass_diagnostics(
    policy_snapshot: list[dict[str, str]] | None = None,
    env: dict[str, str] | None = None,
) -> str:
    """Render local DNS bypass diagnostics and limitation guidance."""
    env = env if env is not None else dict(os.environ)
    proxy_vars = [
        name for name in ("HTTPS_PROXY", "HTTP_PROXY", "ALL_PROXY", "https_proxy", "http_proxy", "all_proxy")
        if env.get(name)
    ]
    lines = [
        "DNS bypass diagnostics",
        "",
        "Hosts-file boundary:",
        "  Hosts entries affect name resolution paths that ask the OS resolver for a hostname.",
        "  They cannot enforce browser DoH/DoT/DoQ, VPN resolvers, remote proxy DNS, or hardcoded app resolvers.",
        "",
        "Browser encrypted-DNS policy signals:",
    ]
    if policy_snapshot:
        for item in policy_snapshot:
            status = dns_bypass_policy_status(item.get("name", ""), item.get("value", ""))
            lines.append(
                f"  - {item.get('browser')} {item.get('scope')} {item.get('name')}={item.get('value')} -> {status}"
            )
    else:
        lines.append("  (no managed Chrome, Edge, or Firefox encrypted-DNS policy values detected)")

    lines.extend(["", "Proxy environment signals:"])
    if proxy_vars:
        for name in proxy_vars:
            lines.append(f"  - {name} is set")
        lines.append("  Remote proxy DNS can resolve names outside the local hosts-file path.")
    else:
        lines.append("  (no common HTTP(S)/ALL proxy environment variables detected)")

    lines.extend([
        "",
        "Recommended follow-up:",
        "  - Use browser or enterprise policies to disable or pin encrypted DNS when local hosts enforcement matters.",
        "  - Enforce resolver policy at the router/firewall for devices or apps that ignore the OS resolver.",
        "  - Use the Windows DNS Client snapshot importer to inspect OS-resolver queries that are visible locally.",
        "  - Treat absence of detected policy as inconclusive; browsers and apps can still use settings or built-in resolvers.",
    ])
    return "\n".join(lines)


# Pi-hole FTL stores per-query rows with integer status codes. Codes 1,4,5,
# 6,7,8,9,10,11 all represent some form of block (upstream block, regex
# match, gravity, wildcard, external block, etc.). Codes 2,3,12 are allow
# decisions. See FTL commit history / pihole-FTL.db schema for the full
# enum.
FTL_BLOCKED_STATUS_CODES = (1, 4, 5, 6, 7, 8, 9, 10, 11)


def _sqlite_readonly_uri(path: str) -> str:
    """Build a SQLite ``file:`` URI that opens ``path`` read-only.

    SQLite URI paths must start with ``/`` for absolute paths. ``pathlib``
    on Windows yields ``C:/foo/bar.db`` (no leading slash), which SQLite
    treats as a relative URI fragment. Prepend a slash for absolute paths.
    """
    posix = pathlib.Path(path).as_posix()
    if not posix.startswith('/'):
        posix = '/' + posix
    return f"file:{posix}?mode=ro"


def parse_pihole_ftl_blocked_domains(sqlite_path: str, max_rows: int = 50_000) -> list[str]:
    """Return blocked domains from a Pi-hole FTL ``pihole-FTL.db`` file.

    Reads the ``queries`` table in read-only mode and keeps only rows where
    the query was blocked (see ``FTL_BLOCKED_STATUS_CODES``). Caller is
    expected to pass a valid path — we raise ``OSError`` subclasses or
    ``sqlite3.Error`` on failure.
    """
    import sqlite3

    if not os.path.isfile(sqlite_path):
        raise FileNotFoundError(f"FTL database not found: {sqlite_path}")

    uri = _sqlite_readonly_uri(sqlite_path)
    try:
        conn = sqlite3.connect(uri, uri=True)
    except sqlite3.Error as e:
        raise OSError(f"Could not open FTL DB: {e}") from e
    try:
        placeholders = ",".join("?" * len(FTL_BLOCKED_STATUS_CODES))
        cursor = conn.execute(
            f"SELECT DISTINCT domain FROM queries "
            f"WHERE status IN ({placeholders}) "
            f"ORDER BY timestamp DESC LIMIT ?",
            (*FTL_BLOCKED_STATUS_CODES, int(max_rows)),
        )
        rows = cursor.fetchall()
    finally:
        conn.close()

    out: list[str] = []
    seen: set[str] = set()
    for row in rows:
        domain = (row[0] or "").strip().lower().lstrip('.')
        if not domain or domain in seen:
            continue
        if not looks_like_domain(domain, allow_single_label=False):
            continue
        seen.add(domain)
        out.append(domain)
    return out


# AdGuard Home reason codes: only the "Filtered*" family represents an
# actual block decision. Earlier drafts of this parser also accepted 1
# (NotFilteredAllowList) and 9/10 (Rewrite/RewriteAutoHosts), which would
# have imported explicitly-allowed and rewrite-target domains as if they
# were blocks.
AGH_BLOCK_REASONS = frozenset({3, 4, 5, 7, 8, 12})


def parse_adguard_home_querylog(text: str) -> list[str]:
    """Extract blocked domains from an AdGuard Home ``querylog.json`` stream.

    AGH writes NDJSON (one JSON object per line). We pull the ``QH`` field
    (question hostname) from entries where ``Result.Reason`` is one of the
    Filtered* codes (``AGH_BLOCK_REASONS``). ``IsFiltered`` alone is accepted
    as a fallback for log versions where ``Reason`` is missing or 0. If
    ``text`` is a JSON array instead of NDJSON we walk it directly.
    """
    candidates: list[dict] = []
    text = text.strip()
    if not text:
        return []
    if text.startswith('['):
        try:
            loaded = json.loads(text)
            if isinstance(loaded, list):
                candidates = [item for item in loaded if isinstance(item, dict)]
        except ValueError:
            return []
    else:
        for line in text.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except ValueError:
                continue
            if isinstance(obj, dict):
                candidates.append(obj)

    out: list[str] = []
    seen: set[str] = set()
    for item in candidates:
        result_raw = item.get("Result")
        result = result_raw if isinstance(result_raw, dict) else {}
        reason = result.get("Reason")
        is_filtered = bool(result.get("IsFiltered"))
        if reason in AGH_BLOCK_REASONS:
            pass  # definitely a block
        elif reason is None and is_filtered:
            pass  # missing Reason but IsFiltered=true → legacy log, accept
        else:
            continue
        domain = (item.get("QH") or item.get("Q") or "").strip().lower().rstrip('.')
        if not domain or domain in seen:
            continue
        if not looks_like_domain(domain, allow_single_label=False):
            continue
        seen.add(domain)
        out.append(domain)
    return out


def _safe_migration_source_name(value: str, fallback: str) -> str:
    clean = re.sub(r"[\r\n\t\x00-\x1f\x7f]+", " ", str(value or "")).strip()
    clean = re.sub(r"\s+", " ", clean)
    if not clean:
        clean = fallback
    return clean[:140]


def _migration_lines_have_hosts_entries(lines: list[str]) -> bool:
    for line in lines:
        entries, _, _ = normalize_line_to_hosts_entries(line)
        if entries:
            return True
    return False


def _migration_record(source: str, kind: str, lines: list[str], path: str | None = None) -> dict | None:
    clean_lines = [str(line).rstrip("\r\n") for line in lines]
    if not _migration_lines_have_hosts_entries(clean_lines):
        return None
    record = {
        "source": _safe_migration_source_name(source, "Migration Import"),
        "kind": _safe_migration_source_name(kind, "hosts"),
        "lines": clean_lines,
    }
    if path:
        record["path"] = str(path)
    return record


def _read_migration_text_file(path: str | os.PathLike) -> tuple[list[str], int]:
    candidate = pathlib.Path(path)
    if not candidate.is_file():
        raise FileNotFoundError(f"Migration import file not found: {candidate}")
    size = candidate.stat().st_size
    if size > MIGRATION_IMPORT_MAX_FILE_BYTES:
        raise ValueError(
            f"{candidate.name} exceeds the migration import file cap "
            f"({_format_size_limit(MIGRATION_IMPORT_MAX_FILE_BYTES)})."
        )
    with candidate.open("rb") as f:
        raw = f.read(MIGRATION_IMPORT_MAX_FILE_BYTES + 1)
    if len(raw) > MIGRATION_IMPORT_MAX_FILE_BYTES:
        raise ValueError(
            f"{candidate.name} exceeds the migration import file cap "
            f"({_format_size_limit(MIGRATION_IMPORT_MAX_FILE_BYTES)})."
        )
    return decode_text_bytes(raw).splitlines(), len(raw)


def _iter_migration_files(directory: pathlib.Path, *, recursive: bool = False) -> list[pathlib.Path]:
    if not directory.is_dir():
        raise FileNotFoundError(f"Migration import directory not found: {directory}")
    if recursive:
        iterator = directory.rglob("*")
    else:
        iterator = directory.iterdir()
    files = sorted(path for path in iterator if path.is_file())
    if len(files) > MIGRATION_IMPORT_MAX_FILES:
        raise ValueError(
            f"{directory} contains {len(files):,} files; migration imports are capped at "
            f"{MIGRATION_IMPORT_MAX_FILES:,} files."
        )
    return files


def _json_dicts(value):
    if isinstance(value, dict):
        yield value
        for child in value.values():
            yield from _json_dicts(child)
    elif isinstance(value, list):
        for child in value:
            yield from _json_dicts(child)


def _switchhosts_title_map(value) -> dict[str, str]:
    titles: dict[str, str] = {}
    for item in _json_dicts(value):
        item_id = str(item.get("id") or "").strip()
        if not item_id:
            continue
        title = item.get("title") or item.get("name") or item.get("url") or ""
        clean_title = _safe_migration_source_name(str(title), "")
        if clean_title:
            titles.setdefault(item_id, clean_title)
    return titles


def parse_switchhosts_export_text(text: str) -> list[dict]:
    """Extract hosts records from SwitchHosts v3/v4 JSON exports."""
    if not text.strip():
        raise ValueError("SwitchHosts export is empty.")
    try:
        payload = json.loads(text)
    except json.JSONDecodeError as e:
        raise ValueError(f"SwitchHosts export JSON is invalid: {e}") from e
    if not isinstance(payload, dict):
        raise ValueError("SwitchHosts export must be a JSON object.")
    version = payload.get("version")
    if not isinstance(version, list) or not version:
        raise ValueError("SwitchHosts export is missing its version array.")
    try:
        major_version = int(version[0])
    except (TypeError, ValueError) as e:
        raise ValueError("SwitchHosts export version is invalid.") from e
    if major_version > 4:
        raise ValueError(f"SwitchHosts export version {major_version} is newer than this importer understands.")

    search_root = payload if major_version == 3 else payload.get("data")
    if not isinstance(search_root, (dict, list)):
        raise ValueError("SwitchHosts export does not contain an importable data object.")

    title_map = _switchhosts_title_map(payload)
    records: list[dict] = []
    seen: set[tuple[str, str]] = set()
    for item in _json_dicts(search_root):
        content = item.get("content")
        if not isinstance(content, str) or not content.strip():
            continue
        item_id = str(item.get("id") or "").strip()
        title = (
            title_map.get(item_id)
            or _safe_migration_source_name(str(item.get("title") or item.get("name") or item_id), "hosts")
        )
        item_type = _safe_migration_source_name(
            str(item.get("type") or item.get("where") or ("remote" if item.get("url") else "local")),
            "local",
        )
        source = f"SwitchHosts {item_type}: {title}"
        lines = content.splitlines()
        dedupe_key = (source, "\n".join(lines))
        if dedupe_key in seen:
            continue
        seen.add(dedupe_key)
        record = _migration_record(source, item_type, lines)
        if record:
            records.append(record)
    return records


def _append_migration_file_record(
    records: list[dict],
    source: str,
    kind: str,
    path: pathlib.Path,
    total_bytes: int,
) -> int:
    lines, byte_count = _read_migration_text_file(path)
    total_bytes += byte_count
    if total_bytes > MIGRATION_IMPORT_MAX_TOTAL_BYTES:
        raise ValueError(
            f"Migration import exceeds the total cap "
            f"({_format_size_limit(MIGRATION_IMPORT_MAX_TOTAL_BYTES)})."
        )
    record = _migration_record(source, kind, lines, str(path))
    if record:
        records.append(record)
    return total_bytes


def parse_gas_mask_archive_path(path: str) -> list[dict]:
    """Read Gas Mask Local/Remote/Combined archive folders as hosts records."""
    root = pathlib.Path(path)
    records: list[dict] = []
    total_bytes = 0
    if root.is_file():
        total_bytes = _append_migration_file_record(records, f"Gas Mask: {root.stem}", "gasmask", root, total_bytes)
        return records
    if not root.is_dir():
        raise FileNotFoundError(f"Gas Mask folder not found: {path}")

    known_dirs = {
        "Local": root / "Local",
        "Remote": root / "Remote",
        "Combined": root / "Combined",
    }
    has_known_layout = any(candidate.is_dir() for candidate in known_dirs.values())
    host_registry: dict[tuple[str, str], dict] = {}

    if has_known_layout:
        for type_name in ("Local", "Remote"):
            directory = known_dirs[type_name]
            if not directory.is_dir():
                continue
            for file_path in _iter_migration_files(directory):
                before = len(records)
                total_bytes = _append_migration_file_record(
                    records,
                    f"Gas Mask {type_name}: {file_path.stem}",
                    type_name.lower(),
                    file_path,
                    total_bytes,
                )
                if len(records) > before:
                    host_registry[(type_name, file_path.stem)] = records[-1]

        combined_dir = known_dirs["Combined"]
        if combined_dir.is_dir():
            for file_path in _iter_migration_files(combined_dir):
                ref_lines, byte_count = _read_migration_text_file(file_path)
                total_bytes += byte_count
                if total_bytes > MIGRATION_IMPORT_MAX_TOTAL_BYTES:
                    raise ValueError(
                        f"Migration import exceeds the total cap "
                        f"({_format_size_limit(MIGRATION_IMPORT_MAX_TOTAL_BYTES)})."
                    )
                expanded_lines: list[str] = []
                for ref in ref_lines:
                    ref = ref.strip()
                    if not ref or "/" not in ref:
                        continue
                    ref_type, ref_name = ref.split("/", 1)
                    linked = host_registry.get((ref_type, ref_name))
                    if not linked:
                        continue
                    if expanded_lines:
                        expanded_lines.append("")
                    expanded_lines.extend([f"# Hosts File: {ref_name}", ""])
                    expanded_lines.extend(linked["lines"])
                if not expanded_lines and _migration_lines_have_hosts_entries(ref_lines):
                    expanded_lines = ref_lines
                record = _migration_record(
                    f"Gas Mask Combined: {file_path.stem}",
                    "combined",
                    expanded_lines,
                    str(file_path),
                )
                if record:
                    records.append(record)
    else:
        for file_path in _iter_migration_files(root):
            total_bytes = _append_migration_file_record(
                records,
                f"Gas Mask: {file_path.stem}",
                "gasmask",
                file_path,
                total_bytes,
            )

    return records


def parse_hostsfileeditor_archive_path(path: str) -> list[dict]:
    """Read HostsFileEditor archive files, which are plain hosts text files."""
    root = pathlib.Path(path)
    records: list[dict] = []
    total_bytes = 0
    if root.is_file():
        total_bytes = _append_migration_file_record(
            records,
            f"HostsFileEditor archive: {root.name}",
            "hostsfileeditor",
            root,
            total_bytes,
        )
        return records
    if not root.is_dir():
        raise FileNotFoundError(f"HostsFileEditor archive path not found: {path}")
    for file_path in _iter_migration_files(root):
        total_bytes = _append_migration_file_record(
            records,
            f"HostsFileEditor archive: {file_path.name}",
            "hostsfileeditor",
            file_path,
            total_bytes,
        )
    return records


def apply_find_replace(
    lines: list[str],
    pattern: str,
    replacement: str,
    *,
    use_regex: bool = False,
    case_sensitive: bool = False,
) -> tuple[list[str], int]:
    """Plain-text or regex find/replace across all lines. Returns (new_lines, count)."""
    if not pattern:
        return list(lines), 0
    if use_regex:
        try:
            flags = 0 if case_sensitive else re.IGNORECASE
            compiled = re.compile(pattern, flags)
        except re.error as e:
            raise ValueError(f"Invalid regex: {e}") from e
        new_lines: list[str] = []
        count = 0
        for line in lines:
            new_line, n = compiled.subn(replacement, line)
            count += n
            new_lines.append(new_line)
        return new_lines, count

    # Literal replace: case-insensitive impl hand-rolled so we preserve
    # original case of *surrounding* text even when matching case-folded.
    if case_sensitive:
        new_lines = []
        count = 0
        for line in lines:
            n = line.count(pattern)
            if n:
                line = line.replace(pattern, replacement)
                count += n
            new_lines.append(line)
        return new_lines, count

    needle = pattern.lower()
    new_lines = []
    count = 0
    for line in lines:
        lowered = line.lower()
        if needle not in lowered:
            new_lines.append(line)
            continue
        # Walk indices to replace in the original case.
        rebuilt: list[str] = []
        i = 0
        while i < len(line):
            j = lowered.find(needle, i)
            if j < 0:
                rebuilt.append(line[i:])
                break
            rebuilt.append(line[i:j])
            rebuilt.append(replacement)
            count += 1
            i = j + len(pattern)
        new_lines.append(''.join(rebuilt))
    return new_lines, count


def discover_import_sections(lines: list[str]) -> list[dict]:
    """Locate every ``# --- {Raw|Normalized} Import Start/End: NAME ---`` block.

    Returns a list of ``{"name", "mode", "start", "end"}`` (inclusive indices).
    Unmatched start markers are skipped silently so a malformed editor can't
    crash the UI - the caller just won't see that block as a whole section.
    """
    sections: list[dict] = []
    pending: dict | None = None
    for idx, line in enumerate(lines):
        start_match = IMPORT_START_RE.match(line.rstrip())
        if start_match:
            pending = {
                "name": start_match.group(2).strip(),
                "mode": start_match.group(1).strip(),
                "start": idx,
            }
            continue
        if pending is None:
            continue
        end_match = IMPORT_END_RE.match(line.rstrip())
        if end_match and end_match.group(2).strip() == pending["name"]:
            pending["end"] = idx
            sections.append(pending)
            pending = None
    return sections


def remove_import_section(lines: list[str], section: dict) -> list[str]:
    """Delete an entire import block including its Start/End markers."""
    start = section.get("start", -1)
    end = section.get("end", -1)
    if start < 0 or end < start or end >= len(lines):
        return list(lines)
    return lines[:start] + lines[end + 1 :]


def _provenance_event_domains(event: dict) -> set[str]:
    domains: set[str] = set()
    if not isinstance(event, dict):
        return domains
    value = event.get("domain")
    if value:
        domains.add(str(value).strip().lower().lstrip("."))
    values = event.get("domains")
    if isinstance(values, (list, tuple)):
        for item in values:
            clean = str(item).strip().lower().lstrip(".")
            if clean:
                domains.add(clean)
    return {domain for domain in domains if domain}


def _provenance_event_matches_domain(event: dict, domain: str) -> bool:
    clean_domain = str(domain or "").strip().lower().lstrip(".")
    if not clean_domain:
        return False
    for event_domain in _provenance_event_domains(event):
        if (
            clean_domain == event_domain
            or clean_domain.endswith("." + event_domain)
            or event_domain.endswith("." + clean_domain)
        ):
            return True
    return False


def _normalize_provenance_filter_text(value) -> str:
    return " ".join(str(value or "").strip().split())


def _split_provenance_filter_values(value) -> list[str]:
    if value is None:
        return []
    if isinstance(value, str):
        raw_values = re.split(r"[,;]", value)
    elif isinstance(value, (list, tuple, set)):
        raw_values = list(value)
    else:
        raw_values = [value]
    return [
        _normalize_provenance_filter_text(item).lower()
        for item in raw_values
        if _normalize_provenance_filter_text(item)
    ]


def _normalize_provenance_kind_filter(value) -> set[str]:
    values = _split_provenance_filter_values(value)
    if not values or any(item in {"all", "*"} for item in values):
        return set()
    valid = {item for item in values if item in PROVENANCE_EVENT_KINDS}
    return valid or {"__invalid__"}


def _parse_provenance_filter_timestamp(value, *, end_of_day: bool = False) -> float | None:
    text = _normalize_provenance_filter_text(value)
    if not text:
        return None
    if text.endswith("Z"):
        text = text[:-1] + "+00:00"
    try:
        if re.fullmatch(r"\d{4}-\d{2}-\d{2}", text):
            parsed_date = datetime.date.fromisoformat(text)
            parsed_time = datetime.time.max if end_of_day else datetime.time.min
            parsed = datetime.datetime.combine(parsed_date, parsed_time)
        else:
            parsed = datetime.datetime.fromisoformat(text)
    except (TypeError, ValueError):
        return None
    try:
        return parsed.timestamp()
    except (OSError, OverflowError, ValueError):
        return None


def _provenance_event_timestamp_epoch(event: dict) -> float | None:
    if not isinstance(event, dict):
        return None
    return _parse_provenance_filter_timestamp(event.get("ts"))


def _provenance_event_text(event: dict) -> str:
    if not isinstance(event, dict):
        return ""
    parts = [
        event.get("ts", ""),
        event.get("kind", ""),
        event.get("user", ""),
        event.get("domain", ""),
        event.get("source", ""),
        event.get("note", ""),
        event.get("app_version", ""),
    ]
    domains = event.get("domains")
    if isinstance(domains, (list, tuple, set)):
        parts.extend(str(item) for item in domains)
    elif domains:
        parts.append(str(domains))
    return " ".join(str(part) for part in parts if part).lower()


def _serialize_provenance_event(event: dict) -> dict:
    if not isinstance(event, dict):
        return {}
    out = {}
    for key in PROVENANCE_EXPORT_FIELDS:
        if key not in event:
            continue
        value = event.get(key)
        if isinstance(value, (list, tuple, set)):
            out[key] = [str(item) for item in value]
        elif value is None:
            out[key] = ""
        else:
            out[key] = str(value)
    for key in sorted(event):
        if key in out or key in PROVENANCE_EXPORT_FIELDS:
            continue
        value = event.get(key)
        if isinstance(value, (list, tuple, set)):
            out[key] = [str(item) for item in value]
        elif isinstance(value, (str, int, float, bool)) or value is None:
            out[key] = value
        else:
            out[key] = str(value)
    return out


def filter_provenance_events(
    events: list[dict] | None,
    *,
    kind=None,
    domain: str = "",
    source: str = "",
    user: str = "",
    text: str = "",
    since: str = "",
    until: str = "",
    limit: int = 0,
) -> list[dict]:
    """Filter local provenance events without mutating or reading the log."""
    kind_filter = _normalize_provenance_kind_filter(kind)
    domain_filter = _normalize_provenance_filter_text(domain).lower().lstrip(".")
    source_filter = _normalize_provenance_filter_text(source).lower()
    user_filter = _normalize_provenance_filter_text(user).lower()
    text_filter = _normalize_provenance_filter_text(text).lower()
    since_epoch = _parse_provenance_filter_timestamp(since)
    until_epoch = _parse_provenance_filter_timestamp(until, end_of_day=True)

    filtered: list[dict] = []
    for event in events or []:
        if not isinstance(event, dict):
            continue
        event_kind = str(event.get("kind", ""))
        if event_kind not in PROVENANCE_EVENT_KINDS:
            continue
        if kind_filter and event_kind not in kind_filter:
            continue
        if domain_filter:
            event_domains = " ".join(sorted(_provenance_event_domains(event))).lower()
            if "." in domain_filter:
                if not _provenance_event_matches_domain(event, domain_filter):
                    continue
            elif domain_filter not in event_domains:
                continue
        if source_filter and source_filter not in str(event.get("source", "")).lower():
            continue
        if user_filter and user_filter not in str(event.get("user", "")).lower():
            continue
        if text_filter and text_filter not in _provenance_event_text(event):
            continue
        if since_epoch is not None or until_epoch is not None:
            event_epoch = _provenance_event_timestamp_epoch(event)
            if event_epoch is None:
                continue
            if since_epoch is not None and event_epoch < since_epoch:
                continue
            if until_epoch is not None and event_epoch > until_epoch:
                continue
        filtered.append(event)

    if limit and limit > 0 and len(filtered) > limit:
        return filtered[-limit:]
    return filtered


def build_provenance_log_report(
    events: list[dict] | None,
    filters: dict | None = None,
    *,
    display_limit: int = PROVENANCE_LOG_DISPLAY_LIMIT,
) -> dict:
    """Build a filtered provenance-log report for the GUI and tests."""
    filters = filters or {}
    active_filters = {
        "kind": _normalize_provenance_filter_text(filters.get("kind", "")) or "all",
        "domain": _normalize_provenance_filter_text(filters.get("domain", "")),
        "source": _normalize_provenance_filter_text(filters.get("source", "")),
        "user": _normalize_provenance_filter_text(filters.get("user", "")),
        "text": _normalize_provenance_filter_text(filters.get("text", "")),
        "since": _normalize_provenance_filter_text(filters.get("since", "")),
        "until": _normalize_provenance_filter_text(filters.get("until", "")),
    }
    source_events = [
        event for event in (events or [])
        if isinstance(event, dict) and event.get("kind") in PROVENANCE_EVENT_KINDS
    ]
    filtered_events = filter_provenance_events(
        source_events,
        kind=active_filters["kind"],
        domain=active_filters["domain"],
        source=active_filters["source"],
        user=active_filters["user"],
        text=active_filters["text"],
        since=active_filters["since"],
        until=active_filters["until"],
    )
    if display_limit and display_limit > 0:
        display_events = filtered_events[-display_limit:]
    else:
        display_events = list(filtered_events)
    kind_counts = {kind: 0 for kind in sorted(PROVENANCE_EVENT_KINDS)}
    for event in filtered_events:
        kind_counts[event.get("kind", "")] = kind_counts.get(event.get("kind", ""), 0) + 1
    return {
        "filters": active_filters,
        "total_events": len(source_events),
        "matched_count": len(filtered_events),
        "displayed_count": len(display_events),
        "events": display_events,
        "filtered_events": filtered_events,
        "kind_counts": kind_counts,
        "display_limit": display_limit,
    }


def format_provenance_log_report(report: dict) -> str:
    """Render a filtered provenance-log report as fixed-width text."""
    if not report:
        return "No provenance report available."
    filters = report.get("filters") or {}
    filter_parts = []
    for key in ("kind", "domain", "source", "user", "text", "since", "until"):
        value = filters.get(key, "")
        if value and not (key == "kind" and value == "all"):
            filter_parts.append(f"{key}={value}")
    lines = [
        f"Total events in current log: {report.get('total_events', 0):,}",
        f"Matched events: {report.get('matched_count', 0):,}",
        f"Displayed events: {report.get('displayed_count', 0):,}",
        f"Filters: {', '.join(filter_parts) if filter_parts else '(none)'}",
        "",
    ]
    kind_counts = report.get("kind_counts") or {}
    if kind_counts:
        count_text = ", ".join(
            f"{kind}={count:,}" for kind, count in sorted(kind_counts.items()) if count
        )
        lines.append(f"Matched by kind: {count_text or '(none)'}")
        lines.append("")
    if report.get("matched_count", 0) > report.get("displayed_count", 0):
        lines.append(
            f"Showing the most recent {report.get('displayed_count', 0):,} matching events. "
            "Export includes all matching events."
        )
        lines.append("")

    events = report.get("events") or []
    if not events:
        lines.append("No provenance events match the current filters.")
        return "\n".join(lines)

    lines.append(f"{'When':<20}  {'Kind':<16}  {'User':<12}  {'Source':<16}  Domain / note")
    lines.append("-" * 112)
    for event in events:
        ts = str(event.get("ts", ""))[:19]
        kind = str(event.get("kind", ""))
        user = (str(event.get("user", "")) or "-")[:12]
        source = (str(event.get("source", "")) or "-")[:16]
        domains = event.get("domains")
        if isinstance(domains, (list, tuple)):
            domain_note = ",".join(str(item) for item in domains)
        else:
            domain_note = str(domains or "")
        note = str(event.get("domain") or event.get("note") or domain_note or "")
        lines.append(f"{ts:<20}  {kind:<16}  {user:<12}  {source:<16}  {note[:80]}")
    return "\n".join(lines)


def export_provenance_events(events: list[dict] | None, export_format: str = "jsonl") -> str:
    """Serialize provenance events for user-directed export."""
    fmt = str(export_format or "jsonl").strip().lower()
    if fmt not in PROVENANCE_EXPORT_FORMATS:
        raise ValueError(f"Unsupported provenance export format: {export_format}")
    rows = [_serialize_provenance_event(event) for event in (events or []) if isinstance(event, dict)]
    if fmt == "json":
        payload = {
            "schema": PROVENANCE_EXPORT_SCHEMA,
            "exported_at": datetime.datetime.now().isoformat(timespec="seconds"),
            "event_count": len(rows),
            "events": rows,
        }
        return json.dumps(payload, indent=2, ensure_ascii=False)
    if fmt == "jsonl":
        return "\n".join(json.dumps(row, ensure_ascii=False) for row in rows) + ("\n" if rows else "")

    output = io.StringIO()
    writer = csv.DictWriter(output, fieldnames=list(PROVENANCE_EXPORT_FIELDS), extrasaction="ignore")
    writer.writeheader()
    for row in rows:
        csv_row = {}
        for field in PROVENANCE_EXPORT_FIELDS:
            value = row.get(field, "")
            if isinstance(value, (list, tuple, set)):
                csv_row[field] = json.dumps([str(item) for item in value], ensure_ascii=False)
            elif value is None:
                csv_row[field] = ""
            else:
                csv_row[field] = str(value)
        writer.writerow(csv_row)
    return output.getvalue()


def build_entry_provenance_report(
    lines: list[str],
    line_no: int,
    source_corpus: dict[str, object] | None = None,
    provenance_events: list[dict] | None = None,
) -> dict:
    """Explain where one editor line appears to come from."""
    line_count = len(lines or [])
    report = {
        "valid": False,
        "error": "",
        "line_no": line_no,
        "line_count": line_count,
        "raw_line": "",
        "section": None,
        "line_role": "outside_imports",
        "entries": [],
    }
    if line_no < 1 or line_no > line_count:
        report["error"] = f"Line {line_no} is outside the current editor range."
        return report

    idx = line_no - 1
    raw_line = lines[idx]
    parsed, transformed = parse_hosts_line_entries(raw_line)
    sections = discover_import_sections(lines)
    section_info = None
    line_role = "outside_imports"
    for section in sections:
        start = int(section.get("start", -1))
        end = int(section.get("end", -1))
        if start <= idx <= end:
            section_info = {
                "name": section.get("name", ""),
                "mode": section.get("mode", ""),
                "start_line": start + 1,
                "end_line": end + 1,
            }
            if idx == start:
                line_role = "import_start_marker"
            elif idx == end:
                line_role = "import_end_marker"
            else:
                line_role = "inside_import"
            break

    events = provenance_events or []
    entry_reports = []
    for normalized, domain, is_block in parsed:
        matching_events = [
            event for event in events
            if isinstance(event, dict) and _provenance_event_matches_domain(event, domain)
        ]
        entry_reports.append({
            "normalized": normalized,
            "domain": domain,
            "is_block": is_block,
            "source_matches": find_sources_containing_domain(domain, source_corpus or {}),
            "provenance_events": matching_events[-10:],
        })

    report.update({
        "valid": True,
        "raw_line": raw_line,
        "section": section_info,
        "line_role": line_role,
        "entries": entry_reports,
        "transformed_by_parser": transformed,
    })
    return report


def format_entry_provenance_report(report: dict) -> str:
    """Render a line-level provenance report for a read-only dialog."""
    if not report or not report.get("valid"):
        return str((report or {}).get("error") or "No line selected.")

    line_role_labels = {
        "outside_imports": "outside import markers / manual or pre-existing content",
        "inside_import": "inside imported source block",
        "import_start_marker": "import section start marker",
        "import_end_marker": "import section end marker",
    }
    lines = [
        f"Line: {report.get('line_no')} of {report.get('line_count')}",
        f"Role: {line_role_labels.get(report.get('line_role'), report.get('line_role'))}",
        "",
        "Raw line:",
        str(report.get("raw_line", "")) or "(blank)",
        "",
    ]

    section = report.get("section")
    if section:
        lines.extend([
            "Import section:",
            f"  Name: {section.get('name')}",
            f"  Mode: {section.get('mode')}",
            f"  Lines: {section.get('start_line')} to {section.get('end_line')}",
            "",
        ])
    else:
        lines.extend(["Import section:", "  (none detected)", ""])

    entries = report.get("entries") or []
    lines.append("Parsed entries:")
    if not entries:
        lines.append("  (no parseable hosts entries on this line)")
    for entry in entries:
        kind = "blocking" if entry.get("is_block") else "custom mapping"
        lines.append(f"  - {entry.get('domain')} ({kind})")
        lines.append(f"    Normalized: {entry.get('normalized')}")
        source_matches = entry.get("source_matches") or []
        if source_matches:
            lines.append(f"    Fetched source matches: {', '.join(source_matches)}")
        else:
            lines.append("    Fetched source matches: none in current session")
        event_rows = entry.get("provenance_events") or []
        if event_rows:
            lines.append("    Local provenance events:")
            for event in event_rows:
                ts = str(event.get("ts", ""))[:19] or "-"
                kind_label = str(event.get("kind", ""))
                source = str(event.get("source", "")) or "-"
                domains_value = event.get("domains", [])
                if isinstance(domains_value, (list, tuple)):
                    domains_note = ",".join(str(item) for item in domains_value)
                else:
                    domains_note = str(domains_value or "")
                note = event.get("note") or event.get("domain") or domains_note
                lines.append(f"      {ts}  {kind_label:<16} source={source}  {note}")
        else:
            lines.append("    Local provenance events: none")
    lines.extend([
        "",
        "Basis: current editor line, import-section markers, fetched source corpus, and local provenance JSONL.",
    ])
    return "\n".join(lines)


def format_relative_time(iso_timestamp: str, now: float | None = None) -> str:
    """Render an ISO 8601 timestamp as a short relative string.

    Used in source tooltips to show "Last fetched: 3 hours ago" without
    requiring the user to parse a timestamp. Returns an empty string on
    invalid input so callers can short-circuit cleanly. ``now`` is a unix
    epoch override exposed so tests can pin the reference point.
    """
    if not iso_timestamp:
        return ""
    try:
        when = datetime.datetime.fromisoformat(iso_timestamp)
    except (TypeError, ValueError):
        return ""

    if now is not None:
        reference = datetime.datetime.fromtimestamp(now, when.tzinfo) if when.tzinfo else datetime.datetime.fromtimestamp(now)
    else:
        reference = datetime.datetime.now(when.tzinfo) if when.tzinfo else datetime.datetime.now()
    delta_seconds = (reference - when).total_seconds()
    if delta_seconds < 0:
        return "just now"
    if delta_seconds < 60:
        return "just now"
    if delta_seconds < 3600:
        minutes = int(delta_seconds // 60)
        return f"{minutes} minute{'s' if minutes != 1 else ''} ago"
    if delta_seconds < 86400:
        hours = int(delta_seconds // 3600)
        return f"{hours} hour{'s' if hours != 1 else ''} ago"
    if delta_seconds < 86400 * 30:
        days = int(delta_seconds // 86400)
        return f"{days} day{'s' if days != 1 else ''} ago"
    if delta_seconds < 86400 * 365:
        months = int(delta_seconds // (86400 * 30))
        return f"{months} month{'s' if months != 1 else ''} ago"
    years = int(delta_seconds // (86400 * 365))
    return f"{years} year{'s' if years != 1 else ''} ago"


def is_loopback_api_host(host: str) -> bool:
    host = str(host or "").strip().strip("[]").lower()
    if host == "localhost":
        return True
    try:
        return ipaddress.ip_address(host).is_loopback
    except ValueError:
        return False


def sanitize_local_api_token(token: str) -> str:
    token = str(token or "").strip()
    if len(token) < LOCAL_API_MIN_TOKEN_LENGTH:
        raise ValueError(f"Local API bearer token must be at least {LOCAL_API_MIN_TOKEN_LENGTH} characters.")
    if _contains_control_chars(token):
        raise ValueError("Local API bearer token contains control characters.")
    return token


def local_api_authorization_valid(headers, expected_token: str) -> bool:
    try:
        expected = sanitize_local_api_token(expected_token)
    except ValueError:
        return False
    header_value = ""
    if headers is not None:
        try:
            header_value = headers.get("Authorization", "")
        except AttributeError:
            header_value = ""
    prefix = "Bearer "
    if not isinstance(header_value, str) or not header_value.startswith(prefix):
        return False
    supplied = header_value[len(prefix):].strip()
    return secrets.compare_digest(supplied, expected)


def build_local_api_status_payload(hosts_path: str | None = None) -> dict:
    return {
        "schema": LOCAL_API_SCHEMA,
        "app": APP_NAME,
        "version": APP_VERSION,
        "hosts_path": hosts_path or _default_hosts_file_path(),
        "loopback_only": True,
        "auth": "bearer",
        "write_endpoints_enabled": False,
        "endpoints": [
            {"method": "GET", "path": "/v1/status", "writes_hosts": False},
            {"method": "POST", "path": "/v1/clean-preview", "writes_hosts": False},
        ],
    }


def _local_api_lines_from_payload(payload: dict) -> list[str]:
    if "lines" in payload:
        lines = payload.get("lines")
        if not isinstance(lines, list):
            raise ValueError("lines must be a list of strings.")
        return [str(line).rstrip("\r\n") for line in lines]
    text = payload.get("text", "")
    if not isinstance(text, str):
        raise ValueError("text must be a string when lines is not supplied.")
    return text.splitlines()


def _local_api_whitelist_set(payload: dict) -> set[str]:
    whitelist = payload.get("whitelist", "")
    if isinstance(whitelist, list):
        whitelist_lines = [str(line) for line in whitelist]
    elif isinstance(whitelist, str):
        whitelist_lines = whitelist.splitlines()
    elif whitelist in (None, ""):
        whitelist_lines = []
    else:
        raise ValueError("whitelist must be a string or list of strings.")
    whitelist_set: set[str] = set()
    for line in whitelist_lines:
        _entries, domains, _transformed = normalize_line_to_hosts_entries(line)
        whitelist_set.update(domain.lstrip(".") for domain in domains)
    return whitelist_set


def build_local_api_clean_preview_payload(payload: dict) -> dict:
    if not isinstance(payload, dict):
        raise ValueError("Request body must be a JSON object.")
    lines = _local_api_lines_from_payload(payload)
    whitelist_set = _local_api_whitelist_set(payload)
    pinned = set(sanitize_pinned_domains(payload.get("pinned_domains", [])))
    cleaned, stats = _get_canonical_cleaned_output_and_stats(lines, whitelist_set, pinned)
    return {
        "schema": LOCAL_API_SCHEMA,
        "operation": "clean-preview",
        "writes_hosts": False,
        "input_line_count": len(lines),
        "cleaned_line_count": len(cleaned),
        "stats": stats,
        "cleaned_lines": cleaned,
    }


def sanitize_block_page_bind_host(host: str | None = None) -> str:
    value = str(host or BLOCK_PAGE_DEFAULT_HOST).strip()
    if not is_loopback_api_host(value):
        raise ValueError("Block page server host must be loopback-only: localhost, 127.0.0.1, or ::1.")
    return value


def sanitize_block_page_port(port: int | str | None = None) -> int:
    try:
        value = int(BLOCK_PAGE_DEFAULT_PORT if port is None else port)
    except (TypeError, ValueError):
        raise ValueError("Block page server port must be an integer.")
    if value < 0 or value > 65535:
        raise ValueError("Block page server port must be between 0 and 65535.")
    return value


def sanitize_block_page_text(value: str | None, default: str, label: str) -> str:
    text = str(default if value in (None, "") else value).strip()
    if not text:
        text = default
    if _contains_control_chars(text):
        raise ValueError(f"Block page {label} must not contain control characters.")
    if len(text) > BLOCK_PAGE_MAX_TEXT_LENGTH:
        raise ValueError(f"Block page {label} must be {BLOCK_PAGE_MAX_TEXT_LENGTH} characters or fewer.")
    return text


def sanitize_block_page_support_url(url: str | None = None) -> str:
    value = str(url or "").strip()
    if not value:
        return ""
    if _contains_control_chars(value) or len(value) > BLOCK_PAGE_MAX_URL_LENGTH:
        raise ValueError("Block page support URL is too long or contains control characters.")
    parsed = urllib.parse.urlparse(value)
    if parsed.scheme not in {"http", "https"} or not parsed.netloc:
        raise ValueError("Block page support URL must be an absolute http or https URL.")
    return value


def _block_page_requested_host(headers: dict | http.client.HTTPMessage | None) -> str:
    raw_host = ""
    if headers is not None:
        try:
            raw_host = headers.get("Host", "")
        except AttributeError:
            raw_host = ""
    raw_host = str(raw_host or "").strip()
    if _contains_control_chars(raw_host):
        raw_host = ""
    return raw_host[:255]


def _block_page_domain_from_host(host_header: str) -> str:
    host_header = str(host_header or "").strip()
    if not host_header:
        return ""
    if host_header.startswith("[") and "]" in host_header:
        candidate = host_header[1:host_header.index("]")]
    else:
        candidate = host_header.split(":", 1)[0]
    candidate = candidate.strip().lower().rstrip(".")
    if looks_like_domain(candidate, allow_single_label=True):
        return candidate
    return ""


def sanitize_block_page_request_path(path: str | None = None) -> str:
    raw_path = str(path or "/").strip()
    if not raw_path:
        raw_path = "/"
    if _contains_control_chars(raw_path):
        raw_path = "/"
    parsed = urllib.parse.urlsplit(raw_path)
    display_path = parsed.path or "/"
    if parsed.query:
        display_path = f"{display_path}?{parsed.query}"
    if not display_path.startswith("/"):
        display_path = f"/{display_path}"
    return display_path[:1024]


def build_block_page_server_config(
    host: str | None = None,
    port: int | str | None = None,
    title: str | None = None,
    message: str | None = None,
    support_url: str | None = None,
) -> dict:
    sanitized_host = sanitize_block_page_bind_host(host)
    sanitized_port = sanitize_block_page_port(port)
    return {
        "schema": BLOCK_PAGE_SCHEMA,
        "app": APP_NAME,
        "version": APP_VERSION,
        "host": sanitized_host,
        "port": sanitized_port,
        "url": f"http://{sanitized_host}:{sanitized_port}/",
        "loopback_only": True,
        "serves_all_routes": True,
        "health_path": BLOCK_PAGE_HEALTH_PATH,
        "writes_hosts_file": False,
        "https_supported": False,
        "requires_admin_for_port_80": sanitized_port == 80,
        "title": sanitize_block_page_text(title, BLOCK_PAGE_DEFAULT_TITLE, "title"),
        "message": sanitize_block_page_text(message, BLOCK_PAGE_DEFAULT_MESSAGE, "message"),
        "support_url": sanitize_block_page_support_url(support_url),
        "warnings": [
            "The server is HTTP-only; HTTPS blocked sites will show browser certificate or TLS errors unless the operator adds a trusted TLS front end.",
            "The hosts file can map names to an IP address but cannot redirect URL paths or ports.",
            "The server binds to loopback only; LAN/router custom block pages need an explicitly managed web server and DNS policy.",
            "The server does not write the Windows hosts file or modify source lists.",
        ],
        "references": list(BLOCK_PAGE_REFERENCES),
    }


def build_block_page_request_context(
    path: str | None = None,
    headers: dict | http.client.HTTPMessage | None = None,
    *,
    title: str | None = None,
    message: str | None = None,
    support_url: str | None = None,
    now: datetime.datetime | None = None,
) -> dict:
    requested_host = _block_page_requested_host(headers)
    requested_path = sanitize_block_page_request_path(path)
    requested_domain = _block_page_domain_from_host(requested_host)
    timestamp = now or datetime.datetime.now(datetime.timezone.utc)
    return {
        "schema": BLOCK_PAGE_SCHEMA,
        "app": APP_NAME,
        "version": APP_VERSION,
        "generated_at": timestamp.isoformat(),
        "title": sanitize_block_page_text(title, BLOCK_PAGE_DEFAULT_TITLE, "title"),
        "message": sanitize_block_page_text(message, BLOCK_PAGE_DEFAULT_MESSAGE, "message"),
        "support_url": sanitize_block_page_support_url(support_url),
        "requested_host": requested_host,
        "requested_domain": requested_domain,
        "requested_path": requested_path,
        "writes_hosts_file": False,
        "https_supported": False,
        "references": list(BLOCK_PAGE_REFERENCES),
    }


def render_block_page_html(context: dict) -> str:
    if not isinstance(context, dict):
        raise ValueError("Block page context must be a dictionary.")
    title = html.escape(str(context.get("title") or BLOCK_PAGE_DEFAULT_TITLE))
    app = html.escape(str(context.get("app") or APP_NAME))
    message = html.escape(str(context.get("message") or BLOCK_PAGE_DEFAULT_MESSAGE))
    requested_host = html.escape(str(context.get("requested_host") or "(no Host header)"))
    requested_domain = html.escape(str(context.get("requested_domain") or "(unknown)"))
    requested_path = html.escape(str(context.get("requested_path") or "/"))
    generated_at = html.escape(str(context.get("generated_at") or ""))
    support_url = str(context.get("support_url") or "").strip()
    support_html = ""
    if support_url:
        escaped_url = html.escape(support_url, quote=True)
        support_html = f'<p><a href="{escaped_url}" rel="noreferrer">Support or allowlist request</a></p>'
    return "\n".join([
        "<!doctype html>",
        '<html lang="en">',
        "<head>",
        '  <meta charset="utf-8">',
        '  <meta name="viewport" content="width=device-width, initial-scale=1">',
        f"  <title>{title}</title>",
        "  <style>",
        "    :root { color-scheme: light dark; font-family: Segoe UI, Arial, sans-serif; }",
        "    body { margin: 0; min-height: 100vh; display: grid; place-items: center; background: #f6f7f9; color: #171a1f; }",
        "    main { width: min(760px, calc(100% - 32px)); border: 1px solid #d8dee8; border-radius: 8px; background: #ffffff; padding: 28px; box-shadow: 0 16px 40px rgba(20, 33, 56, 0.12); }",
        "    h1 { margin: 0 0 12px; font-size: 1.65rem; line-height: 1.2; }",
        "    p { line-height: 1.5; }",
        "    dl { display: grid; grid-template-columns: max-content 1fr; gap: 8px 16px; margin: 20px 0; }",
        "    dt { font-weight: 700; }",
        "    dd { margin: 0; overflow-wrap: anywhere; }",
        "    .note { border-left: 4px solid #b45309; padding-left: 12px; color: #3c2a0a; }",
        "    a { color: #0f5bd7; }",
        "    @media (prefers-color-scheme: dark) { body { background: #101418; color: #edf1f7; } main { background: #171d24; border-color: #303a46; box-shadow: none; } .note { color: #f6d9a6; } a { color: #8ab4ff; } }",
        "  </style>",
        "</head>",
        "<body>",
        "  <main>",
        f"    <h1>{title}</h1>",
        f"    <p>{message}</p>",
        "    <dl>",
        f"      <dt>Requested host</dt><dd>{requested_host}</dd>",
        f"      <dt>Requested domain</dt><dd>{requested_domain}</dd>",
        f"      <dt>Requested path</dt><dd>{requested_path}</dd>",
        f"      <dt>Responder</dt><dd>{app} local block page</dd>",
        f"      <dt>Generated</dt><dd>{generated_at}</dd>",
        "    </dl>",
        "    <p class=\"note\">This local HTTP page is informational only. Hosts files cannot redirect URL paths, and HTTPS requests require separate certificate-aware infrastructure.</p>",
        f"    {support_html}",
        "  </main>",
        "</body>",
        "</html>",
        "",
    ])


def write_block_page_preview_html(
    output_path: str,
    *,
    title: str | None = None,
    message: str | None = None,
    support_url: str | None = None,
    requested_host: str | None = None,
    request_path: str | None = None,
) -> dict:
    headers = {"Host": requested_host or BLOCK_PAGE_DEFAULT_PREVIEW_HOST}
    context = build_block_page_request_context(
        request_path or BLOCK_PAGE_DEFAULT_PREVIEW_PATH,
        headers,
        title=title,
        message=message,
        support_url=support_url,
    )
    write_text_file_atomic(output_path, render_block_page_html(context))
    return context


def format_block_page_server_report(config: dict) -> str:
    lines = [
        "HostsFileGet local block page server",
        f"Schema: {config.get('schema', BLOCK_PAGE_SCHEMA)}",
        f"URL: {config.get('url')}",
        f"Loopback only: {'yes' if config.get('loopback_only') else 'no'}",
        f"Serves all routes: {'yes' if config.get('serves_all_routes') else 'no'}",
        f"Health path: {config.get('health_path')}",
        f"Writes hosts file: {'yes' if config.get('writes_hosts_file') else 'no'}",
        f"HTTPS supported: {'yes' if config.get('https_supported') else 'no'}",
        f"Port 80 admin note: {'likely required' if config.get('requires_admin_for_port_80') else 'not applicable'}",
        f"Title: {config.get('title')}",
    ]
    support_url = config.get("support_url")
    if support_url:
        lines.append(f"Support URL: {support_url}")
    lines.append("")
    lines.append("Warnings:")
    for warning in config.get("warnings", []):
        lines.append(f"- {warning}")
    lines.append("")
    lines.append(f"Roadmap source IDs: {', '.join(config.get('references', []))}")
    return "\n".join(lines)


class BlockPageServer(socketserver.ThreadingMixIn, http.server.HTTPServer):
    daemon_threads = True
    allow_reuse_address = True


class BlockPageRequestHandler(http.server.BaseHTTPRequestHandler):
    server_version = f"{APP_SLUG}BlockPage/{APP_VERSION}"

    def log_message(self, _format, *_args):  # pragma: no cover - avoids noisy CLI tests
        return

    def _headers(self, content_type: str, content_length: int) -> None:
        self.send_header("Content-Type", content_type)
        self.send_header("Content-Length", str(content_length))
        self.send_header("Cache-Control", "no-store")
        self.send_header("X-Content-Type-Options", "nosniff")
        self.send_header("Referrer-Policy", "no-referrer")
        self.send_header("Content-Security-Policy", "default-src 'none'; style-src 'unsafe-inline'; base-uri 'none'; form-action 'none'; frame-ancestors 'none'")

    def _send_html(self, status_code: int, body: str, include_body: bool = True) -> None:
        raw = body.encode("utf-8")
        self.send_response(status_code)
        self._headers("text/html; charset=utf-8", len(raw))
        self.end_headers()
        if include_body:
            self.wfile.write(raw)

    def _send_json(self, status_code: int, payload: dict, include_body: bool = True) -> None:
        raw = json.dumps(payload, indent=2).encode("utf-8")
        self.send_response(status_code)
        self._headers("application/json; charset=utf-8", len(raw))
        self.end_headers()
        if include_body:
            self.wfile.write(raw)

    def _render_context(self) -> dict:
        config = getattr(self.server, "block_page_config", {})
        return build_block_page_request_context(
            self.path,
            self.headers,
            title=config.get("title"),
            message=config.get("message"),
            support_url=config.get("support_url"),
        )

    def do_GET(self):
        path = urllib.parse.urlparse(self.path).path
        if path == BLOCK_PAGE_HEALTH_PATH:
            config = getattr(self.server, "block_page_config", {})
            self._send_json(200, {
                "schema": BLOCK_PAGE_SCHEMA,
                "status": "ok",
                "loopback_only": True,
                "writes_hosts_file": False,
                "url": config.get("url"),
            })
            return
        self._send_html(200, render_block_page_html(self._render_context()))

    def do_HEAD(self):
        path = urllib.parse.urlparse(self.path).path
        if path == BLOCK_PAGE_HEALTH_PATH:
            self._send_json(200, {
                "schema": BLOCK_PAGE_SCHEMA,
                "status": "ok",
                "loopback_only": True,
                "writes_hosts_file": False,
            }, include_body=False)
            return
        self._send_html(200, render_block_page_html(self._render_context()), include_body=False)

    def do_POST(self):
        self._send_json(405, {
            "schema": BLOCK_PAGE_SCHEMA,
            "error": "The block page server is read-only and only serves GET/HEAD responses.",
            "writes_hosts_file": False,
        })


def create_block_page_server(
    host: str = BLOCK_PAGE_DEFAULT_HOST,
    port: int = BLOCK_PAGE_DEFAULT_PORT,
    *,
    title: str | None = None,
    message: str | None = None,
    support_url: str | None = None,
):
    config = build_block_page_server_config(
        host=host,
        port=port,
        title=title,
        message=message,
        support_url=support_url,
    )
    server = BlockPageServer((config["host"], config["port"]), BlockPageRequestHandler)
    actual_host, actual_port = server.server_address[:2]
    config["host"] = actual_host
    config["port"] = actual_port
    config["url"] = f"http://{actual_host}:{actual_port}/"
    server.block_page_config = config
    return server


class LocalApiServer(socketserver.ThreadingMixIn, http.server.HTTPServer):
    daemon_threads = True
    allow_reuse_address = True


class LocalApiRequestHandler(http.server.BaseHTTPRequestHandler):
    server_version = f"{APP_SLUG}LocalAPI/{APP_VERSION}"

    def log_message(self, _format, *_args):  # pragma: no cover - avoids noisy CLI tests
        return

    def _send_json(self, status_code: int, payload: dict, extra_headers: dict | None = None) -> None:
        raw = json.dumps(payload, indent=2).encode("utf-8")
        self.send_response(status_code)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.send_header("Content-Length", str(len(raw)))
        self.send_header("Cache-Control", "no-store")
        for key, value in (extra_headers or {}).items():
            self.send_header(str(key), str(value))
        self.end_headers()
        self.wfile.write(raw)

    def _send_error_json(self, status_code: int, message: str) -> None:
        self._send_json(status_code, {"schema": LOCAL_API_SCHEMA, "error": message})

    def _authorized(self) -> bool:
        token = getattr(self.server, "auth_token", "")
        if local_api_authorization_valid(self.headers, token):
            return True
        self._send_json(
            401,
            {"schema": LOCAL_API_SCHEMA, "error": "Missing or invalid bearer token."},
            {"WWW-Authenticate": "Bearer"},
        )
        return False

    def _read_json_payload(self) -> dict:
        try:
            length = int(self.headers.get("Content-Length", "0"))
        except ValueError:
            raise ValueError("Invalid Content-Length.")
        if length < 0 or length > LOCAL_API_MAX_BODY_BYTES:
            raise ValueError(f"Request body exceeds {LOCAL_API_MAX_BODY_BYTES} byte limit.")
        raw = self.rfile.read(length) if length else b"{}"
        try:
            payload = json.loads(raw.decode("utf-8"))
        except (UnicodeDecodeError, json.JSONDecodeError) as exc:
            raise ValueError(f"Invalid JSON body: {exc}") from exc
        if not isinstance(payload, dict):
            raise ValueError("Request body must be a JSON object.")
        return payload

    def do_GET(self):
        if not self._authorized():
            return
        path = urllib.parse.urlparse(self.path).path
        if path == "/v1/status":
            self._send_json(200, build_local_api_status_payload(getattr(self.server, "hosts_path", None)))
            return
        self._send_error_json(404, "Unknown endpoint.")

    def do_POST(self):
        if not self._authorized():
            return
        path = urllib.parse.urlparse(self.path).path
        if path != "/v1/clean-preview":
            self._send_error_json(404, "Unknown endpoint.")
            return
        try:
            payload = self._read_json_payload()
            response = build_local_api_clean_preview_payload(payload)
        except ValueError as exc:
            self._send_error_json(400, str(exc))
            return
        self._send_json(200, response)


def create_local_api_server(
    host: str = LOCAL_API_DEFAULT_HOST,
    port: int = LOCAL_API_DEFAULT_PORT,
    token: str = "",
    hosts_path: str | None = None,
):
    host = str(host or LOCAL_API_DEFAULT_HOST).strip()
    if not is_loopback_api_host(host):
        raise ValueError("Local API host must be loopback-only: localhost, 127.0.0.1, or ::1.")
    try:
        port = int(port)
    except (TypeError, ValueError):
        raise ValueError("Local API port must be an integer.")
    if port < 0 or port > 65535:
        raise ValueError("Local API port must be between 0 and 65535.")
    sanitized_token = sanitize_local_api_token(token)
    server = LocalApiServer((host, port), LocalApiRequestHandler)
    server.auth_token = sanitized_token
    server.hosts_path = hosts_path or _default_hosts_file_path()
    return server


