    def show_source_bundle_selector(self):
        if self._block_during_import("Source Bundle Selector"):
            return

        bundle_catalog = list(getattr(self, "SOURCE_BUNDLES", []) or [])
        if not bundle_catalog:
            self._show_notice_dialog(
                "No source bundles are configured",
                "The curated source manifest does not define any import bundles.",
                tone="warning",
            )
            return

        dialog = tk.Toplevel(self.root)
        self._configure_modal_window(
            dialog,
            title="Source Bundle Selector",
            size="900x640",
            min_size=(760, 520),
        )

        intro, _ = self._create_sidebar_card(
            dialog,
            "Source bundle selector",
            "Pick a manifest-defined bundle and import its sources through the normal batch pipeline.",
            accent=PALETTE["blue"],
        )
        ttk.Label(
            intro,
            text=f"{len(bundle_catalog):,} bundle{'s' if len(bundle_catalog) != 1 else ''} available.",
            style="SectionBody.TLabel",
            wraplength=820,
            justify="left",
        ).pack(anchor="w")

        body = ttk.Frame(dialog, padding=(20, 0, 20, 12))
        body.pack(fill="both", expand=True)
        body.grid_columnconfigure(0, weight=0)
        body.grid_columnconfigure(1, weight=1)
        body.grid_rowconfigure(0, weight=1)

        listbox = tk.Listbox(
            body,
            width=34,
            height=12,
            bg=PALETTE["surface"],
            fg=PALETTE["text"],
            selectbackground=PALETTE["blue"],
            selectforeground=PALETTE["ink"],
            highlightbackground=PALETTE["border"],
            highlightcolor=PALETTE["focus"],
            relief="flat",
            borderwidth=0,
        )
        listbox.grid(row=0, column=0, sticky="nsew", padx=(0, 12))

        detail = scrolledtext.ScrolledText(body, wrap=tk.WORD, height=16)
        self._style_code_surface(detail, font_spec=self.mono_small_font)
        detail.grid(row=0, column=1, sticky="nsew")

        for bundle in bundle_catalog:
            listbox.insert(
                tk.END,
                f"{bundle.get('name', 'Unnamed bundle')} [{bundle.get('risk', 'medium')}]",
            )

        selected_bundle = {"value": bundle_catalog[0]}

        def selected_index() -> int:
            selection = listbox.curselection()
            if selection:
                return int(selection[0])
            return 0

        def refresh_detail(_event=None):
            index = selected_index()
            bundle = bundle_catalog[index]
            selected_bundle["value"] = bundle
            detail.configure(state="normal")
            detail.delete("1.0", tk.END)
            detail.insert(tk.END, format_source_bundle_report(bundle))
            detail.configure(state="disabled")

        def import_selected():
            bundle = selected_bundle.get("value")
            sources = source_bundle_to_import_sources(bundle)
            if not sources:
                self.update_status("Selected source bundle has no importable sources.", is_error=True)
                return
            dialog.destroy()
            self.start_import_worker(sources)

        listbox.bind("<<ListboxSelect>>", refresh_detail)
        listbox.selection_set(0)
        listbox.activate(0)

        footer = ttk.Frame(dialog, padding=(20, 0, 20, 18))
        footer.pack(fill="x")
        ttk.Button(
            footer,
            text="Import Bundle",
            command=import_selected,
            style="Action.TButton",
        ).pack(side="right", padx=(8, 0))
        ttk.Button(
            footer,
            text="Close",
            command=dialog.destroy,
            style="Secondary.TButton",
        ).pack(side="right")

        refresh_detail()
        dialog.bind("<Escape>", lambda _event: dialog.destroy())
        dialog.grab_set()

    # ----------------------------- Sources Report ----------------------------
    def show_sources_report(self):
        lines = self.get_lines()
        buckets = summarize_source_contributions(lines)
        dialog = tk.Toplevel(self.root)
        self._configure_modal_window(
            dialog,
            title="Sources Report",
            size="980x680",
            min_size=(760, 560),
        )

        total_blocks = sum(b["blocking_entries"] for b in buckets)
        intro, _ = self._create_sidebar_card(
            dialog,
            "Sources report",
            "Ranked by blocking-entry contribution and fetched-source overlap so you can spot bloated, redundant, or low-value imports faster.",
            accent=PALETTE["accent"],
        )
        ttk.Label(
            intro,
            text=(
                f"{len(buckets):,} source bucket{'s' if len(buckets) != 1 else ''} detected. "
                f"{total_blocks:,} blocking entr{'y' if total_blocks == 1 else 'ies'} accounted for in the current editor."
            ),
            style="SectionBody.TLabel",
            wraplength=860,
            justify="left",
        ).pack(anchor="w")

        body = scrolledtext.ScrolledText(dialog, wrap=tk.NONE)
        self._style_code_surface(body, font_spec=self.mono_small_font)
        body.pack(expand=True, fill='both', padx=20, pady=(0, 12))

        if not buckets:
            body.insert(tk.END, "(editor is empty)\n")
        else:
            total_blocks = total_blocks or 1
            body.insert(tk.END, f"{'Source':<50} {'Blocks':>10} {'Lines':>10} {'Share':>8}\n")
            body.insert(tk.END, "-" * 80 + "\n")
            for b in buckets:
                share = 100.0 * b["blocking_entries"] / total_blocks
                name = b["name"][:49]
                body.insert(tk.END, f"{name:<50} {b['blocking_entries']:>10,} {b['total_lines']:>10,} {share:>7.1f}%\n")
        overlap_report = build_source_overlap_report(self._source_corpus_cache)
        body.insert(tk.END, "\n\n")
        body.insert(tk.END, format_source_overlap_report(overlap_report))
        body.insert(tk.END, "\n")
        body.configure(state="disabled")

        btn_row = ttk.Frame(dialog)
        btn_row.pack(fill="x", padx=20, pady=(0, 20))
        ttk.Button(btn_row, text="Close", command=dialog.destroy, style="Secondary.TButton").pack(side="right")
        dialog.grab_set()

